import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Users, Trash2 } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { AppRole } from "@/hooks/useUserRole";

interface UserRole {
  id: string;
  user_id: string;
  role: AppRole;
  created_at: string;
}

export function AdminRoleManager() {
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const { data: userRoles = [], isLoading } = useQuery({
    queryKey: ["user-roles"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("user_roles")
        .select("*")
        .order("created_at", { ascending: false });
      if (error) throw error;
      return data as UserRole[];
    },
  });

  const updateRoleMutation = useMutation({
    mutationFn: async ({ id, role }: { id: string; role: AppRole }) => {
      const { error } = await supabase
        .from("user_roles")
        .update({ role })
        .eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["user-roles"] });
      toast({ title: "Role updated successfully" });
    },
    onError: (err: any) => toast({ title: "Error", description: err.message, variant: "destructive" }),
  });

  const deleteRoleMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase
        .from("user_roles")
        .delete()
        .eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["user-roles"] });
      toast({ title: "User removed" });
    },
    onError: (err: any) => toast({ title: "Error", description: err.message, variant: "destructive" }),
  });

  return (
    <Card className="glass-card">
      <CardHeader>
        <CardTitle className="text-lg flex items-center gap-2">
          <Users className="h-5 w-5 text-primary" />User Role Management
        </CardTitle>
        <CardDescription>Change roles or remove user accounts</CardDescription>
      </CardHeader>
      <CardContent>
        {isLoading ? (
          <div className="text-center py-6 text-muted-foreground">Loading users...</div>
        ) : userRoles.length === 0 ? (
          <div className="text-center py-6 text-muted-foreground">No users found</div>
        ) : (
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>User ID</TableHead>
                <TableHead>Role</TableHead>
                <TableHead>Joined</TableHead>
                <TableHead className="text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {userRoles.map((ur) => (
                <TableRow key={ur.id}>
                  <TableCell className="font-mono text-xs max-w-[200px] truncate">{ur.user_id}</TableCell>
                  <TableCell>
                    <Select
                      value={ur.role}
                      onValueChange={(v) => updateRoleMutation.mutate({ id: ur.id, role: v as AppRole })}
                    >
                      <SelectTrigger className="w-32">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="ceo">
                          <Badge className="bg-purple-500/10 text-purple-600">CEO</Badge>
                        </SelectItem>
                        <SelectItem value="admin">
                          <Badge className="bg-primary/10 text-primary">Admin</Badge>
                        </SelectItem>
                        <SelectItem value="manager">
                          <Badge className="bg-blue-500/10 text-blue-600">Manager</Badge>
                        </SelectItem>
                        <SelectItem value="sales">
                          <Badge className="bg-orange-500/10 text-orange-600">Sales</Badge>
                        </SelectItem>
                        <SelectItem value="employee">
                          <Badge className="bg-muted text-muted-foreground">Employee</Badge>
                        </SelectItem>
                      </SelectContent>
                    </Select>
                  </TableCell>
                  <TableCell className="text-sm text-muted-foreground">
                    {new Date(ur.created_at).toLocaleDateString()}
                  </TableCell>
                  <TableCell className="text-right">
                    <Button
                      size="icon"
                      variant="ghost"
                      className="text-destructive"
                      onClick={() => deleteRoleMutation.mutate(ur.id)}
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        )}
      </CardContent>
    </Card>
  );
}

import { useState, useMemo, useEffect } from "react";
import {
  LayoutDashboard, Users, FolderKanban, Package, FileText, Wrench, Settings, ShieldCheck, ShoppingCart, Store, Receipt, Hammer, MessageSquareQuote, ChevronRight, Globe, Warehouse, UserPlus, ClipboardList, Briefcase, Sparkles, CalendarDays, Search, X, Sun, Moon, BarChart3, Clock, Paintbrush, FileBarChart, Languages, Box,
} from "lucide-react";
import akLogoDefault from "@/assets/ak-logo.png";
import { NavLink } from "@/components/NavLink";
import { useLocation } from "react-router-dom";
import { useUserRole } from "@/hooks/useUserRole";
import { useCompanySettings } from "@/hooks/useCompanySettings";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { useTranslation } from "@/contexts/LanguageContext";
import {
  Sidebar, SidebarContent, SidebarGroup, SidebarGroupContent, SidebarGroupLabel,
  SidebarMenu, SidebarMenuButton, SidebarMenuItem, useSidebar,
} from "@/components/ui/sidebar";
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";

import { allGroups } from "@/constants/sidebarItems";

function ThemeToggle({ collapsed }: { collapsed: boolean }) {
  const [isDark, setIsDark] = useState(() => document.documentElement.classList.contains("dark"));

  const toggle = () => {
    const next = !isDark;
    setIsDark(next);
    document.documentElement.classList.toggle("dark", next);
    localStorage.setItem("theme", next ? "dark" : "light");
  };

  useEffect(() => {
    const saved = localStorage.getItem("theme");
    if (saved === "light") {
      document.documentElement.classList.remove("dark");
      setIsDark(false);
    } else {
      document.documentElement.classList.add("dark");
      setIsDark(true);
    }
  }, []);

  return (
    <button
      onClick={toggle}
      className={`flex items-center gap-2 w-full rounded-lg transition-all text-sidebar-foreground/70 hover:text-sidebar-foreground hover:bg-sidebar-accent/50 ${
        collapsed ? "justify-center p-2" : "px-3 py-2"
      }`}
      title={isDark ? "Light Mode" : "Dark Mode"}
    >
      {isDark ? <Sun className="h-4 w-4 text-amber-400" /> : <Moon className="h-4 w-4 text-indigo-400" />}
      {!collapsed && <span className="text-xs font-medium">{isDark ? "Light Mode" : "Dark Mode"}</span>}
    </button>
  );
}

export function AppSidebar() {
  const { state } = useSidebar();
  const collapsed = state === "collapsed";
  const location = useLocation();
  const { isAdmin, canAccessRevenue } = useUserRole();
  const { settings } = useCompanySettings();
  const { t, language, setLanguage } = useTranslation();
  const logoSrc = settings.logo_url || akLogoDefault;
  const [searchQuery, setSearchQuery] = useState("");

  const { data: pendingOrders } = useQuery({
    queryKey: ["sidebar-pending-orders"],
    queryFn: async () => {
      const { count } = await supabase.from("store_orders").select("*", { count: "exact", head: true }).eq("status", "pending");
      return count || 0;
    },
    refetchInterval: 30000,
  });

  const { data: pendingServiceReqs } = useQuery({
    queryKey: ["sidebar-pending-service-reqs"],
    queryFn: async () => {
      const { count } = await supabase.from("service_requests").select("*", { count: "exact", head: true }).eq("status", "pending");
      return count || 0;
    },
    refetchInterval: 30000,
  });

  const badgeCounts: Record<string, number> = {
    orders: pendingOrders || 0,
    serviceReqs: pendingServiceReqs || 0,
  };

  const filterByRole = (items: any[]) =>
    items.filter(item => {
      if (item.adminOnly && !isAdmin) return false;
      if (item.revenueOnly && !canAccessRevenue) return false;
      return true;
    });

  const filteredGroups = useMemo(() => {
    const q = searchQuery.toLowerCase().trim();
    return allGroups.map(group => {
      const roleFiltered = filterByRole(group.items);
      if (!q) return { ...group, items: roleFiltered };
      return {
        ...group,
        items: roleFiltered.filter(item =>
          t(item.title).toLowerCase().includes(q) || item.url.toLowerCase().includes(q)
        ),
      };
    }).filter(g => g.items.length > 0);
  }, [searchQuery, isAdmin, canAccessRevenue, language]);

  const renderItem = (item: any) => {
    const isActive = location.pathname === item.url;
    const badgeCount = item.badgeKey ? badgeCounts[item.badgeKey] : 0;

    const linkContent = (
      <>
        <item.icon className="h-4 w-4 sm:h-[18px] sm:w-[18px] flex-shrink-0" />
        {!collapsed && <span className="text-xs sm:text-[13px] font-medium flex-1">{t(item.title)}</span>}
        {!collapsed && item.external && <ChevronRight className="h-3 w-3 ml-auto opacity-40" />}
        {!collapsed && badgeCount > 0 && (
          <Badge variant="destructive" className="text-[8px] h-4 min-w-[16px] px-1 ml-auto">
            {badgeCount}
          </Badge>
        )}
        {collapsed && badgeCount > 0 && (
          <span className="absolute -top-0.5 -right-0.5 h-2 w-2 rounded-full bg-destructive" />
        )}
      </>
    );

    const menuButton = (
      <SidebarMenuButton asChild isActive={isActive}>
        {item.external ? (
          <a href={item.url} target="_blank" rel="noopener noreferrer" className={`relative flex items-center gap-3 px-3 py-2 rounded-lg transition-all hover:bg-sidebar-accent/60 ${isActive ? "border-l-2 border-sidebar-primary" : ""}`}>
            {linkContent}
          </a>
        ) : (
          <NavLink to={item.url} end className={`relative flex items-center gap-3 px-3 py-2 rounded-lg transition-all hover:bg-sidebar-accent/60 ${isActive ? "border-l-2 border-sidebar-primary" : ""}`} activeClassName="bg-sidebar-accent text-sidebar-primary font-semibold">
            {linkContent}
          </NavLink>
        )}
      </SidebarMenuButton>
    );

    return (
      <SidebarMenuItem key={item.title}>
        {collapsed ? (
          <TooltipProvider delayDuration={0}>
            <Tooltip>
              <TooltipTrigger asChild>{menuButton}</TooltipTrigger>
              <TooltipContent side="right" className="text-xs font-medium">
                {t(item.title)}
                {badgeCount > 0 && <span className="ml-1.5 text-destructive font-bold">({badgeCount})</span>}
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>
        ) : menuButton}
      </SidebarMenuItem>
    );
  };

  return (
    <Sidebar collapsible="icon" className="border-r-0">
      {/* Brand Header */}
      <div className="px-4 py-5 flex items-center gap-3 border-b border-sidebar-border/50">
        <div className="relative flex-shrink-0">
          <div className="absolute -inset-0.5 bg-gradient-to-br from-violet-500/30 to-indigo-500/30 rounded-xl blur-sm" />
          <img src={logoSrc} alt={settings.company_name} className="relative w-10 h-10 rounded-xl object-contain bg-sidebar-accent/50 p-0.5" />
        </div>
        {!collapsed && (
          <div className="min-w-0 flex-1">
            <h1 className="text-sm font-bold text-sidebar-accent-foreground truncate font-display tracking-tight">{settings.company_name}</h1>
            <p className="text-[9px] text-sidebar-foreground/50 truncate font-medium mt-0.5">{settings.company_tagline}</p>
          </div>
        )}
      </div>

      {/* Search */}
      {!collapsed && (
        <div className="px-3 pt-3 pb-1">
          <div className="relative">
            <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-sidebar-foreground/40" />
            <Input
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder={t("common.search_pages")}
              className="h-8 pl-8 pr-7 text-xs bg-sidebar-accent/30 border-sidebar-border/40 focus:border-sidebar-primary/50 placeholder:text-sidebar-foreground/30"
            />
            {searchQuery && (
              <button onClick={() => setSearchQuery("")} className="absolute right-2 top-1/2 -translate-y-1/2 text-sidebar-foreground/40 hover:text-sidebar-foreground">
                <X className="h-3 w-3" />
              </button>
            )}
          </div>
        </div>
      )}

      <SidebarContent className="py-2 space-y-1">
        {filteredGroups.length === 0 && searchQuery ? (
          <div className="px-4 py-6 text-center">
            <Search className="h-6 w-6 mx-auto text-sidebar-foreground/20 mb-2" />
            <p className="text-[11px] text-sidebar-foreground/40">{t("common.no_pages_found")}</p>
          </div>
        ) : (
          filteredGroups.map(group => (
            <SidebarGroup key={group.label}>
              {!collapsed && (
                <SidebarGroupLabel className="text-[10px] uppercase tracking-widest font-semibold text-sidebar-foreground/40 px-3 mb-1">
                  {t(group.label)}
                  {searchQuery && <span className="ml-1 text-sidebar-primary/60">({group.items.length})</span>}
                </SidebarGroupLabel>
              )}
              <SidebarGroupContent>
                <SidebarMenu>
                  {group.items.map(renderItem)}
                </SidebarMenu>
              </SidebarGroupContent>
            </SidebarGroup>
          ))
        )}
      </SidebarContent>

      {/* Footer with Theme & Language Toggle */}
      <div className={`border-t border-sidebar-border/50 ${collapsed ? "px-2 py-2 space-y-1" : "px-4 py-3 space-y-1"}`}>
        <ThemeToggle collapsed={collapsed} />
        <button
          onClick={() => setLanguage(language === "bn" ? "en" : "bn")}
          className={`flex items-center gap-2 w-full rounded-lg transition-all text-sidebar-foreground/70 hover:text-sidebar-foreground hover:bg-sidebar-accent/50 ${
            collapsed ? "justify-center p-2" : "px-3 py-2"
          }`}
          title={language === "bn" ? "Switch to English" : "বাংলায় পরিবর্তন করুন"}
        >
          <Languages className="h-4 w-4 text-primary" />
          {!collapsed && <span className="text-xs font-medium">{language === "bn" ? "English" : "বাংলা"}</span>}
        </button>
        {!collapsed && (
          <p className="text-[9px] text-sidebar-foreground/30 font-medium mt-2">© {new Date().getFullYear()} {settings.company_name}</p>
        )}
      </div>
    </Sidebar>
  );
}

import { useState, useEffect, useRef } from "react";
import { Html5Qrcode } from "html5-qrcode";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Camera, CameraOff, Search, ScanBarcode } from "lucide-react";
import { useToast } from "@/hooks/use-toast";

interface BarcodeScannerProps {
  onBarcodeDetected: (sku: string) => void;
}

export function BarcodeScanner({ onBarcodeDetected }: BarcodeScannerProps) {
  const [manualSku, setManualSku] = useState("");
  const [cameraActive, setCameraActive] = useState(false);
  const [scanning, setScanning] = useState(false);
  const scannerRef = useRef<Html5Qrcode | null>(null);
  const { toast } = useToast();

  const startCamera = async () => {
    try {
      const scanner = new Html5Qrcode("barcode-reader");
      scannerRef.current = scanner;
      setCameraActive(true);
      setScanning(true);

      await scanner.start(
        { facingMode: "environment" },
        { fps: 10, qrbox: { width: 250, height: 100 } },
        (decodedText) => {
          onBarcodeDetected(decodedText);
          toast({ title: "Barcode scanned", description: `SKU: ${decodedText}` });
        },
        () => {}
      );
    } catch (err: any) {
      toast({ title: "Camera error", description: err?.message || "Could not access camera", variant: "destructive" });
      setCameraActive(false);
      setScanning(false);
    }
  };

  const stopCamera = async () => {
    if (scannerRef.current && scanning) {
      try {
        await scannerRef.current.stop();
        scannerRef.current.clear();
      } catch {}
    }
    scannerRef.current = null;
    setCameraActive(false);
    setScanning(false);
  };

  useEffect(() => {
    return () => {
      if (scannerRef.current && scanning) {
        scannerRef.current.stop().catch(() => {});
      }
    };
  }, [scanning]);

  const handleManualSearch = () => {
    if (manualSku.trim()) {
      onBarcodeDetected(manualSku.trim());
      setManualSku("");
    }
  };

  return (
    <Card className="glass-card">
      <CardHeader>
        <CardTitle className="text-lg flex items-center gap-2">
          <ScanBarcode className="h-5 w-5" />
          Barcode Scanner
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-4">
        {/* Manual SKU Input */}
        <div className="flex gap-2 items-end">
          <div className="flex-1 space-y-2">
            <Label>Enter SKU / Barcode</Label>
            <Input
              value={manualSku}
              onChange={(e) => setManualSku(e.target.value)}
              placeholder="Type or scan barcode..."
              onKeyDown={(e) => e.key === "Enter" && (e.preventDefault(), handleManualSearch())}
            />
          </div>
          <Button type="button" onClick={handleManualSearch} disabled={!manualSku.trim()}>
            <Search className="h-4 w-4 mr-1" /> Find
          </Button>
        </div>

        {/* Camera Toggle */}
        <div className="flex items-center gap-2">
          <Button
            type="button"
            variant={cameraActive ? "destructive" : "outline"}
            onClick={cameraActive ? stopCamera : startCamera}
            className="w-full"
          >
            {cameraActive ? <CameraOff className="h-4 w-4 mr-2" /> : <Camera className="h-4 w-4 mr-2" />}
            {cameraActive ? "Stop Camera" : "Scan with Camera"}
          </Button>
        </div>

        {/* Camera View */}
        <div
          id="barcode-reader"
          className={cameraActive ? "rounded-lg overflow-hidden border border-border" : "hidden"}
        />
      </CardContent>
    </Card>
  );
}

import { useEffect, useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { Save, LayoutGrid, Loader2 } from "lucide-react";
import { toast } from "sonner";
import { ImagePicker } from "@/components/ImagePicker";

interface CategoryTile {
  id: string;
  slug: string;
  title: string;
  subtitle: string | null;
  image_url: string | null;
  link_url: string;
  sort_order: number;
  is_active: boolean;
}

export function CategoryTilesManager() {
  const qc = useQueryClient();
  const [drafts, setDrafts] = useState<Record<string, CategoryTile>>({});
  const [savingId, setSavingId] = useState<string | null>(null);

  const { data: tiles, isLoading } = useQuery({
    queryKey: ["category_tiles_admin"],
    queryFn: async () => {
      const { data, error } = await (supabase.from("category_tiles" as any) as any)
        .select("*")
        .order("sort_order", { ascending: true });
      if (error) throw error;
      return data as CategoryTile[];
    },
  });

  useEffect(() => {
    if (tiles) {
      const map: Record<string, CategoryTile> = {};
      tiles.forEach((t) => (map[t.id] = { ...t }));
      setDrafts(map);
    }
  }, [tiles]);

  const saveMutation = useMutation({
    mutationFn: async (tile: CategoryTile) => {
      const { error } = await (supabase.from("category_tiles" as any) as any)
        .update({
          title: tile.title,
          subtitle: tile.subtitle,
          image_url: tile.image_url,
          link_url: tile.link_url,
          sort_order: tile.sort_order,
          is_active: tile.is_active,
        })
        .eq("id", tile.id);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["category_tiles_admin"] });
      qc.invalidateQueries({ queryKey: ["category_tiles_public"] });
      toast.success("Tile saved");
    },
    onError: (err: any) => toast.error(err?.message || "Save failed"),
    onSettled: () => setSavingId(null),
  });

  const update = (id: string, patch: Partial<CategoryTile>) => {
    setDrafts((d) => ({ ...d, [id]: { ...d[id], ...patch } }));
  };

  if (isLoading) {
    return (
      <Card>
        <CardContent className="p-8 flex items-center justify-center">
          <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
        </CardContent>
      </Card>
    );
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <LayoutGrid className="h-5 w-5" />
          Storefront Category Tiles
        </CardTitle>
        <CardDescription>
          Customize the 3 category cards (CCTV, Attendance, Servicing) shown on your home page. Upload an image
          or paste a public image URL — it overlays the gradient.
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-6">
        {Object.values(drafts)
          .sort((a, b) => a.sort_order - b.sort_order)
          .map((tile) => (
            <div key={tile.id} className="rounded-xl border p-4 sm:p-5 bg-card">
              <div className="flex items-center justify-between mb-4">
                <div>
                  <h4 className="font-bold text-base">{tile.title || tile.slug}</h4>
                  <p className="text-xs text-muted-foreground">slug: {tile.slug}</p>
                </div>
                <div className="flex items-center gap-2">
                  <Label htmlFor={`active-${tile.id}`} className="text-xs">Active</Label>
                  <Switch
                    id={`active-${tile.id}`}
                    checked={tile.is_active}
                    onCheckedChange={(v) => update(tile.id, { is_active: v })}
                  />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-3">
                  <div>
                    <Label className="text-xs">Title</Label>
                    <Input
                      value={tile.title}
                      onChange={(e) => update(tile.id, { title: e.target.value })}
                    />
                  </div>
                  <div>
                    <Label className="text-xs">Subtitle</Label>
                    <Input
                      value={tile.subtitle || ""}
                      onChange={(e) => update(tile.id, { subtitle: e.target.value })}
                    />
                  </div>
                  <div>
                    <Label className="text-xs">Sort Order (Lower = First)</Label>
                    <Input
                      type="number"
                      value={tile.sort_order}
                      onChange={(e) => update(tile.id, { sort_order: parseInt(e.target.value) || 0 })}
                    />
                  </div>
                  <div>
                    <Label className="text-xs">Link URL</Label>
                    <Input
                      value={tile.link_url}
                      onChange={(e) => update(tile.id, { link_url: e.target.value })}
                      placeholder="/?cat=CCTV"
                    />
                  </div>
                </div>
                <ImagePicker
                  value={tile.image_url || ""}
                  onChange={(url) => update(tile.id, { image_url: url || null })}
                  bucket="storefront-images"
                  label="Tile image"
