}

import { useState, useEffect } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { useNavigate } from "react-router-dom";
import { supabase } from "@/integrations/supabase/client";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { useCompanySettings } from "@/hooks/useCompanySettings";
import { useToast } from "@/hooks/use-toast";
import { FileText, Sparkles, User, Phone, Mail, Package } from "lucide-react";

interface GenerateInvoiceDialogProps {
  order: any | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function GenerateInvoiceDialog({ order, open, onOpenChange }: GenerateInvoiceDialogProps) {
  const { settings } = useCompanySettings();
  const queryClient = useQueryClient();
  const navigate = useNavigate();
  const { toast } = useToast();

  const [taxRate, setTaxRate] = useState<number>(0);
  const [taxLabel, setTaxLabel] = useState<string>("VAT");
  const [dueInDays, setDueInDays] = useState<number>(7);
  const [busy, setBusy] = useState(false);

  useEffect(() => {
    if (open) {
      setTaxRate(Number(settings?.default_tax_rate ?? 0));
      setTaxLabel("VAT");
      setDueInDays(7);
    }
  }, [open, settings?.default_tax_rate]);

  const subtotal = order ? Number(order.item_price) * Number(order.quantity) : 0;
  const taxAmount = (subtotal * taxRate) / 100;
  const total = subtotal + taxAmount;

  const generate = useMutation({
    mutationFn: async () => {
      if (!order) throw new Error("No order");

      // 1. Find or create client by phone (fallback by email)
      let clientId: string | null = null;
      if (order.customer_phone) {
        const { data: existing } = await supabase
          .from("clients")
          .select("id")
          .eq("phone", order.customer_phone)
          .maybeSingle();
        if (existing) clientId = existing.id;
      }
      if (!clientId && order.customer_email) {
        const { data: existing } = await supabase
          .from("clients")
          .select("id")
          .eq("email", order.customer_email)
          .maybeSingle();
        if (existing) clientId = existing.id;
      }
      if (!clientId) {
        const { data: newClient, error: cErr } = await supabase
          .from("clients")
          .insert({
            name: order.customer_name,
            phone: order.customer_phone || null,
            email: order.customer_email || null,
            notes: `Auto-created from store order on ${new Date().toLocaleDateString()}`,
          })
          .select("id")
          .single();
        if (cErr) throw cErr;
        clientId = newClient.id;
      }

      // 2. Generate invoice number via existing RPC
      const { data: invNumData, error: numErr } = await supabase.rpc("generate_invoice_number");
      if (numErr) throw numErr;
      const invoiceNumber = invNumData as unknown as string;

      // 3. Create invoice
      const issueDate = new Date().toISOString().split("T")[0];
      const due = new Date();
      due.setDate(due.getDate() + Number(dueInDays || 0));
      const dueDate = due.toISOString().split("T")[0];

      const { data: invoice, error: invErr } = await supabase
        .from("invoices")
        .insert({
          invoice_number: invoiceNumber,
          client_id: clientId,
          issue_date: issueDate,
          due_date: dueDate,
          status: "sent",
          subtotal,
          tax_rate: taxRate,
          tax_amount: taxAmount,
          total,
          notes: `Generated from store order #${order.id.slice(0, 8)}${taxRate > 0 ? ` · ${taxLabel} ${taxRate}%` : ""}`,
        })
        .select("id, invoice_number")
        .single();
      if (invErr) throw invErr;

      // 4. Insert line item
      const { error: itemErr } = await supabase.from("invoice_items").insert({
        invoice_id: invoice.id,
        description: order.item_name,
        quantity: Number(order.quantity),
        unit_price: Number(order.item_price),
        total: subtotal,
      });
      if (itemErr) throw itemErr;

      // 5. Link invoice to order
      await supabase
        .from("store_orders")
        .update({ invoice_id: invoice.id })
        .eq("id", order.id);

      return invoice;
    },
    onMutate: () => setBusy(true),
    onSettled: () => setBusy(false),
    onSuccess: (invoice) => {
      queryClient.invalidateQueries({ queryKey: ["store-orders"] });
      queryClient.invalidateQueries({ queryKey: ["invoices"] });
      queryClient.invalidateQueries({ queryKey: ["clients"] });
      toast({
        title: "Invoice generated",
        description: `${invoice.invoice_number} created. Opening invoices…`,
      });
      onOpenChange(false);
      navigate("/invoices");
    },
    onError: (err: any) => {
      toast({
        title: "Failed to generate invoice",
        description: err?.message || "Please try again.",
        variant: "destructive",
      });
    },
  });

  if (!order) return null;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-lg">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <FileText className="h-5 w-5 text-primary" />
            Generate Invoice
          </DialogTitle>
          <DialogDescription>
            Create an invoice for this order. The customer will be auto-saved to your client list.
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-4">
          {/* Customer card */}
          <div className="rounded-lg border bg-muted/30 p-3 space-y-1.5">
            <div className="flex items-center gap-2 text-sm font-semibold">
              <User className="h-3.5 w-3.5 text-muted-foreground" />
              {order.customer_name}
            </div>
            {order.customer_phone && (
              <div className="flex items-center gap-2 text-xs text-muted-foreground">
                <Phone className="h-3 w-3" />
                {order.customer_phone}
              </div>
            )}
            {order.customer_email && (
              <div className="flex items-center gap-2 text-xs text-muted-foreground">
                <Mail className="h-3 w-3" />
                {order.customer_email}
              </div>
            )}
          </div>

          {/* Item card */}
          <div className="rounded-lg border p-3">
            <div className="flex items-start justify-between gap-3">
              <div className="flex items-start gap-2 min-w-0">
                <Package className="h-4 w-4 text-muted-foreground mt-0.5 flex-shrink-0" />
                <div className="min-w-0">
                  <p className="text-sm font-medium truncate">{order.item_name}</p>
                  <p className="text-xs text-muted-foreground">
                    Qty: {order.quantity} × ৳{Number(order.item_price).toLocaleString()}
                  </p>
                </div>
              </div>
              <Badge variant="secondary" className="flex-shrink-0">
                ৳{subtotal.toLocaleString()}
              </Badge>
            </div>
          </div>

          {/* Tax & due controls */}
          <div className="grid grid-cols-3 gap-3">
            <div className="space-y-1.5">
              <Label htmlFor="tax-label" className="text-xs">Tax label</Label>
              <Input
                id="tax-label"
                value={taxLabel}
                onChange={(e) => setTaxLabel(e.target.value)}
                placeholder="VAT / GST"
                className="h-9"
              />
            </div>
            <div className="space-y-1.5">
              <Label htmlFor="tax-rate" className="text-xs">Tax rate (%)</Label>
              <Input
                id="tax-rate"
                type="number"
                min={0}
                max={100}
                step="0.01"
                value={taxRate}
                onChange={(e) => setTaxRate(Number(e.target.value) || 0)}
                className="h-9"
              />
            </div>
            <div className="space-y-1.5">
              <Label htmlFor="due-days" className="text-xs">Due in (days)</Label>
              <Input
                id="due-days"
                type="number"
                min={0}
                value={dueInDays}
                onChange={(e) => setDueInDays(Number(e.target.value) || 0)}
                className="h-9"
              />
            </div>
          </div>

          {/* Totals */}
          <div className="rounded-lg border bg-gradient-to-br from-primary/5 to-accent/5 p-4 space-y-1.5">
            <div className="flex items-center justify-between text-sm">
              <span className="text-muted-foreground">Subtotal</span>
              <span className="font-medium">৳{subtotal.toLocaleString()}</span>
            </div>
            <div className="flex items-center justify-between text-sm">
              <span className="text-muted-foreground">{taxLabel || "Tax"} ({taxRate}%)</span>
              <span className="font-medium">৳{taxAmount.toLocaleString(undefined, { maximumFractionDigits: 2 })}</span>
            </div>
            <div className="border-t pt-1.5 mt-1.5 flex items-center justify-between">
              <span className="font-semibold">Total</span>
              <span className="text-lg font-bold text-primary">৳{total.toLocaleString(undefined, { maximumFractionDigits: 2 })}</span>
            </div>
          </div>

          <p className="text-[11px] text-muted-foreground flex items-center gap-1.5">
            <Sparkles className="h-3 w-3" />
            After generation you'll be redirected to the Invoices page to download the PDF.
          </p>
        </div>

        <DialogFooter>
          <Button variant="outline" onClick={() => onOpenChange(false)} disabled={busy}>
            Cancel
          </Button>
          <Button onClick={() => generate.mutate()} disabled={busy}>
            {busy ? "Generating…" : "Generate Invoice"}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useRef, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Upload, Link2, X, Loader2, CheckCircle2, AlertCircle } from "lucide-react";
import { toast } from "sonner";

interface ImagePickerProps {
  value: string;
  onChange: (url: string) => void;
  bucket?: string;
  label?: string;
  className?: string;
  /** Aspect ratio for the preview (e.g. "aspect-video", "aspect-square"). */
  previewAspect?: string;
  /** Max file size in MB (default 5). */
  maxSizeMB?: number;
}

const ALLOWED_TYPES = ["image/jpeg", "image/png", "image/webp", "image/gif", "image/svg+xml"];
const ALLOWED_EXT_LABEL = "JPG, PNG, WEBP, GIF, SVG";

interface PreviewMeta {
  source: "upload" | "url";
  sizeKB?: number;
  type?: string;
  width?: number;
  height?: number;
  status: "loading" | "ok" | "error";
  error?: string;
}

/**
 * Dual-mode image picker: upload a file from device OR paste a public image URL.
 * Files go to the given Supabase Storage bucket (default: storefront-images).
 * Includes preview, type/size validation, and live metadata (dimensions, size, type).
 */
export function ImagePicker({
  value,
  onChange,
  bucket = "storefront-images",
  label = "Image",
  className = "",
  previewAspect = "aspect-video",
  maxSizeMB = 5,
}: ImagePickerProps) {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [uploading, setUploading] = useState(false);
  const [urlDraft, setUrlDraft] = useState("");
  const [meta, setMeta] = useState<PreviewMeta | null>(null);

  const handleFile = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (!ALLOWED_TYPES.includes(file.type)) {
      toast.error(`Unsupported type. Allowed: ${ALLOWED_EXT_LABEL}`);
      if (fileInputRef.current) fileInputRef.current.value = "";
      return;
    }
    if (file.size > maxSizeMB * 1024 * 1024) {
      toast.error(`Image must be smaller than ${maxSizeMB}MB`);
      if (fileInputRef.current) fileInputRef.current.value = "";
      return;
    }
    const sizeKB = Math.round(file.size / 1024);
    setUploading(true);
    setMeta({ source: "upload", sizeKB, type: file.type, status: "loading" });
    try {
      const ext = file.name.split(".").pop() || "jpg";
      const path = `${crypto.randomUUID()}.${ext}`;
      const { error: upErr } = await supabase.storage.from(bucket).upload(path, file, {
        cacheControl: "3600",
        upsert: false,
      });
      if (upErr) throw upErr;
      const { data: pub } = supabase.storage.from(bucket).getPublicUrl(path);
      onChange(pub.publicUrl);
      toast.success("Image uploaded");
    } catch (err: any) {
      toast.error(err?.message || "Upload failed");
      setMeta({ source: "upload", sizeKB, type: file.type, status: "error", error: err?.message });
    } finally {
      setUploading(false);
      if (fileInputRef.current) fileInputRef.current.value = "";
    }
  };

  const applyUrl = () => {
    const trimmed = urlDraft.trim();
    if (!trimmed) return;
    if (!/^https?:\/\//i.test(trimmed)) {
      toast.error("URL must start with http:// or https://");
      return;
    }
    // Validate the URL actually loads as an image before applying.
    setMeta({ source: "url", status: "loading" });
    const test = new Image();
    test.onload = () => {
      onChange(trimmed);
      setUrlDraft("");
      setMeta({
        source: "url",
        status: "ok",
        width: test.naturalWidth,
        height: test.naturalHeight,
      });
      toast.success("Image URL set");
    };
    test.onerror = () => {
      setMeta({ source: "url", status: "error", error: "Could not load image from URL" });
      toast.error("URL did not load as an image");
    };
    test.src = trimmed;
  };

  const handlePreviewLoad = (e: React.SyntheticEvent<HTMLImageElement>) => {
    const img = e.currentTarget;
    setMeta((m) => {
      const base: PreviewMeta = m ?? { source: "url", status: "ok" };
      return {
        ...base,
        status: "ok",
        width: img.naturalWidth,
        height: img.naturalHeight,
      };
    });
  };

  const handlePreviewError = () => {
    setMeta((m) => ({
      source: m?.source ?? "url",
      ...(m ?? {}),
      status: "error",
      error: "Image failed to load",
    }));
  };

  const clear = () => {
    onChange("");
    setMeta(null);
  };

  return (
    <div className={`space-y-2 ${className}`}>
      {label && <label className="text-sm font-medium">{label}</label>}

      {/* Preview */}
      <div className={`relative w-full ${previewAspect} rounded-lg overflow-hidden border bg-muted`}>
        {value ? (
          <>
            <img
              src={value}
              alt="preview"
              className="h-full w-full object-cover"
              onLoad={handlePreviewLoad}
              onError={handlePreviewError}
            />
            <button
              type="button"
              onClick={clear}
              className="absolute top-2 right-2 h-7 w-7 rounded-full bg-destructive text-destructive-foreground flex items-center justify-center shadow-md hover:scale-105 transition"
              aria-label="Remove image"
            >
              <X className="h-3.5 w-3.5" />
            </button>
          </>
        ) : (
          <div className="h-full w-full flex items-center justify-center text-xs text-muted-foreground">
            No image
          </div>
        )}
      </div>

      {/* Metadata strip */}
      {(value || meta) && (
        <div className="flex flex-wrap items-center gap-x-3 gap-y-1 text-[11px] text-muted-foreground">
          {meta?.status === "loading" && (
            <span className="flex items-center gap-1">
              <Loader2 className="h-3 w-3 animate-spin" /> Checking…
            </span>
          )}
          {meta?.status === "ok" && (
            <span className="flex items-center gap-1 text-emerald-500">
              <CheckCircle2 className="h-3 w-3" /> Valid
            </span>
          )}
          {meta?.status === "error" && (
            <span className="flex items-center gap-1 text-destructive">
              <AlertCircle className="h-3 w-3" /> {meta.error || "Invalid image"}
            </span>
          )}
          {meta?.type && <span>Type: {meta.type.replace("image/", "").toUpperCase()}</span>}
          {typeof meta?.sizeKB === "number" && (
            <span>
              Size: {meta.sizeKB >= 1024 ? `${(meta.sizeKB / 1024).toFixed(2)} MB` : `${meta.sizeKB} KB`}
            </span>
          )}
          {meta?.width && meta?.height && (
            <span>
              {meta.width}×{meta.height}px
            </span>
          )}
          <span className="ml-auto opacity-70">
            Max {maxSizeMB}MB · {ALLOWED_EXT_LABEL}
          </span>
        </div>
      )}

      {/* Upload */}
      <div className="flex gap-2">
        <input
          ref={fileInputRef}
          type="file"
          accept={ALLOWED_TYPES.join(",")}
          className="hidden"
          onChange={handleFile}
          disabled={uploading}
        />
        <Button
          type="button"
          variant="outline"
          size="sm"
          className="flex-1"
          onClick={() => fileInputRef.current?.click()}
          disabled={uploading}
        >
          {uploading ? <Loader2 className="h-4 w-4 animate-spin" /> : <Upload className="h-4 w-4" />}
          {uploading ? "Uploading…" : "Upload"}
        </Button>
      </div>

      {/* URL paste */}
      <div className="flex gap-2">
        <div className="relative flex-1">
          <Link2 className="absolute left-2.5 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-muted-foreground" />
          <Input
            placeholder="…or paste image URL"
            value={urlDraft}
            onChange={(e) => setUrlDraft(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Enter") {
                e.preventDefault();
                applyUrl();
              }
            }}
            className="pl-8 h-9 text-sm"
          />
        </div>
        <Button type="button" variant="secondary" size="sm" onClick={applyUrl} disabled={!urlDraft.trim()}>
          Apply
        </Button>
      </div>
    </div>
  );
}

export default ImagePicker;

