      {/* Signature & Footer - pushed to bottom */}
      <div style={{ marginTop: "auto", paddingTop: "24px" }}>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "48px" }}>
          <div style={{ textAlign: "center" }}>
