import { useState, useEffect } from "react";
import { GoogleGenerativeAI } from "@google/generative-ai";
import { Sparkles, TrendingUp, AlertCircle, RefreshCw } from "lucide-react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";

interface InsightData {
  todayProfit: number;
  todaySalesRevenue: number;
  pendingOrders: number;
  lowStockCount: number;
  outOfStockCount: number;
  unreadMessages: number;
  totalClients: number;
}

export function AIDashboardInsights({ data }: { data: InsightData }) {
  const [insights, setInsights] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchInsights = async (forceRefresh = false) => {
    try {
      setLoading(true);
      setError(null);

      const apiKey = import.meta.env.VITE_GEMINI_API_KEY;
      if (!apiKey) {
        throw new Error("Gemini API Key missing");
      }

      // Read from session storage to avoid spamming the API on every nav
      const cached = sessionStorage.getItem("dashboard_ai_insights");
      const cacheTime = sessionStorage.getItem("dashboard_ai_insights_time");

      if (!forceRefresh && cached && cacheTime) {
        const isFresh = new Date().getTime() - Number(cacheTime) < 1000 * 60 * 30; // 30 mins
        if (isFresh) {
          setInsights(cached);
          setLoading(false);
          return;
        }
      }

      const genAI = new GoogleGenerativeAI(apiKey);
      const model = genAI.getGenerativeModel({ model: "gemini-2.5-flash" });

      const prompt = `
        Act as an expert retail business analyst for an IT & CCTV retail store in Bangladesh.
        Review the following real-time dashboard metrics and provide a 3-bullet point executive summary.
        Keep it extremely concise, professional, and actionable. Do not use markdown headers, just 3 bullet points.
        Use Bengali language.

        Metrics today:
        - Net Profit Today: ৳${data.todayProfit}
        - Total Sales Revenue Today: ৳${data.todaySalesRevenue}
        - Pending Online Orders: ${data.pendingOrders}
        - Low Stock Items: ${data.lowStockCount}
        - Out of Stock Items: ${data.outOfStockCount}
        - Unread Customer Messages: ${data.unreadMessages}
        - Total Clients: ${data.totalClients}

        Rules:
        - If profit is negative, suggest cost cutting or pushing sales.
        - If there are pending orders or unread messages, emphasize customer service urgency.
        - If stock is low, remind about inventory management.
        - Add a relevant emoji at the start of each bullet point.
      `;

      const result = await model.generateContent(prompt);
      const responseText = result.response.text();

      setInsights(responseText);
      sessionStorage.setItem("dashboard_ai_insights", responseText);
      sessionStorage.setItem("dashboard_ai_insights_time", new Date().getTime().toString());
    } catch (err: any) {
      console.error("AI Insight Error:", err);
      setError(err.message || "Failed to generate AI insights.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    // Adding a slight delay so it doesn't block initial dashboard render
    const timer = setTimeout(() => {
      fetchInsights();
    }, 1000);
    return () => clearTimeout(timer);
  }, [data.todayProfit, data.pendingOrders]);

  if (error && !insights) return null; // Hide completely if API key is missing to not clutter dashboard

  return (
    <Card className="glass-card border-primary/20 relative overflow-hidden group">
      {/* Subtle animated gradient background */}
      <div className="absolute inset-0 bg-gradient-to-r from-primary/5 via-purple-500/5 to-accent/5 opacity-50" />

      <CardContent className="p-4 sm:p-5 relative z-10">
        <div className="flex items-center justify-between mb-3">
          <div className="flex items-center gap-2">
            <div className="bg-primary/10 p-1.5 rounded-md flex items-center justify-center">
              <Sparkles className="h-4 w-4 text-primary animate-pulse" />
            </div>
            <h3 className="font-semibold text-sm flex items-center gap-2 bg-clip-text text-transparent bg-gradient-to-r from-primary to-purple-600">
              AI Business Insights
            </h3>
          </div>
          <Button 
            variant="ghost" 
            size="icon" 
            className="h-6 w-6 text-muted-foreground hover:text-primary transition-colors"
            onClick={() => fetchInsights(true)}
            disabled={loading}
            title="Refresh Insights"
          >
            <RefreshCw className={`h-3.5 w-3.5 ${loading ? 'animate-spin' : ''}`} />
          </Button>
        </div>

        {loading && !insights ? (
          <div className="space-y-2 mt-2">
            <div className="h-3 w-[90%] bg-muted/60 animate-pulse rounded"></div>
            <div className="h-3 w-[75%] bg-muted/60 animate-pulse rounded"></div>
            <div className="h-3 w-[85%] bg-muted/60 animate-pulse rounded"></div>
          </div>
        ) : (
          <div className="text-xs sm:text-sm text-muted-foreground leading-relaxed whitespace-pre-wrap">
            {insights}
          </div>
        )}
      </CardContent>
    </Card>
  );
}

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Clock, ShoppingCart, FileText, TrendingUp, UserPlus, Wrench } from "lucide-react";
import { format } from "date-fns";

interface ActivityTimelineProps {
  orders: any[];
  invoices: any[];
  sales: any[];
  leads: any[];
  serviceRequests: any[];
}

type ActivityItem = {
  id: string;
  icon: any;
  label: string;
  detail: string;
  time: Date;
  color: string;
};

export function ActivityTimeline({ orders, invoices, sales, leads, serviceRequests }: ActivityTimelineProps) {
  const activities: ActivityItem[] = [];

  orders?.slice(0, 3).forEach(o => {
    activities.push({
      id: `order-${o.id}`,
      icon: ShoppingCart,
      label: `New order: ${o.item_name}`,
      detail: `${o.customer_name} • ৳${(Number(o.item_price) * o.quantity).toLocaleString()}`,
      time: new Date(o.created_at),
      color: "text-blue-500 bg-blue-500/10",
    });
  });

  invoices?.slice(0, 2).forEach(inv => {
    activities.push({
      id: `inv-${inv.id}`,
      icon: FileText,
      label: `Invoice ${inv.invoice_number}`,
      detail: `${(inv as any).clients?.name || "—"} • ${inv.status}`,
      time: new Date(inv.created_at),
      color: "text-emerald-500 bg-emerald-500/10",
    });
  });

  sales?.slice(0, 2).forEach(s => {
    activities.push({
      id: `sale-${s.id}`,
      icon: TrendingUp,
      label: `Sale: ${(s as any).products?.name || "Product"}`,
      detail: `৳${Number(s.total).toLocaleString()} • ${s.payment_status}`,
      time: new Date(s.created_at),
      color: "text-amber-500 bg-amber-500/10",
    });
  });

  leads?.slice(0, 2).forEach(l => {
    activities.push({
      id: `lead-${l.id}`,
      icon: UserPlus,
      label: `New lead: ${l.name}`,
      detail: `${l.service_type} • ${l.source || "website"}`,
      time: new Date(l.created_at),
      color: "text-purple-500 bg-purple-500/10",
    });
  });

  serviceRequests?.slice(0, 2).forEach(sr => {
    activities.push({
      id: `sr-${sr.id}`,
      icon: Wrench,
      label: `Service: ${sr.customer_name}`,
      detail: `${sr.category} • ${sr.urgency}`,
      time: new Date(sr.created_at),
      color: "text-rose-500 bg-rose-500/10",
    });
  });

  // Sort by time descending
  activities.sort((a, b) => b.time.getTime() - a.time.getTime());

  return (
    <Card className="glass-card">
      <CardHeader className="pb-2">
        <CardTitle className="text-sm flex items-center gap-2">
          <Clock className="h-4 w-4 text-primary" /> Recent Activity
        </CardTitle>
      </CardHeader>
      <CardContent>
        <div className="space-y-1">
          {activities.slice(0, 8).map((activity) => {
            const Icon = activity.icon;
            return (
              <div key={activity.id} className="flex items-start gap-3 py-2 border-b border-border/30 last:border-0">
                <div className={`h-8 w-8 rounded-lg flex items-center justify-center flex-shrink-0 ${activity.color}`}>
                  <Icon className="h-3.5 w-3.5" />
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-xs font-medium truncate">{activity.label}</p>
                  <p className="text-[10px] text-muted-foreground truncate">{activity.detail}</p>
                </div>
                <span className="text-[9px] text-muted-foreground flex-shrink-0 mt-0.5">
                  {format(activity.time, "dd MMM HH:mm")}
                </span>
              </div>
            );
          })}
          {activities.length === 0 && (
            <p className="text-xs text-muted-foreground text-center py-6">No recent activity</p>
          )}
        </div>
      </CardContent>
    </Card>
  );
}

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { BarChart3 } from "lucide-react";
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from "recharts";
import { format, subDays } from "date-fns";

interface RevenueChartProps {
  sales: any[];
  invoices: any[];
}

export function RevenueChart({ sales, invoices }: RevenueChartProps) {
  // Generate last 7 days data
  const chartData = Array.from({ length: 7 }, (_, i) => {
    const date = subDays(new Date(), 6 - i);
    const dateStr = format(date, "yyyy-MM-dd");
    const daySales = sales?.filter(s => s.sale_date === dateStr).reduce((sum: number, s: any) => sum + Number(s.total), 0) || 0;
    const dayInvoices = invoices?.filter((inv: any) => inv.status === "paid" && format(new Date(inv.issue_date), "yyyy-MM-dd") === dateStr).reduce((sum: number, inv: any) => sum + Number(inv.total), 0) || 0;
    return {
      date: format(date, "dd MMM"),
      sales: daySales,
      invoices: dayInvoices,
      total: daySales + dayInvoices,
    };
  });

  const totalWeek = chartData.reduce((sum, d) => sum + d.total, 0);

  return (
    <Card className="glass-card">
      <CardHeader className="pb-2">
        <div className="flex items-center justify-between">
          <CardTitle className="text-sm flex items-center gap-2">
            <BarChart3 className="h-4 w-4 text-primary" /> Revenue (7 Days)
          </CardTitle>
          <span className="text-xs font-bold text-primary">৳{totalWeek.toLocaleString()}</span>
        </div>
      </CardHeader>
      <CardContent>
        <div className="h-[200px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={chartData} margin={{ top: 5, right: 5, left: -20, bottom: 0 }}>
              <defs>
                <linearGradient id="colorRevenue" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="hsl(var(--primary))" stopOpacity={0.3} />
                  <stop offset="95%" stopColor="hsl(var(--primary))" stopOpacity={0} />
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" className="stroke-border/30" />
              <XAxis dataKey="date" tick={{ fontSize: 10 }} className="text-muted-foreground" />
              <YAxis tick={{ fontSize: 10 }} className="text-muted-foreground" />
              <Tooltip
                contentStyle={{
                  backgroundColor: "hsl(var(--card))",
                  border: "1px solid hsl(var(--border))",
                  borderRadius: "0.75rem",
                  fontSize: "12px",
                }}
                labelStyle={{ fontWeight: "bold", fontSize: "11px" }}
              />
              <Area type="monotone" dataKey="total" stroke="hsl(var(--primary))" fillOpacity={1} fill="url(#colorRevenue)" strokeWidth={2} />
            </AreaChart>
          </ResponsiveContainer>
        </div>
      </CardContent>
    </Card>
  );
}

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Package } from "lucide-react";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from "recharts";

interface TopProductsChartProps {
  sales: any[];
}

export function TopProductsChart({ sales }: TopProductsChartProps) {
  // Calculate top products from sales
  const productQuantities: Record<string, number> = {};

  sales?.forEach(sale => {
    const productName = sale.products?.name || "Unknown Product";
    productQuantities[productName] = (productQuantities[productName] || 0) + Number(sale.quantity || 1);
  });

  const chartData = Object.entries(productQuantities)
    .map(([name, quantity]) => ({ name, quantity }))
    .sort((a, b) => b.quantity - a.quantity)
    .slice(0, 5); // Top 5 products

  const colors = [
    "hsl(var(--primary))",
    "hsl(var(--primary) / 0.8)",
    "hsl(var(--primary) / 0.6)",
    "hsl(var(--primary) / 0.4)",
    "hsl(var(--primary) / 0.2)",
  ];

  return (
    <Card className="glass-card">
      <CardHeader className="pb-2">
        <CardTitle className="text-sm flex items-center gap-2">
          <Package className="h-4 w-4 text-primary" /> Top Products by Volume
        </CardTitle>
      </CardHeader>
      <CardContent>
        <div className="h-[200px] w-full">
          {chartData.length > 0 ? (
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData} layout="vertical" margin={{ top: 5, right: 5, left: -20, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" className="stroke-border/30" horizontal={false} />
                <XAxis type="number" tick={{ fontSize: 10 }} className="text-muted-foreground" />
                <YAxis dataKey="name" type="category" tick={{ fontSize: 10 }} width={80} className="text-muted-foreground" />
                <Tooltip
                  cursor={{ fill: "hsl(var(--muted))" }}
                  contentStyle={{
                    backgroundColor: "hsl(var(--card))",
                    border: "1px solid hsl(var(--border))",
                    borderRadius: "0.75rem",
                    fontSize: "12px",
                  }}
                  labelStyle={{ fontWeight: "bold", fontSize: "11px", color: "hsl(var(--foreground))" }}
                />
                <Bar dataKey="quantity" radius={[0, 4, 4, 0]}>
                  {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={colors[index % colors.length]} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          ) : (
            <div className="flex h-full items-center justify-center">
              <p className="text-xs text-muted-foreground">No sales data available</p>
            </div>
          )}
        </div>
      </CardContent>
    </Card>
  );
}

