      if (error) throw error;
      queryClient.invalidateQueries({ queryKey: ["marketing-posts"] });
      toast.success("পোস্ট সেভ হয়েছে!");
    } catch (err: any) { toast.error(err.message); }
    finally { setIsSaving(false); }
