              phone: customerPhone,
              source: "AI Chat",
              service_type: serviceType,
              status: "new",
              message: `AI চ্যাট থেকে স্বয়ংক্রিয়ভাবে তৈরি। আলোচনার বিষয়: ${summary}`,
              notes: `Session ID: ${sessionId}`,
            });
          }
        }
      } catch (dbErr) {
        console.warn("Could not save session to database (likely RLS policy restriction):", dbErr);
