          <div className="relative flex flex-col h-full sm:rounded-3xl bg-background border border-border/50 shadow-2xl sm:shadow-[0_25px_60px_rgba(0,0,0,0.4)] overflow-hidden backdrop-blur-xl">
            {/* Header — gradient with depth */}
            <div className="relative shrink-0 overflow-hidden">
              <div className="absolute inset-0 bg-gradient-to-r from-blue-600 via-indigo-600 to-purple-600" />
              <div className="absolute inset-0 bg-[radial-gradient(circle_at_30%_50%,rgba(255,255,255,0.1),transparent_70%)]" />
              <div className="absolute bottom-0 left-0 right-0 h-px bg-gradient-to-r from-transparent via-white/20 to-transparent" />

              <div className="relative px-5 py-4 flex items-center gap-3 text-white">
                <div className="relative">
                  <div className="absolute -inset-1 bg-white/20 rounded-xl blur" />
                  <div className="relative h-10 w-10 rounded-xl bg-white/15 backdrop-blur-sm flex items-center justify-center border border-white/20 shadow-inner">
                    <Bot className="h-5 w-5" />
                  </div>
                  <div className="absolute -bottom-0.5 -right-0.5 h-3 w-3 rounded-full bg-emerald-400 border-2 border-indigo-600">
                    <div className="absolute inset-0 rounded-full bg-emerald-400 animate-ping opacity-75" />
                  </div>
                </div>
                <div className="flex-1 min-w-0">
                  <h3 className="font-bold text-sm tracking-wide">AK AI সহকারী</h3>
                  <div className="flex items-center gap-1.5 mt-0.5">
                    <Zap className="h-2.5 w-2.5 text-yellow-300" />
                    <p className="text-[10px] opacity-80 font-medium tracking-wide">টেকনিক্যাল এক্সপার্ট • সেলস কনসালটেন্ট</p>
                  </div>
                </div>
                <button onClick={() => setOpen(false)} className="p-2 hover:bg-white/15 rounded-xl transition-colors backdrop-blur-sm">
                  <X className="h-5 w-5" />
                </button>
              </div>
            </div>

            {/* Messages */}
            <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-3">
              {messages.length === 0 && (
                <div className="space-y-4">
                  {/* Welcome card */}
                  <div className="relative overflow-hidden rounded-2xl">
                    <div className="absolute inset-0 bg-gradient-to-br from-primary/5 to-primary/10" />
                    <div className="relative p-4">
                      <p className="text-sm text-foreground leading-relaxed">
                        👋 আসসালামু আলাইকুম! আমি <strong className="text-primary">AK AI সহকারী</strong>। CCTV, অ্যাটেনডেন্স, নেটওয়ার্কিং — যেকোনো IT সলিউশনে আমি আপনাকে সাহায্য করতে পারি।
                      </p>
                    </div>
                  </div>

                  {/* Quick actions — premium cards */}
                  <div className="space-y-2">
                    {quickActions.map((a, i) => (
                      <button key={i} onClick={() => sendMessage(a.message)}
                        className="w-full group flex items-center gap-3 p-3 rounded-xl border border-border/50 hover:border-primary/30 bg-card/50 hover:bg-primary/5 transition-all duration-200 text-left"
                      >
                        <div className={`h-9 w-9 rounded-xl bg-gradient-to-br ${a.gradient} flex items-center justify-center shrink-0 shadow-sm group-hover:scale-110 group-hover:shadow-md transition-all duration-200`}>
                          <a.icon className="h-4 w-4 text-white" />
                        </div>
                        <span className="text-sm font-medium flex-1">{a.label}</span>
                        <ArrowRight className="h-3.5 w-3.5 text-muted-foreground opacity-0 group-hover:opacity-100 group-hover:translate-x-0.5 transition-all" />
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {messages.map((m, i) => (
                <div key={i} className={`flex ${m.role === "user" ? "justify-end" : "justify-start"} animate-fade-in`}>
                  <div className={`max-w-[85%] rounded-2xl px-4 py-3 text-sm ${
                    m.role === "user"
                      ? "bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-br-sm shadow-lg shadow-blue-500/15"
                      : "bg-muted/60 text-foreground rounded-bl-sm border border-border/30 backdrop-blur-sm"
                  }`}>
                    {m.role === "assistant" ? (
                      <div className="prose prose-sm dark:prose-invert max-w-none [&>p]:mb-1 [&>ul]:mb-1 [&>ol]:mb-1 [&>h1]:text-base [&>h2]:text-sm [&>h3]:text-sm [&>p]:text-sm [&>li]:text-sm">
                        <ReactMarkdown
                          components={{
                            a: ({ href, children, ...props }) => {
                              const isWhatsApp = href?.includes("wa.me");
                              if (isWhatsApp) {
                                return (
                                  <a href={href} target="_blank" rel="noopener noreferrer"
                                    className="inline-flex items-center gap-2 bg-gradient-to-r from-green-500 to-emerald-600 hover:from-green-600 hover:to-emerald-700 text-white font-bold px-4 py-2.5 rounded-xl no-underline transition-all mt-2 mb-1 text-sm shadow-lg shadow-green-500/20 hover:shadow-green-500/30 hover:scale-[1.02]"
                                    {...props}
                                  >
                                    <ShoppingCart className="h-4 w-4" />
                                    {children}
                                  </a>
                                );
                              }
                              return <a href={href} target="_blank" rel="noopener noreferrer" className="text-primary underline" {...props}>{children}</a>;
                            },
                          }}
                        >{m.content}</ReactMarkdown>
                      </div>
                    ) : (
                      <p>{m.content}</p>
                    )}
                  </div>
                </div>
              ))}

              {isLoading && messages[messages.length - 1]?.role === "user" && (
                <div className="flex justify-start animate-fade-in">
                  <div className="bg-muted/60 rounded-2xl rounded-bl-sm px-4 py-3 border border-border/30">
                    <div className="flex items-center gap-2.5">
                      <div className="h-6 w-6 rounded-lg bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center">
                        <Bot className="h-3.5 w-3.5 text-white animate-pulse" />
                      </div>
                      <div className="flex flex-col gap-1">
                        <span className="text-[9px] text-primary font-mono tracking-wider">THINKING</span>
                        <div className="flex gap-1">
                          <span className="w-1.5 h-1.5 bg-primary/50 rounded-full animate-bounce [animation-delay:0ms]" />
                          <span className="w-1.5 h-1.5 bg-primary/50 rounded-full animate-bounce [animation-delay:150ms]" />
                          <span className="w-1.5 h-1.5 bg-primary/50 rounded-full animate-bounce [animation-delay:300ms]" />
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              )}
            </div>

            {/* Input — premium bottom bar */}
            <div className="border-t border-border/50 p-3 shrink-0 bg-background/80 backdrop-blur-xl">
              <form onSubmit={(e) => { e.preventDefault(); sendMessage(input); }}
                className="relative flex gap-2"
              >
                <div className="flex-1 relative">
                  <input
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    placeholder="আপনার প্রশ্ন লিখুন..."
                    className="w-full bg-muted/40 rounded-xl px-4 py-2.5 text-sm border border-border/30 outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary/30 transition-all text-foreground placeholder:text-muted-foreground"
                  />
                </div>
                <Button type="submit" size="icon" disabled={!input.trim() || isLoading}
                  className="rounded-xl h-10 w-10 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 shadow-lg shadow-blue-500/20 transition-all hover:shadow-blue-500/30 hover:scale-105"
                >
                  <Send className="h-4 w-4" />
                </Button>
              </form>
              <p className="text-[9px] text-muted-foreground text-center mt-2 font-medium tracking-wide">
                Powered by <span className="text-primary">Gemini AI</span> • AK IT Solution
              </p>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

import { useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { GoogleGenerativeAI } from "@google/generative-ai";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Sparkles, Loader2, ShoppingCart, MessageCircle, Wand2, CheckCircle2, RotateCcw } from "lucide-react";
import { toast } from "sonner";
import { useCartStore } from "@/stores/cartStore";
import { openWhatsApp } from "@/lib/whatsapp";
import { useCompanySettings } from "@/hooks/useCompanySettings";

type QuoteItem = {
  type: "product" | "service";
  id: string;
  name: string;
  category?: string;
  quantity: number;
  unit_price: number;
  total: number;
  reason: string;
};

type QuoteResult = {
  summary: string;
  notes: string;
  items: QuoteItem[];
  subtotal: number;
  lead_id: string | null;
};

const SUGGESTIONS_BN = [
  "৪টি ক্যামেরা দিয়ে আমার দোকানের জন্য সিসিটিভি সিস্টেম দরকার, রাতে ভালো দেখা যায়",
  "৫০ জন কর্মচারীর জন্য ফেস + ফিঙ্গারপ্রিন্ট অ্যাটেনডেন্স ডিভাইস",
  "ছোট অফিসের জন্য ৮ ক্যামেরা সিসিটিভি, ১ মাস রেকর্ডিং",
  "বাসার জন্য ২ ক্যামেরা, মোবাইল থেকে লাইভ দেখা যাবে",
];
const SUGGESTIONS_EN = [
  "I need a 4-camera CCTV system for my shop with good night vision",
  "Face + fingerprint attendance device for 50 employees",
  "8-camera CCTV for small office with 30-day recording",
  "2-camera home setup with live mobile view",
];

export function AISmartQuoteBuilder({
  language = "bn",
  trigger,
}: {
  language?: "bn" | "en";
  trigger?: React.ReactNode;
}) {
  const [open, setOpen] = useState(false);
  const [requirement, setRequirement] = useState("");
  const [customerName, setCustomerName] = useState("");
  const [customerPhone, setCustomerPhone] = useState("");
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<QuoteResult | null>(null);
  const addToCart = useCartStore((s) => s.addItem);
  const { settings } = useCompanySettings();

  const isBn = language === "bn";
  const t = (bn: string, en: string) => (isBn ? bn : en);

  const handleGenerate = async () => {
    if (requirement.trim().length < 8) {
      toast.error(t("আরো বিস্তারিত লিখুন", "Please describe in more detail"));
      return;
    }
    setLoading(true);
    setResult(null);
    try {
      const apiKey = import.meta.env.VITE_GEMINI_API_KEY;
      if (!apiKey) throw new Error("Gemini API Key is not configured.");

      // Fetch products and services from Supabase
      const { data: products } = await supabase
        .from("products")
        .select("id, name, category, brand, price, stock_quantity, description")
        .eq("show_in_store", true)
        .gt("stock_quantity", 0)
        .limit(300);

      const { data: services } = await supabase
        .from("services")
        .select("id, name, category, price, description")
        .eq("status", "active")
        .limit(100);

      const catalog = {
        products: (products || []).map(p => ({
          id: p.id, name: p.name, category: p.category, brand: p.brand,
          price: Number(p.price), stock: p.stock_quantity, desc: p.description?.slice(0, 120) || "",
        })),
        services: (services || []).map(s => ({
          id: s.id, name: s.name, category: s.category, price: Number(s.price),
        })),
      };

      const lang = language === "en" ? "English" : "Bengali (Bangla)";
      const systemPrompt = `You are AK IT Solution's expert sales engineer for CCTV, attendance devices, networking and IT equipment in Bangladesh. Currency is BDT (৳).

You will receive a customer requirement. Pick the BEST matching products and services from the provided catalog ONLY. Never invent items. Recommend reasonable quantities (e.g. cables, connectors, hard drive sized for camera count, DVR/NVR matching channel count, monitor if needed, installation service).

Respond in ${lang} for human-readable fields. Be concise, practical, and price-conscious.

Return ONLY valid JSON (no markdown, no code blocks), with this exact shape:
{
  "summary": "1-2 sentence summary of what was selected and why",
  "items": [
    { "type": "product" | "service", "id": "<catalog id>", "name": "<exact catalog name>", "quantity": <int>, "unit_price": <number>, "reason": "<short why>" }
  ],
  "notes": "any installation/warranty/delivery note (1-2 lines)"
}`;

      const userPrompt = `Customer requirement: "${requirement.trim()}"\n\nAvailable catalog:\n${JSON.stringify(catalog)}`;

      const genAI = new GoogleGenerativeAI(apiKey);
      const model = genAI.getGenerativeModel({
        model: "gemini-2.5-flash",
        systemInstruction: systemPrompt,
      });

      const response = await model.generateContent(userPrompt);
      let content = response.response.text();
      
      content = content.replace(/^```json\n?/, "").replace(/\n?```$/, "").trim();

      let parsed: any;
      try { parsed = JSON.parse(content); } catch { parsed = { summary: content, items: [], notes: "" }; }

      const productMap = new Map(catalog.products.map(p => [p.id, p]));
      const serviceMap = new Map(catalog.services.map(s => [s.id, s]));
      
      const validItems = (parsed.items || []).map((it: any) => {
        const ref = it.type === "service" ? serviceMap.get(it.id) : productMap.get(it.id);
        if (!ref) return null;
        const qty = Math.max(1, parseInt(it.quantity) || 1);
        return {
          type: it.type,
          id: it.id,
          name: ref.name,
          category: (ref as any).category,
          quantity: qty,
          unit_price: Number(ref.price),
          total: Number(ref.price) * qty,
          reason: String(it.reason || "").slice(0, 200),
        };
      }).filter(Boolean);

      if (!validItems.length) {
        toast.error(t("কোনো মিলিয়ে পণ্য পাওয়া যায়নি", "No matching items found"));
        setLoading(false);
        return;
      }

      const subtotal = validItems.reduce((s: number, i: any) => s + i.total, 0);

      // Attempt to save lead
      let lead_id = null;
      if (customerName && customerPhone) {
        try {
          // Fire and forget insertion, won't block if RLS fails without select
          const { error: dbErr } = await supabase.from("leads").insert({
            name: customerName,
            phone: customerPhone,
            service_type: "AI Quote",
            source: "AI Quote Builder",
            status: "new",
            message: requirement,
            notes: `AI generated quote — Subtotal ৳${subtotal.toLocaleString()}\n\nItems:\n${validItems.map((i: any) => `• ${i.name} ×${i.quantity} = ৳${i.total.toLocaleString()}`).join("\n")}\n\n${parsed.notes || ""}`,
          });
          if (!dbErr) lead_id = "generated";
        } catch (e) {
          console.warn("Failed to insert lead, ignoring RLS error:", e);
        }
      }

      const quoteResult: QuoteResult = {
        summary: parsed.summary || "",
        notes: parsed.notes || "",
        items: validItems,
        subtotal,
        lead_id,
      };

      setResult(quoteResult);
      if (lead_id) {
        toast.success(t("কোট তৈরি হয়েছে — আমরা যোগাযোগ করবো", "Quote created — we'll reach out"));
      }

    } catch (e: any) {
      console.error(e);
      toast.error(e?.message || t("ত্রুটি ঘটেছে", "Something went wrong"));
    } finally {
      setLoading(false);
    }
  };

  const addAllToCart = () => {
    if (!result) return;
    let added = 0;
    result.items.forEach((it) => {
      if (it.type !== "product") return;
      addToCart({
        id: it.id,
        product_id: it.id,
        name: it.name,
        price: it.unit_price,
        image_url: null,
        type: "product",
        quantity: it.quantity,
      });
      added += 1;
    });
    toast.success(t(`${added} টি পণ্য কার্টে যোগ হয়েছে`, `${added} products added to cart`));
    setOpen(false);
  };

  const sendWhatsApp = () => {
    if (!result) return;
    const phone = settings?.whatsapp_number || settings?.phone || "";
    const lines = result.items.map(
      (i) => `• ${i.name} ×${i.quantity} = ৳${i.total.toLocaleString()}`
    ).join("\n");
    const msg = t(
      `🛒 *AI Smart Quote*\n\n${customerName ? `👤 ${customerName}\n` : ""}${customerPhone ? `📞 ${customerPhone}\n\n` : "\n"}📝 *চাহিদা:* ${requirement}\n\n📦 *আইটেম:*\n${lines}\n\n💰 *মোট:* ৳${result.subtotal.toLocaleString()}\n\n${result.notes || ""}`,
      `🛒 *AI Smart Quote*\n\n${customerName ? `👤 ${customerName}\n` : ""}${customerPhone ? `📞 ${customerPhone}\n\n` : "\n"}📝 *Requirement:* ${requirement}\n\n📦 *Items:*\n${lines}\n\n💰 *Total:* ৳${result.subtotal.toLocaleString()}\n\n${result.notes || ""}`
    );
    openWhatsApp(phone, msg);
  };

  const reset = () => {
    setResult(null);
    setRequirement("");
  };

  const suggestions = isBn ? SUGGESTIONS_BN : SUGGESTIONS_EN;

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        {trigger || (
          <Button
            size="lg"
            className="bg-gradient-to-r from-primary to-accent hover:opacity-90 text-primary-foreground shadow-lg shadow-primary/30 gap-2"
          >
            <Sparkles className="h-5 w-5" />
            {t("AI স্মার্ট কোট", "AI Smart Quote")}
          </Button>
        )}
      </DialogTrigger>
      <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto bg-card border-border">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2 text-2xl">
            <Wand2 className="h-6 w-6 text-primary" />
            {t("AI স্মার্ট কোট বিল্ডার", "AI Smart Quote Builder")}
          </DialogTitle>
          <p className="text-sm text-muted-foreground">
            {t(
              "শুধু আপনার প্রয়োজন বলুন — AI সঠিক পণ্য, পরিমাণ ও মূল্য সাজিয়ে দিবে",
              "Just describe your need — AI picks the right products, quantity & price"
            )}
          </p>
        </DialogHeader>

        {!result ? (
          <div className="space-y-4">
            <div>
              <Label className="mb-2 block">{t("আপনার চাহিদা", "Your requirement")} *</Label>
              <Textarea
                value={requirement}
                onChange={(e) => setRequirement(e.target.value)}
                placeholder={t(
                  "যেমন: আমার দোকানের জন্য ৪টি HD ক্যামেরা, রাতের জন্য ভালো, ১ মাস রেকর্ডিং চাই",
                  "e.g. 4 HD cameras for my shop, good night vision, 1-month recording"
                )}
                rows={4}
                className="resize-none"
              />
              <div className="mt-3 flex flex-wrap gap-2">
                {suggestions.map((s) => (
                  <button
                    key={s}
                    type="button"
                    onClick={() => setRequirement(s)}
                    className="text-xs px-3 py-1.5 rounded-full bg-secondary/60 hover:bg-secondary text-secondary-foreground border border-border transition"
                  >
                    {s.length > 50 ? s.slice(0, 50) + "…" : s}
                  </button>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              <div>
                <Label className="mb-2 block">{t("নাম (ঐচ্ছিক)", "Name (optional)")}</Label>
                <Input
                  value={customerName}
                  onChange={(e) => setCustomerName(e.target.value)}
                  placeholder={t("আপনার নাম", "Your name")}
                />
              </div>
              <div>
                <Label className="mb-2 block">{t("ফোন (ঐচ্ছিক)", "Phone (optional)")}</Label>
                <Input
                  value={customerPhone}
                  onChange={(e) => setCustomerPhone(e.target.value)}
                  placeholder="01XXXXXXXXX"
                />
              </div>
            </div>
            <p className="text-xs text-muted-foreground">
              {t(
                "নাম ও ফোন দিলে আমরা সাথে সাথে আপনাকে ফলোআপ করতে পারবো",
                "Adding name & phone lets us follow up with you instantly"
              )}
            </p>

            <Button
              onClick={handleGenerate}
              disabled={loading}
              size="lg"
              className="w-full bg-gradient-to-r from-primary to-accent hover:opacity-90 gap-2"
            >
              {loading ? (
                <>
                  <Loader2 className="h-4 w-4 animate-spin" />
                  {t("AI চিন্তা করছে...", "AI is thinking...")}
                </>
              ) : (
                <>
                  <Sparkles className="h-4 w-4" />
                  {t("কোট তৈরি করুন", "Generate Quote")}
                </>
              )}
            </Button>
          </div>
        ) : (
          <div className="space-y-4">
            <div className="rounded-lg bg-primary/10 border border-primary/30 p-4">
              <div className="flex items-start gap-2">
                <CheckCircle2 className="h-5 w-5 text-primary shrink-0 mt-0.5" />
                <p className="text-sm leading-relaxed">{result.summary}</p>
              </div>
            </div>

            <div className="space-y-2">
              {result.items.map((it, idx) => (
                <div
                  key={idx}
                  className="flex items-start gap-3 p-3 rounded-lg bg-secondary/40 border border-border"
                >
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 flex-wrap">
                      <span className="font-medium">{it.name}</span>
                      <Badge variant="outline" className="text-xs">
                        {it.type === "service" ? t("সেবা", "Service") : t("পণ্য", "Product")}
                      </Badge>
                      {it.category && (
                        <Badge variant="secondary" className="text-xs">{it.category}</Badge>
                      )}
                    </div>
                    {it.reason && (
                      <p className="text-xs text-muted-foreground mt-1">{it.reason}</p>
                    )}
                    <p className="text-xs text-muted-foreground mt-1">
                      ৳{it.unit_price.toLocaleString()} × {it.quantity}
                    </p>
                  </div>
                  <div className="text-right font-semibold whitespace-nowrap">
                    ৳{it.total.toLocaleString()}
                  </div>
                </div>
              ))}
            </div>

            <div className="flex items-center justify-between p-4 rounded-lg bg-gradient-to-r from-primary/20 to-accent/20 border border-primary/30">
