    yourPackage: lang === "bn" ? "আপনার প্যাকেজ" : "Your Package",
    totalPrice: lang === "bn" ? "মোট মূল্য" : "Total Price",
    emptyPackage: lang === "bn" ? "কোনো পণ্য বাছাই করা হয়নি" : "No products selected yet",
    emptyDesc: lang === "bn" ? "উপরের ক্যাটাগরি থেকে পণ্য যোগ করুন" : "Add products from the categories above",
    items: lang === "bn" ? "টি আইটেম" : "items",
    startBuilding: lang === "bn" ? "প্যাকেজ তৈরি শুরু করুন" : "Start building your package",
    searchProducts: lang === "bn" ? "পণ্য খুঁজুন..." : "Search products...",
    placeOrder: lang === "bn" ? "অর্ডার করুন" : "Place Order",
    checkout: lang === "bn" ? "চেকআউট" : "Checkout",
    yourName: lang === "bn" ? "আপনার নাম *" : "Your Name *",
    namePlaceholder: lang === "bn" ? "আপনার নাম লিখুন" : "Enter your name",
    phone: lang === "bn" ? "ফোন নম্বর *" : "Phone Number *",
    paymentMethod: lang === "bn" ? "পেমেন্ট পদ্ধতি *" : "Payment Method *",
    confirmOrder: lang === "bn" ? "অর্ডার নিশ্চিত করুন" : "Confirm Order",
    orderSuccess: lang === "bn" ? "✅ অর্ডার সফল হয়েছে!" : "✅ Order placed successfully!",
    orderSuccessDesc: lang === "bn" ? "আমরা শীঘ্রই আপনার সাথে যোগাযোগ করব।" : "We will contact you shortly.",
    orderError: lang === "bn" ? "অর্ডার দিতে সমস্যা হয়েছে" : "Failed to place order",
  };

  const grouped = useMemo(() => {
    const map: Record<string, any[]> = {};
    products?.forEach((p: any) => {
      const cat = p.category || "Other";
      if (!map[cat]) map[cat] = [];
      map[cat].push(p);
    });
    return map;
  }, [products]);

  // Merge predefined categories with any from DB
  const categories = useMemo(() => {
    const dbCats = Object.keys(grouped);
    const merged = [...new Set([...allCategories, ...dbCats])];
    return merged;
  }, [grouped]);

  const filteredCategoryProducts = useMemo(() => {
    if (!expandedCat || !grouped[expandedCat]) return [];
    if (!searchQuery.trim()) return grouped[expandedCat];
    const q = searchQuery.toLowerCase();
    return grouped[expandedCat].filter((p: any) =>
      p.name.toLowerCase().includes(q) ||
      p.brand?.toLowerCase().includes(q) ||
      p.sku?.toLowerCase().includes(q)
    );
  }, [expandedCat, grouped, searchQuery]);

  const selectedProducts = useMemo(() => {
    const items: { product: any; qty: number }[] = [];
    Object.entries(selections).forEach(([id, qty]) => {
      if (qty > 0) {
        const p = products?.find((pr: any) => pr.id === id);
        if (p) items.push({ product: p, qty });
      }
    });
    return items;
  }, [selections, products]);

  const totalPrice = selectedProducts.reduce((sum, { product, qty }) => {
    const price = product.cash_discount_price ? Number(product.cash_discount_price) : Number(product.price);
    return sum + price * qty;
  }, 0);

  const totalItems = selectedProducts.reduce((sum, { qty }) => sum + qty, 0);

  const updateQty = (id: string, delta: number) => {
    setSelections(prev => {
      const current = prev[id] || 0;
      const next = Math.max(0, current + delta);
      if (next === 0) {
        const { [id]: _, ...rest } = prev;
        return rest;
      }
      return { ...prev, [id]: next };
    });
  };

  const removeItem = (id: string) => {
    setSelections(prev => {
      const { [id]: _, ...rest } = prev;
      return rest;
    });
  };
  const applyTemplate = (template: PackageTemplate) => {
    if (!products || products.length === 0) return;
    const newSelections: Record<string, number> = {};
    template.items.forEach(({ category, count }) => {
      const catProducts = grouped[category] || [];
      const inStock = catProducts.filter((p: any) => p.stock_quantity > 0);
      const toUse = inStock.length > 0 ? inStock : catProducts;
      for (let i = 0; i < Math.min(count, toUse.length); i++) {
        newSelections[toUse[i].id] = (newSelections[toUse[i].id] || 0) + 1;
      }
      // If we need more than available unique products, add qty to last one
      if (count > toUse.length && toUse.length > 0) {
        const lastId = toUse[toUse.length - 1].id;
        newSelections[lastId] = (newSelections[lastId] || 0) + (count - toUse.length);
      }
    });
    setSelections(newSelections);
    setActiveTemplate(template.id);
    setExpandedCat(template.items[0]?.category || null);
    toast.success(lang === "bn" ? `✅ ${template.name.bn} টেমপ্লেট প্রয়োগ করা হয়েছে` : `✅ ${template.name.en} template applied`, {
      description: lang === "bn" ? "আপনি পণ্য পরিবর্তন করতে পারেন" : "You can customize the products",
    });
  };
  const placeOrder = useMutation({
    mutationFn: async () => {
      const orderItems = selectedProducts.map(({ product, qty }) => {
        const price = product.cash_discount_price ? Number(product.cash_discount_price) : Number(product.price);
        return { product, qty, price };
      });
      const inserts = orderItems.map(({ product, qty, price }) => ({
        customer_name: orderForm.name,
        customer_phone: orderForm.phone,
        item_name: `[Package] ${product.name}`,
        item_price: price,
        quantity: qty,
        product_id: product.id,
        message: `Payment: ${orderForm.payment_method}`,
        status: "pending",
      }));
      const { error } = await supabase.from("store_orders").insert(inserts);
      if (error) throw error;
    },
    onSuccess: () => {
      toast.success(t.orderSuccess, { description: t.orderSuccessDesc });
      // Send WhatsApp notification to shop owner
      const ownerPhone = settings.phone?.split(",")[0]?.trim() || "01919060590";
      const phone = ownerPhone.replace(/[^0-9]/g, "");
      const whatsappNumber = phone.startsWith("0") ? `88${phone}` : phone;
      const itemsList = selectedProducts.map(({ product, qty }) => {
        const price = product.cash_discount_price ? Number(product.cash_discount_price) : Number(product.price);
        return `• ${product.name} ×${qty} = ৳${(price * qty).toLocaleString()}`;
      }).join("\n");
      const message = `🛒 *নতুন প্যাকেজ অর্ডার!*\n\n👤 *কাস্টমার:* ${orderForm.name}\n📞 *ফোন:* ${orderForm.phone}\n\n📦 *প্যাকেজ আইটেম:*\n${itemsList}\n\n💰 *মোট:* ৳${totalPrice.toLocaleString()}\n💳 *পেমেন্ট:* ${orderForm.payment_method}\n⏰ *সময়:* ${new Date().toLocaleString("bn-BD")}`;
      window.open(`https://wa.me/${whatsappNumber}?text=${encodeURIComponent(message)}`, "_blank");
      setSelections({});
      setCheckoutOpen(false);
      setOrderForm({ name: "", phone: "", payment_method: "cash_on_delivery" });
    },
    onError: () => toast.error(t.orderError),
  });

  const textPrimary = isDark ? "text-white" : "text-gray-900";
  const textSecondary = isDark ? "text-white/60" : "text-gray-600";
  const textMuted = isDark ? "text-white/40" : "text-gray-400";
  const cardBorder = isDark ? "border-white/10" : "border-gray-200";
  const summaryBg = isDark ? "bg-gradient-to-br from-blue-600/10 to-cyan-600/5 border-blue-500/20" : "bg-gradient-to-br from-blue-50 to-cyan-50 border-blue-200";
  const catBg = isDark ? "bg-white/[0.03] hover:bg-white/[0.06]" : "bg-gray-50 hover:bg-gray-100";
  const catActiveBg = isDark ? "bg-blue-600/10 border-blue-500/30" : "bg-blue-50 border-blue-300";
  const productRowBg = isDark ? "hover:bg-white/[0.03]" : "hover:bg-gray-50";
  const gradientPrice = isDark ? "bg-gradient-to-r from-blue-400 to-cyan-400 bg-clip-text text-transparent" : "text-blue-600";
  const cardBg = isDark ? "bg-white/[0.04]" : "bg-white";
  const inputBg = isDark ? "bg-white/5 border-white/10 text-white placeholder:text-white/30" : "bg-white border-gray-200";
  const dialogBg = isDark ? "bg-[#0f1525] border-white/10 text-white" : "bg-white";
  const infoBg = isDark ? "bg-white/5" : "bg-gray-50";
  const labelColor = isDark ? "text-white/70" : "text-gray-700";

  return (
    <section className="max-w-7xl mx-auto px-3 sm:px-6 lg:px-8 pb-16">
      {/* Header */}
      <div className="text-center mb-6 sm:mb-8">
        <div className={`inline-flex items-center gap-2 px-4 py-1.5 rounded-full text-xs font-medium mb-3 sm:mb-4 ${isDark ? "bg-gradient-to-r from-blue-500/10 to-cyan-500/10 border border-blue-500/20 text-blue-300" : "bg-gradient-to-r from-blue-50 to-cyan-50 border border-blue-200 text-blue-600"}`}>
          <Sparkles className="h-3.5 w-3.5" /> {t.title}
        </div>
        <p className={`text-xs sm:text-sm ${textSecondary} max-w-lg mx-auto`}>{t.subtitle}</p>
      </div>

      {/* Quick Start Templates */}
      {totalItems === 0 && (
        <div className="mb-6">
          <h3 className={`text-xs sm:text-sm font-semibold mb-3 flex items-center gap-2 ${textPrimary}`}>
            <Zap className="h-3.5 w-3.5 text-amber-400" />
            {lang === "bn" ? "দ্রুত শুরু করুন — একটি টেমপ্লেট বেছে নিন" : "Quick Start — Choose a Template"}
          </h3>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 sm:gap-3">
            {packageTemplates.map(tmpl => {
              const Icon = tmpl.icon;
              return (
                <button
                  key={tmpl.id}
                  onClick={() => applyTemplate(tmpl)}
                  className={`group relative flex flex-col items-start gap-1.5 p-3 sm:p-4 rounded-xl border transition-all text-left active:scale-[0.97] ${isDark ? `bg-gradient-to-br ${tmpl.color} hover:shadow-lg hover:shadow-blue-500/5` : `bg-gradient-to-br ${tmpl.color.replace(/\/20/g, '/10').replace(/\/10/g, '/5').replace(/\/30/g, '/20')} hover:shadow-md`}`}
                >
                  <Icon className={`h-5 w-5 sm:h-6 sm:w-6 ${isDark ? "text-white/70" : "text-gray-600"} group-hover:scale-110 transition-transform`} />
                  <span className={`text-[11px] sm:text-xs font-bold leading-tight ${textPrimary}`}>{tmpl.name[lang]}</span>
                  <span className={`text-[9px] sm:text-[10px] leading-tight ${textMuted}`}>{tmpl.desc[lang]}</span>
                  <div className={`mt-1 inline-flex items-center gap-1 text-[8px] sm:text-[9px] font-semibold px-2 py-0.5 rounded-full ${isDark ? "bg-white/10 text-blue-300" : "bg-blue-100 text-blue-600"}`}>
                    <ArrowRight className="h-2.5 w-2.5" /> {lang === "bn" ? "প্রয়োগ করুন" : "Apply"}
                  </div>
                </button>
              );
            })}
          </div>
        </div>
      )}


      {totalItems > 0 && (
        <div className="lg:hidden mb-4">
          <div className={`rounded-xl border ${summaryBg} p-3`}>
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Package className="h-4 w-4 text-blue-400" />
                <span className={`text-sm font-bold ${textPrimary}`}>{t.yourPackage}</span>
                <span className={`text-[10px] px-2 py-0.5 rounded-full ${isDark ? "bg-blue-500/20 text-blue-300" : "bg-blue-100 text-blue-600"}`}>
                  {totalItems} {t.items}
                </span>
              </div>
              <span className={`text-lg font-black ${gradientPrice}`}>৳{totalPrice.toLocaleString()}</span>
            </div>
            {/* Compact items list */}
            <div className="mt-2 flex flex-wrap gap-1.5">
              {selectedProducts.map(({ product, qty }) => (
                <div key={product.id} className={`flex items-center gap-1 px-2 py-1 rounded-lg text-[10px] ${isDark ? "bg-white/[0.05]" : "bg-white/80"}`}>
                  <span className={`font-medium truncate max-w-[120px] ${textPrimary}`}>{product.name}</span>
                  <span className={textMuted}>×{qty}</span>
                  <button onClick={() => removeItem(product.id)} className="text-red-400 hover:text-red-300 ml-0.5">
                    <Trash2 className="h-2.5 w-2.5" />
                  </button>
                </div>
              ))}
            </div>
            <Button
              onClick={() => setCheckoutOpen(true)}
              className="w-full mt-3 gap-2 bg-gradient-to-r from-blue-600 to-cyan-600 hover:from-blue-500 hover:to-cyan-500 border-0 shadow-lg shadow-blue-500/25 rounded-xl text-white h-10 text-xs font-semibold"
            >
              <CheckCircle className="h-4 w-4" /> {t.placeOrder} <ArrowRight className="h-3.5 w-3.5" />
            </Button>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4 sm:gap-6">
        {/* Left: Category Selector */}
        <div className="lg:col-span-2 space-y-3">
          <h3 className={`text-xs sm:text-sm font-semibold mb-2 sm:mb-3 ${textPrimary}`}>{t.selectCategory}</h3>

          {/* Category Grid - responsive columns */}
          <div className="grid grid-cols-4 sm:grid-cols-5 md:grid-cols-5 gap-2 sm:gap-2.5 mb-4 sm:mb-5">
            {categories.map(cat => {
              const Icon = categoryIcons[cat] || Package;
              const isActive = expandedCat === cat;
              const catCount = Object.entries(selections).filter(([id, qty]) => qty > 0 && grouped[cat]?.some((p: any) => p.id === id)).length;
              const productCount = grouped[cat]?.length || 0;
              return (
                <button
                  key={cat}
                  onClick={() => { setExpandedCat(isActive ? null : cat); setSearchQuery(""); }}
                  className={`flex flex-col items-center gap-0.5 p-2.5 sm:p-3 rounded-xl border transition-all text-center relative ${isActive ? `${catActiveBg} shadow-md shadow-blue-500/10` : `${catBg} ${cardBorder}`} ${productCount === 0 ? "opacity-40 pointer-events-none" : "cursor-pointer active:scale-95"}`}
                >
                  <Icon className={`h-4 w-4 sm:h-5 sm:w-5 ${isActive ? "text-blue-400" : isDark ? "text-white/50" : "text-gray-500"}`} />
                  <span className={`text-[9px] sm:text-[11px] font-semibold leading-tight ${isActive ? (isDark ? "text-blue-300" : "text-blue-600") : textSecondary}`}>{cat}</span>
                  {productCount > 0 && (
                    <span className={`text-[7px] font-medium ${isActive ? "text-blue-400/70" : textMuted}`}>({productCount})</span>
                  )}
                  {catCount > 0 && (
                    <span className="absolute -top-1.5 -right-1.5 h-4.5 w-4.5 min-w-[18px] rounded-full bg-gradient-to-r from-blue-500 to-cyan-500 text-[9px] font-bold text-white flex items-center justify-center shadow-sm">{catCount}</span>
                  )}
                </button>
              );
            })}
          </div>

          {expandedCat && (
            grouped[expandedCat] && grouped[expandedCat].length > 0 ? (
              <div className={`rounded-xl border ${cardBorder} overflow-hidden`}>
                <div className={`px-3 py-2 sm:py-2.5 border-b ${cardBorder} ${isDark ? "bg-white/[0.03]" : "bg-gray-50"} flex items-center gap-2`}>
                  <h4 className={`text-[11px] sm:text-xs font-semibold ${textPrimary} flex-shrink-0`}>{expandedCat}</h4>
                  <div className="relative flex-1">
                    <Search className={`absolute left-2.5 top-1/2 -translate-y-1/2 h-3 w-3 ${textMuted}`} />
                    <input
                      type="text"
                      placeholder={t.searchProducts}
                      value={searchQuery}
                      onChange={e => setSearchQuery(e.target.value)}
                      className={`w-full pl-7 pr-3 py-1.5 rounded-lg text-xs border ${inputBg} focus:outline-none focus:ring-1 focus:ring-blue-500/50`}
                    />
                  </div>
                  <span className={`text-[10px] ${textMuted} flex-shrink-0`}>({filteredCategoryProducts.length})</span>
                </div>
                <div className={`divide-y ${isDark ? "divide-white/5" : "divide-gray-100"} max-h-[50vh] overflow-y-auto`}>
                  {filteredCategoryProducts.map((product: any) => {
                    const price = product.cash_discount_price ? Number(product.cash_discount_price) : Number(product.price);
                    const qty = selections[product.id] || 0;
                    const inStock = product.stock_quantity > 0;
                    return (
                      <div key={product.id} className={`flex items-center gap-2 sm:gap-3 px-2 sm:px-4 py-2 sm:py-3 transition-colors ${productRowBg}`}>
                        <div className={`h-10 w-10 sm:h-14 sm:w-14 rounded-lg overflow-hidden flex-shrink-0 ${isDark ? "bg-white/5" : "bg-gray-100"}`}>
                          {product.image_url ? (
                            <img src={product.image_url} alt={product.name} className="h-full w-full object-cover" loading="lazy" />
                          ) : (
                            <div className="h-full w-full flex items-center justify-center">
                              <Package className={`h-4 w-4 sm:h-5 sm:w-5 ${textMuted}`} />
                            </div>
                          )}
                        </div>
                        <div className="flex-1 min-w-0">
                          <p className={`text-[10px] sm:text-sm font-medium leading-tight line-clamp-2 ${textPrimary}`}>{product.name}</p>
                          <div className="flex items-center gap-1.5 mt-0.5">
                            <span className={`text-[10px] sm:text-sm font-bold ${gradientPrice}`}>৳{price.toLocaleString()}</span>
                            {product.cash_discount_price && (
                              <span className={`text-[8px] sm:text-[10px] line-through ${textMuted}`}>৳{Number(product.price).toLocaleString()}</span>
                            )}
                          </div>
                        </div>
                        <div className="flex items-center gap-0.5 sm:gap-1 flex-shrink-0">
                          {qty > 0 ? (
                            <>
                              <button onClick={() => updateQty(product.id, -1)} className={`h-6 w-6 sm:h-8 sm:w-8 rounded-lg flex items-center justify-center transition-all ${isDark ? "bg-white/10 hover:bg-white/20" : "bg-gray-100 hover:bg-gray-200"}`}>
                                <Minus className="h-3 w-3" />
                              </button>
                              <span className={`text-xs sm:text-sm font-bold w-5 sm:w-6 text-center ${textPrimary}`}>{qty}</span>
                              <button onClick={() => updateQty(product.id, 1)} className={`h-6 w-6 sm:h-8 sm:w-8 rounded-lg flex items-center justify-center transition-all ${isDark ? "bg-blue-500/20 hover:bg-blue-500/30 text-blue-400" : "bg-blue-50 hover:bg-blue-100 text-blue-600"}`}>
                                <Plus className="h-3 w-3" />
                              </button>
                            </>
                          ) : (
                            <Button
                              size="sm"
                              disabled={!inStock}
                              onClick={() => updateQty(product.id, 1)}
                              className="h-7 sm:h-8 px-2 sm:px-3 text-[9px] sm:text-xs gap-0.5 sm:gap-1 bg-gradient-to-r from-blue-600 to-cyan-600 hover:from-blue-500 hover:to-cyan-500 border-0 rounded-lg text-white"
                            >
                              <Plus className="h-3 w-3" /> {lang === "bn" ? "যোগ" : "Add"}
                            </Button>
                          )}
                        </div>
                      </div>
                    );
                  })}
                  {filteredCategoryProducts.length === 0 && (
                    <div className={`text-center py-6 ${textMuted} text-xs`}>
                      {lang === "bn" ? "কোনো পণ্য পাওয়া যায়নি" : "No products found"}
                    </div>
                  )}
                </div>
              </div>
            ) : (
              <div className={`text-center py-8 rounded-xl border ${cardBorder} ${cardBg}`}>
                <Package className={`h-8 w-8 mx-auto mb-2 ${isDark ? "text-white/10" : "text-gray-200"}`} />
                <p className={`text-xs ${textMuted}`}>{lang === "bn" ? "এই ক্যাটাগরিতে কোনো পণ্য নেই" : "No products in this category yet"}</p>
              </div>
            )
          )}

          {!expandedCat && (
            <div className={`text-center py-8 sm:py-12 rounded-xl border ${cardBorder} ${cardBg}`}>
              <Package className={`h-10 w-10 sm:h-12 sm:w-12 mx-auto mb-3 ${isDark ? "text-white/10" : "text-gray-200"}`} />
              <p className={`text-xs sm:text-sm font-medium ${textSecondary}`}>{t.startBuilding}</p>
              <p className={`text-[10px] sm:text-xs mt-1 ${textMuted}`}>{t.emptyDesc}</p>
            </div>
          )}
        </div>

        {/* Right: Package Summary (desktop only - mobile shown above) */}
        <div className="hidden lg:block lg:col-span-1">
          <div className={`rounded-xl border sticky top-24 ${summaryBg} overflow-hidden`}>
            <div className="px-4 py-3 border-b border-blue-500/10">
              <h3 className={`text-sm font-bold flex items-center gap-2 ${textPrimary}`}>
                <Package className="h-4 w-4 text-blue-400" /> {t.yourPackage}
                {totalItems > 0 && (
                  <span className={`text-[10px] px-2 py-0.5 rounded-full ${isDark ? "bg-blue-500/20 text-blue-300" : "bg-blue-100 text-blue-600"}`}>
                    {totalItems} {t.items}
                  </span>
                )}
              </h3>
            </div>

            {selectedProducts.length === 0 ? (
              <div className="px-4 py-8 text-center">
                <Package className={`h-10 w-10 mx-auto mb-2 ${isDark ? "text-white/10" : "text-gray-200"}`} />
                <p className={`text-xs ${textMuted}`}>{t.emptyPackage}</p>
              </div>
            ) : (
              <div className="px-3 py-3 space-y-2 max-h-[300px] overflow-y-auto">
                {selectedProducts.map(({ product, qty }) => {
                  const price = product.cash_discount_price ? Number(product.cash_discount_price) : Number(product.price);
                  return (
                    <div key={product.id} className={`flex items-center gap-2 p-2 rounded-lg ${isDark ? "bg-white/[0.03]" : "bg-white/80"}`}>
                      <div className={`h-9 w-9 rounded-md overflow-hidden flex-shrink-0 ${isDark ? "bg-white/5" : "bg-gray-100"}`}>
                        {product.image_url ? (
                          <img src={product.image_url} alt="" className="h-full w-full object-cover" />
                        ) : (
                          <div className="h-full w-full flex items-center justify-center"><Package className={`h-4 w-4 ${textMuted}`} /></div>
                        )}
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className={`text-xs font-medium leading-tight line-clamp-1 ${textPrimary}`}>{product.name}</p>
                        <p className={`text-[10px] ${textMuted}`}>
                          {qty} × ৳{price.toLocaleString()} = <span className="font-semibold text-blue-400">৳{(price * qty).toLocaleString()}</span>
                        </p>
                      </div>
                      <div className="flex items-center gap-0.5 flex-shrink-0">
                        <button onClick={() => updateQty(product.id, -1)} className={`h-6 w-6 rounded flex items-center justify-center ${isDark ? "hover:bg-white/10" : "hover:bg-gray-200"}`}>
                          <Minus className="h-2.5 w-2.5" />
                        </button>
                        <button onClick={() => updateQty(product.id, 1)} className={`h-6 w-6 rounded flex items-center justify-center ${isDark ? "hover:bg-white/10" : "hover:bg-gray-200"}`}>
                          <Plus className="h-2.5 w-2.5" />
                        </button>
                        <button onClick={() => removeItem(product.id)} className="h-6 w-6 rounded flex items-center justify-center text-red-400 hover:bg-red-500/10">
                          <Trash2 className="h-3 w-3" />
                        </button>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}

            {/* Total & Order Button */}
            {selectedProducts.length > 0 && (
              <div className={`px-4 py-3 border-t ${isDark ? "border-blue-500/10" : "border-blue-200"}`}>
                <div className="flex justify-between items-center mb-3">
                  <span className={`text-xs font-semibold ${textSecondary}`}>{t.totalPrice}</span>
                  <span className={`text-2xl font-black ${gradientPrice}`}>৳{totalPrice.toLocaleString()}</span>
                </div>
                <Button
                  onClick={() => setCheckoutOpen(true)}
                  className="w-full gap-2 bg-gradient-to-r from-blue-600 to-cyan-600 hover:from-blue-500 hover:to-cyan-500 border-0 shadow-lg shadow-blue-500/25 rounded-xl text-white h-11 text-sm font-semibold"
                >
                  <CheckCircle className="h-4 w-4" /> {t.placeOrder} <ArrowRight className="h-3.5 w-3.5" />
                </Button>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Checkout Dialog */}
      <Dialog open={checkoutOpen} onOpenChange={setCheckoutOpen}>
        <DialogContent className={`max-w-sm max-h-[90vh] overflow-y-auto ${dialogBg}`}>
          <DialogHeader>
            <DialogTitle className={`flex items-center gap-2 ${textPrimary}`}>
              <CheckCircle className="h-5 w-5 text-blue-400" /> {t.checkout}
            </DialogTitle>
          </DialogHeader>
          <div className={`${infoBg} rounded-xl p-3 mb-2`}>
            <p className={`text-xs ${textSecondary} mb-1`}>{totalItems} {t.items}</p>
            <p className="text-blue-400 font-bold text-lg">৳{totalPrice.toLocaleString()}</p>
            <div className="mt-2 space-y-1">
              {selectedProducts.map(({ product, qty }) => {
                const price = product.cash_discount_price ? Number(product.cash_discount_price) : Number(product.price);
                return (
                  <p key={product.id} className={`text-[10px] ${textMuted}`}>
                    {product.name} × {qty} = ৳{(price * qty).toLocaleString()}
                  </p>
                );
              })}
            </div>
          </div>
          <form onSubmit={(e) => { e.preventDefault(); placeOrder.mutate(); }} className="space-y-3">
            <div className="space-y-1.5">
              <Label className={`text-xs ${labelColor}`}>{t.yourName}</Label>
              <Input value={orderForm.name} onChange={(e) => setOrderForm({ ...orderForm, name: e.target.value })} required placeholder={t.namePlaceholder} className={inputBg} />
            </div>
            <div className="space-y-1.5">
              <Label className={`text-xs ${labelColor}`}>{t.phone}</Label>
              <Input value={orderForm.phone} onChange={(e) => setOrderForm({ ...orderForm, phone: e.target.value })} required placeholder="01XXXXXXXXX" className={inputBg} />
            </div>
            <div className="space-y-1.5">
              <Label className={`text-xs ${labelColor}`}>{t.paymentMethod}</Label>
              <Select value={orderForm.payment_method} onValueChange={(v) => setOrderForm({ ...orderForm, payment_method: v })}>
                <SelectTrigger className={inputBg}>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="cash_on_delivery">
                    <span className="flex items-center gap-2"><Package className="h-3.5 w-3.5" /> {lang === "bn" ? "ক্যাশ অন ডেলিভারি" : "Cash on Delivery"}</span>
                  </SelectItem>
                  <SelectItem value="bkash">
                    <span className="flex items-center gap-2"><Smartphone className="h-3.5 w-3.5" /> bKash</span>
                  </SelectItem>
                  <SelectItem value="nagad">
                    <span className="flex items-center gap-2"><Smartphone className="h-3.5 w-3.5" /> Nagad</span>
                  </SelectItem>
                  <SelectItem value="rocket">
                    <span className="flex items-center gap-2"><Smartphone className="h-3.5 w-3.5" /> Rocket</span>
                  </SelectItem>
                  <SelectItem value="card">
                    <span className="flex items-center gap-2"><CreditCard className="h-3.5 w-3.5" /> {lang === "bn" ? "কার্ড পেমেন্ট" : "Card Payment"}</span>
                  </SelectItem>
                  <SelectItem value="bank_transfer">
                    <span className="flex items-center gap-2"><Building2 className="h-3.5 w-3.5" /> {lang === "bn" ? "ব্যাংক ট্রান্সফার" : "Bank Transfer"}</span>
                  </SelectItem>
                </SelectContent>
              </Select>
            </div>

            {(orderForm.payment_method === "bkash" || orderForm.payment_method === "nagad" || orderForm.payment_method === "rocket") && (
              <div className={`rounded-xl p-3 border text-xs space-y-1.5 ${isDark ? "bg-emerald-500/10 border-emerald-500/20" : "bg-emerald-50 border-emerald-200"}`}>
                <div className="flex items-center gap-2 font-semibold">
                  <Smartphone className="h-4 w-4 text-emerald-400" />
                  <span className={textPrimary}>
                    {orderForm.payment_method === "bkash" ? "bKash" : orderForm.payment_method === "nagad" ? "Nagad" : "Rocket"} {lang === "bn" ? "নম্বর" : "Number"}
                  </span>
                </div>
                <p className={`font-mono text-sm font-bold ${isDark ? "text-emerald-300" : "text-emerald-700"}`}>
                  {settings.phone?.split(",")[0]?.trim() || "01919-060590"}
                </p>
                <p className={`${isDark ? "text-emerald-300/60" : "text-emerald-600/70"}`}>
                  {lang === "bn"
                    ? `উপরের নম্বরে ৳${totalPrice.toLocaleString()} Send Money করুন এবং অর্ডার নিশ্চিত করুন।`
                    : `Send ৳${totalPrice.toLocaleString()} to the above number and confirm your order.`}
                </p>
              </div>
            )}

            {orderForm.payment_method === "bank_transfer" && (
              <div className={`rounded-xl p-3 border text-xs space-y-1.5 ${isDark ? "bg-blue-500/10 border-blue-500/20" : "bg-blue-50 border-blue-200"}`}>
                <div className="flex items-center gap-2 font-semibold">
                  <Building2 className="h-4 w-4 text-blue-400" />
                  <span className={textPrimary}>{lang === "bn" ? "ব্যাংক তথ্য" : "Bank Details"}</span>
                </div>
                {settings.bank_name && <p className={isDark ? "text-blue-300" : "text-blue-700"}>{settings.bank_name}</p>}
                {settings.bank_account_name && <p className={textMuted}>{settings.bank_account_name}</p>}
                {settings.bank_account_number && <p className={`font-mono font-bold ${isDark ? "text-blue-300" : "text-blue-700"}`}>{settings.bank_account_number}</p>}
                {settings.bank_branch && <p className={textMuted}>{settings.bank_branch}</p>}
              </div>
            )}

            <Button type="submit" disabled={placeOrder.isPending} className="w-full gap-2 bg-gradient-to-r from-blue-600 to-cyan-600 hover:from-blue-500 hover:to-cyan-500 border-0 shadow-lg shadow-blue-500/25 rounded-xl text-white h-11">
              <CheckCircle className="h-4 w-4" /> {placeOrder.isPending ? "..." : t.confirmOrder}
            </Button>
          </form>
        </DialogContent>
      </Dialog>
    </section>
  );
}

import { useState, useEffect } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Dialog, DialogContent } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { ShoppingCart, Package, ChevronLeft, ChevronRight, Check, Minus, Plus, Heart, Star, MessageSquareQuote, Phone } from "lucide-react";
import { SocialShareButtons } from "./SocialShareButtons";
import { useWishlistStore } from "@/stores/wishlistStore";
import { toast } from "sonner";

interface ProductDetailDialogProps {
  product: any;
  onClose: () => void;
  onOrder: (name: string, price: number, productId: string, variantId?: string, variantLabel?: string) => void;
  isDark: boolean;
  lang: "bn" | "en";
}

function QuantitySelector({ quantity, onChange, max, isDark }: { quantity: number; onChange: (q: number) => void; max: number; isDark: boolean }) {
  const btnClass = `h-8 w-8 rounded-lg flex items-center justify-center transition-all ${isDark ? "bg-white/10 hover:bg-white/20 text-white" : "bg-gray-100 hover:bg-gray-200 text-gray-700"}`;
  return (
    <div className="flex items-center gap-3">
      <button className={btnClass} onClick={() => onChange(Math.max(1, quantity - 1))} disabled={quantity <= 1}><Minus className="h-4 w-4" /></button>
      <span className={`text-lg font-bold min-w-[2rem] text-center ${isDark ? "text-white" : "text-gray-900"}`}>{quantity}</span>
      <button className={btnClass} onClick={() => onChange(Math.min(max, quantity + 1))} disabled={quantity >= max}><Plus className="h-4 w-4" /></button>
    </div>
  );
}

export function ProductDetailDialog({ product, onClose, onOrder, isDark, lang }: ProductDetailDialogProps) {
  const { toggleItem, isInWishlist } = useWishlistStore();
  const [selectedImage, setSelectedImage] = useState(0);
  const [viewingProduct, setViewingProduct] = useState<any>(null);
  const [quantity, setQuantity] = useState(1);
  const [selectedVariant, setSelectedVariant] = useState<any>(null);

  const activeProduct = viewingProduct || product;

  const { data: galleryImages } = useQuery({
    queryKey: ["product-images", activeProduct?.id],
    queryFn: async () => {
      if (!activeProduct?.id) return [];
      const { data } = await supabase.from("product_images").select("*").eq("product_id", activeProduct.id).order("sort_order");
      return data || [];
    },
    enabled: !!activeProduct?.id,
  });

  const { data: variants } = useQuery({
    queryKey: ["product-variants", activeProduct?.id],
    queryFn: async () => {
      if (!activeProduct?.id) return [];
      const { data } = await supabase.from("product_variants").select("*").eq("product_id", activeProduct.id).order("sort_order");
      return data || [];
    },
    enabled: !!activeProduct?.id,
  });

  const { data: relatedProducts } = useQuery({
    queryKey: ["related-products", activeProduct?.category, activeProduct?.id],
    queryFn: async () => {
      if (!activeProduct?.category || !activeProduct?.id) return [];
      const { data } = await supabase.from("products").select("*").eq("show_in_store", true).eq("category", activeProduct.category).neq("id", activeProduct.id).limit(6);
      return data || [];
    },
    enabled: !!activeProduct?.id && !!activeProduct?.category,
  });

  const { data: reviews } = useQuery({
    queryKey: ["store-reviews-dialog"],
    queryFn: async () => {
      const { data } = await supabase.from("customer_reviews").select("*").eq("is_published", true).order("sort_order").limit(5);
      return data || [];
    },
  });

  const avgRating = reviews && reviews.length > 0
    ? (reviews.reduce((sum: number, r: any) => sum + r.rating, 0) / reviews.length).toFixed(1)
    : null;

  const allImages: string[] = [];
  if (activeProduct?.image_url) allImages.push(activeProduct.image_url);
  galleryImages?.forEach((img: any) => {
    if (!allImages.includes(img.image_url)) allImages.push(img.image_url);
  });

  // Auto-select first variant when variants load
  useEffect(() => {
    if (variants && variants.length > 0 && !selectedVariant) {
      setSelectedVariant(variants[0]);
    }
  }, [variants]);

  useEffect(() => {
    setSelectedImage(0);
    setViewingProduct(null);
    setQuantity(1);
    setSelectedVariant(null);
  }, [product?.id]);

  // Handle hardware back button on mobile
  useEffect(() => {
    if (product) {
      // Push a fake state so the back button has something to pop
      window.history.pushState({ modal: "product-detail" }, "");

      const handlePopState = () => {
        setViewingProduct(null);
        onClose();
      };

      window.addEventListener("popstate", handlePopState);

      return () => {
        window.removeEventListener("popstate", handlePopState);
        // If the modal is closing by UI (not by back button), we clean up the history state
        if (window.history.state?.modal === "product-detail") {
          window.history.back();
        }
      };
    }
  }, [product ? "open" : "closed"]);

  const textPrimary = isDark ? "text-white" : "text-gray-900";
  const textSecondary = isDark ? "text-white/60" : "text-gray-600";
  const textMuted = isDark ? "text-white/40" : "text-gray-400";
  const bgCard = isDark ? "bg-[#0f1524]" : "bg-white";
  const borderColor = isDark ? "border-white/10" : "border-gray-200";
  const thumbBorder = isDark ? "border-blue-400" : "border-blue-500";
  const thumbInactive = isDark ? "border-white/10 hover:border-white/30" : "border-gray-200 hover:border-gray-400";

  if (!product) return null;

  // Use variant price/stock if a variant is selected
  const hasVariants = variants && variants.length > 0;
  const effectivePrice = selectedVariant
    ? Number(selectedVariant.price)
    : activeProduct.cash_discount_price
      ? Number(activeProduct.cash_discount_price)
      : Number(activeProduct.price);
  const effectiveStock = selectedVariant
    ? Number(selectedVariant.stock_quantity)
    : Number(activeProduct.stock_quantity);
  const hasDiscount = !selectedVariant && Number(activeProduct.discount_percentage) > 0;
  const inStock = effectiveStock > 0;

  // Group variants by variant_group
  const variantGroups: Record<string, any[]> = {};
  variants?.forEach((v: any) => {
    const group = v.variant_group || "Option";
    if (!variantGroups[group]) variantGroups[group] = [];
    variantGroups[group].push(v);
  });

  const handleViewRelated = (p: any) => { setViewingProduct(p); setSelectedImage(0); setQuantity(1); setSelectedVariant(null); };


  return (
    <Dialog open={!!product} onOpenChange={(v) => { if (!v) { setViewingProduct(null); onClose(); } }}>
      <DialogContent className={`max-w-2xl max-h-[95vh] overflow-y-auto overflow-x-hidden ${bgCard} ${borderColor} ${textPrimary} p-0 gap-0`}>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-0">
          {/* Image Gallery */}
          <div className={`relative ${isDark ? "bg-white/[0.03]" : "bg-gray-50"}`}>
            <div className="relative aspect-square overflow-hidden">
              {allImages.length > 0 ? (
                <img src={allImages[selectedImage] || allImages[0]} alt={activeProduct.name} className="h-full w-full object-contain p-4 transition-all duration-300" />
              ) : (
                <div className="h-full w-full flex items-center justify-center">
                  <Package className={`h-24 w-24 ${isDark ? "text-white/10" : "text-gray-200"}`} />
                </div>
              )}
              {hasDiscount && (
                <div className="absolute top-3 left-3">
                  <span className="px-3 py-1 rounded-full bg-red-500 text-white text-xs font-bold shadow-lg">-{activeProduct.discount_percentage}% OFF</span>
                </div>
              )}
              {allImages.length > 1 && (
                <>
                  <button onClick={() => setSelectedImage(prev => prev > 0 ? prev - 1 : allImages.length - 1)} className={`absolute left-2 top-1/2 -translate-y-1/2 h-8 w-8 rounded-full flex items-center justify-center transition-all ${isDark ? "bg-white/10 hover:bg-white/20 text-white" : "bg-black/10 hover:bg-black/20 text-gray-700"}`}>
                    <ChevronLeft className="h-4 w-4" />
                  </button>
                  <button onClick={() => setSelectedImage(prev => prev < allImages.length - 1 ? prev + 1 : 0)} className={`absolute right-2 top-1/2 -translate-y-1/2 h-8 w-8 rounded-full flex items-center justify-center transition-all ${isDark ? "bg-white/10 hover:bg-white/20 text-white" : "bg-black/10 hover:bg-black/20 text-gray-700"}`}>
                    <ChevronRight className="h-4 w-4" />
                  </button>
                </>
              )}
            </div>
            {allImages.length > 1 && (
              <div className={`flex gap-2 p-3 overflow-x-auto border-t ${borderColor}`}>
                {allImages.map((img, i) => (
                  <button key={i} onClick={() => setSelectedImage(i)} className={`h-14 w-14 rounded-lg overflow-hidden border-2 flex-shrink-0 transition-all ${selectedImage === i ? thumbBorder : thumbInactive}`}>
                    <img src={img} alt="" className="h-full w-full object-cover" />
                  </button>
                ))}
              </div>
            )}
          </div>

          {/* Product Info */}
          <div className="p-5 sm:p-6 flex flex-col">
            <div className="flex items-center gap-2 mb-2 flex-wrap">
              {activeProduct.brand && activeProduct.brand !== "Other" && (
                <span className={`text-[10px] font-semibold uppercase tracking-wider px-2 py-0.5 rounded-full ${isDark ? "bg-blue-500/10 text-blue-300" : "bg-blue-50 text-blue-600"}`}>{activeProduct.brand}</span>
              )}
              <span className={`text-[10px] font-medium px-2 py-0.5 rounded-full ${isDark ? "bg-white/5 text-white/50" : "bg-gray-100 text-gray-500"}`}>{activeProduct.category}</span>
            </div>

            <div className="flex items-start justify-between gap-2 mb-3">
              <h2 className={`text-lg sm:text-xl font-bold leading-tight break-words ${textPrimary}`}>{activeProduct.name}</h2>
              <button
                onClick={() => {
                  toggleItem(activeProduct.id);
                  toast(isInWishlist(activeProduct.id) ? (lang === "bn" ? "পছন্দ থেকে সরানো হয়েছে" : "Removed from wishlist") : (lang === "bn" ? "পছন্দে যোগ হয়েছে ❤️" : "Added to wishlist ❤️"));
                }}
                className={`flex-shrink-0 h-9 w-9 rounded-full flex items-center justify-center transition-all ${
                  isInWishlist(activeProduct.id)
                    ? "bg-rose-500 text-white shadow-lg shadow-rose-500/30"
                    : isDark
                      ? "bg-white/10 text-white/50 hover:bg-white/20 hover:text-rose-400"
                      : "bg-gray-100 text-gray-400 hover:bg-rose-50 hover:text-rose-500"
                }`}
              >
                <Heart className={`h-4 w-4 ${isInWishlist(activeProduct.id) ? "fill-white" : ""}`} />
              </button>
            </div>

            {/* Price */}
            <div className={`rounded-xl p-3 mb-4 border ${isDark ? "bg-gradient-to-r from-blue-500/5 to-cyan-500/5 border-blue-500/10" : "bg-blue-50/50 border-blue-100"}`}>
              {activeProduct.call_for_price ? (
                <div className="flex items-center gap-2">
                  <span className={`text-xl sm:text-2xl font-black ${isDark ? "bg-gradient-to-r from-amber-400 to-orange-400 bg-clip-text text-transparent" : "text-amber-600"}`}>
                    {lang === "bn" ? "মূল্য জানতে কল করুন" : "Call for Price"}
                  </span>
                </div>
              ) : (
                <>
                  <div className="flex items-end gap-2 flex-wrap">
                    <span className={`text-2xl sm:text-3xl font-black ${isDark ? "bg-gradient-to-r from-blue-400 to-cyan-400 bg-clip-text text-transparent" : "text-blue-600"}`}>৳{effectivePrice.toLocaleString()}</span>
                    {!selectedVariant && activeProduct.cash_discount_price && (
                      <span className={`text-sm line-through mb-1 ${textMuted}`}>৳{Number(activeProduct.price).toLocaleString()}</span>
                    )}
                  </div>
                  {hasDiscount && (
                    <p className="text-xs text-emerald-500 font-medium mt-1">💰 {lang === "bn" ? "সেভ করুন" : "You save"} ৳{(Number(activeProduct.price) - effectivePrice).toLocaleString()}</p>
                  )}
                </>
              )}
            </div>

            {/* Variant Selector */}
            {hasVariants && Object.entries(variantGroups).map(([group, groupVariants]) => (
              <div key={group} className="mb-3">
                <label className={`text-xs font-semibold mb-1.5 block ${textSecondary}`}>{group}</label>
                <div className="flex flex-wrap gap-2">
                  {groupVariants.map((v: any) => {
                    const isSelected = selectedVariant?.id === v.id;
                    return (
                      <button
                        key={v.id}
                        onClick={() => { setSelectedVariant(v); setQuantity(1); }}
                        className={`px-3 py-1.5 rounded-lg text-xs font-medium border transition-all ${
                          isSelected
                            ? isDark
                              ? "bg-blue-500/20 border-blue-400 text-blue-300 shadow-md"
                              : "bg-blue-50 border-blue-500 text-blue-700 shadow-md"
                            : isDark
                              ? "bg-white/5 border-white/10 text-white/70 hover:border-white/30"
                              : "bg-gray-50 border-gray-200 text-gray-600 hover:border-gray-400"
                        }`}
                      >
                        {v.variant_label}
                        {v.price !== Number(activeProduct.price) && (
                          <span className="ml-1 opacity-70">৳{Number(v.price).toLocaleString()}</span>
                        )}
                      </button>
                    );
                  })}
                </div>
              </div>
            ))}

            {/* Stock */}
            <div className="mb-3">
              {inStock ? (
                <div className="flex items-center gap-1.5">
                  <Check className="h-4 w-4 text-emerald-500" />
                  <span className={`text-sm font-medium ${isDark ? "text-emerald-400" : "text-emerald-600"}`}>{lang === "bn" ? "স্টকে আছে" : "In Stock"} ({effectiveStock})</span>
                </div>
              ) : (
                <span className={`text-sm font-medium ${isDark ? "text-red-400" : "text-red-600"}`}>✗ {lang === "bn" ? "স্টক নেই" : "Out of Stock"}</span>
              )}
            </div>

            {/* Quantity Selector */}
            {inStock && !activeProduct.call_for_price && (
              <div className="mb-4">
                <label className={`text-xs font-semibold mb-1.5 block ${textSecondary}`}>{lang === "bn" ? "পরিমাণ" : "Quantity"}</label>
                <QuantitySelector quantity={quantity} onChange={setQuantity} max={effectiveStock} isDark={isDark} />
              </div>
            )}

            {/* Description & Specifications */}
            <div className="mb-4 flex-1">
              {(() => {
                let parsedDesc = activeProduct.description || "";
                let parsedSpecs: any[] = [];
                try {
                  if (activeProduct.description) {
                    const obj = JSON.parse(activeProduct.description);
                    if (obj && typeof obj === 'object' && obj.text !== undefined) {
                      parsedDesc = obj.text;
                      parsedSpecs = obj.specs || [];
                    }
                  }
                } catch (e) {}

                return (
                  <div className="space-y-4">
                    {parsedDesc ? (
                      <p className={`text-sm leading-relaxed break-words whitespace-pre-wrap ${textSecondary}`}>{parsedDesc}</p>
                    ) : (
                      <p className={`text-sm italic ${textMuted}`}>{lang === "bn" ? "কোনো বিবরণ নেই" : "No description available"}</p>
                    )}

                    {parsedSpecs.length > 0 && (
                      <div className={`mt-6 rounded-2xl shadow-sm p-4 sm:p-6 border ${isDark ? "bg-white/[0.02] border-white/10" : "bg-white border-gray-100"}`}>
                        <h2 className={`text-lg sm:text-xl font-bold mb-4 ${textPrimary}`}>Specification</h2>

                        <div className={`px-4 py-2.5 rounded-lg font-semibold text-xs sm:text-sm mb-6 ${isDark ? "bg-blue-500/10 text-blue-400" : "bg-blue-50 text-blue-900"}`}>
                          General Information
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 sm:gap-8 items-start">
                          <div className="md:col-span-2 overflow-x-auto">
                            <table className="w-full text-left border-collapse text-sm">
                              <tbody className="divide-y divide-gray-100 dark:divide-white/5">
                                <tr className="border-b border-gray-100 dark:border-white/5">
                                  <td className={`py-3 font-semibold ${textPrimary} w-1/3`}>Product Name</td>
                                  <td className={`py-3 ${textSecondary}`}>{activeProduct.name}</td>
                                </tr>
                                {parsedSpecs.map((spec, i) => (
                                  <tr key={i} className="border-b border-gray-100 dark:border-white/5 last:border-0">
                                    <td className={`py-3 font-semibold ${textPrimary} w-1/3`}>{spec.feature}</td>
                                    <td className={`py-3 ${textSecondary}`}>{spec.description}</td>
                                  </tr>
                                ))}
                              </tbody>
                            </table>
                          </div>

                          <div className={`flex justify-center items-center rounded-xl aspect-square border overflow-hidden relative ${isDark ? "bg-white/5 border-white/10" : "bg-gray-50 border-gray-200"}`}>
                            {activeProduct.image_url ? (
                              <img src={activeProduct.image_url} alt={activeProduct.name} className="object-contain w-full h-full p-2" />
                            ) : (
                              <div className="text-center text-gray-400 font-medium">
                                <span className="block text-4xl mb-2">📦</span>
                                <span className="text-xs">{lang === "bn" ? "কোনো ছবি নেই" : "No Image"}</span>
                              </div>
                            )}
                          </div>
                        </div>
                      </div>
                    )}
                  </div>
                );
              })()}
            </div>

            {/* Add to Cart / Call for Price */}
            <div className="mt-auto">
              {activeProduct.call_for_price ? (
                <div className="flex gap-2">
                  <Button
                    className="flex-1 gap-2 bg-gradient-to-r from-amber-500 to-orange-600 hover:from-amber-400 hover:to-orange-500 border-0 shadow-xl shadow-amber-500/25 rounded-xl text-white h-12 text-sm font-semibold"
                    onClick={() => {
                      window.open(`tel:+8801919060590`);
                    }}
                  >
                    <Phone className="h-5 w-5" />
                    {lang === "bn" ? "কল করুন" : "Call Now"}
                  </Button>
                  <Button
                    className="flex-1 gap-2 bg-[#25D366] hover:bg-[#20ba5a] border-0 shadow-xl shadow-emerald-500/25 rounded-xl text-white h-12 text-sm font-semibold"
                    onClick={() => {
                      const msg = lang === "bn"
                        ? `হ্যালো, আমি এই প্রোডাক্টটির মূল্য জানতে চাই: ${activeProduct.name}`
                        : `Hello, I'd like to know the price for this product: ${activeProduct.name}`;
                      window.open(`https://wa.me/8801919060590?text=${encodeURIComponent(msg)}`, "_blank");
                    }}
                  >
                    <MessageSquareQuote className="h-5 w-5" />
                    WhatsApp
                  </Button>
                </div>
              ) : (
                <Button
                  className="w-full gap-2 bg-gradient-to-r from-blue-600 to-cyan-600 hover:from-blue-500 hover:to-cyan-500 border-0 shadow-xl shadow-blue-500/25 rounded-xl text-white h-12 text-sm font-semibold"
                  disabled={!inStock}
                  onClick={() => {
                    const label = selectedVariant ? `${activeProduct.name} - ${selectedVariant.variant_label}` : activeProduct.name;
                    for (let i = 0; i < quantity; i++) {
                      onOrder(label, effectivePrice, activeProduct.id, selectedVariant?.id, selectedVariant?.variant_label);
                    }
                  }}
                >
                  <ShoppingCart className="h-5 w-5" />
                  {quantity > 1
                    ? `${lang === "bn" ? "অর্ডার করুন" : "Buy Now"} (${quantity}) — ৳${(effectivePrice * quantity).toLocaleString()}`
                    : (lang === "bn" ? "এখুনি কিনুন" : "Buy Now")}
                </Button>
              )}
            </div>
          </div>
        </div>

        {/* Customer Reviews */}
        {reviews && reviews.length > 0 && (
          <div className={`border-t ${borderColor} p-4 sm:p-5`}>
            <div className="flex items-center justify-between mb-3">
              <div className="flex items-center gap-2">
                <MessageSquareQuote className={`h-4 w-4 ${isDark ? "text-amber-400" : "text-amber-500"}`} />
                <h3 className={`text-sm font-bold ${textPrimary}`}>{lang === "bn" ? "কাস্টমার রিভিউ" : "Customer Reviews"}</h3>
              </div>
              {avgRating && (
                <div className="flex items-center gap-1.5">
                  <div className="flex items-center gap-0.5">
                    {Array.from({ length: 5 }).map((_, i) => (
                      <Star key={i} className={`h-3 w-3 ${i < Math.round(Number(avgRating)) ? "text-amber-400 fill-amber-400" : isDark ? "text-white/15" : "text-gray-200"}`} />
                    ))}
                  </div>
                  <span className={`text-xs font-bold ${isDark ? "text-amber-400" : "text-amber-600"}`}>{avgRating}</span>
                  <span className={`text-[10px] ${textMuted}`}>({reviews.length})</span>
                </div>
              )}
            </div>
            {/* Rating Summary Bar Chart */}
            {(() => {
              const total = reviews.length;
              const counts = [5, 4, 3, 2, 1].map(star => ({
                star,
                count: reviews.filter((r: any) => r.rating === star).length,
              }));
              return (
                <div className={`rounded-lg p-3 mb-3 border ${isDark ? "bg-white/[0.02] border-white/5" : "bg-gray-50/50 border-gray-100"}`}>
                  <div className="flex gap-4">
                    {/* Big average */}
                    <div className="flex flex-col items-center justify-center pr-4 border-r ${borderColor}">
                      <span className={`text-3xl font-black ${isDark ? "text-amber-400" : "text-amber-500"}`}>{avgRating}</span>
                      <div className="flex items-center gap-0.5 mt-1">
                        {Array.from({ length: 5 }).map((_, i) => (
                          <Star key={i} className={`h-3 w-3 ${i < Math.round(Number(avgRating)) ? "text-amber-400 fill-amber-400" : isDark ? "text-white/15" : "text-gray-200"}`} />
                        ))}
                      </div>
                      <span className={`text-[10px] mt-1 ${textMuted}`}>{total} {lang === "bn" ? "রিভিউ" : "reviews"}</span>
                    </div>
                    {/* Bars */}
                    <div className="flex-1 space-y-1.5">
                      {counts.map(({ star, count }) => {
                        const pct = total > 0 ? (count / total) * 100 : 0;
                        return (
                          <div key={star} className="flex items-center gap-2">
                            <span className={`text-[10px] font-semibold w-3 text-right ${textMuted}`}>{star}</span>
                            <Star className="h-2.5 w-2.5 text-amber-400 fill-amber-400 flex-shrink-0" />
                            <div className={`flex-1 h-2 rounded-full overflow-hidden ${isDark ? "bg-white/5" : "bg-gray-200"}`}>
                              <div
                                className="h-full rounded-full bg-gradient-to-r from-amber-400 to-amber-500 transition-all duration-500"
                                style={{ width: `${pct}%` }}
                              />
                            </div>
                            <span className={`text-[9px] font-medium w-5 text-right ${textMuted}`}>{count}</span>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                </div>
              );
            })()}
            <div className="space-y-2.5">
              {reviews.slice(0, 3).map((review: any) => (
                <div key={review.id} className={`rounded-lg p-3 border ${isDark ? "bg-white/[0.02] border-white/5" : "bg-gray-50/50 border-gray-100"}`}>
                  <div className="flex items-center justify-between mb-1.5">
                    <div className="flex items-center gap-2">
                      <div className={`h-6 w-6 rounded-full flex items-center justify-center text-[10px] font-bold ${isDark ? "bg-blue-500/20 text-blue-300" : "bg-blue-50 text-blue-600"}`}>
                        {review.reviewer_name.charAt(0).toUpperCase()}
                      </div>
                      <div>
                        <p className={`text-xs font-semibold ${textPrimary}`}>{review.reviewer_name}</p>
                        {review.reviewer_role && <p className={`text-[9px] ${textMuted}`}>{review.reviewer_role}</p>}
                      </div>
                    </div>
                    <div className="flex items-center gap-0.5">
                      {Array.from({ length: 5 }).map((_, i) => (
                        <Star key={i} className={`h-2.5 w-2.5 ${i < review.rating ? "text-amber-400 fill-amber-400" : isDark ? "text-white/10" : "text-gray-200"}`} />
                      ))}
                    </div>
                  </div>
                  <p className={`text-[11px] leading-relaxed ${textSecondary} line-clamp-2`}>{review.review_text}</p>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Social Share */}
        <div className={`border-t ${borderColor} p-4 sm:p-5`}>
          <h3 className={`text-xs font-bold mb-2 ${textPrimary}`}>{lang === "bn" ? "শেয়ার করুন" : "Share"}</h3>
          <SocialShareButtons
            productName={activeProduct.name}
            productPrice={activeProduct.cash_discount_price ? Number(activeProduct.cash_discount_price) : Number(activeProduct.price)}
            productUrl={`https://akitsolution.store`}
            compact
          />
        </div>

        {/* Related Products */}
        {relatedProducts && relatedProducts.length > 0 && (
          <div className={`border-t ${borderColor} p-4 sm:p-5`}>
            <h3 className={`text-sm font-bold mb-3 ${textPrimary}`}>{lang === "bn" ? "সম্পর্কিত পণ্য" : "Related Products"}</h3>
            <div className="grid grid-cols-3 sm:grid-cols-4 gap-2 sm:gap-3">
              {relatedProducts.slice(0, 4).map((rp: any) => {
                const rpPrice = rp.cash_discount_price ? Number(rp.cash_discount_price) : Number(rp.price);
                return (
                  <button key={rp.id} onClick={() => handleViewRelated(rp)} className={`rounded-xl overflow-hidden border text-left transition-all hover:-translate-y-0.5 hover:shadow-lg ${isDark ? "bg-white/[0.03] border-white/10 hover:border-blue-500/40" : "bg-gray-50 border-gray-200 hover:border-blue-400"}`}>
                    <div className={`aspect-square overflow-hidden ${isDark ? "bg-white/5" : "bg-gray-100"}`}>
                      {rp.image_url ? <img src={rp.image_url} alt={rp.name} className="h-full w-full object-cover" loading="lazy" /> : <div className="h-full w-full flex items-center justify-center"><Package className={`h-6 w-6 ${isDark ? "text-white/10" : "text-gray-300"}`} /></div>}
                    </div>
                    <div className="p-2">
                      <p className={`text-[10px] sm:text-xs font-medium leading-tight line-clamp-2 ${textPrimary}`}>{rp.name}</p>
                      <p className={`text-[10px] sm:text-xs font-bold mt-1 ${isDark ? "text-blue-400" : "text-blue-600"}`}>৳{rpPrice.toLocaleString()}</p>
                    </div>
                  </button>
                );
              })}
            </div>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

import React from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { CheckCircle, Smartphone, Building2 } from "lucide-react";
import { useCartStore } from "@/stores/cartStore";

interface StoreCheckoutDialogProps {
  checkoutOpen: boolean;
  setCheckoutOpen: (open: boolean) => void;
  checkoutForm: { name: string; phone: string; email: string; payment_method: string };
  setCheckoutForm: React.Dispatch<React.SetStateAction<{ name: string; phone: string; email: string; payment_method: string }>>;
  checkoutMutation: any;
  isDark: boolean;
  lang: "en" | "bn";
  settings: any;
}

export function StoreCheckoutDialog({
  checkoutOpen,
  setCheckoutOpen,
  checkoutForm,
  setCheckoutForm,
  checkoutMutation,
  isDark,
  lang,
  settings,
}: StoreCheckoutDialogProps) {
  const { items: cartItems, totalPrice } = useCartStore();
  const dialogBg = isDark ? "bg-[#0A0515]/95 border-white/10" : "bg-white border-gray-200";
  const textPrimary = isDark ? "text-white" : "text-gray-900";
  const textSecondary = isDark ? "text-white/60" : "text-gray-500";
  const labelColor = isDark ? "text-white/70" : "text-gray-700";
  const inputBg = isDark ? "bg-white/5 border-white/10 text-white placeholder:text-white/30" : "bg-gray-50 border-gray-200 text-gray-900";
  const gradientPrice = "bg-gradient-to-r from-violet-600 to-indigo-500 bg-clip-text text-transparent";

  const paymentMethods = [
    { value: "cash_on_delivery", label: lang === "bn" ? "ক্যাশ অন ডেলিভারি" : "Cash on Delivery", icon: "💵" },
    { value: "bkash", label: "bKash", icon: "📱" },
    { value: "nagad", label: "Nagad", icon: "📱" },
    { value: "rocket", label: "Rocket", icon: "📱" },
    { value: "bank_transfer", label: lang === "bn" ? "ব্যাংক ট্রান্সফার" : "Bank Transfer", icon: "🏦" },
    { value: "card", label: lang === "bn" ? "কার্ড পেমেন্ট" : "Card Payment", icon: "💳" },
  ];

  return (
    <Dialog open={checkoutOpen} onOpenChange={setCheckoutOpen}>
      <DialogContent className={`max-w-md max-h-[90vh] overflow-y-auto ${dialogBg}`}>
        <DialogHeader>
          <DialogTitle className={`flex items-center gap-2 ${textPrimary}`}>
            <CheckCircle className="h-5 w-5 text-violet-400" /> {lang === "bn" ? "চেকআউট" : "Checkout"}
          </DialogTitle>
        </DialogHeader>
        <form onSubmit={(e) => { e.preventDefault(); checkoutMutation.mutate(); }} className="space-y-3">
          {/* Order Summary */}
          <div className={`rounded-xl p-3 border ${isDark ? "bg-white/[0.03] border-white/10" : "bg-gray-50 border-gray-200"}`}>
            <p className={`text-[10px] font-semibold uppercase tracking-wider mb-2 ${textSecondary}`}>{lang === "bn" ? "অর্ডার সারসংক্ষেপ" : "Order Summary"}</p>
            {cartItems.map(item => (
              <div key={item.id} className={`flex items-center justify-between py-1 text-xs ${textPrimary}`}>
                <span className="truncate max-w-[200px]">{item.name} ×{item.quantity}</span>
                <span className="font-bold">৳{(item.price * item.quantity).toLocaleString()}</span>
              </div>
            ))}
            <div className={`flex items-center justify-between pt-2 mt-2 border-t text-sm font-bold ${isDark ? "border-white/10" : "border-gray-200"} ${textPrimary}`}>
              <span>{lang === "bn" ? "মোট" : "Total"}</span>
              <span className={gradientPrice}>৳{totalPrice().toLocaleString()}</span>
            </div>
          </div>

          <div className="space-y-1.5">
            <Label className={`text-xs ${labelColor}`}>{lang === "bn" ? "আপনার নাম *" : "Your Name *"}</Label>
            <Input value={checkoutForm.name} onChange={e => setCheckoutForm({ ...checkoutForm, name: e.target.value })} required placeholder={lang === "bn" ? "আপনার নাম" : "Your name"} className={inputBg} />
          </div>
          <div className="space-y-1.5">
            <Label className={`text-xs ${labelColor}`}>{lang === "bn" ? "ফোন নম্বর *" : "Phone Number *"}</Label>
            <Input value={checkoutForm.phone} onChange={e => setCheckoutForm({ ...checkoutForm, phone: e.target.value })} required placeholder="01XXXXXXXXX" className={inputBg} />
          </div>
          <div className="space-y-1.5">
            <Label className={`text-xs ${labelColor}`}>{lang === "bn" ? "ইমেইল (ঐচ্ছিক)" : "Email (optional)"}</Label>
            <Input type="email" value={checkoutForm.email} onChange={e => setCheckoutForm({ ...checkoutForm, email: e.target.value })} placeholder="email@example.com" className={inputBg} />
          </div>

          {/* Payment Method */}
          <div className="space-y-1.5">
            <Label className={`text-xs ${labelColor}`}>{lang === "bn" ? "পেমেন্ট পদ্ধতি *" : "Payment Method *"}</Label>
            <div className="grid grid-cols-2 gap-2">
              {paymentMethods.map(pm => (
                <button
                  type="button"
                  key={pm.value}
                  onClick={() => setCheckoutForm({ ...checkoutForm, payment_method: pm.value })}
                  className={`flex items-center gap-2 p-2.5 rounded-xl border text-xs font-medium transition-all text-left ${checkoutForm.payment_method === pm.value
                    ? isDark ? "border-violet-500/50 bg-violet-500/10 text-violet-300" : "border-violet-400 bg-violet-50 text-violet-600"
                    : isDark ? "border-white/10 bg-white/[0.03] text-white/60 hover:bg-white/[0.06]" : "border-gray-200 bg-white text-gray-600 hover:bg-gray-50"
                    }`}
                >
                  <span>{pm.icon}</span>
                  <span>{pm.label}</span>
                </button>
              ))}
            </div>
          </div>

          {/* Payment Instructions */}
          {["bkash", "nagad", "rocket"].includes(checkoutForm.payment_method) && (
            <div className={`rounded-xl p-3 border text-xs space-y-1 ${isDark ? "bg-orange-500/5 border-orange-500/20 text-orange-300" : "bg-orange-50 border-orange-200 text-orange-700"}`}>
              <p className="font-semibold flex items-center gap-1"><Smartphone className="h-3.5 w-3.5" /> {lang === "bn" ? "পেমেন্ট নির্দেশনা:" : "Payment Instructions:"}</p>
              <p>{lang === "bn" ? `${checkoutForm.payment_method === "bkash" ? "bKash" : checkoutForm.payment_method === "nagad" ? "Nagad" : "Rocket"} এ Send Money করুন:` : `Send Money via ${checkoutForm.payment_method === "bkash" ? "bKash" : checkoutForm.payment_method === "nagad" ? "Nagad" : "Rocket"}:`}</p>
              <p className="font-bold text-sm">{settings.phone?.split(",")[0]?.trim() || "01919-060590"}</p>
              <p>{lang === "bn" ? `পরিমাণ: ৳${totalPrice().toLocaleString()}` : `Amount: ৳${totalPrice().toLocaleString()}`}</p>
            </div>
          )}

          {checkoutForm.payment_method === "bank_transfer" && settings.bank_name && (
            <div className={`rounded-xl p-3 border text-xs space-y-1 ${isDark ? "bg-violet-500/5 border-violet-500/20 text-violet-300" : "bg-violet-50 border-blue-200 text-blue-700"}`}>
              <p className="font-semibold flex items-center gap-1"><Building2 className="h-3.5 w-3.5" /> {lang === "bn" ? "ব্যাংক তথ্য:" : "Bank Details:"}</p>
              <p>{settings.bank_name} — {settings.bank_branch}</p>
              <p className="font-bold">{settings.bank_account_name}</p>
              <p>A/C: {settings.bank_account_number}</p>
            </div>
          )}

          <Button type="submit" disabled={checkoutMutation.isPending} className="w-full gap-2 bg-gradient-to-r from-violet-600 to-indigo-500 hover:from-violet-500 hover:to-indigo-400 border-0 shadow-lg shadow-violet-500/25 rounded-xl text-white h-11 text-sm font-semibold">
            {checkoutMutation.isPending ? (lang === "bn" ? "প্রক্রিয়াকরণ..." : "Processing...") : (
              <><CheckCircle className="h-4 w-4" /> {lang === "bn" ? "অর্ডার নিশ্চিত করুন" : "Confirm Order"}</>
            )}
          </Button>
        </form>
      </DialogContent>
    </Dialog>
  );
}

