import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Textarea } from "@/components/ui/textarea";
import { Plus, Pencil, Trash2, MessageSquare, Download } from "lucide-react";
import { openWhatsApp, clientGreetingMessage } from "@/lib/whatsapp";
import { useToast } from "@/hooks/use-toast";
import { ConfirmDeleteDialog } from "@/components/ConfirmDeleteDialog";
import { useTranslation } from "@/contexts/LanguageContext";
import { exportToCSV } from "@/lib/exportUtils";
import type { TablesInsert } from "@/integrations/supabase/types";

export default function Clients() {
  const [open, setOpen] = useState(false);
  const [editing, setEditing] = useState<any>(null);
  const [form, setForm] = useState<TablesInsert<"clients">>({ name: "", email: "", phone: "", address: "", company: "", notes: "" });
  const queryClient = useQueryClient();
  const { toast } = useToast();
  const { t } = useTranslation();
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);

  const { data: clients, isLoading } = useQuery({
    queryKey: ["clients"],
    queryFn: async () => (await supabase.from("clients").select("*").order("created_at", { ascending: false })).data || [],
  });

  const saveMutation = useMutation({
    mutationFn: async (data: TablesInsert<"clients">) => {
      if (editing) {
        const { error } = await supabase.from("clients").update(data).eq("id", editing.id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from("clients").insert(data);
        if (error) throw error;
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["clients"] });
      setOpen(false);
      setEditing(null);
      setForm({ name: "", email: "", phone: "", address: "", company: "", notes: "" });
      toast({ title: editing ? "Client updated" : "Client added" });
    },
    onError: (err: any) => toast({ title: "Error", description: err.message, variant: "destructive" }),
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("clients").delete().eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["clients"] });
      toast({ title: "Client deleted" });
    },
  });

  const openEdit = (client: any) => {
    setEditing(client);
    setForm({ name: client.name, email: client.email, phone: client.phone, address: client.address, company: client.company, notes: client.notes });
    setOpen(true);
  };

  return (
    <>
      <div className="space-y-6">
        <div className="flex items-center justify-between flex-wrap gap-3">
          <div>
            <h1 className="text-2xl font-bold tracking-tight">{t("page.clients.title")}</h1>
            <p className="text-muted-foreground text-sm">{t("page.clients.subtitle")}</p>
          </div>
          <div className="flex gap-2">
            <Button variant="outline" size="sm" onClick={() => clients?.length && exportToCSV(clients.map(c => ({ Name: c.name, Company: c.company || "", Email: c.email || "", Phone: c.phone || "", Address: c.address || "" })), "clients")}>
              <Download className="h-4 w-4 mr-1" />{t("common.export_csv")}
            </Button>
          <Dialog open={open} onOpenChange={(v) => { setOpen(v); if (!v) { setEditing(null); setForm({ name: "", email: "", phone: "", address: "", company: "", notes: "" }); } }}>
            <DialogTrigger asChild>
              <Button><Plus className="h-4 w-4 mr-2" />{t("page.clients.add")}</Button>
            </DialogTrigger>
            <DialogContent>
              <DialogHeader><DialogTitle>{editing ? t("page.clients.edit") : t("page.clients.add")}</DialogTitle></DialogHeader>
              <form onSubmit={(e) => { e.preventDefault(); saveMutation.mutate(form); }} className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2"><Label>{t("common.name")} *</Label><Input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} required /></div>
                  <div className="space-y-2"><Label>{t("common.company")}</Label><Input value={form.company || ""} onChange={(e) => setForm({ ...form, company: e.target.value })} /></div>
                  <div className="space-y-2"><Label>{t("common.email")}</Label><Input type="email" value={form.email || ""} onChange={(e) => setForm({ ...form, email: e.target.value })} /></div>
                  <div className="space-y-2"><Label>{t("common.phone")}</Label><Input value={form.phone || ""} onChange={(e) => setForm({ ...form, phone: e.target.value })} /></div>
                </div>
                <div className="space-y-2"><Label>{t("common.address")}</Label><Input value={form.address || ""} onChange={(e) => setForm({ ...form, address: e.target.value })} /></div>
                <div className="space-y-2"><Label>{t("common.notes")}</Label><Textarea value={form.notes || ""} onChange={(e) => setForm({ ...form, notes: e.target.value })} /></div>
                <Button type="submit" className="w-full" disabled={saveMutation.isPending}>{editing ? t("common.edit") : t("common.add")} {t("page.clients.title")}</Button>
              </form>
            </DialogContent>
          </Dialog>
          </div>
        </div>

        <Card className="glass-card">
          <CardContent className="p-0">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>{t("common.name")}</TableHead><TableHead>{t("common.company")}</TableHead><TableHead>{t("common.email")}</TableHead><TableHead>{t("common.phone")}</TableHead><TableHead>{t("common.address")}</TableHead><TableHead className="w-24">{t("common.actions")}</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {clients?.map((c) => (
                  <TableRow key={c.id}>
                    <TableCell className="font-medium">{c.name}</TableCell>
                    <TableCell>{c.company || "—"}</TableCell>
                    <TableCell>{c.email || "—"}</TableCell>
                    <TableCell>{c.phone || "—"}</TableCell>
                    <TableCell>{c.address || "—"}</TableCell>
                    <TableCell>
                      <div className="flex gap-1">
                        {c.phone && (
                          <Button variant="ghost" size="icon" onClick={() => openWhatsApp(c.phone!, clientGreetingMessage(c.name))} title="WhatsApp">
                            <MessageSquare className="h-4 w-4 text-green-600" />
                          </Button>
                        )}
                        <Button variant="ghost" size="icon" onClick={() => openEdit(c)}><Pencil className="h-4 w-4" /></Button>
                        <Button variant="ghost" size="icon" onClick={() => setDeleteConfirmId(c.id)}><Trash2 className="h-4 w-4 text-destructive" /></Button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))}
                {(!clients || clients.length === 0) && (
                  <TableRow><TableCell colSpan={6} className="text-center text-muted-foreground py-8">{t("page.clients.no_clients")}</TableCell></TableRow>
                )}
              </TableBody>
            </Table>
          </CardContent>
        </Card>
      </div>

      <ConfirmDeleteDialog
        open={!!deleteConfirmId}
        onOpenChange={(open) => !open && setDeleteConfirmId(null)}
        onConfirm={() => {
          if (deleteConfirmId) {
            deleteMutation.mutate(deleteConfirmId);
            setDeleteConfirmId(null);
          }
        }}
        title="স্থায়ীভাবে ডিলিট করুন"
      />
    </>
);
}

import { useState, useEffect } from "react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { useNavigate, useParams, useLocation } from "react-router-dom";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Badge } from "@/components/ui/badge";
import { Calendar } from "@/components/ui/calendar";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { cn } from "@/lib/utils";
import { format } from "date-fns";
import { Plus, ArrowLeft, Trash2, CalendarIcon } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { BarcodeScanner } from "@/components/BarcodeScanner";
import { useCompanySettings } from "@/hooks/useCompanySettings";
import { SearchableItemSelect } from "@/components/SearchableItemSelect";

interface LineItem {
  description: string;
  quantity: number;
  unit_price: number;
  type: "product" | "service";
  warranty: string;
  sn: string;
}

export default function CreateInvoice() {
  const navigate = useNavigate();
  const { id: editId } = useParams<{ id: string }>();
  const isEditMode = !!editId;
  const queryClient = useQueryClient();
  const { toast } = useToast();
  const { settings } = useCompanySettings();
  const [form, setForm] = useState({ client_id: "", status: "draft", notes: "", tax_rate: "0", invoice_number: "" });
  const [dueDate, setDueDate] = useState<Date>(new Date());
  const [items, setItems] = useState<LineItem[]>([]);
  const [clientMode, setClientMode] = useState<"select" | "type">("select");
  const [typedClientName, setTypedClientName] = useState("");
  const [loaded, setLoaded] = useState(false);
  const location = useLocation();

  useEffect(() => {
    if (!isEditMode) {
      setForm(f => ({ ...f, tax_rate: String(settings.default_tax_rate) }));

      // Handle pre-fill from Servicing
      if (location.state?.fromServicing && !loaded) {
        const rec = location.state.servicingRecord;
        setClientMode("type");
        setTypedClientName(rec.client_name);
        setItems([{
          description: rec.description,
          quantity: 1,
          unit_price: rec.amount,
          type: "service",
          warranty: "",
          sn: ""
        }]);
        setLoaded(true);
        // Clear state so it doesn't persist on refresh
        window.history.replaceState({}, document.title);
      }
    }
  }, [settings.default_tax_rate, isEditMode, location.state, loaded]);

  // Load existing invoice for edit mode
  useEffect(() => {
    if (!editId || loaded) return;
    const loadInvoice = async () => {
      const { data: inv } = await supabase.from("invoices").select("*, clients(name)").eq("id", editId).single();
      if (!inv) { toast({ title: "Invoice not found", variant: "destructive" }); navigate("/invoices"); return; }
      const { data: invItems } = await supabase.from("invoice_items").select("*").eq("invoice_id", editId);

      setForm({
        client_id: inv.client_id || "",
        status: inv.status,
        notes: inv.notes || "",
        tax_rate: String(inv.tax_rate),
        invoice_number: inv.invoice_number,
      });
      if (inv.due_date) setDueDate(new Date(inv.due_date));
      if (inv.client_id) setClientMode("select");

      // Parse items back
      const parsedItems: LineItem[] = (invItems || []).map((item: any) => {
        const isService = item.description?.startsWith("[Service]");
        const isProduct = item.description?.startsWith("[Product]");
        const cleanDesc = item.description?.replace(/^\[(Service|Product)\]\s*/, "").replace(/\s*\(Warranty:.*?\)$/, "").replace(/\s*\(SN:.*?\)/, "") || item.description;
        const warranty = item.description?.match(/\(Warranty:\s*(.*?)\)/)?.[1] || "";
        const sn = item.description?.match(/\(SN:\s*(.*?)\)/)?.[1] || "";
        return {
          description: cleanDesc,
          quantity: item.quantity,
          unit_price: Number(item.unit_price),
          type: isService ? "service" as const : "product" as const,
          warranty,
          sn,
        };
      });
      setItems(parsedItems);
      setLoaded(true);
    };
    loadInvoice();
  }, [editId, loaded, navigate, toast]);

  // Add item form state removed as we use inline spreadsheet now

  const { data: clients } = useQuery({ queryKey: ["clients"], queryFn: async () => (await supabase.from("clients").select("id, name")).data || [] });
  const { data: services } = useQuery({
    queryKey: ["services-active"],
    queryFn: async () => {
      const { data } = await supabase.from("services").select("id, name, price, category").eq("status", "active").order("name");
      return data || [];
    },
  });
  const { data: products } = useQuery({
    queryKey: ["products-list"],
    queryFn: async () => {
      const { data } = await supabase.from("products").select("id, name, price, category, sku").order("name");
      return data || [];
    },
  });

  const subtotal = items.reduce((sum, item) => sum + item.quantity * item.unit_price, 0);
  const taxRate = Number(form.tax_rate) || 0;
  const taxAmount = subtotal * (taxRate / 100);
  const total = subtotal + taxAmount;

  const handleBarcodeDetected = (sku: string) => {
    const product = products?.find(p => p.sku?.toLowerCase() === sku.toLowerCase() || p.name.toLowerCase() === sku.toLowerCase());
    if (product) {
      setItems(prev => [...prev, { description: product.name, quantity: 1, unit_price: Number(product.price), type: "product", warranty: "", sn: "" }]);
      toast({ title: "Product added", description: `${product.name} — ৳${Number(product.price).toLocaleString()}` });
    } else {
      toast({ title: "Product not found", description: `No product found with SKU: ${sku}`, variant: "destructive" });
    }
  };

  const buildLineItems = (invoiceId: string) => {
    return items.filter(i => i.description).map(i => {
      let desc = i.description;
      if (i.type === "service") desc = `[Service] ${desc}`;
      if (i.type === "product") desc = `[Product] ${desc}`;
      if (i.sn) desc += ` (SN: ${i.sn})`;
      if (i.warranty) desc += ` (Warranty: ${i.warranty})`;
      return {
        invoice_id: invoiceId,
        description: desc,
        quantity: i.quantity,
        unit_price: i.unit_price,
        total: i.quantity * i.unit_price,
      };
    });
  };

  const saveMutation = useMutation({
    mutationFn: async () => {
      if (isEditMode && editId) {
        // Update existing invoice
        let clientId: string | null = form.client_id || null;
        if (clientMode === "type" && typedClientName.trim()) {
          const { data: newClient, error: clientError } = await supabase.from("clients").insert({ name: typedClientName.trim() }).select("id").single();
          if (clientError) throw clientError;
          clientId = newClient.id;
        }

        const { error } = await supabase.from("invoices").update({
          client_id: clientId,
          status: form.status,
          due_date: dueDate ? format(dueDate, "yyyy-MM-dd") : null,
          notes: form.notes || null,
          tax_rate: taxRate,
          subtotal,
          tax_amount: taxAmount,
          total,
        }).eq("id", editId);
        if (error) throw error;

        // Delete old items and re-insert
        await supabase.from("invoice_items").delete().eq("invoice_id", editId);
        const lineItems = buildLineItems(editId);
        if (lineItems.length > 0) {
          const { error: itemsError } = await supabase.from("invoice_items").insert(lineItems);
          if (itemsError) throw itemsError;
        }
      } else {
        // Create new invoice
        const { data: invNum } = await supabase.rpc("generate_invoice_number");
        const invoiceNumber = invNum || `AK-${Date.now()}`;

        let clientId: string | null = form.client_id || null;
        if (clientMode === "type" && typedClientName.trim()) {
          const { data: newClient, error: clientError } = await supabase.from("clients").insert({ name: typedClientName.trim() }).select("id").single();
          if (clientError) throw clientError;
          clientId = newClient.id;
        }

        const { data: invoice, error } = await supabase.from("invoices").insert({
          invoice_number: invoiceNumber,
          client_id: clientId,
          project_id: null,
          status: form.status,
          due_date: dueDate ? format(dueDate, "yyyy-MM-dd") : null,
          notes: form.notes || null,
          tax_rate: taxRate,
          subtotal,
          tax_amount: taxAmount,
          total,
        }).select().single();
        if (error) throw error;

        const lineItems = buildLineItems(invoice.id);
        if (lineItems.length > 0) {
          const { error: itemsError } = await supabase.from("invoice_items").insert(lineItems);
          if (itemsError) throw itemsError;
        }
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["invoices"] });
      toast({ title: isEditMode ? "Invoice updated" : "Invoice created" });
      navigate("/invoices");
    },
    onError: (err: any) => toast({ title: "Error", description: err.message, variant: "destructive" }),
  });

  const removeItem = (idx: number) => setItems(items.filter((_, i) => i !== idx));
  const updateItem = (idx: number, field: keyof LineItem, value: any) => {
    const updated = [...items];
    updated[idx] = { ...updated[idx], [field]: value };
    setItems(updated);
  };

  // Unused logic removed

  return (
      <div className="space-y-6 max-w-3xl mx-auto">
        <div className="flex items-center gap-4">
          <Button variant="ghost" size="icon" onClick={() => navigate("/invoices")}><ArrowLeft className="h-4 w-4" /></Button>
          <div>
            <h1 className="text-2xl font-bold tracking-tight">{isEditMode ? "Edit Invoice" : "Create Invoice"}</h1>
            <p className="text-muted-foreground text-sm">
              {isEditMode ? `Editing ${form.invoice_number}` : "Fill in the details to generate a new invoice"}
            </p>
          </div>
        </div>

        <form onSubmit={(e) => { e.preventDefault(); saveMutation.mutate(); }} className="space-y-6">
          <Card className="glass-card">
            <CardHeader><CardTitle className="text-lg">Invoice Details</CardTitle></CardHeader>
            <CardContent className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Client</Label>
                <RadioGroup value={clientMode} onValueChange={(v) => { setClientMode(v as "select" | "type"); setForm({ ...form, client_id: "" }); setTypedClientName(""); }} className="flex gap-4 mb-2">
                  <div className="flex items-center gap-2">
                    <RadioGroupItem value="select" id="client-select" />
                    <Label htmlFor="client-select" className="cursor-pointer font-normal text-xs">Select</Label>
                  </div>
                  <div className="flex items-center gap-2">
                    <RadioGroupItem value="type" id="client-type" />
                    <Label htmlFor="client-type" className="cursor-pointer font-normal text-xs">Type</Label>
                  </div>
                </RadioGroup>
                {clientMode === "select" ? (
                  <Select value={form.client_id} onValueChange={(v) => setForm({ ...form, client_id: v })}>
                    <SelectTrigger><SelectValue placeholder="Select client" /></SelectTrigger>
                    <SelectContent>{clients?.map(c => <SelectItem key={c.id} value={c.id}>{c.name}</SelectItem>)}</SelectContent>
                  </Select>
                ) : (
                  <Input value={typedClientName} onChange={(e) => setTypedClientName(e.target.value)} placeholder="Type client name..." />
                )}
              </div>
              <div className="space-y-2">
                <Label>Due Date</Label>
                <Popover>
                  <PopoverTrigger asChild>
                    <Button variant="outline" className={cn("w-full justify-start text-left font-normal", !dueDate && "text-muted-foreground")}>
                      <CalendarIcon className="mr-2 h-4 w-4" />
                      {dueDate ? format(dueDate, "PPP") : <span>Pick a date</span>}
                    </Button>
                  </PopoverTrigger>
                  <PopoverContent className="w-auto p-0" align="start">
                    <Calendar mode="single" selected={dueDate} onSelect={(d) => d && setDueDate(d)} initialFocus className={cn("p-3 pointer-events-auto")} />
                  </PopoverContent>
                </Popover>
              </div>
              <div className="space-y-2"><Label>Tax Rate (%)</Label><Input type="number" value={form.tax_rate} onChange={(e) => setForm({ ...form, tax_rate: e.target.value })} /></div>
              <div className="space-y-2">
                <Label>Payment Status</Label>
                <Select value={form.status} onValueChange={(v) => setForm({ ...form, status: v })}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="draft">Draft</SelectItem>
                    <SelectItem value="paid">Paid</SelectItem>
                    <SelectItem value="sent">Sent (Unpaid)</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </CardContent>
          </Card>

          {/* Summary Card - Moved to Top */}
          <Card className="glass-card">
            <CardContent className="pt-6 space-y-2 text-sm">
              <div className="flex justify-between items-center bg-primary/5 p-3 rounded-xl border border-primary/10">
                <div className="flex items-center gap-2">
                  <div className="p-1.5 rounded-lg bg-primary/10">
                    <Plus className="h-4 w-4 text-primary" />
                  </div>
                  <span className="font-bold text-primary">Running Total</span>
                </div>
                <span className="text-2xl font-black text-primary">৳{total.toLocaleString()}</span>
              </div>
              <div className="grid grid-cols-2 gap-4 pt-2 px-1">
                <div className="flex justify-between border-r border-border/50 pr-4"><span className="text-muted-foreground">Subtotal</span><span className="font-medium text-foreground">৳{subtotal.toLocaleString()}</span></div>
                <div className="flex justify-between pl-4"><span className="text-muted-foreground">Tax ({taxRate}%)</span><span className="font-medium text-foreground">৳{taxAmount.toLocaleString()}</span></div>
              </div>
            </CardContent>
          </Card>

          {/* Barcode Scanner */}
          <BarcodeScanner onBarcodeDetected={handleBarcodeDetected} />

          {/* Spreadsheet Line Items */}
          <Card className="glass-card relative z-20">
            <CardHeader className="flex flex-row items-center justify-between py-4">
              <CardTitle className="text-lg">Line Items</CardTitle>
              <div className="flex items-center gap-2">
                <div className="w-64">
                  <SearchableItemSelect
                    items={[...(products || []), ...(services || [])].map(i => ({ ...i, price: Number(i.price) }))}
                    value=""
                    onSelect={(id) => {
                      const product = products?.find(p => p.id === id);
                      const service = services?.find(s => s.id === id);
                      if (product) {
                        setItems([...items, { description: product.name, quantity: 1, unit_price: Number(product.price), type: "product", warranty: "", sn: "" }]);
                      } else if (service) {
                        setItems([...items, { description: service.name, quantity: 1, unit_price: Number(service.price), type: "service", warranty: "", sn: "" }]);
                      }
                      toast({ title: "Item added from catalog" });
                    }}
                    placeholder="Quick add from catalog..."
                  />
                </div>
                <Button type="button" variant="outline" size="sm" onClick={() => {
                  setItems([...items, { description: "", quantity: 1, unit_price: 0, type: "product", warranty: "", sn: "" }]);
                }}>
                  <Plus className="h-4 w-4 mr-1" /> Blank Row
                </Button>
              </div>
            </CardHeader>
            <CardContent className="p-0 overflow-x-auto">
              <table className="w-full text-sm text-left">
                <thead className="bg-muted/50 text-muted-foreground uppercase text-xs">
                  <tr>
                    <th className="px-4 py-3 font-medium">Type</th>
                    <th className="px-4 py-3 font-medium min-w-[200px]">Description</th>
                    <th className="px-4 py-3 font-medium min-w-[120px]">S/N</th>
                    <th className="px-4 py-3 font-medium w-[80px]">Qty</th>
                    <th className="px-4 py-3 font-medium w-[120px]">Unit Price</th>
                    <th className="px-4 py-3 font-medium min-w-[120px]">Warranty</th>
                    <th className="px-4 py-3 font-medium text-right">Total</th>
                    <th className="px-4 py-3 font-medium w-[50px]"></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-border/50">
                  {items.map((item, idx) => (
                    <tr key={idx} className="hover:bg-muted/20 transition-colors">
                      <td className="px-4 py-2">
                        <Select value={item.type} onValueChange={(v) => updateItem(idx, "type", v)}>
                          <SelectTrigger className="h-8 text-xs w-[90px] border-transparent bg-transparent hover:bg-muted"><SelectValue /></SelectTrigger>
                          <SelectContent>
                            <SelectItem value="product">Product</SelectItem>
                            <SelectItem value="service">Service</SelectItem>
                          </SelectContent>
                        </Select>
                      </td>
                      <td className="px-4 py-2">
                        <Input value={item.description} onChange={(e) => updateItem(idx, "description", e.target.value)} placeholder="Item description" className="h-8 text-sm border-transparent bg-transparent hover:bg-muted focus:bg-background" />
                      </td>
                      <td className="px-4 py-2">
                        <Input value={item.sn} onChange={(e) => updateItem(idx, "sn", e.target.value)} placeholder="Serial No." className="h-8 text-sm border-transparent bg-transparent hover:bg-muted focus:bg-background" />
                      </td>
                      <td className="px-4 py-2">
                        <Input type="number" value={item.quantity === 0 ? "" : item.quantity} onChange={(e) => updateItem(idx, "quantity", Number(e.target.value))} className="h-8 text-sm border-transparent bg-transparent hover:bg-muted focus:bg-background px-2" />
                      </td>
                      <td className="px-4 py-2">
                        <Input type="number" value={item.unit_price === 0 ? "" : item.unit_price} onChange={(e) => updateItem(idx, "unit_price", Number(e.target.value))} className="h-8 text-sm border-transparent bg-transparent hover:bg-muted focus:bg-background px-2" />
                      </td>
                      <td className="px-4 py-2">
                        <Input value={item.warranty} onChange={(e) => updateItem(idx, "warranty", e.target.value)} placeholder="e.g. 1 Yr" className="h-8 text-sm border-transparent bg-transparent hover:bg-muted focus:bg-background disabled:opacity-50" disabled={item.type === "service"} />
                      </td>
                      <td className="px-4 py-2 text-right font-medium">
                        ৳{(item.quantity * item.unit_price).toLocaleString()}
                      </td>
                      <td className="px-4 py-2 text-center">
                        <Button type="button" variant="ghost" size="icon" className="h-7 w-7 text-muted-foreground hover:text-destructive hover:bg-destructive/10" onClick={() => removeItem(idx)}>
                          <Trash2 className="h-3.5 w-3.5" />
                        </Button>
                      </td>
                    </tr>
                  ))}
                  {items.length === 0 && (
                    <tr>
                      <td colSpan={8} className="px-4 py-8 text-center text-muted-foreground">
                        No items added yet. Search the catalog or add a blank row.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
              <div className="p-3 border-t bg-muted/10 flex justify-center">
                <Button type="button" variant="ghost" size="sm" className="text-primary text-xs" onClick={() => {
                  setItems([...items, { description: "", quantity: 1, unit_price: 0, type: "product", warranty: "", sn: "" }]);
                }}>
                  <Plus className="h-3.5 w-3.5 mr-1" /> Add Blank Row
                </Button>
              </div>
            </CardContent>
          </Card>

          <div className="space-y-4">
            <div className="space-y-2"><Label>Notes</Label><Textarea value={form.notes} onChange={(e) => setForm({ ...form, notes: e.target.value })} placeholder="Payment terms, bank details, etc." /></div>
            <Button type="submit" className="w-full" disabled={saveMutation.isPending || items.length === 0}>
              {isEditMode ? "Update Invoice" : "Generate Invoice"}
            </Button>
          </div>
        </form>
      </div>
);
}

import { useState, useEffect } from "react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { useNavigate, useParams } from "react-router-dom";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Calendar } from "@/components/ui/calendar";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { cn } from "@/lib/utils";
import { format, addDays } from "date-fns";
import { Plus, ArrowLeft, Trash2, CalendarIcon } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { useCompanySettings } from "@/hooks/useCompanySettings";
import { SearchableItemSelect } from "@/components/SearchableItemSelect";

interface LineItem {
  description: string;
  quantity: number;
  unit_price: number;
  type: "product" | "service";
  warranty: string;
}

export default function CreateQuotation() {
  const navigate = useNavigate();
  const { id: editId } = useParams<{ id: string }>();
  const isEditMode = !!editId;
  const queryClient = useQueryClient();
  const { toast } = useToast();
  const { settings } = useCompanySettings();
  const [form, setForm] = useState({ client_id: "", notes: "", tax_rate: "0", quotation_number: "" });
  const [validUntil, setValidUntil] = useState<Date>(addDays(new Date(), 30));
  const [items, setItems] = useState<LineItem[]>([]);
  const [clientMode, setClientMode] = useState<"select" | "type">("select");
  const [typedClientName, setTypedClientName] = useState("");
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    if (!isEditMode) {
      setForm(f => ({ ...f, tax_rate: String(settings.default_tax_rate) }));
    }
  }, [settings.default_tax_rate, isEditMode]);

  useEffect(() => {
    if (!editId || loaded) return;
    const loadQuotation = async () => {
      const { data: q } = await supabase.from("quotations").select("*, clients(name)").eq("id", editId).single();
      if (!q) { toast({ title: "Quotation not found", variant: "destructive" }); navigate("/quotations"); return; }
      const { data: qItems } = await supabase.from("quotation_items").select("*").eq("quotation_id", editId);

      setForm({
        client_id: q.client_id || "",
        notes: q.notes || "",
        tax_rate: String(q.tax_rate),
        quotation_number: q.quotation_number,
      });
      if (q.valid_until) setValidUntil(new Date(q.valid_until));
      if (q.client_id) setClientMode("select");

      const parsedItems: LineItem[] = (qItems || []).map((item: any) => {
        const isService = item.description?.startsWith("[Service]");
        const isProduct = item.description?.startsWith("[Product]");
        const cleanDesc = item.description?.replace(/^\[(Service|Product)\]\s*/, "").replace(/\s*\(Warranty:.*?\)$/, "") || item.description;
        const warranty = item.description?.match(/\(Warranty:\s*(.*?)\)/)?.[1] || "";
        return {
          description: cleanDesc,
          quantity: item.quantity,
          unit_price: Number(item.unit_price),
          type: isService ? "service" as const : "product" as const,
          warranty,
        };
      });
      setItems(parsedItems);
      setLoaded(true);
    };
    loadQuotation();
  }, [editId, loaded, navigate, toast]);

  const { data: clients } = useQuery({ queryKey: ["clients"], queryFn: async () => (await supabase.from("clients").select("id, name")).data || [] });
  const { data: services } = useQuery({
    queryKey: ["services-active"],
    queryFn: async () => {
      const { data } = await supabase.from("services").select("id, name, price, category").eq("status", "active").order("name");
      return data || [];
    },
  });
  const { data: products } = useQuery({
    queryKey: ["products-list"],
    queryFn: async () => {
      const { data } = await supabase.from("products").select("id, name, price, category, sku").order("name");
      return data || [];
    },
  });

  const subtotal = items.reduce((sum, item) => sum + item.quantity * item.unit_price, 0);
  const taxRate = Number(form.tax_rate) || 0;
  const taxAmount = subtotal * (taxRate / 100);
  const total = subtotal + taxAmount;

  const saveMutation = useMutation({
    mutationFn: async () => {
      let clientId: string | null = form.client_id || null;
      if (clientMode === "type" && typedClientName.trim()) {
        const { data: newClient, error: clientError } = await supabase.from("clients").insert({ name: typedClientName.trim() }).select("id").single();
        if (clientError) throw clientError;
        clientId = newClient.id;
      }

      const quotationData = {
        client_id: clientId,
        valid_until: validUntil ? format(validUntil, "yyyy-MM-dd") : null,
        notes: form.notes || null,
        tax_rate: taxRate,
        subtotal,
        tax_amount: taxAmount,
        total,
      };

      let qId = editId;

      if (isEditMode) {
        const { error } = await supabase.from("quotations").update(quotationData).eq("id", editId);
        if (error) throw error;
        await supabase.from("quotation_items").delete().eq("quotation_id", editId);
      } else {
        const { data: qtNum } = await supabase.rpc("generate_quotation_number");
        const quotationNumber = qtNum || `QT-${Date.now()}`;
        const { data: quotation, error } = await supabase.from("quotations").insert({
          ...quotationData,
          quotation_number: quotationNumber,
          status: "draft",
        }).select().single();
        if (error) throw error;
        qId = quotation.id;
      }

      const lineItems = items.filter(i => i.description).map(i => {
        let desc = i.type === "product" ? `[Product] ${i.description}` : i.type === "service" ? `[Service] ${i.description}` : i.description;
        if (i.warranty) desc += ` (Warranty: ${i.warranty})`;
        return {
          quotation_id: qId,
          description: desc,
          quantity: i.quantity,
          unit_price: i.unit_price,
          total: i.quantity * i.unit_price,
        };
      });

      if (lineItems.length > 0) {
        const { error: itemsError } = await supabase.from("quotation_items").insert(lineItems);
        if (itemsError) throw itemsError;
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["quotations"] });
      toast({ title: isEditMode ? "Quotation updated" : "Quotation created successfully" });
      navigate("/quotations");
    },
    onError: (err: any) => toast({ title: "Error", description: err.message, variant: "destructive" }),
  });

  const removeItem = (idx: number) => setItems(items.filter((_, i) => i !== idx));
  const updateItem = (idx: number, field: keyof LineItem, value: any) => {
    const updated = [...items];
    updated[idx] = { ...updated[idx], [field]: value };
    setItems(updated);
  };

  return (
      <div className="space-y-6 max-w-3xl mx-auto">
        <div className="flex items-center gap-4">
          <Button variant="ghost" size="icon" onClick={() => navigate("/quotations")}><ArrowLeft className="h-4 w-4" /></Button>
          <div>
            <h1 className="text-2xl font-bold tracking-tight">{isEditMode ? `Edit Quotation ${form.quotation_number}` : "Create Quotation"}</h1>
            <p className="text-muted-foreground text-sm">Prepare a quotation for CCTV, attendance devices & IT products</p>
          </div>
        </div>

        <form onSubmit={(e) => { e.preventDefault(); saveMutation.mutate(); }} className="space-y-6">
          <Card className="glass-card">
            <CardHeader><CardTitle className="text-lg">Quotation Details</CardTitle></CardHeader>
            <CardContent className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Client</Label>
                <RadioGroup value={clientMode} onValueChange={(v) => { setClientMode(v as "select" | "type"); setForm({ ...form, client_id: "" }); setTypedClientName(""); }} className="flex gap-4 mb-2">
                  <div className="flex items-center gap-2">
                    <RadioGroupItem value="select" id="client-select" />
                    <Label htmlFor="client-select" className="cursor-pointer font-normal text-xs">Select</Label>
                  </div>
                  <div className="flex items-center gap-2">
                    <RadioGroupItem value="type" id="client-type" />
                    <Label htmlFor="client-type" className="cursor-pointer font-normal text-xs">Type</Label>
                  </div>
                </RadioGroup>
                {clientMode === "select" ? (
                  <Select value={form.client_id} onValueChange={(v) => setForm({ ...form, client_id: v })}>
                    <SelectTrigger><SelectValue placeholder="Select client" /></SelectTrigger>
                    <SelectContent>{clients?.map(c => <SelectItem key={c.id} value={c.id}>{c.name}</SelectItem>)}</SelectContent>
                  </Select>
                ) : (
                  <Input value={typedClientName} onChange={(e) => setTypedClientName(e.target.value)} placeholder="Type client name..." />
                )}
              </div>
              <div className="space-y-2">
                <Label>Valid Until</Label>
                <Popover>
                  <PopoverTrigger asChild>
                    <Button variant="outline" className={cn("w-full justify-start text-left font-normal", !validUntil && "text-muted-foreground")}>
                      <CalendarIcon className="mr-2 h-4 w-4" />
                      {validUntil ? format(validUntil, "PPP") : <span>Pick a date</span>}
                    </Button>
                  </PopoverTrigger>
                  <PopoverContent className="w-auto p-0" align="start">
                    <Calendar mode="single" selected={validUntil} onSelect={(d) => d && setValidUntil(d)} initialFocus className="p-3 pointer-events-auto" />
                  </PopoverContent>
                </Popover>
              </div>
              <div className="space-y-2"><Label>Tax Rate (%)</Label><Input type="number" value={form.tax_rate} onChange={(e) => setForm({ ...form, tax_rate: e.target.value })} /></div>
            </CardContent>
          </Card>

          {/* Summary Card */}
          <Card className="glass-card">
            <CardContent className="pt-6 space-y-2 text-sm">
              <div className="flex justify-between items-center bg-primary/5 p-3 rounded-xl border border-primary/10">
                <div className="flex items-center gap-2">
                  <div className="p-1.5 rounded-lg bg-primary/10">
                    <Plus className="h-4 w-4 text-primary" />
                  </div>
                  <span className="font-bold text-primary">Running Total</span>
                </div>
                <span className="text-2xl font-black text-primary">৳{total.toLocaleString()}</span>
              </div>
              <div className="grid grid-cols-2 gap-4 pt-2 px-1">
                <div className="flex justify-between border-r border-border/50 pr-4"><span className="text-muted-foreground">Subtotal</span><span className="font-medium text-foreground">৳{subtotal.toLocaleString()}</span></div>
                <div className="flex justify-between pl-4"><span className="text-muted-foreground">Tax ({taxRate}%)</span><span className="font-medium text-foreground">৳{taxAmount.toLocaleString()}</span></div>
              </div>
            </CardContent>
          </Card>

          {/* Spreadsheet Line Items */}
          <Card className="glass-card relative z-20">
            <CardHeader className="flex flex-row items-center justify-between py-4">
              <CardTitle className="text-lg">Line Items</CardTitle>
              <div className="flex items-center gap-2">
                <div className="w-64">
                  <SearchableItemSelect
                    items={[...(products || []), ...(services || [])].map(i => ({ ...i, price: Number(i.price) }))}
                    value=""
                    onSelect={(id) => {
                      const product = products?.find(p => p.id === id);
                      const service = services?.find(s => s.id === id);
                      if (product) {
                        setItems([...items, { description: product.name, quantity: 1, unit_price: Number(product.price), type: "product", warranty: "" }]);
                      } else if (service) {
                        setItems([...items, { description: service.name, quantity: 1, unit_price: Number(service.price), type: "service", warranty: "" }]);
                      }
                      toast({ title: "Item added from catalog" });
                    }}
                    placeholder="Quick add from catalog..."
                  />
                </div>
                <Button type="button" variant="outline" size="sm" onClick={() => {
                  setItems([...items, { description: "", quantity: 1, unit_price: 0, type: "product", warranty: "" }]);
                }}>
                  <Plus className="h-4 w-4 mr-1" /> Blank Row
                </Button>
              </div>
            </CardHeader>
            <CardContent className="p-0 overflow-x-auto">
              <table className="w-full text-sm text-left">
                <thead className="bg-muted/50 text-muted-foreground uppercase text-xs">
                  <tr>
                    <th className="px-4 py-3 font-medium">Type</th>
                    <th className="px-4 py-3 font-medium min-w-[200px]">Description</th>
                    <th className="px-4 py-3 font-medium w-[80px]">Qty</th>
                    <th className="px-4 py-3 font-medium w-[120px]">Unit Price</th>
                    <th className="px-4 py-3 font-medium min-w-[120px]">Warranty</th>
                    <th className="px-4 py-3 font-medium text-right">Total</th>
                    <th className="px-4 py-3 font-medium w-[50px]"></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-border/50">
                  {items.map((item, idx) => (
                    <tr key={idx} className="hover:bg-muted/20 transition-colors">
                      <td className="px-4 py-2">
                        <Select value={item.type} onValueChange={(v) => updateItem(idx, "type", v)}>
                          <SelectTrigger className="h-8 text-xs w-[90px] border-transparent bg-transparent hover:bg-muted"><SelectValue /></SelectTrigger>
                          <SelectContent>
                            <SelectItem value="product">Product</SelectItem>
                            <SelectItem value="service">Service</SelectItem>
                          </SelectContent>
                        </Select>
                      </td>
                      <td className="px-4 py-2">
                        <Input value={item.description} onChange={(e) => updateItem(idx, "description", e.target.value)} placeholder="Item description" className="h-8 text-sm border-transparent bg-transparent hover:bg-muted focus:bg-background" />
                      </td>
                      <td className="px-4 py-2">
                        <Input type="number" value={item.quantity === 0 ? "" : item.quantity} onChange={(e) => updateItem(idx, "quantity", Number(e.target.value))} className="h-8 text-sm border-transparent bg-transparent hover:bg-muted focus:bg-background px-2" />
                      </td>
                      <td className="px-4 py-2">
                        <Input type="number" value={item.unit_price === 0 ? "" : item.unit_price} onChange={(e) => updateItem(idx, "unit_price", Number(e.target.value))} className="h-8 text-sm border-transparent bg-transparent hover:bg-muted focus:bg-background px-2" />
                      </td>
                      <td className="px-4 py-2">
                        <Input value={item.warranty} onChange={(e) => updateItem(idx, "warranty", e.target.value)} placeholder="e.g. 1 Yr" className="h-8 text-sm border-transparent bg-transparent hover:bg-muted focus:bg-background disabled:opacity-50" disabled={item.type === "service"} />
                      </td>
                      <td className="px-4 py-2 text-right font-medium">
                        ৳{(item.quantity * item.unit_price).toLocaleString()}
                      </td>
                      <td className="px-4 py-2 text-center">
                        <Button type="button" variant="ghost" size="icon" className="h-7 w-7 text-muted-foreground hover:text-destructive hover:bg-destructive/10" onClick={() => removeItem(idx)}>
                          <Trash2 className="h-3.5 w-3.5" />
                        </Button>
                      </td>
                    </tr>
                  ))}
                  {items.length === 0 && (
                    <tr>
                      <td colSpan={7} className="px-4 py-8 text-center text-muted-foreground">
                        No items added yet. Search the catalog or add a blank row.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
              <div className="p-3 border-t bg-muted/10 flex justify-center">
                <Button type="button" variant="ghost" size="sm" className="text-primary text-xs" onClick={() => {
                  setItems([...items, { description: "", quantity: 1, unit_price: 0, type: "product", warranty: "" }]);
                }}>
                  <Plus className="h-3.5 w-3.5 mr-1" /> Add Blank Row
                </Button>
              </div>
            </CardContent>
          </Card>

          <div className="space-y-2">
            <Label>Notes / Terms & Conditions</Label>
            <Textarea value={form.notes} onChange={(e) => setForm({ ...form, notes: e.target.value })} placeholder="e.g. Payment terms, warranty info, installation timeline..." rows={3} />
          </div>

          <div className="flex gap-3 justify-end">
            <Button type="button" variant="outline" onClick={() => navigate("/quotations")}>Cancel</Button>
            <Button type="submit" disabled={saveMutation.isPending || items.length === 0}>
              {saveMutation.isPending ? "Saving..." : isEditMode ? "Update Quotation" : "Create Quotation"}
            </Button>
          </div>
        </form>
      </div>
  );
}

import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { FolderKanban, ShoppingCart, LogOut } from "lucide-react";
import { StatCard } from "@/components/StatCard";
import { Button } from "@/components/ui/button";
import { useNavigate } from "react-router-dom";
import { ChangePasswordCard } from "@/components/ChangePasswordCard";
import { DeleteAccountCard } from "@/components/DeleteAccountCard";

export default function EmployeeDashboard() {
  const navigate = useNavigate();

  const { data: projects } = useQuery({
    queryKey: ["projects"],
    queryFn: async () => (await supabase.from("projects").select("*, clients(name)")).data || [],
  });

  const { data: orders } = useQuery({
    queryKey: ["store-orders"],
    queryFn: async () => (await supabase.from("store_orders").select("*")).data || [],
  });

  const activeProjects = projects?.filter(p => p.status === "in_progress").length || 0;
  const pendingOrders = orders?.filter(o => o.status === "pending").length || 0;

  const statusColor: Record<string, string> = {
    pending: "bg-warning/10 text-warning border-warning/20",
    in_progress: "bg-info/10 text-info border-info/20",
    completed: "bg-success/10 text-success border-success/20",
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    navigate("/auth");
  };

  return (
    <div className="min-h-screen bg-background p-4 md:p-8">
      <div className="max-w-4xl mx-auto space-y-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold tracking-tight">Employee Dashboard</h1>
            <p className="text-muted-foreground text-sm">View-only access to projects and orders</p>
          </div>
          <Button variant="outline" size="sm" onClick={handleLogout}>
            <LogOut className="h-4 w-4 mr-2" /> Logout
          </Button>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <StatCard title="Active Projects" value={activeProjects} icon={FolderKanban} />
          <StatCard title="Pending Orders" value={pendingOrders} icon={ShoppingCart} />
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <Card>
            <CardHeader><CardTitle className="text-base">Projects</CardTitle></CardHeader>
            <CardContent className="space-y-3">
              {projects?.map(p => (
                <div key={p.id} className="flex items-center justify-between py-2 border-b border-border/50 last:border-0">
                  <div>
                    <p className="text-sm font-medium">{p.title}</p>
                    <p className="text-xs text-muted-foreground">{(p as any).clients?.name || "No client"}</p>
                  </div>
                  <Badge variant="outline" className={statusColor[p.status] || ""}>{p.status}</Badge>
                </div>
              ))}
              {(!projects || projects.length === 0) && <p className="text-sm text-muted-foreground">No projects yet</p>}
            </CardContent>
          </Card>

          <Card>
            <CardHeader><CardTitle className="text-base">Recent Orders</CardTitle></CardHeader>
            <CardContent className="space-y-3">
              {orders?.slice(0, 10).map(o => (
                <div key={o.id} className="flex items-center justify-between py-2 border-b border-border/50 last:border-0">
                  <div>
                    <p className="text-sm font-medium">{o.item_name}</p>
                    <p className="text-xs text-muted-foreground">{o.customer_name}</p>
                  </div>
                  <Badge variant="outline" className={statusColor[o.status] || ""}>{o.status}</Badge>
                </div>
              ))}
              {(!orders || orders.length === 0) && <p className="text-sm text-muted-foreground">No orders yet</p>}
            </CardContent>
          </Card>
        </div>

        <ChangePasswordCard />
        <DeleteAccountCard />
      </div>
    </div>
  );
}

import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Plus, Trash2, Pencil, Search, Users, MapPin, Briefcase, Crown, ShieldCheck, User, Clock, CheckCircle, Link2 } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { useIsMobile } from "@/hooks/use-mobile";
import { cn } from "@/lib/utils";

interface Employee {
  id: string;
  name: string;
  phone: string | null;
  email: string | null;
  role: string;
  designation: string | null;
  client_id: string | null;
  project_id: string | null;
  work_location: string | null;
  status: string;
  created_at: string;
  clients?: { name: string } | null;
  projects?: { title: string } | null;
  // Linked user account info
  userRole?: string | null;
  isApproved?: boolean | null;
  hasAccount?: boolean;
}

const defaultForm = {
  name: "",
  phone: "",
  email: "",
  role: "Technician",
  designation: "",
  client_id: "",
  project_id: "",
  work_location: "",
  status: "active",
};

const ROLE_ICON: Record<string, React.ReactNode> = {
  ceo: <Crown className="h-3 w-3 text-amber-600" />,
  admin: <ShieldCheck className="h-3 w-3 text-destructive" />,
  manager: <Briefcase className="h-3 w-3 text-blue-600" />,
  employee: <User className="h-3 w-3 text-primary" />,
};

export default function Employees() {
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState(defaultForm);
  const [search, setSearch] = useState("");
  const { toast } = useToast();
  const isMobile = useIsMobile();
  const queryClient = useQueryClient();

  // Fetch employees + linked user role data
  const { data: employees = [], isLoading } = useQuery({
    queryKey: ["employees"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("employees")
        .select("*, clients(name), projects(title)")
        .order("created_at", { ascending: false });
      if (error) throw error;

      // Get all profiles to match emails to user_ids
      const emails = (data || []).map((e: any) => e.email).filter(Boolean);
      const { data: profiles } = await supabase
        .from("profiles")
        .select("id, email")
        .in("email", emails);

      const emailToUserId = new Map((profiles || []).map((p: any) => [p.email, p.id]));

      // Get user_roles for matched users
      const userIds = Array.from(emailToUserId.values());
      const { data: roles } = userIds.length > 0
        ? await supabase.from("user_roles").select("user_id, role, is_approved").in("user_id", userIds)
        : { data: [] };

      const userIdToRole = new Map((roles || []).map((r: any) => [r.user_id, r]));

      return (data || []).map((emp: any) => {
        const userId = emailToUserId.get(emp.email);
        const roleData = userId ? userIdToRole.get(userId) : null;
        return {
          ...emp,
          userRole: roleData?.role || null,
          isApproved: roleData?.is_approved ?? null,
          hasAccount: !!roleData,
        };
      }) as Employee[];
    },
  });

  const { data: clients = [] } = useQuery({
    queryKey: ["clients"],
    queryFn: async () => {
      const { data } = await supabase.from("clients").select("id, name").order("name");
      return data || [];
    },
  });

  const { data: projects = [] } = useQuery({
    queryKey: ["projects"],
    queryFn: async () => {
      const { data } = await supabase.from("projects").select("id, title").order("title");
      return data || [];
    },
  });

  const saveMutation = useMutation({
    mutationFn: async (values: typeof form) => {
      const payload = {
        name: values.name,
        phone: values.phone || null,
        email: values.email || null,
        role: values.role,
        designation: values.designation || null,
        client_id: values.client_id || null,
        project_id: values.project_id || null,
        work_location: values.work_location || null,
        status: values.status,
      };
      if (editingId) {
        const { error } = await supabase.from("employees").update(payload).eq("id", editingId);
        if (error) throw error;

        // Sync designation to user_roles if this employee has a linked account
        if (values.email && values.designation) {
          const { data: profile } = await supabase.from("profiles").select("id").eq("email", values.email).single();
          if (profile) {
            await supabase.from("user_roles").update({ designation: values.designation } as any).eq("user_id", profile.id);
          }
        }
      } else {
        const { error } = await supabase.from("employees").insert(payload);
        if (error) throw error;
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["employees"] });
      queryClient.invalidateQueries({ queryKey: ["user-roles-management"] });
      toast({ title: editingId ? "Employee updated" : "Employee added" });
      closeDialog();
    },
    onError: () => toast({ title: "Error saving employee", variant: "destructive" }),
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("employees").delete().eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["employees"] });
      toast({ title: "Employee deleted" });
    },
  });

  const closeDialog = () => {
    setDialogOpen(false);
    setEditingId(null);
    setForm(defaultForm);
  };

  const openEdit = (emp: Employee) => {
    setEditingId(emp.id);
    setForm({
      name: emp.name,
      phone: emp.phone || "",
      email: emp.email || "",
      role: emp.role,
      designation: emp.designation || "",
      client_id: emp.client_id || "",
      project_id: emp.project_id || "",
      work_location: emp.work_location || "",
      status: emp.status,
    });
    setDialogOpen(true);
  };

  const filtered = employees.filter(
    (e) =>
      e.name.toLowerCase().includes(search.toLowerCase()) ||
      e.role.toLowerCase().includes(search.toLowerCase()) ||
      (e.work_location || "").toLowerCase().includes(search.toLowerCase()) ||
      (e.userRole || "").toLowerCase().includes(search.toLowerCase())
  );

  const activeCount = employees.filter((e) => e.status === "active").length;
  const linkedCount = employees.filter((e) => e.hasAccount).length;

  const statusColor: Record<string, string> = {
    active: "bg-success/10 text-success",
    inactive: "bg-muted text-muted-foreground",
    on_leave: "bg-warning/10 text-warning",
  };

  return (
      <>
      <div className="space-y-4">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold tracking-tight">Employees</h1>
            <p className="text-muted-foreground text-sm">Manage your workforce and assignments — automatically linked with User Management</p>
          </div>
          <div className="flex gap-2">
            <Button size="sm" variant="outline" asChild>
              <a href="/users"><Users className="h-4 w-4 mr-1" /> User Management</a>
            </Button>
            <Button size="sm" onClick={() => { setForm(defaultForm); setEditingId(null); setDialogOpen(true); }}>
              <Plus className="h-4 w-4 mr-1" /> Add Employee
            </Button>
          </div>
        </div>

        {/* Stats */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
          <Card><CardContent className="p-4 flex items-center gap-3">
            <Users className="h-8 w-8 text-primary" />
            <div><p className="text-2xl font-bold">{employees.length}</p><p className="text-xs text-muted-foreground">Total</p></div>
          </CardContent></Card>
          <Card><CardContent className="p-4 flex items-center gap-3">
            <Briefcase className="h-8 w-8 text-success" />
            <div><p className="text-2xl font-bold">{activeCount}</p><p className="text-xs text-muted-foreground">Active</p></div>
          </CardContent></Card>
          <Card><CardContent className="p-4 flex items-center gap-3">
            <Link2 className="h-8 w-8 text-primary" />
            <div><p className="text-2xl font-bold">{linkedCount}</p><p className="text-xs text-muted-foreground">Linked Accounts</p></div>
          </CardContent></Card>
          <Card><CardContent className="p-4 flex items-center gap-3">
            <MapPin className="h-8 w-8 text-info" />
            <div><p className="text-2xl font-bold">{new Set(employees.map((e) => e.work_location).filter(Boolean)).size}</p><p className="text-xs text-muted-foreground">Locations</p></div>
          </CardContent></Card>
        </div>

        {/* Search */}
        <div className="relative max-w-sm">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input placeholder="Search employees..." className="pl-9" value={search} onChange={(e) => setSearch(e.target.value)} />
        </div>

        {/* Table / Cards */}
        {isLoading ? (
          <div className="text-center py-12 text-muted-foreground">Loading...</div>
        ) : filtered.length === 0 ? (
          <div className="text-center py-12 text-muted-foreground">No employees found</div>
        ) : isMobile ? (
          <div className="space-y-3">
            {filtered.map((emp) => (
              <Card key={emp.id}>
                <CardContent className="p-4 space-y-2">
                  <div className="flex items-center justify-between">
                    <div>
                      <div className="flex items-center gap-1.5">
                        <p className="font-semibold">{emp.name}</p>
                        {emp.hasAccount && (
                          <span title="Has linked user account">
                            {ROLE_ICON[emp.userRole || "employee"]}
                          </span>
                        )}
                      </div>
                      <p className="text-xs text-muted-foreground">
                        {emp.role}{emp.designation ? ` · ${emp.designation}` : ""}
                        {emp.hasAccount && (
                          <span className="ml-1">
                            · {emp.userRole?.toUpperCase()}
                            {emp.isApproved === false && " (Pending)"}
                          </span>
                        )}
                      </p>
                    </div>
                    <Badge className={cn("text-xs", statusColor[emp.status] || statusColor.inactive)}>{emp.status}</Badge>
                  </div>
                  {emp.phone && <p className="text-xs text-muted-foreground">📞 {emp.phone}</p>}
                  {emp.work_location && <p className="text-xs text-muted-foreground">📍 {emp.work_location}</p>}
                  {emp.clients?.name && <p className="text-xs text-muted-foreground">Client: {emp.clients.name}</p>}
                  {emp.projects?.title && <p className="text-xs text-muted-foreground">Project: {emp.projects.title}</p>}
                  <div className="flex gap-2 pt-1">
                    <Button size="sm" variant="outline" onClick={() => openEdit(emp)}><Pencil className="h-3 w-3 mr-1" /> Edit</Button>
                    <Button size="sm" variant="destructive" onClick={() => deleteMutation.mutate(emp.id)}><Trash2 className="h-3 w-3" /></Button>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        ) : (
          <Card>
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Name</TableHead>
                  <TableHead>Role / Designation</TableHead>
                  <TableHead>System Role</TableHead>
                  <TableHead>Phone</TableHead>
                  <TableHead>Location</TableHead>
                  <TableHead>Client</TableHead>
                  <TableHead>Project</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead className="text-right">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {filtered.map((emp) => (
                  <TableRow key={emp.id}>
                    <TableCell>
                      <div className="flex items-center gap-2">
                        <div className="font-medium">{emp.name}</div>
                        {emp.hasAccount && (
                          <Link2 className="h-3 w-3 text-muted-foreground" />
                        )}
                      </div>
                    </TableCell>
                    <TableCell>
                      <span>{emp.role}</span>
                      {emp.designation && <span className="text-muted-foreground text-xs ml-1">({emp.designation})</span>}
                    </TableCell>
                    <TableCell>
                      {emp.hasAccount ? (
                        <div className="flex items-center gap-1.5">
                          {ROLE_ICON[emp.userRole || "employee"]}
                          <span className="text-sm capitalize">{emp.userRole}</span>
                          {emp.isApproved === false ? (
                            <Badge variant="outline" className="ml-1 text-[10px] px-1 py-0 bg-yellow-50 text-yellow-700 border-yellow-200">
                              <Clock className="h-2.5 w-2.5 mr-0.5" />Pending
                            </Badge>
                          ) : (
                            <Badge variant="outline" className="ml-1 text-[10px] px-1 py-0 bg-green-50 text-green-700 border-green-200">
                              <CheckCircle className="h-2.5 w-2.5 mr-0.5" />Active
                            </Badge>
                          )}
                        </div>
                      ) : (
                        <span className="text-xs text-muted-foreground">No account</span>
                      )}
                    </TableCell>
                    <TableCell>{emp.phone || "—"}</TableCell>
                    <TableCell>{emp.work_location || "—"}</TableCell>
                    <TableCell>{emp.clients?.name || "—"}</TableCell>
                    <TableCell>{emp.projects?.title || "—"}</TableCell>
                    <TableCell><Badge className={cn("text-xs", statusColor[emp.status] || statusColor.inactive)}>{emp.status}</Badge></TableCell>
                    <TableCell className="text-right">
                      <Button size="icon" variant="ghost" onClick={() => openEdit(emp)}><Pencil className="h-4 w-4" /></Button>
                      <Button size="icon" variant="ghost" className="text-destructive" onClick={() => deleteMutation.mutate(emp.id)}><Trash2 className="h-4 w-4" /></Button>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </Card>
        )}
      </div>

      {/* Add/Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={(o) => { if (!o) closeDialog(); }}>
        <DialogContent className="sm:max-w-lg max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>{editingId ? "Edit Employee" : "Add Employee"}</DialogTitle>
          </DialogHeader>
          <div className="grid gap-3 py-2">
            <div className="grid grid-cols-2 gap-3">
              <div><Label>Name *</Label><Input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} /></div>
              <div><Label>Phone</Label><Input value={form.phone} onChange={(e) => setForm({ ...form, phone: e.target.value })} /></div>
            </div>
            <div><Label>Email</Label><Input type="email" value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })} /></div>
            <div className="grid grid-cols-2 gap-3">
              <div>
                <Label>Role</Label>
                <Select value={form.role} onValueChange={(v) => setForm({ ...form, role: v })}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="Technician">Technician</SelectItem>
                    <SelectItem value="Engineer">Engineer</SelectItem>
                    <SelectItem value="Manager">Manager</SelectItem>
                    <SelectItem value="Supervisor">Supervisor</SelectItem>
                    <SelectItem value="Team Lead">Team Lead</SelectItem>
                    <SelectItem value="Support Staff">Support Staff</SelectItem>
                    <SelectItem value="Helper">Helper</SelectItem>
                    <SelectItem value="Driver">Driver</SelectItem>
                    <SelectItem value="Other">Other</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div>
                <Label>Designation</Label>
                <Select value={form.designation || "_none"} onValueChange={(v) => setForm({ ...form, designation: v === "_none" ? "" : v })}>
                  <SelectTrigger><SelectValue placeholder="Select" /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="_none">None</SelectItem>
                    <SelectItem value="Technician">Technician</SelectItem>
                    <SelectItem value="Engineer">Engineer</SelectItem>
                    <SelectItem value="Manager">Manager</SelectItem>
                    <SelectItem value="Supervisor">Supervisor</SelectItem>
                    <SelectItem value="Team Lead">Team Lead</SelectItem>
                    <SelectItem value="Support Staff">Support Staff</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>
            <div><Label>Work Location</Label><Input placeholder="Site address or area" value={form.work_location} onChange={(e) => setForm({ ...form, work_location: e.target.value })} /></div>
            <div className="grid grid-cols-2 gap-3">
              <div>
                <Label>Assign to Client</Label>
                <Select value={form.client_id || "_none"} onValueChange={(v) => setForm({ ...form, client_id: v === "_none" ? "" : v })}>
                  <SelectTrigger><SelectValue placeholder="Select client" /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="_none">None</SelectItem>
                    {clients.map((c) => <SelectItem key={c.id} value={c.id}>{c.name}</SelectItem>)}
                  </SelectContent>
                </Select>
              </div>
              <div>
                <Label>Assign to Project</Label>
                <Select value={form.project_id || "_none"} onValueChange={(v) => setForm({ ...form, project_id: v === "_none" ? "" : v })}>
                  <SelectTrigger><SelectValue placeholder="Select project" /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="_none">None</SelectItem>
                    {projects.map((p) => <SelectItem key={p.id} value={p.id}>{p.title}</SelectItem>)}
                  </SelectContent>
                </Select>
              </div>
            </div>
            <div>
              <Label>Status</Label>
              <Select value={form.status} onValueChange={(v) => setForm({ ...form, status: v })}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="active">Active</SelectItem>
                  <SelectItem value="inactive">Inactive</SelectItem>
                  <SelectItem value="on_leave">On Leave</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={closeDialog}>Cancel</Button>
            <Button disabled={!form.name.trim() || saveMutation.isPending} onClick={() => saveMutation.mutate(form)}>
              {saveMutation.isPending ? "Saving..." : editingId ? "Update" : "Add"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
      </>
);
}

import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { StatCard } from "@/components/StatCard";
import { Users, FolderKanban, FileText, Package, DollarSign, ShoppingCart, TrendingUp, Clock, AlertCircle, CalendarDays, ArrowUpRight, ArrowDownRight, Wallet, UserPlus, ClipboardList, MessageCircle, Bot, Boxes, BarChart3, Wrench } from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { WelcomeBanner } from "@/components/dashboard/WelcomeBanner";
import { RevenueChart } from "@/components/dashboard/RevenueChart";
import { TopProductsChart } from "@/components/dashboard/TopProductsChart";
import { ActivityTimeline } from "@/components/dashboard/ActivityTimeline";
import { QuickActions } from "@/components/dashboard/QuickActions";
import { AIDashboardInsights } from "@/components/dashboard/AIDashboardInsights";

import { format } from "date-fns";
import { useNavigate } from "react-router-dom";
import { useUserRole } from "@/hooks/useUserRole";

export default function Dashboard() {
  const navigate = useNavigate();
  const { canAccessRevenue } = useUserRole();
  const { data: clients } = useQuery({ queryKey: ["clients"], queryFn: async () => (await supabase.from("clients").select("*")).data || [] });
  const { data: invoices } = useQuery({ queryKey: ["invoices"], queryFn: async () => (await supabase.from("invoices").select("*, clients(name)").order("created_at", { ascending: false })).data || [] });
  const { data: products } = useQuery({ queryKey: ["products"], queryFn: async () => (await supabase.from("products").select("*")).data || [] });
  const { data: orders } = useQuery({ queryKey: ["store-orders"], queryFn: async () => (await supabase.from("store_orders").select("*").order("created_at", { ascending: false })).data || [] });
  const { data: sales } = useQuery({ queryKey: ["sales"], queryFn: async () => (await supabase.from("sales").select("*, products(name), clients(name)").order("sale_date", { ascending: false })).data || [] });
  const { data: quotations } = useQuery({ queryKey: ["quotations"], queryFn: async () => (await supabase.from("quotations").select("*, clients(name)").order("created_at", { ascending: false })).data || [] });
  const { data: expenses } = useQuery({ queryKey: ["expenses-dashboard"], queryFn: async () => (await supabase.from("expenses").select("*")).data || [] });
  const { data: purchases } = useQuery({ queryKey: ["purchases-dashboard"], queryFn: async () => (await supabase.from("purchases").select("*")).data || [] });
  const { data: leads } = useQuery({ queryKey: ["leads-dashboard"], queryFn: async () => (await supabase.from("leads").select("*")).data || [] });
  const { data: serviceRequests } = useQuery({ queryKey: ["service-requests-dashboard"], queryFn: async () => (await supabase.from("service_requests").select("*")).data || [] });
  const { data: aiChats } = useQuery({ queryKey: ["ai-chats-dashboard"], queryFn: async () => (await supabase.from("ai_chat_sessions").select("*").order("updated_at", { ascending: false }).limit(5)).data || [] });
  const { data: storeMessages } = useQuery({ queryKey: ["store-messages-dashboard"], queryFn: async () => (await supabase.from("store_messages").select("*").eq("is_read", false)).data || [] });
  const { data: activeServicing } = useQuery({ queryKey: ["active-servicing-dashboard"], queryFn: async () => (await supabase.from("servicing").select("*").eq("status", "pending").order("service_date", { ascending: true })).data || [] });

  const totalRevenue = invoices?.filter(i => i.status === "paid").reduce((sum, i) => sum + Number(i.total), 0) || 0;
  const pendingOrders = orders?.filter(o => o.status === "pending").length || 0;
  const lowStockProducts = products?.filter(p => p.stock_quantity > 0 && p.stock_quantity <= 5).length || 0;
  const outOfStockProducts = products?.filter(p => p.stock_quantity === 0).length || 0;
  const storeOrderRevenue = orders?.filter(o => o.status === "completed").reduce((sum, o) => sum + Number(o.item_price) * o.quantity, 0) || 0;

  const today = new Date();
  const todayStr = format(today, "yyyy-MM-dd");

  const todaySalesRevenue = sales?.filter(s => s.sale_date === todayStr).reduce((sum, s) => sum + Number(s.total), 0) || 0;
  const todayPaidInvoices = invoices?.filter(i => i.status === "paid" && format(new Date(i.issue_date), "yyyy-MM-dd") === todayStr).reduce((sum, i) => sum + Number(i.total), 0) || 0;
  const todayIncome = todaySalesRevenue + todayPaidInvoices;
  const todayExpenses = expenses?.filter(e => e.expense_date === todayStr).reduce((sum, e) => sum + Number(e.amount), 0) || 0;
  const todayPurchases = purchases?.filter(p => p.purchase_date === todayStr).reduce((sum, p) => sum + Number(p.total_cost), 0) || 0;
  const todaySpending = todayExpenses + todayPurchases;
  const todayProfit = todayIncome - todaySpending;

