          <StatCard title="Pending Orders" value={pendingOrders} icon={ShoppingCart} trend={pendingOrders > 0 ? "Needs attention" : "All clear"} trendUp={pendingOrders === 0} />
          <StatCard title="Products" value={products?.length || 0} icon={Package} />
