export default function Marketing() {
  const [search, setSearch] = useState("");
  const [selectedClients, setSelectedClients] = useState<string[]>([]);
  const [selectedTemplate, setSelectedTemplate] = useState(templates[0]);
  const [customMessage, setCustomMessage] = useState("");
  const [selectAll, setSelectAll] = useState(false);

  const { data: clients = [] } = useQuery({
    queryKey: ["marketing-clients"],
    queryFn: async () => {
      const { data, error } = await supabase.from("clients").select("id, name, phone, email, company").order("name");
      if (error) throw error;
      return data.filter((c: any) => c.phone);
    },
  });

  const { data: companySettings } = useQuery({
    queryKey: ["company-settings-marketing"],
    queryFn: async () => {
      const { data } = await supabase.from("company_settings").select("phone").limit(1).single();
      return data;
    },
  });

  const filteredClients = clients.filter((c: any) =>
    c.name.toLowerCase().includes(search.toLowerCase()) ||
    c.phone?.includes(search) ||
    c.company?.toLowerCase().includes(search.toLowerCase())
  );

  const toggleSelectAll = () => {
    if (selectAll) {
      setSelectedClients([]);
    } else {
      setSelectedClients(filteredClients.map((c: any) => c.id));
    }
    setSelectAll(!selectAll);
  };

  const toggleClient = (id: string) => {
    setSelectedClients(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const sendWhatsAppCampaign = () => {
    if (selectedClients.length === 0) {
      toast.error("Please select at least one client");
      return;
    }
    const companyPhone = companySettings?.phone?.split(",")[0]?.trim() || "01919-060590";
    const messageTemplate = selectedTemplate.id === "custom" ? customMessage : selectedTemplate.message;
    if (!messageTemplate) {
      toast.error("Please write a message");
      return;
    }
    const selectedClientData = clients.filter((c: any) => selectedClients.includes(c.id));
    selectedClientData.forEach((client: any, index: number) => {
      const personalizedMessage = messageTemplate.replace(/{name}/g, client.name).replace(/{phone}/g, companyPhone);
      const phone = client.phone.replace(/[^0-9]/g, "");
      const whatsappNumber = phone.startsWith("0") ? `88${phone}` : phone;
      const url = `https://wa.me/${whatsappNumber}?text=${encodeURIComponent(personalizedMessage)}`;
      setTimeout(() => window.open(url, "_blank"), index * 1500);
    });
    toast.success(`${selectedClientData.length} WhatsApp messages initiated`);
  };

  return (
      <div className="space-y-4">
        <div>
          <h1 className="text-xl font-bold">Marketing Hub</h1>
          <p className="text-sm text-muted-foreground">AI-powered marketing across all platforms</p>
        </div>

        <Tabs defaultValue="ai-content" className="w-full">
          <TabsList className="grid w-full grid-cols-7 h-9">
            <TabsTrigger value="ai-content" className="text-xs gap-1"><Sparkles className="h-3.5 w-3.5 hidden sm:block" /> AI Content</TabsTrigger>
            <TabsTrigger value="designer" className="text-xs gap-1"><Palette className="h-3.5 w-3.5 hidden sm:block" /> Designer</TabsTrigger>
            <TabsTrigger value="saved" className="text-xs gap-1"><FileText className="h-3.5 w-3.5 hidden sm:block" /> Saved</TabsTrigger>
            <TabsTrigger value="whatsapp" className="text-xs gap-1"><MessageCircle className="h-3.5 w-3.5 hidden sm:block" /> WhatsApp</TabsTrigger>
            <TabsTrigger value="seo" className="text-xs gap-1"><Globe className="h-3.5 w-3.5 hidden sm:block" /> SEO</TabsTrigger>
            <TabsTrigger value="campaigns" className="text-xs gap-1"><Target className="h-3.5 w-3.5 hidden sm:block" /> Campaigns</TabsTrigger>
            <TabsTrigger value="settings" className="text-xs gap-1"><Settings className="h-3.5 w-3.5 hidden sm:block" /> Settings</TabsTrigger>
          </TabsList>

          <TabsContent value="ai-content" className="mt-4">
            <AIContentGenerator />
          </TabsContent>

          <TabsContent value="designer" className="mt-4">
            <PostDesigner />
          </TabsContent>

          <TabsContent value="saved" className="mt-4">
            <SavedPosts />
          </TabsContent>

          <TabsContent value="whatsapp" className="mt-4">
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
              <div className="lg:col-span-1 space-y-3">
                <Card>
                  <CardHeader className="pb-2">
                    <CardTitle className="text-sm flex items-center gap-2"><MessageCircle className="h-4 w-4" /> Message Template</CardTitle>
                  </CardHeader>
                  <CardContent className="space-y-2">
                    {templates.map(tmpl => (
                      <button key={tmpl.id} onClick={() => setSelectedTemplate(tmpl)}
                        className={`w-full text-left p-2.5 rounded-lg border text-xs transition-all ${selectedTemplate.id === tmpl.id ? "border-primary bg-primary/5 font-medium" : "border-border hover:bg-muted/50"}`}>
                        {tmpl.title}
                      </button>
                    ))}
                  </CardContent>
                </Card>
                <Card>
                  <CardHeader className="pb-2"><CardTitle className="text-sm">Message Preview</CardTitle></CardHeader>
                  <CardContent>
                    {selectedTemplate.id === "custom" ? (
                      <textarea value={customMessage} onChange={e => setCustomMessage(e.target.value)}
                        placeholder="Write your custom message here... Use {name} for client name and {phone} for company phone"
                        className="w-full min-h-[200px] rounded-md border px-3 py-2 text-xs bg-background" />
                    ) : (
                      <div className="bg-green-50 dark:bg-green-900/10 rounded-lg p-3 text-xs whitespace-pre-wrap border border-green-200 dark:border-green-800">
                        {selectedTemplate.message.replace(/{name}/g, "Customer Name").replace(/{phone}/g, "01919-060590")}
                      </div>
                    )}
                  </CardContent>
                </Card>
              </div>
              <div className="lg:col-span-2 space-y-3">
                <Card>
                  <CardHeader className="pb-2">
                    <div className="flex items-center justify-between">
                      <CardTitle className="text-sm flex items-center gap-2">
                        <Users className="h-4 w-4" /> Select Clients
                        <Badge variant="secondary" className="text-[10px]">{selectedClients.length} selected</Badge>
                      </CardTitle>
                      <Button variant="outline" size="sm" className="text-xs h-7" onClick={toggleSelectAll}>
                        {selectAll ? "Deselect All" : "Select All"}
                      </Button>
                    </div>
                  </CardHeader>
                  <CardContent className="space-y-2">
                    <div className="relative">
                      <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                      <Input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search clients..." className="pl-8" />
                    </div>
                    <div className="max-h-[400px] overflow-y-auto space-y-1">
                      {filteredClients.length === 0 ? (
                        <p className="text-center text-sm text-muted-foreground py-4">No clients with phone numbers found</p>
                      ) : (
                        filteredClients.map((client: any) => (
                          <label key={client.id}
                            className={`flex items-center gap-3 p-2.5 rounded-lg border cursor-pointer transition-all text-sm ${selectedClients.includes(client.id) ? "border-primary bg-primary/5" : "border-transparent hover:bg-muted/50"}`}>
                            <Checkbox checked={selectedClients.includes(client.id)} onCheckedChange={() => toggleClient(client.id)} />
                            <div className="flex-1 min-w-0">
                              <p className="font-medium text-xs">{client.name}</p>
                              <div className="flex items-center gap-3 text-[10px] text-muted-foreground mt-0.5">
                                {client.phone && <span className="flex items-center gap-0.5"><Phone className="h-2.5 w-2.5" /> {client.phone}</span>}
                                {client.company && <span>{client.company}</span>}
                              </div>
                            </div>
                          </label>
                        ))
                      )}
                    </div>
                  </CardContent>
                </Card>
                <Button onClick={sendWhatsAppCampaign} className="w-full gap-2 h-11" disabled={selectedClients.length === 0}>
                  <Send className="h-4 w-4" /> Send WhatsApp to {selectedClients.length} Client{selectedClients.length !== 1 ? "s" : ""}
                </Button>
                <p className="text-[10px] text-muted-foreground text-center">Each client will open in a new WhatsApp tab with personalized message</p>
              </div>
            </div>
          </TabsContent>

          <TabsContent value="seo" className="mt-4">
            <SEODashboard />
          </TabsContent>

          <TabsContent value="campaigns" className="mt-4">
            <CampaignManager />
          </TabsContent>

          <TabsContent value="settings" className="mt-4">
            <SocialMediaSettings />
          </TabsContent>
        </Tabs>
      </div>
);
}

import { useState, useEffect } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { ShoppingCart, MessageCircle, Trash2, Eye, EyeOff, MessageSquare, FileText, FilePlus2 } from "lucide-react";
import { openWhatsApp, orderStatusMessage } from "@/lib/whatsapp";
import { useToast } from "@/hooks/use-toast";
import { ConfirmDeleteDialog } from "@/components/ConfirmDeleteDialog";
import { GenerateInvoiceDialog } from "@/components/GenerateInvoiceDialog";

export default function Orders() {
  const queryClient = useQueryClient();
  const { toast } = useToast();
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();
  const tabParam = searchParams.get("tab")?.toLowerCase() || "orders";
  const [activeTab, setActiveTab] = useState(tabParam);

  useEffect(() => {
    setActiveTab(tabParam);
  }, [tabParam]);

  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);
  const [invoiceOrder, setInvoiceOrder] = useState<any | null>(null);

  const { data: orders } = useQuery({
    queryKey: ["store-orders"],
    queryFn: async () => {
      const { data } = await supabase
        .from("store_orders")
        .select("*")
        .order("created_at", { ascending: false });
      return data || [];
    },
  });

  const { data: messages } = useQuery({
    queryKey: ["store-messages"],
    queryFn: async () => {
      const { data } = await supabase
        .from("store_messages")
        .select("*")
        .order("created_at", { ascending: false });
      return data || [];
    },
  });

  const updateOrderStatus = useMutation({
    mutationFn: async ({ id, status }: { id: string; status: string }) => {
      const { error } = await supabase.from("store_orders").update({ status }).eq("id", id);
      if (error) throw error;

      // When order is completed, auto-create a sale and decrement stock
      if (status === "completed") {
        const order = orders?.find(o => o.id === id);
        if (order) {
          // Create sale record
          await supabase.from("sales").insert({
            product_id: order.product_id || null,
            quantity: order.quantity,
            unit_price: Number(order.item_price),
            total: Number(order.item_price) * order.quantity,
            payment_status: "paid",
            notes: `Store Order - ${order.customer_name} (${order.customer_phone || ""})`,
          });

          // Decrement stock if product exists
          if (order.product_id) {
            const { data: product } = await supabase.from("products").select("stock_quantity").eq("id", order.product_id).single();
            if (product) {
              await supabase.from("products").update({ stock_quantity: Math.max(0, product.stock_quantity - order.quantity) }).eq("id", order.product_id);
              await supabase.from("inventory_movements").insert({
                product_id: order.product_id,
                movement_type: "out",
                quantity: order.quantity,
                reference_type: "sale",
                notes: `Store Order - ${order.customer_name}`,
              });
            }
          }
        }
      }
      // Auto-open WhatsApp with status message
      const order = orders?.find(o => o.id === id);
      if (order?.customer_phone) {
        openWhatsApp(order.customer_phone, orderStatusMessage(order, status));
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["store-orders"] });
      queryClient.invalidateQueries({ queryKey: ["sales"] });
      queryClient.invalidateQueries({ queryKey: ["products"] });
      toast({ title: "Order status updated" });
    },
  });

  const deleteOrder = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("store_orders").delete().eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["store-orders"] });
      toast({ title: "Order deleted" });
    },
  });

  const toggleMessageRead = useMutation({
    mutationFn: async ({ id, is_read }: { id: string; is_read: boolean }) => {
      const { error } = await supabase.from("store_messages").update({ is_read }).eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ["store-messages"] }),
  });

  const deleteMessage = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("store_messages").delete().eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["store-messages"] });
      toast({ title: "Message deleted" });
    },
  });

  const unreadCount = messages?.filter(m => !m.is_read).length || 0;
  const pendingOrders = orders?.filter(o => o.status === "pending").length || 0;

  const statusColor: Record<string, string> = {
    pending: "bg-warning/10 text-warning",
    confirmed: "bg-info/10 text-info",
    completed: "bg-success/10 text-success",
    cancelled: "bg-destructive/10 text-destructive",
  };

  return (
    <>
      <div className="space-y-6">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Orders & Messages</h1>
          <p className="text-muted-foreground text-sm">
            Manage store orders and customer inquiries
          </p>
        </div>

        <Tabs value={activeTab} onValueChange={(val) => { setActiveTab(val); setSearchParams({ tab: val }, { replace: true }); }}>
          <TabsList>
            <TabsTrigger value="orders" className="gap-2">
              <ShoppingCart className="h-4 w-4" />
              Orders {pendingOrders > 0 && <Badge variant="destructive" className="text-[10px] px-1.5 py-0">{pendingOrders}</Badge>}
            </TabsTrigger>
            <TabsTrigger value="messages" className="gap-2">
              <MessageCircle className="h-4 w-4" />
              Messages {unreadCount > 0 && <Badge variant="destructive" className="text-[10px] px-1.5 py-0">{unreadCount}</Badge>}
            </TabsTrigger>
          </TabsList>

          <TabsContent value="orders">
            <Card className="glass-card">
              <CardContent className="p-0">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Customer</TableHead>
                      <TableHead>Item</TableHead>
                      <TableHead>Price</TableHead>
                      <TableHead>Qty</TableHead>
                      <TableHead>Status</TableHead>
                      <TableHead>Date</TableHead>
                      <TableHead className="w-24">Actions</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {orders?.map((order) => (
                      <TableRow key={order.id}>
                        <TableCell>
                          <div>
                            <p className="font-medium text-sm">{order.customer_name}</p>
                            <p className="text-xs text-muted-foreground">{order.customer_phone || order.customer_email || "—"}</p>
                          </div>
                        </TableCell>
                        <TableCell className="font-medium text-sm">{order.item_name}</TableCell>
                        <TableCell>৳{Number(order.item_price).toLocaleString()}</TableCell>
                        <TableCell>{order.quantity}</TableCell>
                        <TableCell>
                          <Select value={order.status} onValueChange={(v) => updateOrderStatus.mutate({ id: order.id, status: v })}>
                            <SelectTrigger className="h-7 w-28">
                              <Badge variant="outline" className={`text-[10px] ${statusColor[order.status] || ""}`}>
                                {order.status}
                              </Badge>
                            </SelectTrigger>
                            <SelectContent>
                              <SelectItem value="pending">Pending</SelectItem>
                              <SelectItem value="confirmed">Confirmed</SelectItem>
                              <SelectItem value="completed">Completed</SelectItem>
                              <SelectItem value="cancelled">Cancelled</SelectItem>
                            </SelectContent>
                          </Select>
                        </TableCell>
                        <TableCell className="text-xs text-muted-foreground">
                          {new Date(order.created_at).toLocaleDateString()}
                        </TableCell>
                        <TableCell>
                          <div className="flex gap-1">
                            {order.invoice_id ? (
                              <Button
                                variant="ghost"
                                size="icon"
                                onClick={() => navigate("/invoices")}
                                title="View Invoice"
                              >
                                <FileText className="h-4 w-4 text-primary" />
                              </Button>
                            ) : (
                              <Button
                                variant="ghost"
                                size="icon"
                                onClick={() => setInvoiceOrder(order)}
                                title="Generate Invoice"
                              >
                                <FilePlus2 className="h-4 w-4 text-info" />
                              </Button>
                            )}
                            {order.customer_phone && (
                              <Button variant="ghost" size="icon" onClick={() => openWhatsApp(order.customer_phone!, orderStatusMessage(order, order.status))} title="WhatsApp">
                                <MessageSquare className="h-4 w-4 text-green-600" />
                              </Button>
                            )}
                            <Button variant="ghost" size="icon" onClick={() => setDeleteConfirmId(order.id)}>
                              <Trash2 className="h-4 w-4 text-destructive" />
                            </Button>
                          </div>
                        </TableCell>
                      </TableRow>
                    ))}
                    {(!orders || orders.length === 0) && (
                      <TableRow>
                        <TableCell colSpan={7} className="text-center text-muted-foreground py-8">No orders yet</TableCell>
                      </TableRow>
                    )}
                  </TableBody>
                </Table>
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="messages">
            <Card className="glass-card">
              <CardContent className="p-0">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Customer</TableHead>
                      <TableHead>Contact</TableHead>
                      <TableHead>Message</TableHead>
                      <TableHead>Date</TableHead>
                      <TableHead className="w-24">Actions</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {messages?.map((msg) => (
                      <TableRow key={msg.id} className={!msg.is_read ? "bg-primary/5" : ""}>
                        <TableCell className="font-medium text-sm">{msg.customer_name}</TableCell>
                        <TableCell className="text-xs text-muted-foreground">
                          {msg.customer_phone || msg.customer_email || "—"}
                        </TableCell>
                        <TableCell className="max-w-xs">
                          <p className="text-sm line-clamp-2">{msg.message}</p>
                        </TableCell>
                        <TableCell className="text-xs text-muted-foreground">
                          {new Date(msg.created_at).toLocaleDateString()}
                        </TableCell>
                        <TableCell>
                          <div className="flex gap-1">
                            <Button
                              variant="ghost"
                              size="icon"
                              onClick={() => toggleMessageRead.mutate({ id: msg.id, is_read: !msg.is_read })}
                              title={msg.is_read ? "Mark unread" : "Mark read"}
                            >
                              {msg.is_read ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                            </Button>
                            <Button variant="ghost" size="icon" onClick={() => deleteMessage.mutate(msg.id)}>
                              <Trash2 className="h-4 w-4 text-destructive" />
                            </Button>
                          </div>
                        </TableCell>
                      </TableRow>
                    ))}
                    {(!messages || messages.length === 0) && (
                      <TableRow>
                        <TableCell colSpan={5} className="text-center text-muted-foreground py-8">No messages yet</TableCell>
                      </TableRow>
                    )}
                  </TableBody>
                </Table>
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>
      </div>

      <ConfirmDeleteDialog
        open={!!deleteConfirmId}
        onOpenChange={(open) => !open && setDeleteConfirmId(null)}
        onConfirm={() => {
          if (deleteConfirmId) {
            deleteOrder.mutate(deleteConfirmId);
            setDeleteConfirmId(null);
          }
        }}
        title="স্থায়ীভাবে ডিলিট করুন"
      />

      <GenerateInvoiceDialog
        order={invoiceOrder}
        open={!!invoiceOrder}
        onOpenChange={(open) => !open && setInvoiceOrder(null)}
      />
    </>
);
}

import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Switch } from "@/components/ui/switch";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Plus, Pencil, Trash2, Image, FolderKanban } from "lucide-react";
import { toast } from "sonner";
import { ConfirmDeleteDialog } from "@/components/ConfirmDeleteDialog";

type PortfolioProject = {
  id: string;
  title: string;
  description: string | null;
  category: string;
  image_url: string | null;
  client_name: string | null;
  location: string | null;
  completed_date: string | null;
  is_featured: boolean;
  created_at: string;
};

const categories = ["CCTV", "Networking", "IT Support", "Computer", "Server", "Access Control", "Other"];

export default function Portfolio() {
  const queryClient = useQueryClient();
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editing, setEditing] = useState<PortfolioProject | null>(null);
  const [form, setForm] = useState({ title: "", description: "", category: "CCTV", client_name: "", location: "", completed_date: "", is_featured: false });
  const [uploading, setUploading] = useState(false);
  const [imageUrl, setImageUrl] = useState<string | null>(null);
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);

  const { data: projects = [], isLoading } = useQuery({
    queryKey: ["portfolio_projects"],
    queryFn: async () => {
      const { data, error } = await supabase.from("portfolio_projects").select("*").order("completed_date", { ascending: false });
      if (error) throw error;
      return data as PortfolioProject[];
    },
  });

  const saveMutation = useMutation({
    mutationFn: async (values: any) => {
      if (editing) {
        const { error } = await supabase.from("portfolio_projects").update(values).eq("id", editing.id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from("portfolio_projects").insert(values);
        if (error) throw error;
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["portfolio_projects"] });
      toast.success(editing ? "Project updated" : "Project added");
      closeDialog();
    },
    onError: (e: any) => toast.error(e.message),
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("portfolio_projects").delete().eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["portfolio_projects"] });
      toast.success("Project deleted");
    },
    onError: (e: any) => toast.error(e.message),
  });

  const openCreate = () => {
    setEditing(null);
    setForm({ title: "", description: "", category: "CCTV", client_name: "", location: "", completed_date: "", is_featured: false });
    setImageUrl(null);
    setDialogOpen(true);
  };

  const openEdit = (p: PortfolioProject) => {
    setEditing(p);
    setForm({ title: p.title, description: p.description || "", category: p.category, client_name: p.client_name || "", location: p.location || "", completed_date: p.completed_date || "", is_featured: p.is_featured });
    setImageUrl(p.image_url);
    setDialogOpen(true);
  };

  const closeDialog = () => { setDialogOpen(false); setEditing(null); };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setUploading(true);
    const ext = file.name.split(".").pop();
    const path = `${Date.now()}.${ext}`;
    const { error } = await supabase.storage.from("portfolio-images").upload(path, file);
    if (error) { toast.error("Upload failed"); setUploading(false); return; }
    const { data: urlData } = supabase.storage.from("portfolio-images").getPublicUrl(path);
    setImageUrl(urlData.publicUrl);
    setUploading(false);
  };

  const handleSave = () => {
    if (!form.title.trim()) { toast.error("Title is required"); return; }
    saveMutation.mutate({
      title: form.title, description: form.description || null, category: form.category,
      image_url: imageUrl, client_name: form.client_name || null, location: form.location || null,
      completed_date: form.completed_date || null, is_featured: form.is_featured,
    });
  };

  return (
    <>
      <div className="space-y-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold flex items-center gap-2"><FolderKanban className="h-6 w-6 text-primary" /> Portfolio</h1>
            <p className="text-muted-foreground text-sm">Manage your completed project showcase</p>
          </div>
          <Button onClick={openCreate}><Plus className="h-4 w-4 mr-2" /> Add Project</Button>
        </div>

        <Card>
          <CardHeader><CardTitle className="text-base">All Projects ({projects.length})</CardTitle></CardHeader>
          <CardContent>
            {isLoading ? (
              <div className="flex justify-center py-10"><div className="animate-spin h-8 w-8 border-2 border-primary border-t-transparent rounded-full" /></div>
            ) : projects.length === 0 ? (
              <p className="text-center text-muted-foreground py-10">No portfolio projects yet. Add your first completed project!</p>
            ) : (
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Image</TableHead>
                    <TableHead>Title</TableHead>
                    <TableHead>Category</TableHead>
                    <TableHead>Location</TableHead>
                    <TableHead>Featured</TableHead>
                    <TableHead className="text-right">Actions</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {projects.map(p => (
                    <TableRow key={p.id}>
                      <TableCell>
                        {p.image_url ? <img src={p.image_url} alt={p.title} className="h-10 w-14 rounded object-cover" /> : <div className="h-10 w-14 rounded bg-muted flex items-center justify-center"><Image className="h-4 w-4 text-muted-foreground" /></div>}
                      </TableCell>
                      <TableCell className="font-medium">{p.title}</TableCell>
                      <TableCell><Badge variant="secondary">{p.category}</Badge></TableCell>
                      <TableCell className="text-sm text-muted-foreground">{p.location || "—"}</TableCell>
                      <TableCell>{p.is_featured ? <Badge className="bg-primary/10 text-primary">Featured</Badge> : "—"}</TableCell>
                      <TableCell className="text-right space-x-2">
                        <Button variant="ghost" size="icon" onClick={() => openEdit(p)}><Pencil className="h-4 w-4" /></Button>
                        <Button variant="ghost" size="icon" className="text-destructive" onClick={() => setDeleteConfirmId(p.id)}><Trash2 className="h-4 w-4" /></Button>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            )}
          </CardContent>
        </Card>
      </div>

      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-lg">
          <DialogHeader><DialogTitle>{editing ? "Edit Project" : "Add Project"}</DialogTitle></DialogHeader>
          <div className="space-y-4">
            <div><Label>Title *</Label><Input value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} placeholder="e.g. 32-Camera CCTV Installation" /></div>
            <div><Label>Description</Label><Textarea value={form.description} onChange={e => setForm({ ...form, description: e.target.value })} placeholder="Brief description of the project" rows={3} /></div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <Label>Category</Label>
                <Select value={form.category} onValueChange={v => setForm({ ...form, category: v })}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>{categories.map(c => <SelectItem key={c} value={c}>{c}</SelectItem>)}</SelectContent>
                </Select>
              </div>
              <div><Label>Completed Date</Label><Input type="date" value={form.completed_date} onChange={e => setForm({ ...form, completed_date: e.target.value })} /></div>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div><Label>Client Name</Label><Input value={form.client_name} onChange={e => setForm({ ...form, client_name: e.target.value })} placeholder="Optional" /></div>
              <div><Label>Location</Label><Input value={form.location} onChange={e => setForm({ ...form, location: e.target.value })} placeholder="e.g. Dhaka" /></div>
            </div>
            <div>
              <Label>Project Image</Label>
              <Input type="file" accept="image/*" onChange={handleImageUpload} disabled={uploading} />
              {imageUrl && <img src={imageUrl} alt="Preview" className="mt-2 h-24 rounded-lg object-cover" />}
            </div>
            <div className="flex items-center gap-3">
              <Switch checked={form.is_featured} onCheckedChange={v => setForm({ ...form, is_featured: v })} />
              <Label>Featured Project</Label>
            </div>
            <Button className="w-full" onClick={handleSave} disabled={saveMutation.isPending}>{saveMutation.isPending ? "Saving..." : editing ? "Update Project" : "Add Project"}</Button>
          </div>
        </DialogContent>
      </Dialog>

      <ConfirmDeleteDialog
        open={!!deleteConfirmId}
        onOpenChange={(open) => !open && setDeleteConfirmId(null)}
        onConfirm={() => {
          if (deleteConfirmId) {
            deleteMutation.mutate(deleteConfirmId);
            setDeleteConfirmId(null);
          }
        }}
        title="স্থায়ীভাবে ডিলিট করুন"
      />
    </>
  );
}

import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { toast } from "sonner";
import { supabase } from "@/integrations/supabase/client";
import {
  Loader2, PackagePlus, Image as ImageIcon, Upload, Percent,
  Eye, EyeOff, Save, ArrowLeft, Link as LinkIcon, Wand2,
  Trash2, Sparkles, CheckCircle2, AlertTriangle, Layers, Plus,
  ExternalLink, Phone, Search, X, ChevronDown, ChevronUp
} from "lucide-react";
import { useQueryClient } from "@tanstack/react-query";
import { ProductFinderKeywordTab } from "@/components/product-finder/KeywordSearchTab";
import { ProductFinderManualTab } from "@/components/product-finder/ManualEntryTab";


const CATEGORIES = [
  "CCTV", "DVR/NVR", "Monitor", "Laptop", "Computer", "Networking",
  "Accessories", "Printer", "Keyboard/Mouse", "Server", "Mobile",
  "Attendance Device", "Smart Home", "Audio/Video", "Storage", "Software", "Other"
];

const BRANDS = ["Dahua", "Hikvision", "TP-Link", "Uniview", "ZKTeco", "Tenda", "Ruijie", "Other"];

interface ScrapedProduct {
  id: string;
  name: string;
  category: string;
  brand: string;
  description: string;
  price: string;
  cash_discount_price: string;
  discount_percentage: string;
  image_url: string;
  images: string[];
  show_in_store: boolean;
  call_for_price: boolean;
  sku: string;
  stock_quantity: string;
  sourceUrl: string;
}

interface ScrapeProgress {
  url: string;
  status: "pending" | "scraping" | "success" | "failed";
  error?: string;
  productName?: string;
}

export default function ProductFinder() {
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const [activeTab, setActiveTab] = useState<"batch" | "keyword" | "manual">("batch");

  // Batch states
  const [batchUrlsText, setBatchUrlsText] = useState("");
  const [progressList, setProgressList] = useState<ScrapeProgress[]>([]);
  const [scrapedProducts, setScrapedProducts] = useState<ScrapedProduct[]>([]);
  const [bulkLoading, setBulkLoading] = useState(false);
  const [isFetchingBatch, setIsFetchingBatch] = useState(false);

  // Keyword search states
  const [keywordInput, setKeywordInput] = useState("");
  const [isFetchingKeyword, setIsFetchingKeyword] = useState(false);

  // Bulk card assignment utilities
  const [bulkCategory, setBulkCategory] = useState("");
  const [bulkBrand, setBulkBrand] = useState("");

  // Manual States
  const [manualLoading, setManualLoading] = useState(false);
  const [manualForm, setManualForm] = useState({
    name: "", category: "CCTV", brand: "Other", description: "", price: "", stock_quantity: "10", sku: "",
    cash_discount_price: "", discount_percentage: "0", show_in_store: true, call_for_price: false,
    image_url: "",
  });
  const [manualImageFiles, setManualImageFiles] = useState<File[]>([]);
  const [manualImagePreviews, setManualImagePreviews] = useState<string[]>([]);
  const [manualPrimaryIndex, setManualPrimaryIndex] = useState<number>(0);

  // ---------------------------------------------------------
  // Helper: scrape a single URL or keyword via Edge Function
  // ---------------------------------------------------------
  const scrapeOne = async (body: { url?: string; keyword?: string }): Promise<ScrapedProduct[]> => {
    const response = await fetch("/api/scrape", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body)
    });

    if (!response.ok) {
      throw new Error(`API error: ${response.statusText}`);
    }
    
    const data = await response.json();

    let responseData = data;
    if (typeof data === "string") {
      try { responseData = JSON.parse(data); } catch (_) {}
    }

    // API-level error returned in body
    if (responseData?.error) {
      throw new Error(responseData.error);
    }

    const products = responseData?.products;
    if (!products || !Array.isArray(products) || products.length === 0) {
      throw new Error("কোনো প্রোডাক্ট ডেটা পাওয়া যায়নি");
    }

    return products.map((extracted: any, subIdx: number) => {
      const regularPrice = extracted.price ? extracted.price.toString() : "0";
      const discountPct = extracted.discount_percentage ? extracted.discount_percentage.toString() : "0";
      let cashPrice = "";

      if (Number(regularPrice) > 0 && Number(discountPct) > 0) {
        cashPrice = Math.round(Number(regularPrice) * (1 - Number(discountPct) / 100)).toString();
      }

      let productImages: string[] = [];
      if (Array.isArray(extracted.images) && extracted.images.length > 0) {
        productImages = extracted.images.filter((img: any) => typeof img === "string" && img.trim() !== "");
      }
      if (extracted.image_url && !productImages.includes(extracted.image_url)) {
        productImages.unshift(extracted.image_url);
      }

      return {
        id: `scraped_${Date.now()}_${subIdx}_${Math.random().toString(36).substring(2, 9)}`,
        name: extracted.name || "অজ্ঞাত প্রোডাক্ট",
        category: CATEGORIES.includes(extracted.category) ? extracted.category : "CCTV",
        brand: BRANDS.includes(extracted.brand) ? extracted.brand : "Other",
        description: extracted.description || "",
        price: regularPrice,
        cash_discount_price: cashPrice,
        discount_percentage: discountPct,
        image_url: productImages[0] || extracted.image_url || "",
        images: productImages,
        show_in_store: true,
        call_for_price: false,
        sku: "",
        stock_quantity: "10",
        sourceUrl: body.url || `keyword: ${body.keyword}`,
      };
    });
  };

  // ---------------------------------------------------------
  // Batch (URL) Scraping — Sequential to avoid timeouts
  // ---------------------------------------------------------
  const handleBatchScrape = async () => {
    const urls = batchUrlsText
      .split("\n")
      .map(u => u.trim())
      .filter(u => u.startsWith("http://") || u.startsWith("https://"));

    if (urls.length === 0) {
      toast.error("অনুগ্রহ করে অন্তত একটি সঠিক URL দিন (http:// বা https:// দিয়ে শুরু)");
      return;
    }

    setIsFetchingBatch(true);
    setScrapedProducts([]);
    setProgressList(urls.map(url => ({ url, status: "pending" as const })));

    // Sequential scraping — avoids parallel timeout issues
    for (let idx = 0; idx < urls.length; idx++) {
      const url = urls[idx];
      setProgressList(prev => prev.map((item, i) => i === idx ? { ...item, status: "scraping" } : item));

      try {
        const newProducts = await scrapeOne({ url });
        setScrapedProducts(prev => [...prev, ...newProducts]);
        setProgressList(prev => prev.map((item, i) => i === idx ? {
          ...item,
          status: "success",
          productName: `${newProducts.length} টি প্রোডাক্ট পাওয়া গেছে`
        } : item));
      } catch (err: any) {
        console.error(`Scrape failed for ${url}:`, err);
        setProgressList(prev => prev.map((item, i) => i === idx ? {
          ...item,
          status: "failed",
          error: err.message || "সংযোগে ত্রুটি ঘটেছে"
        } : item));
      }
    }

    setIsFetchingBatch(false);
    toast.success("সকল URL প্রসেসিং সম্পন্ন হয়েছে!");
  };

  // ---------------------------------------------------------
  // Keyword Search Scraping
  // ---------------------------------------------------------
  const handleKeywordSearch = async () => {
    const kw = keywordInput.trim();
    if (!kw) {
      toast.error("অনুগ্রহ করে একটি কীওয়ার্ড লিখুন");
      return;
    }

    setIsFetchingKeyword(true);
    try {
      const newProducts = await scrapeOne({ keyword: kw });
      setScrapedProducts(prev => [...prev, ...newProducts]);
      toast.success(`"${kw}" এর জন্য ${newProducts.length} টি প্রোডাক্ট পাওয়া গেছে!`);
      setKeywordInput("");
      // Switch to batch tab to show results
      setActiveTab("batch");
    } catch (err: any) {
      toast.error(`AI অনুসন্ধান ব্যর্থ: ${err.message}`);
    } finally {
      setIsFetchingKeyword(false);
    }
  };

  // ---------------------------------------------------------
  // Card field change handlers
  // ---------------------------------------------------------
  const handleCardPriceChange = (id: string, field: "price" | "cash_discount_price", val: string) => {
    setScrapedProducts(prev => prev.map(p => {
      if (p.id !== id) return p;
      const updated = { ...p, [field]: val };
      const regular = Number(field === "price" ? val : p.price) || 0;
      const cash = Number(field === "cash_discount_price" ? val : p.cash_discount_price) || 0;
      if (regular > 0 && cash > 0 && cash < regular) {
        updated.discount_percentage = (((regular - cash) / regular) * 100).toFixed(1);
      } else {
        updated.discount_percentage = "0";
      }
      return updated;
    }));
  };

  const handleCardPercentageChange = (id: string, val: string) => {
    setScrapedProducts(prev => prev.map(p => {
      if (p.id !== id) return p;
      const pct = Number(val) || 0;
      const regular = Number(p.price) || 0;
      const updated = { ...p, discount_percentage: val };
      if (regular > 0 && pct > 0 && pct < 100) {
        updated.cash_discount_price = Math.round(regular * (1 - pct / 100)).toString();
      }
      return updated;
    }));
  };

  const handleCardFieldChange = (id: string, field: keyof ScrapedProduct, val: any) => {
    setScrapedProducts(prev => prev.map(p => p.id === id ? { ...p, [field]: val } : p));
  };

  const removeScrapedProduct = (id: string) => {
    setScrapedProducts(prev => prev.filter(p => p.id !== id));
    toast.info("প্রোডাক্টটি তালিকা থেকে বাদ দেওয়া হয়েছে");
  };

  const applyBulkCategory = (cat: string) => {
    if (!cat) return;
    setBulkCategory(cat);
    setScrapedProducts(prev => prev.map(p => ({ ...p, category: cat })));
    toast.success(`সব প্রোডাক্টের ক্যাটাগরি "${cat}" এ সেট করা হয়েছে!`);
  };

  const applyBulkBrand = (brand: string) => {
    if (!brand) return;
    setBulkBrand(brand);
    setScrapedProducts(prev => prev.map(p => ({ ...p, brand })));
    toast.success(`সব প্রোডাক্টের ব্র্যান্ড "${brand}" এ সেট করা হয়েছে!`);
  };

  // ---------------------------------------------------------
  // Bulk Submit to Supabase
  // ---------------------------------------------------------
  const handleBulkSubmit = async () => {
    if (scrapedProducts.length === 0) {
      toast.error("কোনো প্রোডাক্ট ইম্পোর্ট করার জন্য পাওয়া যায়নি");
      return;
    }

    // Validate — every product must have a name
    const invalid = scrapedProducts.find(p => !p.name.trim());
    if (invalid) {
      toast.error("সব প্রোডাক্টের নাম দেওয়া আবশ্যক");
      return;
    }

    setBulkLoading(true);
    try {
      const productsPayload = scrapedProducts.map(p => ({
        name: p.name.trim(),
        category: p.category,
        brand: p.brand,
        description: p.description.trim() || null,
        sku: p.sku.trim() || null,
        price: Number(p.price) || 0,
        stock_quantity: Number(p.stock_quantity) || 0,
        cash_discount_price: p.cash_discount_price ? Number(p.cash_discount_price) : null,
        discount_percentage: Number(p.discount_percentage) || 0,
        show_in_store: p.show_in_store,
        call_for_price: p.call_for_price || false,
        image_url: p.image_url || null,
      }));

      const { data: insertedProducts, error: insertError } = await supabase
        .from("products")
        .insert(productsPayload)
        .select();

      if (insertError) throw insertError;

      // Insert all images into product_images table
      if (insertedProducts && insertedProducts.length > 0) {
        const imageInserts: any[] = [];
        insertedProducts.forEach((prod, idx) => {
          const orig = scrapedProducts[idx];
          if (!orig) return;
          const seen = new Set<string>();
          if (orig.image_url) seen.add(orig.image_url);
          (orig.images || []).forEach(img => { if (img && typeof img === "string") seen.add(img); });

          Array.from(seen).forEach((imgUrl, imgIdx) => {
            imageInserts.push({ product_id: prod.id, image_url: imgUrl, sort_order: imgIdx });
          });
        });

        if (imageInserts.length > 0) {
          const { error: imgError } = await supabase.from("product_images").insert(imageInserts);
          if (imgError) console.error("Image insert error:", imgError);
        }
      }

      toast.success(`✅ ${scrapedProducts.length} টি প্রোডাক্ট সফলভাবে স্টোরে যোগ করা হয়েছে!`);
      queryClient.invalidateQueries({ queryKey: ["products"] });
      navigate("/products");
    } catch (err: any) {
      console.error("Bulk insert error:", err);
      toast.error(`ইম্পোর্ট ব্যর্থ হয়েছে: ${err.message}`);
    } finally {
      setBulkLoading(false);
    }
  };

  // ---------------------------------------------------------
  // Manual Form Handlers
  // ---------------------------------------------------------
  const handleManualPriceChange = (field: "price" | "cash_discount_price", value: string) => {
    const newForm = { ...manualForm, [field]: value };
    const regular = Number(field === "price" ? value : manualForm.price) || 0;
    const cash = Number(field === "cash_discount_price" ? value : manualForm.cash_discount_price) || 0;
    if (regular > 0 && cash > 0 && cash < regular) {
      newForm.discount_percentage = (((regular - cash) / regular) * 100).toFixed(1);
    } else {
      newForm.discount_percentage = "0";
    }
    setManualForm(newForm);
  };

  const handleManualPercentageChange = (value: string) => {
    const pct = Number(value) || 0;
    const regular = Number(manualForm.price) || 0;
    const newForm = { ...manualForm, discount_percentage: value };
    if (regular > 0 && pct > 0 && pct < 100) {
      newForm.cash_discount_price = Math.round(regular * (1 - pct / 100)).toString();
    }
    setManualForm(newForm);
  };

  const handleManualImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (files.length > 0) {
      setManualImageFiles(prev => [...prev, ...files]);
      setManualImagePreviews(prev => [...prev, ...files.map(f => URL.createObjectURL(f))]);
      setManualForm(f => ({ ...f, image_url: "" }));
    }
    // reset input so same files can be re-selected
    e.target.value = "";
  };

  const removeManualImage = (index: number) => {
    setManualImageFiles(prev => prev.filter((_, i) => i !== index));
    setManualImagePreviews(prev => prev.filter((_, i) => i !== index));
    setManualPrimaryIndex(prev => {
      if (prev === index) return 0;
      if (prev > index) return prev - 1;
      return prev;
    });
  };

  const handleManualSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!manualForm.name.trim()) {
      toast.error("প্রোডাক্টের নাম দিতে হবে");
      return;
    }
    if (!manualForm.call_for_price && !manualForm.price) {
      toast.error("মূল্য দিন অথবা 'Call for Price' চালু করুন");
      return;
    }

    setManualLoading(true);
    try {
      const payload: any = {
        name: manualForm.name.trim(),
        category: manualForm.category,
        brand: manualForm.brand,
        description: manualForm.description.trim() || null,
        sku: manualForm.sku.trim() || null,
        price: Number(manualForm.price) || 0,
        stock_quantity: Number(manualForm.stock_quantity) || 0,
        cash_discount_price: manualForm.cash_discount_price ? Number(manualForm.cash_discount_price) : null,
        discount_percentage: Number(manualForm.discount_percentage) || 0,
        show_in_store: manualForm.show_in_store,
        call_for_price: manualForm.call_for_price || false,
      };

      // If a URL is pasted (no files selected), use that as primary image
      if (manualForm.image_url.trim() && manualImageFiles.length === 0) {
        payload.image_url = manualForm.image_url.trim();
      }

      const { data: inserted, error } = await supabase.from("products").insert(payload).select().single();
      if (error) throw error;

      // Upload all selected files
      const uploadedUrls: string[] = [];
      if (manualImageFiles.length > 0 && inserted) {
        for (let i = 0; i < manualImageFiles.length; i++) {
          const file = manualImageFiles[i];
          const ext = file.name.split(".").pop();
          const filePath = `${inserted.id}_${Date.now()}_${i}.${ext}`;
          const { error: uploadError } = await supabase.storage
            .from("product-images")
            .upload(filePath, file, { upsert: true });
          if (!uploadError) {
            const { data: urlData } = supabase.storage.from("product-images").getPublicUrl(filePath);
            if (urlData?.publicUrl) uploadedUrls.push(urlData.publicUrl);
          }
        }
      }

      // Also include pasted URL if any files were also uploaded
      if (manualForm.image_url.trim()) uploadedUrls.unshift(manualForm.image_url.trim());

      // Determine primary image (the one the user set as primary)
      const primaryUrl = uploadedUrls[manualPrimaryIndex] || uploadedUrls[0] || payload.image_url || null;

      if (inserted) {
        // Set main image_url
        if (primaryUrl) {
          await supabase.from("products").update({ image_url: primaryUrl } as any).eq("id", inserted.id);
        }
        // Insert ALL images into product_images table
        if (uploadedUrls.length > 0) {
          const imageInserts = uploadedUrls.map((url, idx) => ({
            product_id: inserted.id,
            image_url: url,
            sort_order: idx,
          }));
          const { error: imgErr } = await supabase.from("product_images").insert(imageInserts);
          if (imgErr) console.error("Image gallery insert error:", imgErr);
        } else if (payload.image_url) {
          await supabase.from("product_images").insert({ product_id: inserted.id, image_url: payload.image_url, sort_order: 0 });
        }
      }

      toast.success(`✅ প্রোডাক্ট সফলভাবে স্টোরে যুক্ত করা হয়েছে!${uploadedUrls.length > 0 ? ` (${uploadedUrls.length}টি ছবি আপলোড হয়েছে)` : ""}`);
      queryClient.invalidateQueries({ queryKey: ["products"] });
      navigate("/products");
    } catch (err: any) {
      console.error("Manual submit error:", err);
      toast.error(`ব্যর্থ হয়েছে: ${err.message}`);
    } finally {
      setManualLoading(false);
    }
  };

  // ---------------------------------------------------------
  // Render
  // ---------------------------------------------------------
  return (
    <div className="container mx-auto p-4 max-w-6xl space-y-6 pb-24">
      {/* Header */}
      <div className="relative overflow-hidden rounded-3xl bg-gradient-to-r from-blue-700 via-indigo-700 to-purple-800 p-6 sm:p-8 text-primary-foreground shadow-2xl">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_40%_120%,rgba(255,255,255,0.1),transparent_80%)]" />
        <div className="absolute -top-12 -right-12 h-44 w-44 rounded-full bg-white/5 blur-2xl" />
        <div className="relative z-10 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
          <div className="space-y-2">
            <div className="flex items-center gap-2">
              <Button variant="ghost" size="icon" onClick={() => navigate("/products")} className="text-white hover:bg-white/10 rounded-full h-9 w-9">
                <ArrowLeft className="h-5 w-5" />
              </Button>
              <span className="text-xs uppercase tracking-widest font-bold px-2 py-0.5 rounded-full bg-white/15 backdrop-blur-md">
                AK IT Solution Store Manager
              </span>
            </div>
            <h1 className="text-3xl sm:text-4xl font-extrabold tracking-tight flex items-center gap-3">
              <PackagePlus className="h-10 w-10 text-yellow-300 drop-shadow" /> প্রোডাক্ট যুক্ত করুন
            </h1>
            <p className="text-white/80 text-sm sm:text-base max-w-2xl font-light">
              ওয়েবসাইট লিঙ্ক বা কীওয়ার্ড দিয়ে AI ব্যবহার করে প্রোডাক্ট ইম্পোর্ট করুন, অথবা নিজে ম্যানুয়ালি যোগ করুন।
            </p>
          </div>
          <div className="shrink-0 hidden lg:block">
            <Sparkles className="h-28 w-28 text-white/10 animate-pulse" />
          </div>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex bg-muted/65 p-1.5 rounded-2xl max-w-lg mx-auto border border-border/40 backdrop-blur-xl">
        {[
          { key: "batch", icon: <Layers className="h-4 w-4" />, label: "লিঙ্ক ইম্পোর্ট" },
          { key: "keyword", icon: <Search className="h-4 w-4" />, label: "AI অনুসন্ধান" },
          { key: "manual", icon: <Plus className="h-4 w-4" />, label: "ম্যানুয়াল" },
        ].map(tab => (
          <button
            key={tab.key}
            onClick={() => setActiveTab(tab.key as any)}
            className={`flex-1 py-2.5 text-xs sm:text-sm font-bold rounded-xl transition-all duration-300 flex items-center justify-center gap-1.5 ${
              activeTab === tab.key
                ? "bg-gradient-to-r from-blue-600 to-indigo-600 text-white shadow-lg shadow-indigo-500/25"
                : "text-muted-foreground hover:text-foreground"
            }`}
          >
            {tab.icon} {tab.label}
          </button>
        ))}
      </div>

      {/* ============================================================ */}
      {/* TAB: Batch Link Import */}
      {/* ============================================================ */}
      {activeTab === "batch" && (
        <div className="space-y-6">
          <Card className="border-2 border-primary/20 shadow-xl bg-gradient-to-b from-card to-background rounded-3xl overflow-hidden">
            <CardHeader className="bg-primary/5 border-b border-primary/10 px-6 py-5">
              <CardTitle className="text-xl flex items-center gap-2 text-primary font-extrabold">
                <LinkIcon className="h-5 w-5 text-indigo-500" /> একসাথে একাধিক প্রোডাক্টের লিঙ্ক দিন
              </CardTitle>
              <CardDescription className="text-sm font-medium">
                Ryans, Startech, TechLand বা যেকোনো সাইটের লিঙ্ক দিন। প্রতি লাইনে একটি করে লিঙ্ক লিখুন।
              </CardDescription>
            </CardHeader>
            <CardContent className="p-6 space-y-4">
              <Textarea
                value={batchUrlsText}
                onChange={(e) => setBatchUrlsText(e.target.value)}
                placeholder={"https://www.startech.com.bd/product-page\nhttps://www.ryanscomputers.com/product"}
                rows={5}
                className="text-sm rounded-2xl bg-muted/20 border-primary/25 focus-visible:ring-primary h-36 font-mono p-4 resize-none"
              />
              <div className="flex flex-col sm:flex-row justify-between items-center gap-3">
                <span className="text-xs text-muted-foreground font-medium bg-muted px-3 py-1.5 rounded-lg">
                  💡 প্রতি লাইনে একটি লিঙ্ক দিন — একসাথে অনেক লিঙ্ক দেওয়া যাবে
                </span>
                <Button
                  onClick={handleBatchScrape}
                  disabled={isFetchingBatch || !batchUrlsText.trim()}
                  className="h-12 px-8 rounded-xl text-base font-bold shadow-lg shadow-indigo-500/20 bg-gradient-to-r from-blue-600 via-indigo-600 to-purple-600 hover:scale-105 active:scale-95 transition-all w-full sm:w-auto"
                >
                  {isFetchingBatch ? (
                    <><Loader2 className="animate-spin h-5 w-5 mr-2" /> ডেটা আনা হচ্ছে…</>
                  ) : (
                    <><Wand2 className="h-5 w-5 mr-2" /> প্রোডাক্ট ডেটা আনুন</>
                  )}
                </Button>
              </div>
            </CardContent>
          </Card>

          {/* Progress Panel */}
          {progressList.length > 0 && (
            <Card className="border border-border/50 shadow-md rounded-2xl overflow-hidden bg-card/60 backdrop-blur-xl">
              <CardHeader className="bg-muted/40 px-6 py-4 border-b border-border/30">
                <CardTitle className="text-sm font-extrabold text-muted-foreground flex items-center gap-2">
                  🔄 স্ক্র্যাপিং স্ট্যাটাস
                </CardTitle>
              </CardHeader>
              <CardContent className="p-4 space-y-2.5 max-h-56 overflow-y-auto">
                {progressList.map((prog, index) => (
                  <div key={index} className="flex flex-col sm:flex-row sm:items-center justify-between p-3 rounded-xl border border-border/40 bg-background/50 gap-2">
                    <div className="flex items-center gap-3 min-w-0 flex-1">
                      <div className="shrink-0 h-7 w-7 rounded-lg bg-muted flex items-center justify-center font-bold text-xs text-muted-foreground">
                        {index + 1}
                      </div>
                      <div className="min-w-0 flex-1">
                        <span className="text-xs text-muted-foreground block truncate font-mono">{prog.url}</span>
                        {prog.productName && <span className="text-xs font-bold text-emerald-600 dark:text-emerald-400 mt-0.5 block">✨ {prog.productName}</span>}
                        {prog.error && <span className="text-xs font-bold text-destructive mt-0.5 block">⚠️ {prog.error}</span>}
                      </div>
                    </div>
                    <div className="shrink-0">
                      {prog.status === "pending" && <span className="text-[10px] font-bold uppercase px-2.5 py-1 rounded-full bg-muted text-muted-foreground">বাকি</span>}
                      {prog.status === "scraping" && <span className="text-[10px] font-bold uppercase px-2.5 py-1 rounded-full bg-blue-100 dark:bg-blue-950 text-blue-600 dark:text-blue-400 animate-pulse flex items-center gap-1"><Loader2 className="h-3 w-3 animate-spin" /> আনা হচ্ছে</span>}
                      {prog.status === "success" && <span className="text-[10px] font-bold uppercase px-2.5 py-1 rounded-full bg-emerald-100 dark:bg-emerald-950 text-emerald-600 dark:text-emerald-400 flex items-center gap-1"><CheckCircle2 className="h-3.5 w-3.5" /> সম্পন্ন</span>}
                      {prog.status === "failed" && <span className="text-[10px] font-bold uppercase px-2.5 py-1 rounded-full bg-red-100 dark:bg-red-950 text-red-600 dark:text-red-400 flex items-center gap-1"><AlertTriangle className="h-3.5 w-3.5" /> ব্যর্থ</span>}
                    </div>
                  </div>
                ))}
              </CardContent>
            </Card>
          )}

          {/* Scraped Products */}
          {scrapedProducts.length > 0 && (
            <div className="space-y-4">
              {/* Bulk Controls */}
              <Card className="border border-border/50 rounded-2xl overflow-hidden bg-gradient-to-r from-indigo-500/5 via-purple-500/5 to-pink-500/5">
                <CardContent className="p-4 flex flex-col md:flex-row items-start md:items-center justify-between gap-4">
                  <div>
                    <p className="text-sm font-extrabold text-foreground">{scrapedProducts.length} টি প্রোডাক্ট তৈরি আছে</p>
                    <p className="text-xs text-muted-foreground mt-0.5">নিচের সব প্রোডাক্টের ক্যাটাগরি বা ব্র্যান্ড একসাথে সেট করুন।</p>
                  </div>
                  <div className="flex flex-col sm:flex-row items-center gap-3 w-full md:w-auto">
                    <div className="space-y-1 w-full sm:w-44">
                      <Label className="text-[11px] font-bold">একসাথে ক্যাটাগরি সেট</Label>
                      <Select value={bulkCategory} onValueChange={applyBulkCategory}>
                        <SelectTrigger className="h-9 rounded-lg"><SelectValue placeholder="ক্যাটাগরি সিলেক্ট" /></SelectTrigger>
                        <SelectContent>{CATEGORIES.map(c => <SelectItem key={c} value={c}>{c}</SelectItem>)}</SelectContent>
                      </Select>
                    </div>
                    <div className="space-y-1 w-full sm:w-44">
                      <Label className="text-[11px] font-bold">একসাথে ব্র্যান্ড সেট</Label>
                      <Select value={bulkBrand} onValueChange={applyBulkBrand}>
                        <SelectTrigger className="h-9 rounded-lg"><SelectValue placeholder="ব্র্যান্ড সিলেক্ট" /></SelectTrigger>
                        <SelectContent>{BRANDS.map(b => <SelectItem key={b} value={b}>{b}</SelectItem>)}</SelectContent>
                      </Select>
                    </div>
                  </div>
                </CardContent>
              </Card>

              {/* Product Cards Grid */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {scrapedProducts.map((p) => (
                  <Card key={p.id} className="relative border-2 border-border hover:border-primary/30 transition-all shadow-lg rounded-3xl overflow-hidden bg-card flex flex-col group">
                    {/* Remove button */}
                    <button
                      onClick={() => removeScrapedProduct(p.id)}
                      className="absolute top-3 right-3 z-20 p-1.5 bg-background/80 hover:bg-red-500 hover:text-white rounded-full transition-all border border-border shadow-sm"
                      title="বাতিল করুন"
                    >
                      <Trash2 className="h-4 w-4" />
                    </button>

                    {/* Image + Name */}
                    <div className="p-5 border-b border-border/50 bg-muted/15 flex flex-col gap-3">
                      <div className="flex items-start gap-4 w-full">
                        {/* Thumbnail */}
                        <div className="relative shrink-0 w-24 h-24 rounded-2xl border bg-white overflow-hidden shadow-inner flex items-center justify-center">
                          {p.image_url ? (
                            <img src={p.image_url} alt="Product" className="h-full w-full object-contain p-1" />
                          ) : (
                            <ImageIcon className="h-8 w-8 text-muted-foreground/60" />
                          )}
                          {p.sourceUrl.startsWith("http") && (
                            <a href={p.sourceUrl} target="_blank" rel="noopener noreferrer"
                              className="absolute bottom-1 right-1 p-1 bg-primary text-white rounded-md hover:scale-110 transition-all shadow"
                              title="লিঙ্কে যান"
                            >
                              <ExternalLink className="h-3 w-3" />
                            </a>
                          )}
                        </div>

                        {/* Product Name */}
                        <div className="flex-1 min-w-0 space-y-2">
                          <div className="space-y-1">
                            <Label className="text-xs font-bold text-muted-foreground">প্রোডাক্টের নাম *</Label>
                            <Input
                              value={p.name}
                              onChange={(e) => handleCardFieldChange(p.id, "name", e.target.value)}
                              placeholder="Product Name"
                              className="h-10 text-sm rounded-xl font-bold bg-background shadow-sm"
                            />
                          </div>

                          {/* Image URL paste field */}
                          <div className="space-y-1">
                            <Label className="text-xs font-bold text-muted-foreground">ছবির লিঙ্ক (Image URL)</Label>
                            <Input
                              value={p.image_url}
                              onChange={(e) => handleCardFieldChange(p.id, "image_url", e.target.value)}
                              placeholder="https://example.com/image.jpg"
                              className="h-8 text-xs rounded-xl bg-background"
                            />
                          </div>
                        </div>
                      </div>

                      {/* Image thumbnails switcher */}
                      {p.images && p.images.length > 1 && (
                        <div className="flex gap-1.5 py-1 overflow-x-auto max-w-full">
                          {p.images.map((imgUrl, i) => (
                            <button
                              key={i}
                              type="button"
                              onClick={() => handleCardFieldChange(p.id, "image_url", imgUrl)}
                              className={`relative h-10 w-10 shrink-0 rounded-lg overflow-hidden border-2 transition-all ${
                                p.image_url === imgUrl ? "border-primary shadow-sm" : "border-border/60 hover:border-muted-foreground"
                              }`}
                              title={`ছবি ${i + 1} বেছে নিন`}
                            >
                              <img src={imgUrl} alt="" className="h-full w-full object-contain bg-white" />
                            </button>
                          ))}
                        </div>
                      )}
                    </div>

                    {/* Editor */}
                    <div className="p-5 space-y-4 flex-1 flex flex-col">
                      <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1">
                          <Label className="text-xs font-bold text-muted-foreground">ক্যাটাগরি</Label>
                          <Select value={p.category} onValueChange={(v) => handleCardFieldChange(p.id, "category", v)}>
                            <SelectTrigger className="h-10 rounded-xl bg-background"><SelectValue /></SelectTrigger>
                            <SelectContent>{CATEGORIES.map(cat => <SelectItem key={cat} value={cat}>{cat}</SelectItem>)}</SelectContent>
                          </Select>
                        </div>
                        <div className="space-y-1">
                          <Label className="text-xs font-bold text-muted-foreground">ব্র্যান্ড</Label>
                          <Select value={p.brand} onValueChange={(v) => handleCardFieldChange(p.id, "brand", v)}>
                            <SelectTrigger className="h-10 rounded-xl bg-background"><SelectValue /></SelectTrigger>
                            <SelectContent>{BRANDS.map(brand => <SelectItem key={brand} value={brand}>{brand}</SelectItem>)}</SelectContent>
                          </Select>
                        </div>
                      </div>

                      {/* Pricing */}
                      <div className="p-4 rounded-2xl bg-muted/30 border border-border/40 space-y-3">
                        <div className="grid grid-cols-2 gap-3">
                          <div className="space-y-1">
                            <Label className="text-xs font-bold text-primary">রেগুলার মূল্য (৳)</Label>
                            <Input
                              type="number"
                              value={p.price}
                              onChange={(e) => handleCardPriceChange(p.id, "price", e.target.value)}
                              className="h-10 font-bold rounded-xl border-primary/20 bg-background"
                              placeholder="0"
                              disabled={p.call_for_price}
                            />
                          </div>
                          <div className="space-y-1">
                            <Label className="text-xs font-bold text-muted-foreground">ক্যাশ মূল্য (৳)</Label>
                            <Input
                              type="number"
                              value={p.cash_discount_price}
                              onChange={(e) => handleCardPriceChange(p.id, "cash_discount_price", e.target.value)}
                              className="h-10 font-bold rounded-xl bg-background"
                              placeholder="0"
                              disabled={p.call_for_price}
                            />
                          </div>
                        </div>
                        <div className="grid grid-cols-2 gap-3">
                          <div className="space-y-1">
                            <Label className="text-[11px] font-bold text-muted-foreground">ডিসকাউন্ট (%)</Label>
                            <Input
                              type="number" step="0.1" min="0" max="99"
                              value={p.discount_percentage}
                              onChange={(e) => handleCardPercentageChange(p.id, e.target.value)}
                              className="h-9 rounded-lg"
                              disabled={p.call_for_price}
                            />
                          </div>
                          <div className="space-y-1">
                            <Label className="text-[11px] font-bold text-muted-foreground">স্টক পরিমাণ</Label>
                            <Input
                              type="number"
                              value={p.stock_quantity}
                              onChange={(e) => handleCardFieldChange(p.id, "stock_quantity", e.target.value)}
                              className="h-9 rounded-lg"
                            />
                          </div>
                        </div>
                      </div>

                      {/* Description */}
                      <div className="space-y-1">
                        <Label className="text-xs font-bold text-muted-foreground">বিবরণ</Label>
                        <Textarea
                          value={p.description}
                          onChange={(e) => handleCardFieldChange(p.id, "description", e.target.value)}
                          placeholder="প্রোডাক্টের বিবরণ..."
                          rows={2}
                          className="text-xs rounded-xl bg-background resize-none"
                        />
                      </div>

                      {/* Toggles */}
                      <div className="pt-2 mt-auto border-t border-border/40 flex flex-col gap-2">
                        <div className="flex items-center justify-between">
                          <span className="text-xs font-bold flex items-center gap-1.5">
                            {p.show_in_store ? <Eye className="h-4 w-4 text-emerald-500" /> : <EyeOff className="h-4 w-4 text-muted-foreground" />}
                            স্টোরে দেখান
                          </span>
                          <Switch checked={p.show_in_store} onCheckedChange={(v) => handleCardFieldChange(p.id, "show_in_store", v)} className="scale-90" />
                        </div>
                        <div className="flex items-center justify-between border-t border-border/20 pt-2">
                          <span className="text-xs font-bold flex items-center gap-1.5">
                            <Phone className="h-4 w-4 text-amber-500" />
                            Call for Price (মূল্য লুকান)
                          </span>
                          <Switch checked={p.call_for_price || false} onCheckedChange={(v) => handleCardFieldChange(p.id, "call_for_price", v)} className="scale-90" />
                        </div>
                      </div>
                    </div>
                  </Card>
                ))}
              </div>

              {/* Floating Save Toolbar */}
              <div className="fixed bottom-4 left-4 right-4 sm:left-auto sm:right-6 sm:w-96 z-40 animate-in slide-in-from-bottom-5 duration-300">
                <Card className="border-2 border-indigo-500/30 bg-background/95 shadow-[0_15px_45px_rgba(99,102,241,0.2)] rounded-3xl overflow-hidden backdrop-blur-md">
                  <CardContent className="p-4 flex items-center justify-between gap-4">
                    <div className="space-y-0.5">
                      <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest block">ইম্পোর্ট সেন্টার</span>
                      <span className="text-sm font-extrabold text-foreground">{scrapedProducts.length} টি প্রোডাক্ট রেডি</span>
                    </div>
                    <Button
                      onClick={handleBulkSubmit}
                      disabled={bulkLoading}
                      className="h-12 px-6 rounded-2xl font-bold bg-gradient-to-r from-blue-600 via-indigo-600 to-purple-600 text-white hover:scale-105 active:scale-95 transition-all shadow-md flex items-center gap-2"
                    >
                      {bulkLoading ? <Loader2 className="h-5 w-5 animate-spin" /> : <Save className="h-5 w-5" />}
                      স্টোরে যোগ করুন
                    </Button>
                  </CardContent>
                </Card>
              </div>
            </div>
          )}
        </div>
      )}

      {/* TAB: Keyword / AI Search */}
      {activeTab === "keyword" && (
        <ProductFinderKeywordTab
          keywordInput={keywordInput}
          setKeywordInput={setKeywordInput}
          handleKeywordSearch={handleKeywordSearch}
          isFetchingKeyword={isFetchingKeyword}
        />
      )}

      {/* TAB: Manual Entry */}
      {activeTab === "manual" && (
        <ProductFinderManualTab
          manualForm={manualForm}
          setManualForm={setManualForm}
          handleManualSubmit={handleManualSubmit}
          manualLoading={manualLoading}
          CATEGORIES={CATEGORIES}
          BRANDS={BRANDS}
          handleManualPriceChange={handleManualPriceChange}
          handleManualPercentageChange={handleManualPercentageChange}
          manualImagePreviews={manualImagePreviews}
          manualPrimaryIndex={manualPrimaryIndex}
          setManualPrimaryIndex={setManualPrimaryIndex}
          removeManualImage={removeManualImage}
          handleManualImageSelect={handleManualImageSelect}
          setManualImageFiles={setManualImageFiles}
          setManualImagePreviews={setManualImagePreviews}
        />
      )}
    </div>
  );
}

import { useState, useRef, useEffect, useMemo } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent } from "@/components/ui/card";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { Switch } from "@/components/ui/switch";
import { Checkbox } from "@/components/ui/checkbox";
import { Plus, Pencil, Trash2, Camera, CameraOff, ScanBarcode, Upload, ImageIcon, Eye, EyeOff, Percent, X, GripVertical, Layers, Search, Filter, CheckSquare, Wand2, Loader2, Phone, Star } from "lucide-react";
import { ConfirmDeleteDialog } from "@/components/ConfirmDeleteDialog";
import { useToast } from "@/hooks/use-toast";
import { Html5Qrcode } from "html5-qrcode";

const categories = ["CCTV", "DVR/NVR", "Monitor", "Laptop", "Computer", "Networking", "Accessories", "Printer", "Keyboard/Mouse", "Server", "Mobile", "Attendance Device", "Smart Home", "Audio/Video", "Storage", "Software", "Other"];
const brands = ["Dahua", "Hikvision", "TP-Link", "Uniview", "ZKTeco", "Tenda", "Ruijie", "Other"];

export default function Products() {
  const [open, setOpen] = useState(false);
  const [editing, setEditing] = useState<any>(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("All");
  const [form, setForm] = useState({
    name: "", category: "CCTV", brand: "Other", description: "", price: "", stock_quantity: "0", sku: "",
    cash_discount_price: "", discount_percentage: "0", show_in_store: true, call_for_price: false, is_featured: false,
    specifications: [] as {feature: string, description: string}[],
  });
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [additionalImages, setAdditionalImages] = useState<File[]>([]);
  const [additionalPreviews, setAdditionalPreviews] = useState<string[]>([]);
  const [existingImages, setExistingImages] = useState<any[]>([]);
  const [uploading, setUploading] = useState(false);
  const [cameraOpen, setCameraOpen] = useState(false);
  const [variants, setVariants] = useState<any[]>([]);
  const [deletedVariantIds, setDeletedVariantIds] = useState<string[]>([]);
  // Multi-select
  const [isMultiSelect, setIsMultiSelect] = useState(false);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isDeleting, setIsDeleting] = useState(false);
  const [bulkCategoryValue, setBulkCategoryValue] = useState("");
  const [savingBulkCategory, setSavingBulkCategory] = useState(false);
  const [savingBulkShow, setSavingBulkShow] = useState(false);
  // AI Image Edit
  const [aiEditingProductId, setAiEditingProductId] = useState<string | null>(null);
  const [aiEditPrompt, setAiEditPrompt] = useState("");
  const [isAiEditing, setIsAiEditing] = useState(false);
  const [showAiEdit, setShowAiEdit] = useState(false);
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);
  const [bulkDeleteConfirm, setBulkDeleteConfirm] = useState(false);
  const [aiSuggestions] = useState([
    { label: "Facebook পোস্টার", prompt: "Create a professional Facebook promotional poster for this product. Use a modern, dark premium aesthetic with glowing indigo/blue accents. Include bold Bengali text 'AK IT Solution - অবিশ্বাস্য মূল্যে প্রিমিয়াম প্রোডাক্ট!' and 'অর্ডার করতে ইনবক্স করুন।'. Add a stylish price tag badge and a sleek gradient background that highlights the product." },
    { label: "অনলাইন বুকিং ব্যানার", prompt: "Generate a professional online booking/order banner. Feature the product prominently with a high-end glow effect. Background should be a clean tech-inspired office or data center. Include text 'AK IT Solution - অনলাইন বুকিং চলছে' and a 'Book Now' call-to-action style element." },
    { label: "ইন্সটাগ্রাম পোস্ট", prompt: "Transform into a minimalist, square Instagram post. Center the product on a clean, professional studio background with soft realistic shadows. Use a premium color palette (slate, indigo, white). Include 'AK IT Solution' branding in a subtle, elegant font." },
    { label: "সেল পোস্টার", prompt: "Create a high-energy 'SALE' poster. Use vibrant colors like emerald green or electric yellow against a dark background. Include big 'বিরাট মূল্যহ্রাস!' text and a 'Limited Stock' urgency badge. Make the product look heroic with dynamic lighting." },
    { label: "ক্লিয়ার ব্যাকগ্রাউন্ড", prompt: "Remove the background and place the product on a pure white, professional studio background. Add a soft, realistic drop shadow and improve the product's overall lighting and contrast for a catalog-ready look." },
  ]);

  const scannerRef = useRef<Html5Qrcode | null>(null);
  const queryClient = useQueryClient();
  const { toast } = useToast();

  const { data: products } = useQuery({ queryKey: ["products"], queryFn: async () => (await supabase.from("products").select("*").order("created_at", { ascending: false })).data || [] });

  const { data: variantCounts } = useQuery({
    queryKey: ["variant-counts"],
    queryFn: async () => {
      const { data } = await supabase.from("product_variants").select("product_id");
      const counts: Record<string, number> = {};
      data?.forEach((v: any) => { counts[v.product_id] = (counts[v.product_id] || 0) + 1; });
      return counts;
    },
  });

  const categoryCounts = useMemo(() => {
    const counts: Record<string, number> = { All: products?.length || 0 };
    products?.forEach((p: any) => { counts[p.category] = (counts[p.category] || 0) + 1; });
    return counts;
  }, [products]);

  const filteredProducts = useMemo(() => {
    return products?.filter((p: any) => {
      const matchesCategory = selectedCategory === "All" || p.category === selectedCategory;
      const matchesSearch = !searchQuery ||
        p.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        (p.sku || "").toLowerCase().includes(searchQuery.toLowerCase()) ||
        (p.brand || "").toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    }) || [];
  }, [products, selectedCategory, searchQuery]);

  const fetchProductImages = async (productId: string) => {
    const { data } = await supabase.from("product_images").select("*").eq("product_id", productId).order("sort_order");
    return data || [];
  };

  useEffect(() => {
    if (cameraOpen && open) {
      const timerId = setTimeout(async () => {
        try {
          const scanner = new Html5Qrcode("dialog-barcode-reader");
          scannerRef.current = scanner;
          await scanner.start(
            { facingMode: "environment" },
            { fps: 10, qrbox: { width: 250, height: 100 } },
            (decodedText) => {
              setForm((f) => ({ ...f, sku: decodedText }));
              toast({ title: "Barcode scanned", description: `SKU: ${decodedText}` });
              setCameraOpen(false);
            },
            () => {}
          );
        } catch (err: any) {
          toast({ title: "Camera error", description: err?.message || "Could not access camera", variant: "destructive" });
          setCameraOpen(false);
        }
      }, 300);
      return () => clearTimeout(timerId);
    } else {
      if (scannerRef.current) {
        scannerRef.current.stop().catch(() => {});
        scannerRef.current.clear();
        scannerRef.current = null;
      }
    }
  }, [cameraOpen, open]);

  useEffect(() => { if (!open) setCameraOpen(false); }, [open]);

  const handlePriceChange = (field: "price" | "cash_discount_price", value: string) => {
    const newForm = { ...form, [field]: value };
    const regular = Number(field === "price" ? value : form.price) || 0;
    const cash = Number(field === "cash_discount_price" ? value : form.cash_discount_price) || 0;
    if (regular > 0 && cash > 0 && cash < regular) {
      newForm.discount_percentage = (((regular - cash) / regular) * 100).toFixed(1);
    } else {
      newForm.discount_percentage = "0";
    }
    setForm(newForm);
  };

  const handlePercentageChange = (value: string) => {
    const pct = Number(value) || 0;
    const regular = Number(form.price) || 0;
    const newForm = { ...form, discount_percentage: value };
    if (regular > 0 && pct > 0 && pct < 100) {
      newForm.cash_discount_price = Math.round(regular * (1 - pct / 100)).toString();
    }
    setForm(newForm);
  };

  const uploadImage = async (productId: string): Promise<string | null> => {
    if (!imageFile) return null;
    const ext = imageFile.name.split('.').pop();
    const filePath = `${productId}.${ext}`;
    const { error } = await supabase.storage.from("product-images").upload(filePath, imageFile, { upsert: true });
    if (error) throw error;
    const { data } = supabase.storage.from("product-images").getPublicUrl(filePath);
    return data.publicUrl;
  };

  const uploadAdditionalImages = async (productId: string) => {
    for (let i = 0; i < additionalImages.length; i++) {
      const file = additionalImages[i];
      const ext = file.name.split('.').pop();
      const filePath = `${productId}_${Date.now()}_${i}.${ext}`;
      const { error } = await supabase.storage.from("product-images").upload(filePath, file, { upsert: true });
      if (error) continue;
      const { data } = supabase.storage.from("product-images").getPublicUrl(filePath);
      await supabase.from("product_images").insert({
        product_id: productId,
        image_url: data.publicUrl,
        sort_order: existingImages.length + i,
      });
    }
  };

  const saveMutation = useMutation({
    mutationFn: async (data: any) => {
      setUploading(true);
      // Extract image files passed explicitly from the mutate() call
      const currentImageFile: File | null = data._imageFile ?? null;
      const currentAdditionalImages: File[] = data._additionalImages ?? [];
      const currentExistingImages: any[] = data._existingImages ?? [];
      const currentEditing = data._editing ?? null;
      const currentVariants = data._variants ?? [];
      const currentDeletedVariantIds = data._deletedVariantIds ?? [];

      let finalDescription = data.description;
      if (data.specifications && data.specifications.length > 0) {
        finalDescription = JSON.stringify({
          text: data.description,
          specs: data.specifications
        });
      }

      // Core payload — only columns that are guaranteed to exist in DB
      const corePayload: any = {
        name: data.name, category: data.category, brand: data.brand, description: finalDescription, sku: data.sku,
        price: Number(data.price) || 0,
        stock_quantity: Number(data.stock_quantity) || 0,
        cash_discount_price: data.cash_discount_price ? Number(data.cash_discount_price) : null,
        discount_percentage: Number(data.discount_percentage) || 0,
        show_in_store: data.show_in_store,
      };
      // Extra fields — may not exist if migrations not applied yet; safe-update separately
      const extraPayload: any = {
        is_featured: data.is_featured || false,
        call_for_price: data.call_for_price || false,
      };
      let productId = currentEditing?.id;
      if (currentEditing) {
        const { error } = await supabase.from("products").update(corePayload).eq("id", currentEditing.id);
        if (error) {
          console.error("Supabase update error:", error);
          throw new Error(error.message || "Failed to update product");
        }
        // Try to update extra columns — silently skip if columns don't exist yet
        await supabase.from("products").update(extraPayload).eq("id", currentEditing.id);
      } else {
        const { data: inserted, error } = await supabase.from("products").insert(corePayload).select().single();
        if (error) throw error;
        productId = inserted.id;
        // Try to update extra columns after insert
        if (productId) {
          await supabase.from("products").update(extraPayload).eq("id", productId);
        }
      }
      // Upload main image if a new file was selected
      if (currentImageFile && productId) {
        const ext = currentImageFile.name.split('.').pop();
        const filePath = `${productId}.${ext}`;
        const { error: uploadError } = await supabase.storage.from("product-images").upload(filePath, currentImageFile, { upsert: true });
        if (uploadError) throw uploadError;
        const { data: urlData } = supabase.storage.from("product-images").getPublicUrl(filePath);
        if (urlData?.publicUrl) {
          await supabase.from("products").update({ image_url: urlData.publicUrl } as any).eq("id", productId);
        }
      }
      // Upload additional gallery images
      if (currentAdditionalImages.length > 0 && productId) {
        for (let i = 0; i < currentAdditionalImages.length; i++) {
          const file = currentAdditionalImages[i];
          const ext = file.name.split('.').pop();
          const filePath = `${productId}_${Date.now()}_${i}.${ext}`;
          const { error: addErr } = await supabase.storage.from("product-images").upload(filePath, file, { upsert: true });
          if (addErr) continue;
          const { data: addUrlData } = supabase.storage.from("product-images").getPublicUrl(filePath);
          await supabase.from("product_images").insert({
            product_id: productId,
            image_url: addUrlData.publicUrl,
            sort_order: currentExistingImages.length + i,
          });
        }
      }
      if (productId) {
        for (const delId of currentDeletedVariantIds) {
          await supabase.from("product_variants").delete().eq("id", delId);
        }
        for (const v of currentVariants) {
          const variantPayload = {
            product_id: productId,
            variant_label: v.variant_label,
            variant_group: v.variant_group || "Size",
            price: Number(v.price) || 0,
            stock_quantity: Number(v.stock_quantity) || 0,
            sku: v.sku || null,
            sort_order: v.sort_order || 0,
          };
          if (v.id && !v.isNew) {
            await supabase.from("product_variants").update(variantPayload).eq("id", v.id);
          } else {
            await supabase.from("product_variants").insert(variantPayload);
          }
        }
      }
      return { isEditing: !!currentEditing };
    },
    onSuccess: (result) => {
      setUploading(false);
      queryClient.invalidateQueries({ queryKey: ["products"] });
      queryClient.invalidateQueries({ queryKey: ["variant-counts"] });
      setOpen(false); setEditing(null); resetForm();
      toast({ title: result?.isEditing ? "Product updated" : "Product added" });
    },
    onError: (err: any) => { setUploading(false); toast({ title: "Error", description: err.message, variant: "destructive" }); },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      // Delete related data first to avoid foreign key violations or orphaned records
      await supabase.from("product_variants").delete().eq("product_id", id);
      await supabase.from("product_images").delete().eq("product_id", id);
      const { error } = await supabase.from("products").delete().eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["products"] });
      queryClient.invalidateQueries({ queryKey: ["variant-counts"] });
      toast({ title: "প্রোডাক্ট ডিলিট করা হয়েছে" });
    },
  });

  const handleBulkDelete = async () => {
    if (selectedIds.size === 0) return;
    setIsDeleting(true);
    try {
      const ids = Array.from(selectedIds);
      for (const id of ids) {
        await supabase.from("product_variants").delete().eq("product_id", id);
        await supabase.from("product_images").delete().eq("product_id", id);
        await supabase.from("products").delete().eq("id", id);
      }
      queryClient.invalidateQueries({ queryKey: ["products"] });
      toast({ title: `${ids.length}টি প্রোডাক্ট ডিলিট হয়েছে` });
      setSelectedIds(new Set());
      setIsMultiSelect(false);
    } catch {
      toast({ title: "ডিলিট ব্যর্থ", variant: "destructive" });
    } finally {
      setIsDeleting(false);
    }
  };

  const handleBulkCategoryChange = async (newCategory: string) => {
    if (selectedIds.size === 0) return;
    setSavingBulkCategory(true);
    try {
      const ids = Array.from(selectedIds);
      const { error } = await supabase.from("products").update({ category: newCategory }).in("id", ids);
      if (error) throw error;
      queryClient.invalidateQueries({ queryKey: ["products"] });
      toast({ title: `${ids.length}টি প্রোডাক্টের ক্যাটাগরি "${newCategory}" করা হয়েছে` });
      setSelectedIds(new Set());
      setBulkCategoryValue("");
    } catch {
      toast({ title: "ক্যাটাগরি আপডেট ব্যর্থ", variant: "destructive" });
    } finally {
      setSavingBulkCategory(false);
    }
  };

  const handleBulkShowChange = async (show: boolean) => {
    if (selectedIds.size === 0) return;
    setSavingBulkShow(true);
    try {
      const ids = Array.from(selectedIds);
      const { error } = await supabase.from("products").update({ show_in_store: show } as any).in("id", ids);
      if (error) throw error;
      queryClient.invalidateQueries({ queryKey: ["products"] });
      toast({ title: `${ids.length}টি প্রোডাক্ট অনলাইন স্টোরে ${show ? "দেখানো হয়েছে (Online)" : "সরানো হয়েছে (Offline)"}` });
      setSelectedIds(new Set());
      setIsMultiSelect(false);
    } catch {
      toast({ title: "স্ট্যাটাস আপডেট ব্যর্থ", variant: "destructive" });
    } finally {
      setSavingBulkShow(false);
    }
  };

  const handleBulkFeatureChange = async (featured: boolean) => {
    if (selectedIds.size === 0) return;
    setSavingBulkShow(true);
    try {
      const ids = Array.from(selectedIds);
      const { error } = await supabase.from("products").update({ is_featured: featured } as any).in("id", ids);
      if (error) throw error;
      queryClient.invalidateQueries({ queryKey: ["products"] });
      toast({ title: `${ids.length}টি প্রোডাক্ট ${featured ? "Feature করা হয়েছে" : "Feature থেকে সরানো হয়েছে"}` });
      setSelectedIds(new Set());
      setIsMultiSelect(false);
    } catch {
      toast({ title: "স্ট্যাটাস আপডেট ব্যর্থ", variant: "destructive" });
    } finally {
      setSavingBulkShow(false);
    }
  };

  const toggleSelect = (id: string) => {
    setSelectedIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id); else next.add(id);
      return next;
    });
  };

  const selectAll = () => setSelectedIds(new Set(filteredProducts.map((p: any) => p.id)));
  const deselectAll = () => setSelectedIds(new Set());

  const handleAiEditImage = async (productId: string, prompt: string) => {
    const product = products?.find((p: any) => p.id === productId);
    if (!product?.image_url) {
      toast({ title: "এই প্রোডাক্টে কোনো ছবি নেই", variant: "destructive" });
      return;
    }

    setIsAiEditing(true);
    try {
      const { data, error } = await supabase.functions.invoke("product-image-proxy", {
        body: {
          image_url: product.image_url,
          product_id: productId,
          ai_edit: true,
          ai_prompt: prompt,
        },
      });
      if (error) throw error;
      if (data?.public_url) {
        await supabase.from("products").update({ image_url: data.public_url } as any).eq("id", productId);
        await supabase.from("product_images").insert({ product_id: productId, image_url: data.public_url, sort_order: 99 });
        queryClient.invalidateQueries({ queryKey: ["products"] });
        toast({ title: "ছবি AI দিয়ে এডিট হয়েছে!" });
      }
    } catch (err: any) {
      toast({ title: "AI এডিট ব্যর্থ", description: err.message, variant: "destructive" });
    } finally {
      setIsAiEditing(false);
      setShowAiEdit(false);
      setAiEditingProductId(null);
    }
  };

  const toggleVisibility = useMutation({
    mutationFn: async ({ id, show }: { id: string; show: boolean }) => {
      const { error } = await supabase.from("products").update({ show_in_store: show } as any).eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["products"] }); },
  });

  const deleteExistingImage = async (imageId: string) => {
    await supabase.from("product_images").delete().eq("id", imageId);
    setExistingImages(prev => prev.filter(img => img.id !== imageId));
  };

  const resetForm = () => {
    setForm({ name: "", category: "CCTV", brand: "Other", description: "", price: "", stock_quantity: "0", sku: "", cash_discount_price: "", discount_percentage: "0", show_in_store: true, call_for_price: false, is_featured: false, specifications: [] });
    setImageFile(null); setImagePreview(null);
    setAdditionalImages([]); setAdditionalPreviews([]); setExistingImages([]);
    setVariants([]); setDeletedVariantIds([]);
  };

  const openEdit = async (p: any) => {
    setEditing(p);

    let parsedDesc = p.description || "";
    let parsedSpecs = [];
    try {
      const obj = JSON.parse(p.description || "{}");
      if (obj && typeof obj === 'object' && obj.text !== undefined) {
        parsedDesc = obj.text;
        parsedSpecs = obj.specs || [];
      }
    } catch (e) {}

    setForm({
      name: p.name, category: p.category, brand: p.brand || "Other", description: parsedDesc,
      price: p.price.toString(), stock_quantity: p.stock_quantity.toString(), sku: p.sku || "",
      cash_discount_price: (p as any).cash_discount_price?.toString() || "",
      discount_percentage: p.discount_percentage?.toString() || "0",
      show_in_store: p.show_in_store,
      is_featured: p.is_featured || false,
      call_for_price: (p as any).call_for_price || false,
      specifications: parsedSpecs,
    });
    setImagePreview((p as any).image_url || null);
    setImageFile(null);
    setAdditionalImages([]); setAdditionalPreviews([]);
    const imgs = await fetchProductImages(p.id);
    setExistingImages(imgs);
    const { data: variantData } = await supabase.from("product_variants").select("*").eq("product_id", p.id).order("sort_order");
    setVariants(variantData || []);
    setDeletedVariantIds([]);
    setOpen(true);
  };

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) { setImageFile(file); setImagePreview(URL.createObjectURL(file)); }
  };

  const handleAdditionalImages = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (files.length > 0) {
      setAdditionalImages(prev => [...prev, ...files]);
      setAdditionalPreviews(prev => [...prev, ...files.map(f => URL.createObjectURL(f))]);
    }
  };

  const removeAdditionalImage = (index: number) => {
    setAdditionalImages(prev => prev.filter((_, i) => i !== index));
    setAdditionalPreviews(prev => prev.filter((_, i) => i !== index));
  };

  const catColor: Record<string, string> = { CCTV: "bg-info/10 text-info", "Attendance Device": "bg-accent/10 text-accent", Networking: "bg-warning/10 text-warning", Server: "bg-primary/10 text-primary" };

  return (
    <>
      <div className="space-y-6">
        <div className="flex items-center justify-between flex-wrap gap-4">
          <div>
            <h1 className="text-2xl font-bold tracking-tight">Products</h1>
            <p className="text-muted-foreground text-sm">
              {selectedCategory === "All" ? "All categories" : selectedCategory} — {filteredProducts.length} products
            </p>
          </div>
          <div className="flex items-center gap-2">
            {/* Multi-select toggle */}
            <Button
              variant={isMultiSelect ? "default" : "outline"}
              size="sm"
              onClick={() => { setIsMultiSelect(!isMultiSelect); setSelectedIds(new Set()); }}
            >
              <CheckSquare className="h-4 w-4 mr-1" />
              {isMultiSelect ? "সিলেক্ট মোড ON" : "মাল্টি সিলেক্ট"}
            </Button>

            <Dialog open={open} onOpenChange={(v) => { setOpen(v); if (!v) { setEditing(null); resetForm(); } }}>
              <DialogTrigger asChild><Button><Plus className="h-4 w-4 mr-2" />Add Product</Button></DialogTrigger>
              <DialogContent className="max-w-lg max-h-[90vh] overflow-y-auto">
                <DialogHeader><DialogTitle>{editing ? "Edit Product" : "Add Product"}</DialogTitle></DialogHeader>

                {/* Main Product Image */}
                <div className="space-y-2 border-b border-border pb-4">
                  <Label>Main Image</Label>
                  <div className="flex items-center gap-4">
                    <div className="h-24 w-24 rounded-lg border-2 border-dashed border-border bg-muted flex items-center justify-center overflow-hidden flex-shrink-0">
                      {imagePreview ? (
                        <img src={imagePreview} alt="Preview" className="h-full w-full object-cover" />
                      ) : (
                        <ImageIcon className="h-8 w-8 text-muted-foreground/40" />
                      )}
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="product-image" className="cursor-pointer">
                        <div className="flex items-center gap-2 text-sm text-primary hover:underline">
                          <Upload className="h-4 w-4" />
                          {imagePreview ? "Change image" : "Upload image"}
                        </div>
                      </Label>
                      <input id="product-image" type="file" accept="image/*" className="hidden" onChange={handleImageSelect} />
                      <p className="text-[10px] text-muted-foreground">JPG, PNG up to 5MB</p>
                    </div>
                  </div>
                </div>

                {/* Additional Images */}
                <div className="space-y-2 border-b border-border pb-4">
                  <div className="flex items-center justify-between">
                    <Label>Gallery Images</Label>
                    <Label htmlFor="additional-images" className="cursor-pointer">
                      <div className="flex items-center gap-1 text-xs text-primary hover:underline">
                        <Plus className="h-3 w-3" /> Add More
                      </div>
                    </Label>
                    <input id="additional-images" type="file" accept="image/*" multiple className="hidden" onChange={handleAdditionalImages} />
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {existingImages.map((img) => (
                      <div key={img.id} className="relative h-16 w-16 rounded-lg border border-border overflow-hidden group">
                        <img src={img.image_url} alt="" className="h-full w-full object-cover" />
                        <button onClick={() => deleteExistingImage(img.id)} className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                          <X className="h-4 w-4 text-white" />
                        </button>
                      </div>
                    ))}
                    {additionalPreviews.map((preview, i) => (
                      <div key={i} className="relative h-16 w-16 rounded-lg border border-border overflow-hidden group">
                        <img src={preview} alt="" className="h-full w-full object-cover" />
                        <button onClick={() => removeAdditionalImage(i)} className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                          <X className="h-4 w-4 text-white" />
                        </button>
                      </div>
                    ))}
                    {existingImages.length === 0 && additionalPreviews.length === 0 && (
                      <p className="text-[10px] text-muted-foreground">No gallery images yet</p>
                    )}
                  </div>
                </div>

                {/* Barcode Scanner */}
                <div className="space-y-3 border-b border-border pb-4">
                  <p className="text-sm text-muted-foreground flex items-center gap-2">
                    <ScanBarcode className="h-4 w-4" /> Scan barcode/QR or enter SKU
                  </p>
                  <div className="flex gap-2 items-end">
                    <div className="flex-1 space-y-1">
                      <Label>SKU / Barcode</Label>
                      <Input value={form.sku} onChange={(e) => setForm({ ...form, sku: e.target.value })} placeholder="Type or scan barcode..." />
                    </div>
                    <Button type="button" variant={cameraOpen ? "destructive" : "outline"} size="icon" onClick={() => setCameraOpen(!cameraOpen)}>
                      {cameraOpen ? <CameraOff className="h-4 w-4" /> : <Camera className="h-4 w-4" />}
                    </Button>
                  </div>
                  {cameraOpen && <div id="dialog-barcode-reader" className="rounded-lg overflow-hidden border border-border" />}
                </div>

                <form onSubmit={(e) => { e.preventDefault(); saveMutation.mutate({ ...form, _imageFile: imageFile, _additionalImages: additionalImages, _existingImages: existingImages, _editing: editing, _variants: variants, _deletedVariantIds: deletedVariantIds }); }} className="space-y-4">
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2"><Label>Name *</Label><Input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} required /></div>
                    <div className="space-y-2"><Label>Category</Label>
                      <Select value={form.category} onValueChange={(v) => setForm({ ...form, category: v })}>
                        <SelectTrigger><SelectValue /></SelectTrigger>
                        <SelectContent>{categories.map(c => <SelectItem key={c} value={c}>{c}</SelectItem>)}</SelectContent>
                      </Select>
                    </div>
                    <div className="space-y-2"><Label>Brand</Label>
                      <Select value={form.brand} onValueChange={(v) => setForm({ ...form, brand: v })}>
                        <SelectTrigger><SelectValue /></SelectTrigger>
                        <SelectContent>{brands.map(b => <SelectItem key={b} value={b}>{b}</SelectItem>)}</SelectContent>
                      </Select>
                    </div>
                  </div>

                  <div className="border border-border rounded-lg p-4 space-y-4">
                    <h4 className="text-sm font-semibold flex items-center gap-2"><Percent className="h-4 w-4 text-primary" /> Pricing & Discount</h4>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-2"><Label>Regular Price (৳) *</Label><Input type="number" value={form.price} onChange={(e) => handlePriceChange("price", e.target.value)} required /></div>
                      <div className="space-y-2"><Label>Cash Discount Price (৳)</Label><Input type="number" value={form.cash_discount_price} onChange={(e) => handlePriceChange("cash_discount_price", e.target.value)} placeholder="Optional" /></div>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-2"><Label>Discount %</Label><Input type="number" step="0.1" min="0" max="99" value={form.discount_percentage} onChange={(e) => handlePercentageChange(e.target.value)} /></div>
                      <div className="space-y-2"><Label>Stock</Label><Input type="number" value={form.stock_quantity} onChange={(e) => setForm({ ...form, stock_quantity: e.target.value })} /></div>
                    </div>
                    {Number(form.discount_percentage) > 0 && (
                      <p className="text-xs text-muted-foreground">💰 Save ৳{(Number(form.price) - Number(form.cash_discount_price)).toLocaleString()} ({form.discount_percentage}% off)</p>
                    )}
                  </div>

                  <div className="flex items-center justify-between border border-border rounded-lg p-4">
                    <div className="flex items-center gap-3">
                      {form.show_in_store ? <Eye className="h-4 w-4 text-primary" /> : <EyeOff className="h-4 w-4 text-muted-foreground" />}
                      <div>
                        <Label className="text-sm font-medium">Show in Online Store</Label>
                        <p className="text-[10px] text-muted-foreground">Toggle to show/hide this product from the public store</p>
                      </div>
                    </div>
                    <Switch checked={form.show_in_store} onCheckedChange={(v) => setForm({ ...form, show_in_store: v })} />
                  </div>

                  <div className="flex items-center justify-between border border-border rounded-lg p-4">
                    <div className="flex items-center gap-3">
                      <Star className={`h-4 w-4 ${form.is_featured ? "text-amber-500 fill-amber-500" : "text-muted-foreground"}`} />
                      <div>
                        <Label className="text-sm font-medium">Feature in Store (Top)</Label>
                        <p className="text-[10px] text-muted-foreground">Show this product first in the public store</p>
                      </div>
                    </div>
                    <Switch checked={form.is_featured} onCheckedChange={(v) => setForm({ ...form, is_featured: v })} />
                  </div>

                  <div className="flex items-center justify-between border border-border rounded-lg p-4">
                    <div className="flex items-center gap-3">
                      <Phone className="h-4 w-4 text-primary" />
                      <div>
                        <Label className="text-sm font-medium">Call for Price (মূল্য জানতে কল করুন)</Label>
                        <p className="text-[10px] text-muted-foreground">মূল্য গোপন রেখে সাইটে 'Call for Price' প্রদর্শন করুন</p>
                      </div>
                    </div>
                    <Switch checked={form.call_for_price} onCheckedChange={(v) => setForm({ ...form, call_for_price: v })} />
                  </div>

                  {/* Variants Section */}
                  <div className="border border-border rounded-lg p-4 space-y-3">
                    <div className="flex items-center justify-between">
                      <h4 className="text-sm font-semibold flex items-center gap-2"><Layers className="h-4 w-4 text-primary" /> Variants / Options</h4>
                      <Button type="button" variant="outline" size="sm" onClick={() => setVariants([...variants, { isNew: true, id: `new-${Date.now()}`, variant_label: "", variant_group: "Size", price: form.price || "0", stock_quantity: "0", sku: "", sort_order: variants.length }])}>
                        <Plus className="h-3 w-3 mr-1" /> Add Variant
                      </Button>
                    </div>
                    {variants.length === 0 && <p className="text-[10px] text-muted-foreground">No variants. Product will be sold as-is.</p>}
                    {variants.map((v, idx) => (
                      <div key={v.id} className="grid grid-cols-[1fr_80px_80px_60px_30px] gap-2 items-end">
                        <div className="space-y-1"><Label className="text-[10px]">Label *</Label><Input className="h-8 text-xs" placeholder="e.g. 8 Channel" value={v.variant_label} onChange={(e) => { const updated = [...variants]; updated[idx] = { ...v, variant_label: e.target.value }; setVariants(updated); }} /></div>
                        <div className="space-y-1"><Label className="text-[10px]">Price (৳)</Label><Input className="h-8 text-xs" type="number" value={v.price} onChange={(e) => { const updated = [...variants]; updated[idx] = { ...v, price: e.target.value }; setVariants(updated); }} /></div>
                        <div className="space-y-1"><Label className="text-[10px]">Stock</Label><Input className="h-8 text-xs" type="number" value={v.stock_quantity} onChange={(e) => { const updated = [...variants]; updated[idx] = { ...v, stock_quantity: e.target.value }; setVariants(updated); }} /></div>
                        <div className="space-y-1"><Label className="text-[10px]">Group</Label><Input className="h-8 text-xs" placeholder="Size" value={v.variant_group} onChange={(e) => { const updated = [...variants]; updated[idx] = { ...v, variant_group: e.target.value }; setVariants(updated); }} /></div>
                        <Button type="button" variant="ghost" size="icon" className="h-8 w-8" onClick={() => { if (!v.isNew) setDeletedVariantIds(prev => [...prev, v.id]); setVariants(variants.filter((_, i) => i !== idx)); }}>
                          <Trash2 className="h-3.5 w-3.5 text-destructive" />
                        </Button>
                      </div>
                    ))}
                  </div>

                  <div className="space-y-2"><Label>Description</Label><Textarea value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })} /></div>

                  {/* Specifications Builder */}
                  <div className="space-y-3 pt-2 border-t">
                    <div className="flex items-center justify-between">
                      <h4 className="text-sm font-semibold">Specifications</h4>
                      <Button type="button" variant="outline" size="sm" onClick={() => setForm({ ...form, specifications: [...form.specifications, { feature: "", description: "" }] })}>
                        <Plus className="h-3 w-3 mr-1" /> Add Spec
                      </Button>
                    </div>
                    {form.specifications.length === 0 && <p className="text-[10px] text-muted-foreground">No specifications added. Click 'Add Spec' to build a specification table.</p>}
                    {form.specifications.map((spec, idx) => (
                      <div key={idx} className="grid grid-cols-[1fr_2fr_30px] gap-2 items-end">
                        <div className="space-y-1"><Label className="text-[10px]">Feature</Label><Input className="h-8 text-xs" placeholder="e.g. Brand" value={spec.feature} onChange={(e) => { const updated = [...form.specifications]; updated[idx].feature = e.target.value; setForm({ ...form, specifications: updated }); }} /></div>
                        <div className="space-y-1"><Label className="text-[10px]">Description</Label><Input className="h-8 text-xs" placeholder="e.g. Hikvision" value={spec.description} onChange={(e) => { const updated = [...form.specifications]; updated[idx].description = e.target.value; setForm({ ...form, specifications: updated }); }} /></div>
                        <Button type="button" variant="ghost" size="icon" className="h-8 w-8" onClick={() => { const updated = [...form.specifications]; updated.splice(idx, 1); setForm({ ...form, specifications: updated }); }}>
                          <Trash2 className="h-3.5 w-3.5 text-destructive" />
                        </Button>
                      </div>
                    ))}
                  </div>
                  <Button type="submit" className="w-full" disabled={saveMutation.isPending || uploading}>
                    {uploading ? "Uploading..." : editing ? "Update" : "Add"} Product
                  </Button>
                </form>
              </DialogContent>
            </Dialog>
          </div>
        </div>

        {/* Multi-select toolbar */}
        {isMultiSelect && (
          <div className="flex flex-wrap items-center gap-3 p-3 rounded-lg border border-primary/20 bg-primary/5">
            <span className="text-sm font-medium">{selectedIds.size}টি সিলেক্টেড</span>
            <Button variant="outline" size="sm" className="h-7 text-xs" onClick={selectAll}>
              সব সিলেক্ট ({filteredProducts.length})
            </Button>
            <Button variant="ghost" size="sm" className="h-7 text-xs" onClick={deselectAll}>ক্লিয়ার</Button>
            <div className="flex items-center gap-2 ml-auto">
              <Select value={bulkCategoryValue} onValueChange={handleBulkCategoryChange}>
                <SelectTrigger className="w-40 h-7 text-xs border-primary/30">
                  <SelectValue placeholder="ক্যাটাগরি চেঞ্জ" />
                </SelectTrigger>
                <SelectContent>
                  {categories.map((c) => <SelectItem key={c} value={c}>{c}</SelectItem>)}
                </SelectContent>
              </Select>
              {savingBulkCategory && <Loader2 className="h-4 w-4 animate-spin" />}

              <Button
                variant="outline"
                size="sm"
                className="h-7 text-xs border-emerald-500/30 text-emerald-600 hover:bg-emerald-50 hover:text-emerald-700 dark:hover:bg-emerald-950/20"
                onClick={() => handleBulkShowChange(true)}
                disabled={selectedIds.size === 0 || savingBulkShow}
              >
                {savingBulkShow ? <Loader2 className="h-3 w-3 mr-1 animate-spin" /> : <Eye className="h-3 w-3 mr-1" />}
                অনলাইন দেখান
              </Button>

              <Button
                variant="outline"
                size="sm"
                className="h-7 text-xs border-muted-foreground/30 text-muted-foreground hover:bg-muted/50"
                onClick={() => handleBulkShowChange(false)}
                disabled={selectedIds.size === 0 || savingBulkShow}
              >
                {savingBulkShow ? <Loader2 className="h-3 w-3 mr-1 animate-spin" /> : <EyeOff className="h-3 w-3 mr-1" />}
                স্টোর থেকে সরান
              </Button>

              <Button
                variant="outline"
                size="sm"
                className="h-7 text-xs border-amber-500/30 text-amber-600 hover:bg-amber-50 hover:text-amber-700 dark:hover:bg-amber-950/20"
                onClick={() => handleBulkFeatureChange(true)}
                disabled={selectedIds.size === 0 || savingBulkShow}
              >
                {savingBulkShow ? <Loader2 className="h-3 w-3 mr-1 animate-spin" /> : <Star className="h-3 w-3 mr-1" />}
                Top Feature
              </Button>

              <Button
                variant="destructive"
                size="sm"
                className="h-7 text-xs"
                onClick={() => setBulkDeleteConfirm(true)}
                disabled={selectedIds.size === 0 || isDeleting}
              >
                {isDeleting ? <Loader2 className="h-3 w-3 mr-1 animate-spin" /> : <Trash2 className="h-3 w-3 mr-1" />}
                {selectedIds.size}টি ডিলিট করুন
              </Button>
            </div>
          </div>
        )}

        {/* Category Tabs */}
        <div className="flex flex-col gap-3">
          <div className="flex items-center gap-2 overflow-x-auto scrollbar-hide pb-1">
            {["All", ...categories].map(cat => {
              const count = categoryCounts[cat] || 0;
              const isActive = selectedCategory === cat;
              return (
                <button
                  key={cat}
                  onClick={() => setSelectedCategory(cat)}
                  className={`flex items-center gap-1.5 px-3 py-2 rounded-lg text-xs font-medium whitespace-nowrap transition-all flex-shrink-0 border ${
                    isActive
                      ? "bg-primary text-primary-foreground border-primary shadow-md"
                      : "bg-card text-muted-foreground border-border hover:bg-accent hover:text-accent-foreground"
                  }`}
                >
                  {cat}
                  <Badge variant={isActive ? "secondary" : "outline"} className="text-[10px] px-1.5 py-0 h-4 min-w-[1.25rem] justify-center">{count}</Badge>
                </button>
              );
            })}
          </div>

          <div className="relative max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input placeholder="Search by name, SKU, or brand..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="pl-9" />
          </div>
        </div>

        <Card className="glass-card">
          <CardContent className="p-0">
            <Table>
              <TableHeader>
                <TableRow>
                  {isMultiSelect && <TableHead className="w-10"></TableHead>}
                  <TableHead className="w-12">Image</TableHead>
                  <TableHead>Name</TableHead>
                  <TableHead>Category</TableHead>
                  <TableHead>Brand</TableHead>
                  <TableHead>Regular Price</TableHead>
                  <TableHead>Cash Price</TableHead>
                  <TableHead>Discount</TableHead>
                  <TableHead>Stock</TableHead>
                  <TableHead className="w-16">Store</TableHead>
                  <TableHead className="w-28">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {filteredProducts?.map((p: any) => (
                  <TableRow key={p.id} className={`${!p.show_in_store ? "opacity-50" : ""} ${selectedIds.has(p.id) ? "bg-primary/5" : ""}`}>
                    {isMultiSelect && (
                      <TableCell>
                        <Checkbox checked={selectedIds.has(p.id)} onCheckedChange={() => toggleSelect(p.id)} />
                      </TableCell>
                    )}
                    <TableCell>
                      <div className="h-10 w-10 rounded-md bg-muted overflow-hidden flex items-center justify-center">
                        {p.image_url ? (
                          <img src={p.image_url} alt={p.name} className="h-full w-full object-cover" />
                        ) : (
                          <ImageIcon className="h-4 w-4 text-muted-foreground/40" />
                        )}
                      </div>
                    </TableCell>
                    <TableCell className="font-medium">
                      {p.name}
                      {p.is_featured && <Badge className="ml-2 text-[10px] bg-amber-500 hover:bg-amber-600 text-white border-0 shadow-sm"><Star className="h-2 w-2 mr-1 fill-white" /> Top</Badge>}
                      {variantCounts?.[p.id] ? <Badge variant="secondary" className="ml-2 text-[10px]">{variantCounts[p.id]} variants</Badge> : null}
                    </TableCell>
                    <TableCell><Badge variant="outline" className={catColor[p.category] || ""}>{p.category}</Badge></TableCell>
                    <TableCell><span className="text-xs text-muted-foreground">{(p as any).brand || "—"}</span></TableCell>
                    <TableCell>
                      {p.call_for_price ? (
                        <Badge variant="outline" className="bg-amber-500/10 text-amber-500 font-semibold border-amber-500/30 whitespace-nowrap">Call for Price</Badge>
                      ) : (
                        `৳${Number(p.price).toLocaleString()}`
                      )}
                    </TableCell>
                    <TableCell>
                      {p.cash_discount_price ? (
                        <span className="text-primary font-medium">৳{Number(p.cash_discount_price).toLocaleString()}</span>
                      ) : "—"}
                    </TableCell>
                    <TableCell>
                      {Number(p.discount_percentage) > 0 ? (
                        <Badge variant="outline" className="bg-primary/10 text-primary">{p.discount_percentage}%</Badge>
                      ) : "—"}
                    </TableCell>
                    <TableCell><span className={Number(p.stock_quantity) <= 5 ? "text-destructive font-medium" : ""}>{p.stock_quantity}</span></TableCell>
                    <TableCell>
                      <Switch checked={p.show_in_store !== false} onCheckedChange={(v) => toggleVisibility.mutate({ id: p.id, show: v })} className="scale-75" />
                    </TableCell>
                    <TableCell>
                      <div className="flex gap-1">
                        <Button variant="ghost" size="icon" onClick={() => openEdit(p)}><Pencil className="h-4 w-4" /></Button>
                        <Button variant="ghost" size="icon" onClick={() => { setAiEditingProductId(p.id); setShowAiEdit(true); setAiEditPrompt(""); }} title="AI ছবি এডিট">
                          <Wand2 className="h-4 w-4 text-primary" />
                        </Button>
                        <Button variant="ghost" size="icon" onClick={() => setDeleteConfirmId(p.id)}><Trash2 className="h-4 w-4 text-destructive" /></Button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))}
                {filteredProducts.length === 0 && <TableRow><TableCell colSpan={isMultiSelect ? 12 : 11} className="text-center text-muted-foreground py-8">No products found</TableCell></TableRow>}
              </TableBody>
            </Table>
          </CardContent>
        </Card>

        {/* AI Image Edit Dialog */}
        <Dialog open={showAiEdit} onOpenChange={setShowAiEdit}>
          <DialogContent className="max-w-md bg-[#0f0a1f]/95 border-white/10 backdrop-blur-2xl text-white shadow-2xl shadow-primary/20">
            <DialogHeader>
              <DialogTitle className="flex items-center gap-2.5 text-xl font-bold tracking-tight text-gradient">
                <div className="p-2 rounded-xl bg-primary/10 border border-primary/20">
                  <Wand2 className="h-5 w-5 text-primary" />
                </div>
                AI ছবি এডিট ও পোস্টার
              </DialogTitle>
            </DialogHeader>
            <div className="space-y-6 pt-4">
              {/* Current Image Preview */}
              {aiEditingProductId && (
                <div className="relative group aspect-video rounded-2xl overflow-hidden bg-black/40 border border-white/5 shadow-inner">
                  {products?.find((p: any) => p.id === aiEditingProductId)?.image_url ? (
                    <img 
                      src={products.find((p: any) => p.id === aiEditingProductId)!.image_url} 
                      alt="" 
                      className="w-full h-full object-contain transition-transform duration-500 group-hover:scale-105" 
                    />
                  ) : (
                    <div className="absolute inset-0 flex items-center justify-center">
                      <ImageIcon className="h-12 w-12 text-white/10" />
                    </div>
                  )}
                  <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
                </div>
              )}

              {/* Quick Suggestions */}
              <div className="space-y-3">
                <Label className="text-[10px] uppercase tracking-[0.2em] font-bold text-primary/80">AI সাজেশন — এক ক্লিকে:</Label>
                <div className="grid grid-cols-1 gap-2.5">
                  {aiSuggestions.map((s, i) => (
                    <Button
                      key={i}
                      variant="outline"
                      size="sm"
                      className="group justify-start text-xs h-auto py-3 px-4 rounded-xl border-white/5 bg-white/5 hover:bg-primary/20 hover:border-primary/30 hover:text-white transition-all"
                      disabled={isAiEditing}
                      onClick={() => aiEditingProductId && handleAiEditImage(aiEditingProductId, s.prompt)}
                    >
                      <div className="p-1.5 rounded-lg bg-primary/10 group-hover:bg-primary/20 mr-3 transition-colors">
                        <Wand2 className="h-3.5 w-3.5 text-primary" />
                      </div>
                      {s.label}
                    </Button>
                  ))}
                </div>
              </div>

              <div className="h-px bg-gradient-to-r from-transparent via-white/10 to-transparent" />

              {/* Custom prompt */}
              <div className="space-y-3">
                <Label className="text-[10px] uppercase tracking-[0.2em] font-bold text-primary/80">অথবা নিজের ইন্সট্রাকশন লিখুন:</Label>
                <div className="relative">
                  <Input
                    value={aiEditPrompt}
                    onChange={(e) => setAiEditPrompt(e.target.value)}
                    placeholder="e.g. এই ছবিটিকে একটি প্রিমিয়াম সেল পোস্টার বানান..."
                    className="bg-white/5 border-white/10 rounded-xl pl-4 pr-10 py-6 text-sm placeholder:text-white/20 focus:border-primary/40 focus:ring-primary/20 transition-all"
                    disabled={isAiEditing}
                  />
                  <div className="absolute right-3 top-1/2 -translate-y-1/2 p-1.5 bg-primary/10 rounded-lg">
                    <Search className="h-3.5 w-3.5 text-primary/50" />
                  </div>
                </div>
                <Button
                  className="w-full py-6 rounded-xl bg-gradient-to-r from-primary to-accent hover:from-primary/90 hover:to-accent/90 shadow-lg shadow-primary/25 font-bold tracking-wide transition-all hover:scale-[1.02] active:scale-[0.98]"
                  disabled={isAiEditing || !aiEditPrompt.trim()}
                  onClick={() => aiEditingProductId && handleAiEditImage(aiEditingProductId, aiEditPrompt)}
                >
                  {isAiEditing ? (
                    <><Loader2 className="h-4 w-4 mr-2 animate-spin" />AI কাজ করছে...</>
                  ) : (
                    <><Wand2 className="h-4 w-4 mr-2" />AI দিয়ে জেনারেট করুন</>
                  )}
                </Button>
              </div>
            </div>
          </DialogContent>
        </Dialog>
      </div>

      {/* Single Delete Confirmation */}
      <ConfirmDeleteDialog
        open={!!deleteConfirmId}
        onOpenChange={(open) => !open && setDeleteConfirmId(null)}
        onConfirm={() => {
          if (deleteConfirmId) {
            deleteMutation.mutate(deleteConfirmId);
            setDeleteConfirmId(null);
          }
        }}
        title="প্রোডাক্ট স্থায়ীভাবে ডিলিট করুন"
        itemName={products?.find((p: any) => p.id === deleteConfirmId)?.name}
      />

      {/* Bulk Delete Confirmation */}
      <ConfirmDeleteDialog
        open={bulkDeleteConfirm}
        onOpenChange={setBulkDeleteConfirm}
        onConfirm={() => {
          setBulkDeleteConfirm(false);
          handleBulkDelete();
        }}
        title={`${selectedIds.size}টি প্রোডাক্ট স্থায়ীভাবে ডিলিট করুন`}
        description={`আপনি কি নিশ্চিত যে ${selectedIds.size}টি প্রোডাক্ট স্থায়ীভাবে ডিলিট করতে চান? এই কাজটি পূর্বাবস্থায় ফেরানো যাবে না।`}
        loading={isDeleting}
      />
    </>
  );
}

import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent } from "@/components/ui/card";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { Calendar } from "@/components/ui/calendar";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { cn } from "@/lib/utils";
import { format } from "date-fns";
import { Plus, Pencil, Trash2, CalendarIcon, Upload, ImageIcon, X, ListPlus, Eye, EyeOff } from "lucide-react";
import { Switch } from "@/components/ui/switch";
import { useToast } from "@/hooks/use-toast";
import { ConfirmDeleteDialog } from "@/components/ConfirmDeleteDialog";

export default function Projects() {
  const [open, setOpen] = useState(false);
  const [editing, setEditing] = useState<any>(null);
  const [form, setForm] = useState({ title: "", description: "", client_id: "", status: "pending", priority: "medium", budget: "", show_in_store: false });
  const [startDate, setStartDate] = useState<Date | undefined>(new Date());
  const [endDate, setEndDate] = useState<Date | undefined>(undefined);
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [includedItems, setIncludedItems] = useState<string[]>([]);
  const [newItem, setNewItem] = useState("");
  const [uploading, setUploading] = useState(false);
  const queryClient = useQueryClient();
  const { toast } = useToast();
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);

  const { data: projects } = useQuery({ queryKey: ["projects"], queryFn: async () => (await supabase.from("projects").select("*, clients(name)").order("created_at", { ascending: false })).data || [] });
  const { data: clients } = useQuery({ queryKey: ["clients"], queryFn: async () => (await supabase.from("clients").select("id, name")).data || [] });

  const uploadImage = async (projectId: string): Promise<string | null> => {
    if (!imageFile) return null;
    const ext = imageFile.name.split('.').pop();
    const filePath = `${projectId}.${ext}`;
    const { error } = await supabase.storage.from("package-images").upload(filePath, imageFile, { upsert: true });
    if (error) throw error;
    const { data } = supabase.storage.from("package-images").getPublicUrl(filePath);
    return data.publicUrl;
  };

  const saveMutation = useMutation({
    mutationFn: async () => {
      setUploading(true);
      const payload: any = {
        title: form.title, description: form.description,
        client_id: form.client_id || null,
        budget: form.budget ? Number(form.budget) : null,
        start_date: startDate ? format(startDate, "yyyy-MM-dd") : null,
        end_date: endDate ? format(endDate, "yyyy-MM-dd") : null,
        status: form.status, priority: form.priority,
        included_items: includedItems,
        show_in_store: form.show_in_store,
      };
      let projectId = editing?.id;
      if (editing) {
        const { error } = await supabase.from("projects").update(payload).eq("id", editing.id);
        if (error) throw error;
      } else {
        const { data: inserted, error } = await supabase.from("projects").insert(payload).select().single();
        if (error) throw error;
        projectId = inserted.id;
      }
      if (imageFile && projectId) {
        const imageUrl = await uploadImage(projectId);
        if (imageUrl) {
          await supabase.from("projects").update({ image_url: imageUrl } as any).eq("id", projectId);
        }
      }
    },
    onSuccess: () => { setUploading(false); queryClient.invalidateQueries({ queryKey: ["projects"] }); setOpen(false); setEditing(null); resetForm(); toast({ title: editing ? "Package updated" : "Package created" }); },
    onError: (err: any) => { setUploading(false); toast({ title: "Error", description: err.message, variant: "destructive" }); },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => { const { error } = await supabase.from("projects").delete().eq("id", id); if (error) throw error; },
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["projects"] }); toast({ title: "Package deleted" }); },
  });

  const toggleVisibility = useMutation({
    mutationFn: async ({ id, show }: { id: string; show: boolean }) => {
      const { error } = await supabase.from("projects").update({ show_in_store: show } as any).eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ["projects"] }),
  });

  const resetForm = () => {
    setForm({ title: "", description: "", client_id: "", status: "pending", priority: "medium", budget: "", show_in_store: false });
    setStartDate(new Date()); setEndDate(undefined);
    setImageFile(null); setImagePreview(null);
    setIncludedItems([]); setNewItem("");
  };

  const openEdit = (p: any) => {
    setEditing(p);
    setForm({ title: p.title, description: p.description || "", client_id: p.client_id || "", status: p.status, priority: p.priority, budget: p.budget?.toString() || "", show_in_store: (p as any).show_in_store === true });
    setStartDate(p.start_date ? new Date(p.start_date) : new Date());
    setEndDate(p.end_date ? new Date(p.end_date) : undefined);
    setImagePreview((p as any).image_url || null);
    setImageFile(null);
    setIncludedItems(Array.isArray((p as any).included_items) ? (p as any).included_items : []);
    setNewItem("");
    setOpen(true);
  };

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) { setImageFile(file); setImagePreview(URL.createObjectURL(file)); }
  };

  const addItem = () => {
    if (newItem.trim()) {
      setIncludedItems([...includedItems, newItem.trim()]);
      setNewItem("");
    }
  };

  const removeItem = (index: number) => {
    setIncludedItems(includedItems.filter((_, i) => i !== index));
  };

  const statusColor: Record<string, string> = { pending: "bg-warning/10 text-warning", in_progress: "bg-info/10 text-info", completed: "bg-success/10 text-success", cancelled: "bg-destructive/10 text-destructive" };
  const priorityColor: Record<string, string> = { low: "bg-muted text-muted-foreground", medium: "bg-warning/10 text-warning", high: "bg-destructive/10 text-destructive" };

  return (
    <>
      <div className="space-y-6">
        <div className="flex items-center justify-between">
          <div><h1 className="text-2xl font-bold tracking-tight">Packages</h1><p className="text-muted-foreground text-sm">Manage camera & IT solution packages for the online store</p></div>
          <Dialog open={open} onOpenChange={(v) => { setOpen(v); if (!v) { setEditing(null); resetForm(); } }}>
            <DialogTrigger asChild><Button><Plus className="h-4 w-4 mr-2" />New Package</Button></DialogTrigger>
            <DialogContent className="max-w-lg max-h-[90vh] overflow-y-auto">
              <DialogHeader><DialogTitle>{editing ? "Edit Package" : "New Package"}</DialogTitle></DialogHeader>

              {/* Package Image */}
              <div className="space-y-2 border-b border-border pb-4">
                <Label>Package Image</Label>
                <div className="flex items-center gap-4">
                  <div className="h-24 w-24 rounded-lg border-2 border-dashed border-border bg-muted flex items-center justify-center overflow-hidden flex-shrink-0">
                    {imagePreview ? (
                      <img src={imagePreview} alt="Preview" className="h-full w-full object-cover" />
                    ) : (
                      <ImageIcon className="h-8 w-8 text-muted-foreground/40" />
                    )}
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="package-image" className="cursor-pointer">
                      <div className="flex items-center gap-2 text-sm text-primary hover:underline">
                        <Upload className="h-4 w-4" />
                        {imagePreview ? "Change image" : "Upload image"}
                      </div>
                    </Label>
                    <input id="package-image" type="file" accept="image/*" className="hidden" onChange={handleImageSelect} />
                    <p className="text-[10px] text-muted-foreground">JPG, PNG up to 5MB</p>
                  </div>
                </div>
              </div>

              <form onSubmit={(e) => { e.preventDefault(); saveMutation.mutate(); }} className="space-y-4">
                <div className="space-y-2"><Label>Title *</Label><Input value={form.title} onChange={(e) => setForm({ ...form, title: e.target.value })} required /></div>
                <div className="space-y-2"><Label>Description</Label><Textarea value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })} /></div>

                {/* Included Items */}
                <div className="space-y-3 border border-border rounded-lg p-4">
                  <Label className="flex items-center gap-2"><ListPlus className="h-4 w-4 text-primary" /> Package Includes</Label>
                  <div className="flex gap-2">
                    <Input
                      value={newItem}
                      onChange={(e) => setNewItem(e.target.value)}
                      placeholder="e.g. 4x CCTV Camera, 1x DVR 8CH..."
                      onKeyDown={(e) => { if (e.key === "Enter") { e.preventDefault(); addItem(); } }}
                    />
                    <Button type="button" variant="outline" size="sm" onClick={addItem}>Add</Button>
                  </div>
                  {includedItems.length > 0 && (
                    <div className="flex flex-wrap gap-2 mt-2">
                      {includedItems.map((item, i) => (
                        <Badge key={i} variant="secondary" className="gap-1 pr-1">
                          {item}
                          <button type="button" onClick={() => removeItem(i)} className="ml-1 hover:text-destructive">
                            <X className="h-3 w-3" />
                          </button>
                        </Badge>
                      ))}
                    </div>
                  )}
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2"><Label>Client</Label>
                    <Select value={form.client_id} onValueChange={(v) => setForm({ ...form, client_id: v })}>
                      <SelectTrigger><SelectValue placeholder="Select client" /></SelectTrigger>
                      <SelectContent>{clients?.map(c => <SelectItem key={c.id} value={c.id}>{c.name}</SelectItem>)}</SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label>Budget (৳)</Label>
                    <Input type="number" value={form.budget} onChange={(e) => setForm({ ...form, budget: e.target.value })} />
                  </div>
                  <div className="space-y-2"><Label>Status</Label>
                    <Select value={form.status} onValueChange={(v) => setForm({ ...form, status: v })}>
                      <SelectTrigger><SelectValue /></SelectTrigger>
                      <SelectContent><SelectItem value="pending">Pending</SelectItem><SelectItem value="in_progress">In Progress</SelectItem><SelectItem value="completed">Completed</SelectItem><SelectItem value="cancelled">Cancelled</SelectItem></SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2"><Label>Priority</Label>
                    <Select value={form.priority} onValueChange={(v) => setForm({ ...form, priority: v })}>
                      <SelectTrigger><SelectValue /></SelectTrigger>
                      <SelectContent><SelectItem value="low">Low</SelectItem><SelectItem value="medium">Medium</SelectItem><SelectItem value="high">High</SelectItem></SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label>Start Date</Label>
                    <Popover>
                      <PopoverTrigger asChild>
                        <Button variant="outline" className={cn("w-full justify-start text-left font-normal", !startDate && "text-muted-foreground")}>
                          <CalendarIcon className="mr-2 h-4 w-4" />
                          {startDate ? format(startDate, "PPP") : <span>Pick a date</span>}
                        </Button>
                      </PopoverTrigger>
                      <PopoverContent className="w-auto p-0" align="start">
                        <Calendar mode="single" selected={startDate} onSelect={setStartDate} initialFocus className={cn("p-3 pointer-events-auto")} />
                      </PopoverContent>
                    </Popover>
                  </div>
                  <div className="space-y-2">
                    <Label>End Date</Label>
                    <Popover>
                      <PopoverTrigger asChild>
                        <Button variant="outline" className={cn("w-full justify-start text-left font-normal", !endDate && "text-muted-foreground")}>
                          <CalendarIcon className="mr-2 h-4 w-4" />
                          {endDate ? format(endDate, "PPP") : <span>Pick a date</span>}
                        </Button>
                      </PopoverTrigger>
                      <PopoverContent className="w-auto p-0" align="start">
                        <Calendar mode="single" selected={endDate} onSelect={setEndDate} initialFocus className={cn("p-3 pointer-events-auto")} />
                      </PopoverContent>
                    </Popover>
                  </div>
                </div>
                {/* Show in Store Toggle */}
                <div className="flex items-center justify-between border border-border rounded-lg p-4">
                  <div className="flex items-center gap-3">
                    {form.show_in_store ? <Eye className="h-4 w-4 text-primary" /> : <EyeOff className="h-4 w-4 text-muted-foreground" />}
                    <div>
                      <Label className="text-sm font-medium">Show in Online Store</Label>
                      <p className="text-[10px] text-muted-foreground">Make this package visible to customers</p>
                    </div>
                  </div>
                  <Switch checked={form.show_in_store} onCheckedChange={(v) => setForm({ ...form, show_in_store: v })} />
                </div>

                <Button type="submit" className="w-full" disabled={saveMutation.isPending || uploading}>
                  {uploading ? "Uploading..." : editing ? "Update" : "Create"} Package
                </Button>
              </form>
            </DialogContent>
          </Dialog>
        </div>
        <Card className="glass-card">
          <CardContent className="p-0">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead className="w-12">Image</TableHead>
                  <TableHead>Title</TableHead>
                  <TableHead>Includes</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead>Store</TableHead>
                  <TableHead>Budget</TableHead>
                  <TableHead className="w-24">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {projects?.map((p) => (
                  <TableRow key={p.id} className={!(p as any).show_in_store ? "opacity-50" : ""}>
                    <TableCell>
                      <div className="h-10 w-10 rounded-md bg-muted overflow-hidden flex items-center justify-center">
                        {(p as any).image_url ? (
                          <img src={(p as any).image_url} alt={p.title} className="h-full w-full object-cover" />
                        ) : (
                          <ImageIcon className="h-4 w-4 text-muted-foreground/40" />
                        )}
                      </div>
                    </TableCell>
                    <TableCell className="font-medium">{p.title}</TableCell>
                    <TableCell>
                      <div className="flex flex-wrap gap-1 max-w-[200px]">
                        {Array.isArray((p as any).included_items) && (p as any).included_items.length > 0
                          ? (p as any).included_items.slice(0, 3).map((item: string, i: number) => (
                              <Badge key={i} variant="secondary" className="text-[10px]">{item}</Badge>
                            ))
                          : <span className="text-muted-foreground text-xs">—</span>
                        }
                        {Array.isArray((p as any).included_items) && (p as any).included_items.length > 3 && (
                          <Badge variant="outline" className="text-[10px]">+{(p as any).included_items.length - 3}</Badge>
                        )}
                      </div>
                    </TableCell>
                    <TableCell><Badge variant="outline" className={statusColor[p.status] || ""}>{(p.status || "pending").replace("_", " ")}</Badge></TableCell>
                    <TableCell>
                      <Switch
                        checked={(p as any).show_in_store === true}
                        onCheckedChange={(v) => toggleVisibility.mutate({ id: p.id, show: v })}
                        className="scale-75"
                      />
                    </TableCell>
                    <TableCell>{p.budget ? `৳${Number(p.budget).toLocaleString()}` : "—"}</TableCell>
                    <TableCell><div className="flex gap-1"><Button variant="ghost" size="icon" onClick={() => openEdit(p)}><Pencil className="h-4 w-4" /></Button><Button variant="ghost" size="icon" onClick={() => setDeleteConfirmId(p.id)}><Trash2 className="h-4 w-4 text-destructive" /></Button></div></TableCell>
                  </TableRow>
                ))}
                {(!projects || projects.length === 0) && <TableRow><TableCell colSpan={7} className="text-center text-muted-foreground py-8">No packages yet</TableCell></TableRow>}
              </TableBody>
            </Table>
          </CardContent>
        </Card>
      </div>

      <ConfirmDeleteDialog
        open={!!deleteConfirmId}
        onOpenChange={(open) => !open && setDeleteConfirmId(null)}
        onConfirm={() => {
          if (deleteConfirmId) {
            deleteMutation.mutate(deleteConfirmId);
            setDeleteConfirmId(null);
          }
        }}
        title="স্থায়ীভাবে ডিলিট করুন"
      />
    </>
);
}

