const statusColors: Record<string, string> = {
  draft: "bg-muted text-muted-foreground",
  sent: "bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-400",
  accepted: "bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400",
  rejected: "bg-destructive/10 text-destructive",
  expired: "bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-400",
};

export default function Quotations() {
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const { toast } = useToast();
  const { settings } = useCompanySettings();
  const [previewQuotation, setPreviewQuotation] = useState<any>(null);
  const [downloading, setDownloading] = useState(false);
  const [downloadingId, setDownloadingId] = useState<string | null>(null);
  const [whatsappId, setWhatsappId] = useState<string | null>(null);

  const { data: quotations, isLoading } = useQuery({
    queryKey: ["quotations"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("quotations")
        .select("*, clients(name, address)")
        .order("created_at", { ascending: false });
      if (error) throw error;
      return data || [];
    },
  });

  const convertToInvoiceMutation = useMutation({
    mutationFn: async (q: any) => {
      // Fetch quotation items
      const { data: qItems } = await supabase.from("quotation_items").select("*").eq("quotation_id", q.id);
      // Generate invoice number
      const { data: invNum } = await supabase.rpc("generate_invoice_number");
      // Create invoice
      const { data: invoice, error: invError } = await supabase.from("invoices").insert({
        invoice_number: invNum,
        client_id: q.client_id,
        issue_date: new Date().toISOString().split("T")[0],
        subtotal: q.subtotal,
        tax_rate: q.tax_rate,
        tax_amount: q.tax_amount,
        total: q.total,
        status: "draft",
        notes: q.notes ? `Converted from ${q.quotation_number}. ${q.notes}` : `Converted from ${q.quotation_number}`,
      }).select().single();
      if (invError) throw invError;
      // Copy items
      if (qItems?.length) {
        const invoiceItems = qItems.map((item: any) => ({
          invoice_id: invoice.id,
          description: item.description,
          quantity: item.quantity,
          unit_price: item.unit_price,
          total: item.total,
        }));
        const { error: itemsError } = await supabase.from("invoice_items").insert(invoiceItems);
        if (itemsError) throw itemsError;
      }
      // Update quotation status to accepted
      await supabase.from("quotations").update({ status: "accepted" }).eq("id", q.id);
      return invoice;
    },
    onSuccess: (invoice) => {
      queryClient.invalidateQueries({ queryKey: ["quotations"] });
      toast({ title: "Invoice created!", description: `Invoice ${invoice.invoice_number} created from quotation.` });
      navigate("/invoices");
    },
    onError: (err: any) => {
      toast({ title: "Conversion failed", description: err.message, variant: "destructive" });
    },
  });

  const updateStatusMutation = useMutation({
    mutationFn: async ({ id, status }: { id: string; status: string }) => {
      const { error } = await supabase.from("quotations").update({ status }).eq("id", id);
      if (error) throw error;
      return status;
    },
    onSuccess: (status) => {
      queryClient.invalidateQueries({ queryKey: ["quotations"] });
      toast({ title: `Quotation marked as ${status}` });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("quotations").delete().eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["quotations"] });
      toast({ title: "Quotation deleted" });
    },
  });

  const viewQuotation = async (q: any) => {
    const { data: items } = await supabase.from("quotation_items").select("*").eq("quotation_id", q.id);
    setPreviewQuotation({ ...q, items: items || [] });
  };


  const generateVectorPdf = async (
    quotation: any,
    settings: any,
    fileName: string,
    options: { skipDownload?: boolean } = {}
  ): Promise<Blob | null> => {
    const doc = new jsPDF({ orientation: "portrait", unit: "mm", format: "a4" });
    const pageWidth = doc.internal.pageSize.getWidth();
    let y = 20;

    // Header
    doc.setFillColor(13, 148, 136); // #0d9488
    doc.roundedRect(pageWidth - 50, 15, 35, 12, 2, 2, "F");
    doc.setTextColor(255, 255, 255);
    doc.setFont("helvetica", "bold");
    doc.setFontSize(14);
    doc.text("QUOTATION", pageWidth - 32.5, 23, { align: "center" });

    doc.setTextColor(17, 24, 39);
    doc.setFontSize(22);
    doc.text(settings.company_name || "AK IT Solution", 15, y);
    y += 5;

    doc.setFont("helvetica", "normal");
    doc.setFontSize(10);
    doc.setTextColor(107, 114, 128);
    if (settings.company_tagline) {
      doc.text(settings.company_tagline, 15, y);
      y += 5;
    }

    doc.setFontSize(9);
    if (settings.address) { doc.text(`Address: ${settings.address}`, 15, y); y += 4; }
    if (settings.phone) { doc.text(`Phone: ${settings.phone}`, 15, y); y += 4; }
    if (settings.email) { doc.text(`Email: ${settings.email}`, 15, y); y += 4; }

    // Quotation details
    doc.setTextColor(31, 41, 55);
    doc.setFont("helvetica", "bold");
    doc.setFontSize(12);
    doc.text(quotation.quotation_number, pageWidth - 15, 33, { align: "right" });

    doc.setFont("helvetica", "normal");
    doc.setFontSize(10);
    doc.setTextColor(107, 114, 128);
    doc.text(`Date: ${new Date(quotation.issue_date).toLocaleDateString("en-GB")}`, pageWidth - 15, 39, { align: "right" });
    if (quotation.valid_until) {
      doc.text(`Valid Until: ${new Date(quotation.valid_until).toLocaleDateString("en-GB")}`, pageWidth - 15, 44, { align: "right" });
    }

    y = Math.max(y + 10, 55);
    doc.setDrawColor(209, 213, 219);
    doc.line(15, y, pageWidth - 15, y);
    y += 10;

    // Prepared For
    doc.setFont("helvetica", "bold");
    doc.setFontSize(9);
    doc.setTextColor(156, 163, 175);
    doc.text("PREPARED FOR", 15, y);
    y += 5;

    doc.setFontSize(12);
    doc.setTextColor(17, 24, 39);
    const clientName = (quotation as any).clients?.name || "Client";
    doc.text(clientName, 15, y);
    y += 5;

    if ((quotation as any).clients?.address) {
      doc.setFont("helvetica", "normal");
      doc.setFontSize(10);
      doc.setTextColor(75, 85, 99);
      const splitAddress = doc.splitTextToSize((quotation as any).clients.address, 80);
      doc.text(splitAddress, 15, y);
      y += splitAddress.length * 5;
    }
    y += 5;

    // Table
    const tableData = (quotation.items || []).map((item: any, idx: number) => {
      const isService = item.description?.startsWith("[Service]");
      const isProduct = item.description?.startsWith("[Product]");
      const cleanDesc = item.description?.replace(/^\[(Service|Product)\]\s*/, "").replace(/\s*\(Warranty:.*?\)$/, "").replace(/\s*\(SN:.*?\)/, "") || item.description;
      const warranty = item.description?.match(/\(Warranty:\s*(.*?)\)/)?.[1] || "—";
      const itemType = isService ? "Service" : isProduct ? "Product" : "Custom";
      return [
        (idx + 1).toString(),
        cleanDesc,
        itemType,
        warranty,
        item.quantity.toString(),
        `Tk ${Number(item.unit_price).toLocaleString()}`,
        `Tk ${Number(item.total).toLocaleString()}`
      ];
    });

    autoTable(doc, {
      startY: y,
      head: [["#", "Description", "Type", "Warranty", "Qty", "Price", "Total"]],
      body: tableData,
      theme: "grid",
      headStyles: { fillColor: [13, 148, 136], textColor: 255, fontSize: 9, fontStyle: "bold" },
      bodyStyles: { fontSize: 9, textColor: 55 },
      columnStyles: {
        0: { cellWidth: 10, halign: 'center' },
        2: { cellWidth: 20, halign: 'center' },
        3: { cellWidth: 25, halign: 'center' },
        4: { cellWidth: 15, halign: 'center' },
        5: { cellWidth: 25, halign: 'right' },
        6: { cellWidth: 25, halign: 'right' }
      }
    });

    y = (doc as any).lastAutoTable.finalY + 10;
    const rightMargin = pageWidth - 15;
    doc.setFont("helvetica", "normal");
    doc.setFontSize(10);
    doc.setTextColor(107, 114, 128);

    doc.text("Subtotal:", rightMargin - 40, y);
    doc.setTextColor(55, 65, 81);
    doc.text(`Tk ${Number(quotation.subtotal).toLocaleString()}`, rightMargin, y, { align: "right" });
    y += 6;

    doc.setTextColor(107, 114, 128);
    doc.text(`Tax (${quotation.tax_rate}%):`, rightMargin - 40, y);
    doc.setTextColor(55, 65, 81);
    doc.text(`Tk ${Number(quotation.tax_amount).toLocaleString()}`, rightMargin, y, { align: "right" });
    y += 6;

    doc.setDrawColor(13, 148, 136);
    doc.line(rightMargin - 60, y, rightMargin, y);
    y += 8;

    doc.setFont("helvetica", "bold");
    doc.setFontSize(12);
    doc.setTextColor(17, 24, 39);
    doc.text("Total:", rightMargin - 40, y);
    doc.setTextColor(13, 148, 136);
    doc.text(`Tk ${Number(quotation.total).toLocaleString()}`, rightMargin, y, { align: "right" });

    let leftY = (doc as any).lastAutoTable.finalY + 10;

    if (quotation.notes) {
      doc.setFont("helvetica", "bold");
      doc.setFontSize(9);
      doc.setTextColor(245, 158, 11);
      doc.text("NOTES / TERMS", 15, leftY);
      leftY += 5;
      doc.setFont("helvetica", "normal");
      doc.setTextColor(55, 65, 81);
      const splitNotes = doc.splitTextToSize(quotation.notes, 100);
      doc.text(splitNotes, 15, leftY);
      leftY += splitNotes.length * 4;
    }

    const pageHeight = doc.internal.pageSize.getHeight();
    let sigY = Math.max(y, leftY) + 30;
    if (sigY > pageHeight - 30) { doc.addPage(); sigY = 30; }

    doc.setDrawColor(156, 163, 175);
    doc.line(30, sigY, 80, sigY);
    doc.setFont("helvetica", "bold");
    doc.setFontSize(9);
    doc.setTextColor(75, 85, 99);
    doc.text("Client Signature", 55, sigY + 5, { align: "center" });

    doc.line(pageWidth - 80, sigY, pageWidth - 30, sigY);
    doc.text("Authorized Signature", pageWidth - 55, sigY + 5, { align: "center" });
    doc.setFont("helvetica", "normal");
    doc.setFontSize(8);
    doc.setTextColor(156, 163, 175);
    doc.text(settings.company_name || "", pageWidth - 55, sigY + 9, { align: "center" });

    doc.text(`${settings.footer_text || ""} | ${settings.company_name || ""} | ${settings.phone || ""}`, pageWidth / 2, pageHeight - 10, { align: "center" });

    const pdfBlob = doc.output("blob");
    if (options.skipDownload) return pdfBlob;

    const shareNavigator = navigator as any;
    const isMobileUa = /Android|iPhone|iPad|iPod/i.test(navigator.userAgent);
    if (isMobileUa && shareNavigator.share) {
      const pdfFile = new File([pdfBlob], fileName, { type: "application/pdf" });
      try { await shareNavigator.share({ files: [pdfFile], title: fileName }); return null; } catch {}
    }

    const blobUrl = URL.createObjectURL(pdfBlob);
    const link = document.createElement("a");
    link.href = blobUrl;
    link.download = fileName;
    link.style.display = "none";
    document.body.appendChild(link);
    link.click();
    setTimeout(() => { if(link.parentNode) link.parentNode.removeChild(link); URL.revokeObjectURL(blobUrl); }, 30000);
    return pdfBlob;
  };


  const downloadQuotationPdf = async (q: any) => {
    setDownloadingId(q.id);
    try {
      const { data: items } = await supabase.from("quotation_items").select("*").eq("quotation_id", q.id);
      const fullQ = { ...q, items: items || [] };
      setPreviewQuotation(fullQ);
      await new Promise(r => setTimeout(r, 800));
      const el = document.getElementById("quotation-print");
      if (!el) { toast({ title: "Error generating PDF", variant: "destructive" }); return; }
      const clientName = q.clients?.name?.replace(/[^a-zA-Z0-9]/g, "_") || "Client";
      await generateVectorPdf(fullQ, settings, `Quotation_${q.quotation_number}_${clientName}.pdf`);
      toast({ title: "PDF downloaded!" });
    } catch (err: any) {
      toast({ title: "PDF Error", description: err.message, variant: "destructive" });
    } finally {
      setDownloadingId(null);
    }
  };

  const sendQuotationWhatsApp = async (q: any) => {
    const clientPhone = q.clients?.phone as string | undefined;
    const phone = clientPhone || settings.whatsapp_number || settings.phone?.split(",")[0]?.trim() || "";
    if (!phone) {
      toast({ title: "No WhatsApp number found", description: "Add a phone to the client or company settings.", variant: "destructive" });
      return;
    }

    setWhatsappId(q.id);
    try {
      const { data: items } = await supabase.from("quotation_items").select("*").eq("quotation_id", q.id);
      const fullQ = { ...q, items: items || [] };
      let clientRow = q.clients;
      if (!clientRow?.phone && q.client_id) {
        const { data: c } = await supabase.from("clients").select("name, address, phone").eq("id", q.client_id).maybeSingle();
        if (c) clientRow = c;
      }
      fullQ.clients = clientRow;

      setPreviewQuotation(fullQ);
      await new Promise((r) => setTimeout(r, 800));
      const el = document.getElementById("quotation-print");
      if (!el) { toast({ title: "Error generating PDF", variant: "destructive" }); return; }

      const clientName = clientRow?.name?.replace(/[^a-zA-Z0-9]/g, "_") || "Client";
      const fileName = `Quotation_${fullQ.quotation_number}_${clientName}.pdf`;
      const blob = await generateVectorPdf(fullQ, settings, fileName, { skipDownload: true });
      if (!blob) throw new Error("PDF generation failed");

      // Upload to public storage bucket
      const path = `${fullQ.quotation_number}-${Date.now()}.pdf`;
      const { error: upErr } = await supabase.storage.from("invoices").upload(path, blob, {
        contentType: "application/pdf",
        upsert: true,
      });
      if (upErr) throw upErr;

      const { data: publicData } = supabase.storage.from("invoices").getPublicUrl(path);
      const pdfUrl = publicData.publicUrl;

      const targetPhone = clientRow?.phone || phone;
      const cName = clientRow?.name || "Customer";
      const message =
        `আসসালামু আলাইকুম ${cName},\n\n` +
        `${settings.company_name} থেকে আপনার কোটেশন পাঠানো হলো ✅\n\n` +
        `📝 Quotation: ${fullQ.quotation_number}\n` +
        `📅 Date: ${new Date(fullQ.issue_date).toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" })}\n` +
        `💰 Total: ৳${Number(fullQ.total).toLocaleString()}\n\n` +
        `📎 PDF Download:\n${pdfUrl}\n\n` +
        `কোনো প্রশ্ন থাকলে জানাবেন।\n\nধন্যবাদ\n${settings.company_name}`;

      openWhatsApp(targetPhone, message);
      toast({ title: "WhatsApp opened", description: "Quotation link copied into the chat." });
    } catch (e: any) {
      toast({ title: "Error sending quotation", description: e?.message, variant: "destructive" });
    } finally {
      setWhatsappId(null);
      setPreviewQuotation(null);
    }
  };

  const handlePrint = () => {
    const printEl = document.getElementById("quotation-print");
    if (!printEl) return;
    const printWindow = window.open("", "_blank");
    if (!printWindow) return;
    printWindow.document.write(`<html><head><title>Quotation</title><style>@media print{body{margin:0;padding:0;}}</style></head><body>${printEl.outerHTML}</body></html>`);
    printWindow.document.close();
    printWindow.focus();
    setTimeout(() => { printWindow.print(); printWindow.close(); }, 500);
  };

  return (
      <>
      <div className="space-y-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold tracking-tight">Quotations</h1>
            <p className="text-muted-foreground text-sm">Create and manage quotations for CCTV, attendance devices & IT products</p>
          </div>
          <Button onClick={() => navigate("/quotations/create")}>
            <Plus className="h-4 w-4 mr-2" />New Quotation
          </Button>
        </div>

        <Card className="glass-card">
          <CardContent className="p-0">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Quote #</TableHead>
                  <TableHead>Client</TableHead>
                  <TableHead>Date</TableHead>
                  <TableHead>Valid Until</TableHead>
                  <TableHead className="text-right">Total (৳)</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead className="text-right">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {isLoading ? (
                  <TableRow><TableCell colSpan={7} className="text-center py-8 text-muted-foreground">Loading...</TableCell></TableRow>
                ) : !quotations?.length ? (
                  <TableRow><TableCell colSpan={7} className="text-center py-8 text-muted-foreground">No quotations yet. Create your first one!</TableCell></TableRow>
                ) : (
                  quotations.map((q: any) => (
                    <TableRow key={q.id}>
                      <TableCell className="font-medium">{q.quotation_number}</TableCell>
                      <TableCell>{q.clients?.name || "—"}</TableCell>
                      <TableCell>{format(new Date(q.issue_date), "dd MMM yyyy")}</TableCell>
                      <TableCell>{q.valid_until ? format(new Date(q.valid_until), "dd MMM yyyy") : "—"}</TableCell>
                      <TableCell className="text-right font-medium">৳{Number(q.total).toLocaleString()}</TableCell>
                      <TableCell>
                        <DropdownMenu>
                          <DropdownMenuTrigger asChild>
                            <Button variant="ghost" className="h-auto p-0 hover:bg-transparent">
                              <Badge className={`${statusColors[q.status] || ""} cursor-pointer`} variant="outline">{q.status}</Badge>
                            </Button>
                          </DropdownMenuTrigger>
                          <DropdownMenuContent align="start">
                            <DropdownMenuItem onClick={() => updateStatusMutation.mutate({ id: q.id, status: "draft" })} disabled={q.status === "draft"}>
                              <Clock className="h-3.5 w-3.5 mr-2 text-muted-foreground" />Draft
                            </DropdownMenuItem>
                            <DropdownMenuItem onClick={() => updateStatusMutation.mutate({ id: q.id, status: "sent" })} disabled={q.status === "sent"}>
                              <Send className="h-3.5 w-3.5 mr-2 text-blue-600" />Sent
                            </DropdownMenuItem>
                            <DropdownMenuItem onClick={() => updateStatusMutation.mutate({ id: q.id, status: "accepted" })} disabled={q.status === "accepted"}>
                              <CheckCircle className="h-3.5 w-3.5 mr-2 text-green-600" />Accepted
                            </DropdownMenuItem>
                            <DropdownMenuItem onClick={() => updateStatusMutation.mutate({ id: q.id, status: "rejected" })} disabled={q.status === "rejected"}>
                              <XCircle className="h-3.5 w-3.5 mr-2 text-destructive" />Rejected
                            </DropdownMenuItem>
                            <DropdownMenuItem onClick={() => updateStatusMutation.mutate({ id: q.id, status: "expired" })} disabled={q.status === "expired"}>
                              <Clock className="h-3.5 w-3.5 mr-2 text-yellow-600" />Expired
                            </DropdownMenuItem>
                          </DropdownMenuContent>
                        </DropdownMenu>
                      </TableCell>
                      <TableCell className="text-right">
                        <div className="flex items-center justify-end gap-0.5">
                          <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => navigate(`/quotations/edit/${q.id}`)} title="Edit Quotation">
                            <Pencil className="h-4 w-4" />
                          </Button>
                          <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => viewQuotation(q)} title="Preview">
                            <Eye className="h-4 w-4" />
                          </Button>
                          <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => downloadQuotationPdf(q)} disabled={downloadingId === q.id} title="Download PDF">
                            <Download className={`h-4 w-4 ${downloadingId === q.id ? "animate-spin" : ""}`} />
                          </Button>
                          <Button variant="ghost" size="icon" className="h-8 w-8" title="Send via WhatsApp" disabled={whatsappId === q.id} onClick={() => sendQuotationWhatsApp(q)}>
                            <WhatsAppIcon className="h-4 w-4 text-green-600" />
                          </Button>
                          <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => convertToInvoiceMutation.mutate(q)} disabled={convertToInvoiceMutation.isPending} title="Convert to Invoice">
                            <FileText className="h-4 w-4 text-primary" />
                          </Button>
                          <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => deleteMutation.mutate(q.id)} title="Delete">
                            <Trash2 className="h-4 w-4 text-destructive" />
                          </Button>
                        </div>
                      </TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          </CardContent>
        </Card>
      </div>

      {/* Preview Dialog */}
      <Dialog open={!!previewQuotation} onOpenChange={(open) => !open && setPreviewQuotation(null)}>
        <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto p-0">
          <DialogHeader className="p-4 pb-0 flex flex-row items-center justify-between">
            <DialogTitle>Quotation Preview</DialogTitle>
            <div className="flex gap-2">
              <Button size="sm" variant="outline" onClick={handlePrint}>
                <Printer className="h-4 w-4 mr-1" />Print
              </Button>
              <Button size="sm" variant="outline" className="text-green-600 border-green-600/40 hover:bg-green-600/10" onClick={() => { setPreviewQuotation(null); sendQuotationWhatsApp(previewQuotation); }}>
                <WhatsAppIcon className="h-4 w-4 mr-2" />WhatsApp
              </Button>
              <Button size="sm" onClick={() => previewQuotation && downloadQuotationPdf(previewQuotation)} disabled={downloading}>
                <Download className="h-4 w-4 mr-1" />{downloading ? "Generating..." : "Download PDF"}
              </Button>
            </div>
          </DialogHeader>
          <div className="p-4 overflow-x-auto">
            {previewQuotation && <QuotationPreview quotation={previewQuotation} />}
          </div>
        </DialogContent>
      </Dialog>
      </>
);
}

import { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, LineChart, Line, Legend } from "recharts";
import { Download, FileText, TrendingUp, Users, Package, CalendarDays } from "lucide-react";
import { useTranslation } from "@/contexts/LanguageContext";
import { exportToCSV, formatCurrency } from "@/lib/exportUtils";
import { format, subMonths, startOfMonth, endOfMonth, parseISO } from "date-fns";

const COLORS = ["hsl(var(--primary))", "#10b981", "#f59e0b", "#6366f1", "#ec4899", "#14b8a6", "#f97316", "hsl(var(--destructive))"];

export default function Reports() {
  const { t } = useTranslation();
  const [dateRange, setDateRange] = useState("12m");

  const { data: sales } = useQuery({
    queryKey: ["report-sales"],
    queryFn: async () => {
      const { data } = await supabase.from("sales").select("total, sale_date, quantity, products(name, category), clients(name)").order("sale_date", { ascending: false });
      return data || [];
    },
  });

  const { data: invoices } = useQuery({
    queryKey: ["report-invoices"],
    queryFn: async () => {
      const { data } = await supabase.from("invoices").select("total, issue_date, status, clients(name)").order("issue_date", { ascending: false });
      return data || [];
    },
  });

  const { data: expenses } = useQuery({
    queryKey: ["report-expenses"],
    queryFn: async () => {
      const { data } = await supabase.from("expenses").select("*").order("expense_date", { ascending: false });
      return data || [];
    },
  });

  const { data: products } = useQuery({
    queryKey: ["report-products"],
    queryFn: async () => {
      const { data } = await supabase.from("products").select("*").order("name");
      return data || [];
    },
  });

  const months = dateRange === "12m" ? 12 : dateRange === "6m" ? 6 : 3;

  // P&L monthly data
  const plData = useMemo(() => {
    const data: { month: string; income: number; expense: number; profit: number }[] = [];
    for (let i = months - 1; i >= 0; i--) {
      const d = subMonths(new Date(), i);
      const start = startOfMonth(d);
      const end = endOfMonth(d);
      const label = format(d, "MMM yy");
      const inc = (sales || []).filter((s: any) => { const sd = parseISO(s.sale_date); return sd >= start && sd <= end; }).reduce((s: number, r: any) => s + Number(r.total), 0)
        + (invoices || []).filter((inv: any) => inv.status === "paid").filter((inv: any) => { const id = parseISO(inv.issue_date); return id >= start && id <= end; }).reduce((s: number, r: any) => s + Number(r.total), 0);
      const exp = (expenses || []).filter((e: any) => { const ed = parseISO(e.expense_date); return ed >= start && ed <= end; }).reduce((s: number, e: any) => s + Number(e.amount), 0);
      data.push({ month: label, income: inc, expense: exp, profit: inc - exp });
    }
    return data;
  }, [sales, invoices, expenses, months]);

  // Client revenue
  const clientRevenue = useMemo(() => {
    const map: Record<string, number> = {};
    (sales || []).forEach((s: any) => {
      const name = s.clients?.name || "Walk-in";
      map[name] = (map[name] || 0) + Number(s.total);
    });
    (invoices || []).filter((i: any) => i.status === "paid").forEach((inv: any) => {
      const name = inv.clients?.name || "Walk-in";
      map[name] = (map[name] || 0) + Number(inv.total);
    });
    return Object.entries(map).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value).slice(0, 10);
  }, [sales, invoices]);

  // Product performance
  const productPerf = useMemo(() => {
    const map: Record<string, { revenue: number; qty: number }> = {};
    (sales || []).forEach((s: any) => {
      const name = s.products?.name || "Unknown";
      if (!map[name]) map[name] = { revenue: 0, qty: 0 };
      map[name].revenue += Number(s.total);
      map[name].qty += Number(s.quantity || 1);
    });
    return Object.entries(map).map(([name, v]) => ({ name, ...v })).sort((a, b) => b.revenue - a.revenue).slice(0, 15);
  }, [sales]);

  // Totals
  const totalIncome = plData.reduce((s, d) => s + d.income, 0);
  const totalExpense = plData.reduce((s, d) => s + d.expense, 0);
  const totalProfit = totalIncome - totalExpense;

  const handleExportPL = () => exportToCSV(plData, "profit_loss_report");
  const handleExportClients = () => exportToCSV(clientRevenue, "client_revenue_report");
  const handleExportProducts = () => exportToCSV(productPerf.map(p => ({ Product: p.name, Revenue: p.revenue, Quantity: p.qty })), "product_performance");

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">{t("page.reports.title")}</h1>
          <p className="text-muted-foreground text-sm">{t("page.reports.subtitle")}</p>
        </div>
        <Select value={dateRange} onValueChange={setDateRange}>
          <SelectTrigger className="w-[120px]"><CalendarDays className="h-4 w-4 mr-1" /><SelectValue /></SelectTrigger>
          <SelectContent>
            <SelectItem value="3m">{t("date.3m")}</SelectItem>
            <SelectItem value="6m">{t("date.6m")}</SelectItem>
            <SelectItem value="12m">{t("date.12m")}</SelectItem>
          </SelectContent>
        </Select>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        <Card className="glass-card border-success/20">
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1"><TrendingUp className="h-4 w-4 text-success" /><span className="text-xs text-muted-foreground">{t("page.revenue.total_income")}</span></div>
            <p className="text-2xl font-bold text-success">{formatCurrency(totalIncome)}</p>
          </CardContent>
        </Card>
        <Card className="glass-card border-destructive/20">
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1"><TrendingUp className="h-4 w-4 text-destructive" /><span className="text-xs text-muted-foreground">{t("page.revenue.total_expense")}</span></div>
            <p className="text-2xl font-bold text-destructive">{formatCurrency(totalExpense)}</p>
          </CardContent>
        </Card>
        <Card className={`glass-card ${totalProfit >= 0 ? "border-success/20" : "border-destructive/20"}`}>
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1"><TrendingUp className="h-4 w-4" /><span className="text-xs text-muted-foreground">{t("page.revenue.net_profit")}</span></div>
            <p className={`text-2xl font-bold ${totalProfit >= 0 ? "text-success" : "text-destructive"}`}>{formatCurrency(totalProfit)}</p>
          </CardContent>
        </Card>
      </div>

      <Tabs defaultValue="pl">
        <TabsList className="flex-wrap">
          <TabsTrigger value="pl"><FileText className="h-3.5 w-3.5 mr-1" />{t("page.reports.profit_loss")}</TabsTrigger>
          <TabsTrigger value="clients"><Users className="h-3.5 w-3.5 mr-1" />{t("page.reports.client_revenue")}</TabsTrigger>
          <TabsTrigger value="products"><Package className="h-3.5 w-3.5 mr-1" />{t("page.reports.product_performance")}</TabsTrigger>
        </TabsList>

        {/* P&L Tab */}
        <TabsContent value="pl" className="space-y-4">
          <div className="flex justify-end">
            <Button variant="outline" size="sm" onClick={handleExportPL}><Download className="h-3.5 w-3.5 mr-1" />{t("common.export_csv")}</Button>
          </div>
          <Card className="glass-card">
            <CardContent className="pt-4">
              <ResponsiveContainer width="100%" height={350}>
                <BarChart data={plData}>
                  <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                  <XAxis dataKey="month" tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 11 }} />
                  <YAxis tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 11 }} />
                  <Tooltip contentStyle={{ background: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: 8, color: "hsl(var(--foreground))" }} />
                  <Legend />
                  <Bar dataKey="income" fill="hsl(var(--primary))" radius={[4, 4, 0, 0]} name={t("page.revenue.income")} />
                  <Bar dataKey="expense" fill="hsl(var(--destructive))" radius={[4, 4, 0, 0]} name={t("page.revenue.expense")} />
                  <Bar dataKey="profit" fill="#10b981" radius={[4, 4, 0, 0]} name={t("page.revenue.net_profit")} />
                </BarChart>
              </ResponsiveContainer>
            </CardContent>
          </Card>
          <Card className="glass-card">
            <CardContent className="p-0">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>{t("page.reports.monthly_summary")}</TableHead>
                    <TableHead>{t("page.revenue.income")}</TableHead>
                    <TableHead>{t("page.revenue.expense")}</TableHead>
                    <TableHead>{t("page.revenue.net_profit")}</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {plData.map(d => (
                    <TableRow key={d.month}>
                      <TableCell className="font-medium">{d.month}</TableCell>
                      <TableCell className="text-success">{formatCurrency(d.income)}</TableCell>
                      <TableCell className="text-destructive">{formatCurrency(d.expense)}</TableCell>
                      <TableCell className={d.profit >= 0 ? "text-success font-medium" : "text-destructive font-medium"}>{formatCurrency(d.profit)}</TableCell>
                    </TableRow>
                  ))}
                  <TableRow className="font-bold border-t-2">
                    <TableCell>{t("common.total")}</TableCell>
                    <TableCell className="text-success">{formatCurrency(totalIncome)}</TableCell>
                    <TableCell className="text-destructive">{formatCurrency(totalExpense)}</TableCell>
                    <TableCell className={totalProfit >= 0 ? "text-success" : "text-destructive"}>{formatCurrency(totalProfit)}</TableCell>
                  </TableRow>
                </TableBody>
              </Table>
            </CardContent>
          </Card>
        </TabsContent>

        {/* Client Revenue Tab */}
        <TabsContent value="clients" className="space-y-4">
          <div className="flex justify-end">
            <Button variant="outline" size="sm" onClick={handleExportClients}><Download className="h-3.5 w-3.5 mr-1" />{t("common.export_csv")}</Button>
          </div>
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <Card className="glass-card">
              <CardContent className="pt-4">
                <ResponsiveContainer width="100%" height={350}>
                  <BarChart data={clientRevenue} layout="vertical">
                    <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                    <XAxis type="number" tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 11 }} />
                    <YAxis type="category" dataKey="name" width={120} tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 10 }} />
                    <Tooltip contentStyle={{ background: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: 8, color: "hsl(var(--foreground))" }} />
                    <Bar dataKey="value" fill="hsl(var(--primary))" radius={[0, 4, 4, 0]} name={t("page.revenue.income")} />
                  </BarChart>
                </ResponsiveContainer>
              </CardContent>
            </Card>
            <Card className="glass-card">
              <CardContent className="pt-4">
                {clientRevenue.length ? (
                  <ResponsiveContainer width="100%" height={350}>
                    <PieChart>
                      <Pie data={clientRevenue} cx="50%" cy="50%" outerRadius={120} dataKey="value" label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}>
                        {clientRevenue.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
                      </Pie>
                      <Tooltip />
                    </PieChart>
                  </ResponsiveContainer>
                ) : <p className="text-center text-muted-foreground py-16">{t("common.no_data")}</p>}
              </CardContent>
            </Card>
          </div>
        </TabsContent>

        {/* Product Performance Tab */}
        <TabsContent value="products" className="space-y-4">
          <div className="flex justify-end">
            <Button variant="outline" size="sm" onClick={handleExportProducts}><Download className="h-3.5 w-3.5 mr-1" />{t("common.export_csv")}</Button>
          </div>
          <Card className="glass-card">
            <CardContent className="pt-4">
              <ResponsiveContainer width="100%" height={400}>
                <BarChart data={productPerf}>
                  <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                  <XAxis dataKey="name" tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 9 }} angle={-35} textAnchor="end" height={80} />
                  <YAxis tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 11 }} />
                  <Tooltip contentStyle={{ background: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: 8, color: "hsl(var(--foreground))" }} />
                  <Legend />
                  <Bar dataKey="revenue" fill="hsl(var(--primary))" radius={[4, 4, 0, 0]} name={t("page.revenue.income")} />
                  <Bar dataKey="qty" fill="#f59e0b" radius={[4, 4, 0, 0]} name="Qty" />
                </BarChart>
              </ResponsiveContainer>
            </CardContent>
          </Card>
          <Card className="glass-card">
            <CardContent className="p-0">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>{t("common.name")}</TableHead>
                    <TableHead>{t("page.revenue.income")}</TableHead>
                    <TableHead>Qty Sold</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {productPerf.map(p => (
                    <TableRow key={p.name}>
                      <TableCell className="font-medium">{p.name}</TableCell>
                      <TableCell className="text-success">{formatCurrency(p.revenue)}</TableCell>
                      <TableCell>{p.qty}</TableCell>
                    </TableRow>
                  ))}
                  {!productPerf.length && <TableRow><TableCell colSpan={3} className="text-center py-8 text-muted-foreground">{t("common.no_data")}</TableCell></TableRow>}
                </TableBody>
              </Table>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { KeyRound } from "lucide-react";
import { useToast } from "@/hooks/use-toast";

export default function ResetPassword() {
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [loading, setLoading] = useState(false);
  const [isRecovery, setIsRecovery] = useState(false);
  const navigate = useNavigate();
  const { toast } = useToast();

  useEffect(() => {
    // Check for recovery event in URL hash
    const hash = window.location.hash;
    if (hash.includes("type=recovery")) {
      setIsRecovery(true);
    }

    const { data: { subscription } } = supabase.auth.onAuthStateChange((event) => {
      if (event === "PASSWORD_RECOVERY") {
        setIsRecovery(true);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const handleReset = async (e: React.FormEvent) => {
    e.preventDefault();
    if (password !== confirmPassword) {
      toast({ title: "Passwords don't match", variant: "destructive" });
      return;
    }
    if (password.length < 6) {
      toast({ title: "Password must be at least 6 characters", variant: "destructive" });
      return;
    }
    setLoading(true);
    try {
      const { error } = await supabase.auth.updateUser({ password });
      if (error) throw error;
      toast({ title: "Password updated!", description: "You can now sign in with your new password." });
      navigate("/auth");
    } catch (err: any) {
      toast({ title: "Error", description: err.message, variant: "destructive" });
    } finally {
      setLoading(false);
    }
  };

  if (!isRecovery) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background p-4">
        <Card className="w-full max-w-md">
          <CardContent className="py-12 text-center">
            <p className="text-muted-foreground">Invalid or expired reset link.</p>
            <Button variant="link" onClick={() => navigate("/auth")} className="mt-2">Go to Sign In</Button>
          </CardContent>
        </Card>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-background p-4">
      <Card className="w-full max-w-md">
        <CardHeader className="text-center space-y-3">
          <div className="w-14 h-14 rounded-xl bg-primary flex items-center justify-center mx-auto">
            <KeyRound className="h-7 w-7 text-primary-foreground" />
          </div>
          <CardTitle className="text-xl">Set New Password</CardTitle>
          <CardDescription>Enter your new password below</CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleReset} className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="new-password">New Password</Label>
              <Input id="new-password" type="password" value={password} onChange={(e) => setPassword(e.target.value)} required placeholder="••••••••" minLength={6} />
            </div>
            <div className="space-y-2">
              <Label htmlFor="confirm-password">Confirm Password</Label>
              <Input id="confirm-password" type="password" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} required placeholder="••••••••" minLength={6} />
            </div>
            <Button type="submit" className="w-full" disabled={loading}>
              {loading ? "Updating..." : "Update Password"}
            </Button>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useMemo } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Textarea } from "@/components/ui/textarea";
import { Plus, TrendingUp, TrendingDown, DollarSign, Trash2, BarChart3, PieChart as PieIcon, CalendarDays } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { format, subMonths, startOfMonth, endOfMonth, parseISO } from "date-fns";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend, LineChart, Line } from "recharts";

const CHART_COLORS = ["hsl(var(--primary))", "hsl(var(--destructive))", "#10b981", "#f59e0b", "#6366f1", "#ec4899", "#14b8a6", "#f97316"];

export default function Revenue() {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [expenseOpen, setExpenseOpen] = useState(false);
  const [dateRange, setDateRange] = useState("6m");
  const [expenseForm, setExpenseForm] = useState({
    description: "", amount: 0, category: "General",
    expense_date: new Date().toISOString().split("T")[0], notes: "",
  });

  const { data: paidSales } = useQuery({
    queryKey: ["sales-paid"],
    queryFn: async () => {
      const { data } = await supabase.from("sales").select("total, sale_date, products(name), clients(name)").eq("payment_status", "paid").order("sale_date", { ascending: false });
      return data || [];
    },
  });

  const { data: paidInvoices } = useQuery({
    queryKey: ["invoices-paid"],
    queryFn: async () => {
      const { data } = await supabase.from("invoices").select("total, issue_date, invoice_number, clients(name)").eq("status", "paid").order("issue_date", { ascending: false });
      return data || [];
    },
  });

  const { data: expenses, isLoading: expensesLoading } = useQuery({
    queryKey: ["expenses"],
    queryFn: async () => {
      const { data } = await supabase.from("expenses").select("*").order("expense_date", { ascending: false });
      return data || [];
    },
  });

  const { data: allSales } = useQuery({
    queryKey: ["all-sales-for-chart"],
    queryFn: async () => {
      const { data } = await supabase.from("sales").select("total, sale_date, products(name)").order("sale_date", { ascending: false });
      return data || [];
    },
  });

  const createExpense = useMutation({
    mutationFn: async () => {
      const { data: { user } } = await supabase.auth.getUser();
      const { error } = await supabase.from("expenses").insert({ ...expenseForm, created_by: user?.id || null });
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["expenses"] });
      toast({ title: "Expense recorded" });
      setExpenseOpen(false);
      setExpenseForm({ description: "", amount: 0, category: "General", expense_date: new Date().toISOString().split("T")[0], notes: "" });
    },
    onError: (e: any) => toast({ title: "Error", description: e.message, variant: "destructive" }),
  });

  const deleteExpense = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("expenses").delete().eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["expenses"] }); toast({ title: "Expense deleted" }); },
  });

  const totalIncome = (paidSales?.reduce((s: number, r: any) => s + Number(r.total), 0) || 0) +
    (paidInvoices?.reduce((s: number, r: any) => s + Number(r.total), 0) || 0);
  const totalExpenses = expenses?.reduce((s: number, e: any) => s + Number(e.amount), 0) || 0;
  const netRevenue = totalIncome - totalExpenses;

  // Monthly chart data
  const monthlyData = useMemo(() => {
    const months = dateRange === "12m" ? 12 : dateRange === "6m" ? 6 : 3;
    const data: { month: string; income: number; expense: number; profit: number }[] = [];
    for (let i = months - 1; i >= 0; i--) {
      const d = subMonths(new Date(), i);
      const start = startOfMonth(d);
      const end = endOfMonth(d);
      const label = format(d, "MMM yy");
      const inc = (paidSales || []).filter((s: any) => { const sd = parseISO(s.sale_date); return sd >= start && sd <= end; }).reduce((s: number, r: any) => s + Number(r.total), 0)
        + (paidInvoices || []).filter((inv: any) => { const id = parseISO(inv.issue_date); return id >= start && id <= end; }).reduce((s: number, r: any) => s + Number(r.total), 0);
      const exp = (expenses || []).filter((e: any) => { const ed = parseISO(e.expense_date); return ed >= start && ed <= end; }).reduce((s: number, e: any) => s + Number(e.amount), 0);
      data.push({ month: label, income: inc, expense: exp, profit: inc - exp });
    }
    return data;
  }, [paidSales, paidInvoices, expenses, dateRange]);

  // Expense by category
  const expenseByCategory = useMemo(() => {
    const map: Record<string, number> = {};
    (expenses || []).forEach((e: any) => { map[e.category] = (map[e.category] || 0) + Number(e.amount); });
    return Object.entries(map).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value);
  }, [expenses]);

  // Top products
  const topProducts = useMemo(() => {
    const map: Record<string, number> = {};
    (allSales || []).forEach((s: any) => {
      const name = s.products?.name || "Unknown";
      map[name] = (map[name] || 0) + Number(s.total);
    });
    return Object.entries(map).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value).slice(0, 8);
  }, [allSales]);

  const categories = ["General", "Salary", "Rent", "Equipment", "Utilities", "Marketing", "Transport", "Other"];

  const todayIncome = useMemo(() => {
    const today = new Date().toISOString().split("T")[0];
    return (paidSales || []).filter((s: any) => s.sale_date === today).reduce((s: number, r: any) => s + Number(r.total), 0);
  }, [paidSales]);

  const pendingPayments = useMemo(() => {
    return 0; // Can be extended with unpaid invoices
  }, []);

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Revenue Dashboard</h1>
          <p className="text-muted-foreground text-sm">বিক্রি, খরচ ও লাভ-ক্ষতির সম্পূর্ণ বিশ্লেষণ</p>
        </div>
        <div className="flex gap-2">
          <Select value={dateRange} onValueChange={setDateRange}>
            <SelectTrigger className="w-[120px]"><CalendarDays className="h-4 w-4 mr-1" /><SelectValue /></SelectTrigger>
            <SelectContent>
              <SelectItem value="3m">৩ মাস</SelectItem>
              <SelectItem value="6m">৬ মাস</SelectItem>
              <SelectItem value="12m">১ বছর</SelectItem>
            </SelectContent>
          </Select>
          <Dialog open={expenseOpen} onOpenChange={setExpenseOpen}>
            <DialogTrigger asChild>
              <Button variant="outline"><Plus className="h-4 w-4 mr-2" />Add Expense</Button>
            </DialogTrigger>
            <DialogContent className="max-w-md">
              <DialogHeader><DialogTitle>Record Expense</DialogTitle></DialogHeader>
              <div className="space-y-4">
                <div><Label>Description</Label><Input value={expenseForm.description} onChange={e => setExpenseForm({ ...expenseForm, description: e.target.value })} /></div>
                <div><Label>Amount (৳)</Label><Input type="number" min={0} value={expenseForm.amount} onChange={e => setExpenseForm({ ...expenseForm, amount: +e.target.value })} /></div>
                <div><Label>Category</Label>
                  <Select value={expenseForm.category} onValueChange={v => setExpenseForm({ ...expenseForm, category: v })}>
                    <SelectTrigger><SelectValue /></SelectTrigger>
                    <SelectContent>{categories.map(c => <SelectItem key={c} value={c}>{c}</SelectItem>)}</SelectContent>
                  </Select>
                </div>
                <div><Label>Date</Label><Input type="date" value={expenseForm.expense_date} onChange={e => setExpenseForm({ ...expenseForm, expense_date: e.target.value })} /></div>
                <div><Label>Notes</Label><Textarea value={expenseForm.notes} onChange={e => setExpenseForm({ ...expenseForm, notes: e.target.value })} /></div>
                <Button className="w-full" onClick={() => createExpense.mutate()} disabled={createExpense.isPending || !expenseForm.description}>
                  {createExpense.isPending ? "Saving..." : "Record Expense"}
                </Button>
              </div>
            </DialogContent>
          </Dialog>
        </div>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
        <Card className="glass-card border-success/20">
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1"><TrendingUp className="h-4 w-4 text-success" /><span className="text-xs text-muted-foreground">মোট আয়</span></div>
            <p className="text-xl font-bold text-success">৳{totalIncome.toLocaleString()}</p>
          </CardContent>
        </Card>
        <Card className="glass-card border-destructive/20">
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1"><TrendingDown className="h-4 w-4 text-destructive" /><span className="text-xs text-muted-foreground">মোট খরচ</span></div>
            <p className="text-xl font-bold text-destructive">৳{totalExpenses.toLocaleString()}</p>
          </CardContent>
        </Card>
        <Card className={`glass-card ${netRevenue >= 0 ? "border-success/20" : "border-destructive/20"}`}>
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1"><DollarSign className="h-4 w-4" /><span className="text-xs text-muted-foreground">নেট লাভ</span></div>
            <p className={`text-xl font-bold ${netRevenue >= 0 ? "text-success" : "text-destructive"}`}>৳{netRevenue.toLocaleString()}</p>
          </CardContent>
        </Card>
        <Card className="glass-card border-primary/20">
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1"><BarChart3 className="h-4 w-4 text-primary" /><span className="text-xs text-muted-foreground">আজকের আয়</span></div>
            <p className="text-xl font-bold text-primary">৳{todayIncome.toLocaleString()}</p>
          </CardContent>
        </Card>
      </div>

      {/* Charts Row */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Monthly Revenue vs Expense */}
        <Card className="glass-card">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm flex items-center gap-2"><BarChart3 className="h-4 w-4 text-primary" />মাসিক আয় vs খরচ</CardTitle>
          </CardHeader>
          <CardContent>
            <ResponsiveContainer width="100%" height={280}>
              <BarChart data={monthlyData}>
                <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                <XAxis dataKey="month" tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 11 }} />
                <YAxis tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 11 }} />
                <Tooltip contentStyle={{ background: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: 8, color: "hsl(var(--foreground))" }} />
                <Bar dataKey="income" fill="hsl(var(--primary))" radius={[4, 4, 0, 0]} name="আয়" />
                <Bar dataKey="expense" fill="hsl(var(--destructive))" radius={[4, 4, 0, 0]} name="খরচ" />
              </BarChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>

        {/* Profit Trend */}
        <Card className="glass-card">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm flex items-center gap-2"><TrendingUp className="h-4 w-4 text-success" />লাভ/ক্ষতি ট্রেন্ড</CardTitle>
          </CardHeader>
          <CardContent>
            <ResponsiveContainer width="100%" height={280}>
              <LineChart data={monthlyData}>
                <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                <XAxis dataKey="month" tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 11 }} />
                <YAxis tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 11 }} />
                <Tooltip contentStyle={{ background: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: 8, color: "hsl(var(--foreground))" }} />
                <Line type="monotone" dataKey="profit" stroke="#10b981" strokeWidth={2} dot={{ fill: "#10b981" }} name="লাভ" />
              </LineChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>

        {/* Expense by Category Pie */}
        <Card className="glass-card">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm flex items-center gap-2"><PieIcon className="h-4 w-4 text-primary" />ক্যাটাগরি অনুযায়ী খরচ</CardTitle>
          </CardHeader>
          <CardContent>
            {expenseByCategory.length === 0 ? (
              <p className="text-center text-muted-foreground text-sm py-16">কোনো খরচ নেই</p>
            ) : (
              <ResponsiveContainer width="100%" height={280}>
                <PieChart>
                  <Pie data={expenseByCategory} cx="50%" cy="50%" outerRadius={90} dataKey="value" label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}>
                    {expenseByCategory.map((_, i) => <Cell key={i} fill={CHART_COLORS[i % CHART_COLORS.length]} />)}
                  </Pie>
                  <Tooltip contentStyle={{ background: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: 8, color: "hsl(var(--foreground))" }} />
                </PieChart>
              </ResponsiveContainer>
            )}
          </CardContent>
        </Card>

        {/* Top Products */}
        <Card className="glass-card">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm flex items-center gap-2"><BarChart3 className="h-4 w-4 text-primary" />সবচেয়ে বেশি বিক্রি</CardTitle>
          </CardHeader>
          <CardContent>
            {topProducts.length === 0 ? (
              <p className="text-center text-muted-foreground text-sm py-16">কোনো বিক্রি ডেটা নেই</p>
            ) : (
              <ResponsiveContainer width="100%" height={280}>
                <BarChart data={topProducts} layout="vertical">
                  <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                  <XAxis type="number" tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 11 }} />
                  <YAxis type="category" dataKey="name" width={100} tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 10 }} />
                  <Tooltip contentStyle={{ background: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: 8, color: "hsl(var(--foreground))" }} />
                  <Bar dataKey="value" fill="hsl(var(--primary))" radius={[0, 4, 4, 0]} name="বিক্রি (৳)" />
                </BarChart>
              </ResponsiveContainer>
            )}
          </CardContent>
        </Card>
      </div>

      {/* Tables */}
      <Tabs defaultValue="expenses">
        <TabsList>
          <TabsTrigger value="income">Income</TabsTrigger>
          <TabsTrigger value="expenses">Expenses</TabsTrigger>
        </TabsList>
        <TabsContent value="income">
          <Card className="glass-card">
            <CardHeader><CardTitle className="text-base">Income from Sales & Invoices</CardTitle></CardHeader>
            <CardContent className="p-0">
              <Table>
                <TableHeader><TableRow><TableHead>Source</TableHead><TableHead>Details</TableHead><TableHead>Client</TableHead><TableHead>Date</TableHead><TableHead>Amount</TableHead></TableRow></TableHeader>
                <TableBody>
                  {paidSales?.map((s: any, i: number) => (
                    <TableRow key={`sale-${i}`}><TableCell className="text-sm font-medium">Sale</TableCell><TableCell className="text-sm">{s.products?.name || "—"}</TableCell><TableCell className="text-sm">{s.clients?.name || "—"}</TableCell><TableCell className="text-sm">{format(new Date(s.sale_date), "dd MMM yyyy")}</TableCell><TableCell className="text-sm font-medium text-success">৳{Number(s.total).toLocaleString()}</TableCell></TableRow>
                  ))}
                  {paidInvoices?.map((inv: any, i: number) => (
                    <TableRow key={`inv-${i}`}><TableCell className="text-sm font-medium">Invoice</TableCell><TableCell className="text-sm">{inv.invoice_number}</TableCell><TableCell className="text-sm">{inv.clients?.name || "—"}</TableCell><TableCell className="text-sm">{format(new Date(inv.issue_date), "dd MMM yyyy")}</TableCell><TableCell className="text-sm font-medium text-success">৳{Number(inv.total).toLocaleString()}</TableCell></TableRow>
                  ))}
                  {(!paidSales?.length && !paidInvoices?.length) && <TableRow><TableCell colSpan={5} className="text-center py-8 text-muted-foreground">No income recorded yet</TableCell></TableRow>}
                </TableBody>
              </Table>
            </CardContent>
          </Card>
        </TabsContent>
        <TabsContent value="expenses">
          <Card className="glass-card">
            <CardHeader><CardTitle className="text-base">Expenses</CardTitle></CardHeader>
            <CardContent className="p-0">
              <Table>
                <TableHeader><TableRow><TableHead>Date</TableHead><TableHead>Description</TableHead><TableHead>Category</TableHead><TableHead>Amount</TableHead><TableHead></TableHead></TableRow></TableHeader>
                <TableBody>
                  {expensesLoading ? <TableRow><TableCell colSpan={5} className="text-center py-8">Loading...</TableCell></TableRow>
                    : expenses?.length === 0 ? <TableRow><TableCell colSpan={5} className="text-center py-8 text-muted-foreground">No expenses</TableCell></TableRow>
                    : expenses?.map((e: any) => (
                      <TableRow key={e.id}>
                        <TableCell className="text-sm">{format(new Date(e.expense_date), "dd MMM yyyy")}</TableCell>
                        <TableCell className="text-sm font-medium">{e.description}</TableCell>
                        <TableCell className="text-sm">{e.category}</TableCell>
                        <TableCell className="text-sm font-medium text-destructive">৳{Number(e.amount).toLocaleString()}</TableCell>
                        <TableCell><Button variant="ghost" size="icon" onClick={() => deleteExpense.mutate(e.id)}><Trash2 className="h-4 w-4 text-destructive" /></Button></TableCell>
                      </TableRow>
                    ))}
                </TableBody>
              </Table>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { toast } from "sonner";
import { format } from "date-fns";
import {
  TrendingUp, Plus, Search, Edit2, Trash2, Package,
  Users, DollarSign, ShoppingBag, Filter, ArrowUpRight,
  CheckCircle, Clock, XCircle,
} from "lucide-react";
import { ConfirmDeleteDialog } from "@/components/ConfirmDeleteDialog";
import { BarcodeScanner } from "@/components/BarcodeScanner";

type PaymentStatus = "paid" | "pending" | "partial";

interface SaleForm {
  product_id: string;
  client_id: string;
  quantity: number;
  unit_price: number;
  payment_status: PaymentStatus;
  sale_date: string;
  notes: string;
}

const defaultForm: SaleForm = {
  product_id: "",
  client_id: "",
  quantity: 1,
  unit_price: 0,
  payment_status: "paid",
  sale_date: format(new Date(), "yyyy-MM-dd"),
  notes: "",
};

const paymentStatusConfig: Record<PaymentStatus, { label: string; color: string; icon: typeof CheckCircle }> = {
  paid: { label: "Paid", color: "bg-success/10 text-success border-success/20", icon: CheckCircle },
  pending: { label: "Pending", color: "bg-warning/10 text-warning border-warning/20", icon: Clock },
  partial: { label: "Partial", color: "bg-info/10 text-info border-info/20", icon: XCircle },
};

export default function Sales() {
  const qc = useQueryClient();
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState<"all" | PaymentStatus>("all");
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [form, setForm] = useState<SaleForm>(defaultForm);

  // Data queries
  const { data: sales = [], isLoading } = useQuery({
    queryKey: ["sales"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("sales")
        .select("*, products(name, sku), clients(name)")
        .order("sale_date", { ascending: false });
      if (error) throw error;
      return data || [];
    },
  });

  const { data: products = [] } = useQuery({
    queryKey: ["products-for-sales"],
    queryFn: async () => {
      const { data } = await supabase.from("products").select("id, name, price, sku").order("name");
      return data || [];
    },
  });

  const { data: clients = [] } = useQuery({
    queryKey: ["clients-for-sales"],
    queryFn: async () => {
      const { data } = await supabase.from("clients").select("id, name").order("name");
      return data || [];
    },
  });

  // Mutations
  const saveMutation = useMutation({
    mutationFn: async (data: SaleForm & { id?: string }) => {
      const payload = {
        product_id: data.product_id || null,
        client_id: data.client_id || null,
        quantity: data.quantity,
        unit_price: data.unit_price,
        total: data.quantity * data.unit_price,
        payment_status: data.payment_status,
        sale_date: data.sale_date,
        notes: data.notes || null,
      };
      if (data.id) {
        const { error } = await supabase.from("sales").update(payload).eq("id", data.id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from("sales").insert(payload);
        if (error) throw error;
      }
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["sales"] });
      toast.success(editingId ? "Sale updated!" : "Sale recorded!");
      setDialogOpen(false);
      setForm(defaultForm);
      setEditingId(null);
    },
    onError: () => toast.error("Something went wrong"),
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("sales").delete().eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["sales"] });
      toast.success("Sale deleted");
      setDeleteId(null);
    },
  });

  // Stats
  const totalRevenue = sales.filter(s => s.payment_status === "paid").reduce((sum, s) => sum + Number(s.total), 0);
  const pendingRevenue = sales.filter(s => s.payment_status === "pending").reduce((sum, s) => sum + Number(s.total), 0);
  const totalSales = sales.length;
  const todayStr = format(new Date(), "yyyy-MM-dd");
  const todaySales = sales.filter(s => s.sale_date === todayStr).length;

  // Filtered list
  const filtered = sales.filter(s => {
    const matchSearch =
      !search ||
      (s as any).products?.name?.toLowerCase().includes(search.toLowerCase()) ||
      (s as any).clients?.name?.toLowerCase().includes(search.toLowerCase());
    const matchStatus = statusFilter === "all" || s.payment_status === statusFilter;
    return matchSearch && matchStatus;
  });

  const openNew = () => {
    setForm(defaultForm);
    setEditingId(null);
    setDialogOpen(true);
  };

  const openEdit = (sale: any) => {
    setForm({
      product_id: sale.product_id || "",
      client_id: sale.client_id || "",
      quantity: sale.quantity,
      unit_price: Number(sale.unit_price),
      payment_status: sale.payment_status as PaymentStatus,
      sale_date: sale.sale_date,
      notes: sale.notes || "",
    });
    setEditingId(sale.id);
    setDialogOpen(true);
  };

  const handleProductChange = (productId: string) => {
    const product = products.find((p: any) => p.id === productId);
    setForm(f => ({ ...f, product_id: productId, unit_price: product ? Number(product.price) : f.unit_price }));
  };

  const handleBarcodeDetected = (sku: string) => {
    const product = products?.find((p: any) => p.sku === sku);
    if (product) {
      setForm(f => ({ ...f, product_id: product.id, unit_price: Number(product.price) }));
      toast.success(`Product found: ${product.name}`);
    } else {
      toast.error(`No product found with SKU: ${sku}`);
    }
  };

  const handleSubmit = () => {
    if (!form.quantity || form.unit_price <= 0) {
      toast.error("Please fill in quantity and price.");
      return;
    }
    saveMutation.mutate({ ...form, id: editingId || undefined });
  };

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight flex items-center gap-2">
            <TrendingUp className="h-6 w-6 text-primary" />
            Sales
          </h1>
          <p className="text-sm text-muted-foreground mt-0.5">Track all your direct sales records</p>
        </div>
        <Button onClick={openNew} className="gap-2 corporate-gradient text-white border-0">
          <Plus className="h-4 w-4" />
          Add Sale
        </Button>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        <Card className="glass-card">
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1">
              <div className="h-7 w-7 rounded-lg bg-success/10 flex items-center justify-center">
                <DollarSign className="h-3.5 w-3.5 text-success" />
              </div>
              <span className="text-[10px] text-muted-foreground font-medium">Paid Revenue</span>
            </div>
            <p className="text-xl font-black text-success">৳{totalRevenue.toLocaleString()}</p>
          </CardContent>
        </Card>
        <Card className="glass-card">
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1">
              <div className="h-7 w-7 rounded-lg bg-warning/10 flex items-center justify-center">
                <Clock className="h-3.5 w-3.5 text-warning" />
              </div>
              <span className="text-[10px] text-muted-foreground font-medium">Pending</span>
            </div>
            <p className="text-xl font-black text-warning">৳{pendingRevenue.toLocaleString()}</p>
          </CardContent>
        </Card>
        <Card className="glass-card">
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1">
              <div className="h-7 w-7 rounded-lg bg-primary/10 flex items-center justify-center">
                <ShoppingBag className="h-3.5 w-3.5 text-primary" />
              </div>
              <span className="text-[10px] text-muted-foreground font-medium">Total Sales</span>
            </div>
            <p className="text-xl font-black">{totalSales}</p>
          </CardContent>
        </Card>
        <Card className="glass-card">
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1">
              <div className="h-7 w-7 rounded-lg bg-accent/10 flex items-center justify-center">
                <ArrowUpRight className="h-3.5 w-3.5 text-accent" />
              </div>
              <span className="text-[10px] text-muted-foreground font-medium">Today</span>
            </div>
            <p className="text-xl font-black">{todaySales}</p>
          </CardContent>
        </Card>
      </div>

      {/* Filters */}
      <div className="flex flex-col sm:flex-row gap-3">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Search by product or client..."
            value={search}
            onChange={e => setSearch(e.target.value)}
            className="pl-9"
          />
        </div>
        <div className="flex gap-2">
          {(["all", "paid", "pending", "partial"] as const).map(status => (
            <button
              key={status}
              onClick={() => setStatusFilter(status)}
              className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-all capitalize ${
                statusFilter === status
                  ? "bg-primary text-primary-foreground shadow-sm"
                  : "bg-muted text-muted-foreground hover:bg-muted/80"
              }`}
            >
              {status === "all" ? "All" : paymentStatusConfig[status].label}
            </button>
          ))}
        </div>
      </div>

      {/* Sales Table */}
      <Card className="glass-card">
        <CardHeader className="pb-3">
          <CardTitle className="text-sm flex items-center gap-2">
            <TrendingUp className="h-4 w-4 text-primary" />
            Sales Records
            <Badge variant="secondary" className="ml-auto">{filtered.length}</Badge>
          </CardTitle>
        </CardHeader>
        <CardContent className="p-0">
          {isLoading ? (
            <div className="flex items-center justify-center py-12">
              <div className="animate-spin h-6 w-6 border-2 border-primary border-t-transparent rounded-full" />
            </div>
          ) : filtered.length === 0 ? (
            <div className="text-center py-12">
              <ShoppingBag className="h-10 w-10 text-muted-foreground/30 mx-auto mb-3" />
              <p className="text-sm text-muted-foreground">No sales found</p>
              <Button variant="outline" size="sm" className="mt-3" onClick={openNew}>
                <Plus className="h-3.5 w-3.5 mr-1.5" /> Record First Sale
              </Button>
            </div>
          ) : (
            <div className="divide-y divide-border/50">
              {/* Table header */}
              <div className="hidden sm:grid grid-cols-[1fr_1fr_80px_100px_100px_80px] gap-4 px-4 py-2 text-[10px] font-semibold text-muted-foreground uppercase tracking-wider bg-muted/30">
                <span>Product</span>
                <span>Client</span>
                <span>Qty</span>
                <span>Total</span>
                <span>Status</span>
                <span className="text-right">Actions</span>
              </div>
              {filtered.map(sale => {
                const cfg = paymentStatusConfig[sale.payment_status as PaymentStatus] || paymentStatusConfig.pending;
                const StatusIcon = cfg.icon;
                return (
                  <div
                    key={sale.id}
                    className="grid grid-cols-1 sm:grid-cols-[1fr_1fr_80px_100px_100px_80px] gap-2 sm:gap-4 px-4 py-3 hover:bg-muted/20 transition-colors"
                  >
                    {/* Product */}
                    <div className="flex items-center gap-2 min-w-0">
                      <div className="h-8 w-8 rounded-lg bg-primary/10 flex items-center justify-center flex-shrink-0">
                        <Package className="h-3.5 w-3.5 text-primary" />
                      </div>
                      <div className="min-w-0">
                        <p className="text-sm font-medium truncate">{(sale as any).products?.name || "Unknown Product"}</p>
                        <p className="text-[10px] text-muted-foreground">{format(new Date(sale.sale_date), "dd MMM yyyy")}</p>
                      </div>
                    </div>
                    {/* Client */}
                    <div className="flex items-center gap-1.5 min-w-0">
                      <Users className="h-3.5 w-3.5 text-muted-foreground flex-shrink-0" />
                      <span className="text-sm truncate">{(sale as any).clients?.name || "Walk-in"}</span>
                    </div>
                    {/* Qty */}
                    <div className="flex items-center">
                      <span className="text-sm font-semibold">×{sale.quantity}</span>
                    </div>
                    {/* Total */}
                    <div className="flex flex-col">
                      <span className="text-sm font-bold">৳{Number(sale.total).toLocaleString()}</span>
                      <span className="text-[10px] text-muted-foreground">৳{Number(sale.unit_price).toLocaleString()} each</span>
                    </div>
                    {/* Status */}
                    <div className="flex items-center">
                      <Badge variant="outline" className={`text-[10px] gap-1 ${cfg.color}`}>
                        <StatusIcon className="h-2.5 w-2.5" />
                        {cfg.label}
                      </Badge>
                    </div>
                    {/* Actions */}
                    <div className="flex items-center justify-end gap-1">
                      <Button variant="ghost" size="icon" className="h-7 w-7" onClick={() => openEdit(sale)}>
                        <Edit2 className="h-3.5 w-3.5" />
                      </Button>
                      <Button variant="ghost" size="icon" className="h-7 w-7 text-destructive hover:text-destructive" onClick={() => setDeleteId(sale.id)}>
                        <Trash2 className="h-3.5 w-3.5" />
                      </Button>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Add/Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={open => { setDialogOpen(open); if (!open) { setForm(defaultForm); setEditingId(null); } }}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <TrendingUp className="h-5 w-5 text-primary" />
              {editingId ? "Edit Sale" : "Record New Sale"}
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-2">
            <BarcodeScanner onBarcodeDetected={handleBarcodeDetected} />
            {/* Product */}
            <div className="space-y-1.5">
              <Label>Product</Label>
              <Select value={form.product_id} onValueChange={handleProductChange}>
                <SelectTrigger>
                  <SelectValue placeholder="Select product..." />
                </SelectTrigger>
                <SelectContent>
                  {products.map((p: any) => (
                    <SelectItem key={p.id} value={p.id}>{p.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            {/* Client */}
            <div className="space-y-1.5">
              <Label>Client <span className="text-muted-foreground text-xs">(optional)</span></Label>
              <Select value={form.client_id} onValueChange={v => setForm(f => ({ ...f, client_id: v }))}>
                <SelectTrigger>
                  <SelectValue placeholder="Select client..." />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="none">Walk-in Customer</SelectItem>
                  {clients.map((c: any) => (
                    <SelectItem key={c.id} value={c.id}>{c.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            {/* Qty & Price */}
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-1.5">
                <Label>Quantity *</Label>
                <Input
                  type="number"
                  min={1}
                  value={form.quantity}
                  onChange={e => setForm(f => ({ ...f, quantity: Number(e.target.value) }))}
                />
              </div>
              <div className="space-y-1.5">
                <Label>Unit Price (৳) *</Label>
                <Input
                  type="number"
                  min={0}
                  value={form.unit_price}
                  onChange={e => setForm(f => ({ ...f, unit_price: Number(e.target.value) }))}
                />
              </div>
            </div>
            {/* Total preview */}
            <div className="rounded-lg bg-primary/5 border border-primary/20 px-3 py-2 flex justify-between items-center">
              <span className="text-xs text-muted-foreground">Total</span>
              <span className="text-base font-bold text-primary">৳{(form.quantity * form.unit_price).toLocaleString()}</span>
            </div>
            {/* Status & Date */}
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-1.5">
                <Label>Payment Status</Label>
                <Select value={form.payment_status} onValueChange={v => setForm(f => ({ ...f, payment_status: v as PaymentStatus }))}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="paid">✅ Paid</SelectItem>
                    <SelectItem value="pending">⏳ Pending</SelectItem>
                    <SelectItem value="partial">🔄 Partial</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-1.5">
                <Label>Sale Date</Label>
                <Input
                  type="date"
                  value={form.sale_date}
                  onChange={e => setForm(f => ({ ...f, sale_date: e.target.value }))}
                />
              </div>
            </div>
            {/* Notes */}
            <div className="space-y-1.5">
              <Label>Notes <span className="text-muted-foreground text-xs">(optional)</span></Label>
              <Textarea
                rows={2}
                placeholder="Any additional notes..."
                value={form.notes}
                onChange={e => setForm(f => ({ ...f, notes: e.target.value }))}
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDialogOpen(false)}>Cancel</Button>
            <Button onClick={handleSubmit} disabled={saveMutation.isPending} className="corporate-gradient text-white border-0">
              {saveMutation.isPending ? "Saving..." : editingId ? "Update Sale" : "Record Sale"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Confirm */}
      <ConfirmDeleteDialog
        open={!!deleteId}
        onClose={() => setDeleteId(null)}
        onConfirm={() => deleteId && deleteMutation.mutate(deleteId)}
        title="Delete Sale"
        description="Are you sure you want to delete this sale record? This action cannot be undone."
      />
    </div>
  );
}

import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Textarea } from "@/components/ui/textarea";
import { Search, Trash2, Edit2, CheckCircle, Wrench, Clock, AlertTriangle, MessageSquare } from "lucide-react";
import { openWhatsApp, serviceRequestMessage } from "@/lib/whatsapp";
import { sendSMS } from "@/lib/sms";
import { useToast } from "@/hooks/use-toast";
import { format } from "date-fns";

const CATEGORIES = ["CCTV", "Networking", "Attendance Device", "Computer", "Printer", "Server", "Software", "Smart Home", "Other"];
const STATUSES = ["all", "pending", "accepted", "in_progress", "completed", "cancelled"];
const URGENCIES = ["normal", "urgent", "emergency"];

const statusColors: Record<string, string> = {
  pending: "bg-yellow-500/15 text-yellow-600 border-yellow-500/30",
  accepted: "bg-blue-500/15 text-blue-600 border-blue-500/30",
  in_progress: "bg-purple-500/15 text-purple-600 border-purple-500/30",
  completed: "bg-green-500/15 text-green-600 border-green-500/30",
  cancelled: "bg-destructive/15 text-destructive border-destructive/30",
};

const urgencyColors: Record<string, string> = {
  normal: "bg-muted text-muted-foreground",
  urgent: "bg-orange-500/15 text-orange-600",
  emergency: "bg-red-500/15 text-red-600",
};

export default function ServiceRequests() {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState("all");
  const [editId, setEditId] = useState<string | null>(null);
  const [open, setOpen] = useState(false);
  const [form, setForm] = useState({
    customer_name: "", phone: "", email: "", category: "Other",
    description: "", preferred_date: "", urgency: "normal", status: "pending", notes: "",
  });

  const { data: requests = [], isLoading } = useQuery({
    queryKey: ["service-requests"],
    queryFn: async () => {
      const { data } = await supabase.from("service_requests").select("*").order("created_at", { ascending: false });
      return data || [];
    },
  });

  const saveRequest = useMutation({
    mutationFn: async () => {
      const payload = {
        customer_name: form.customer_name,
        phone: form.phone || null,
        email: form.email || null,
        category: form.category,
        description: form.description,
        preferred_date: form.preferred_date || null,
        urgency: form.urgency,
        status: form.status,
        notes: form.notes || null,
      };
      if (editId) {
        const { error } = await supabase.from("service_requests").update(payload).eq("id", editId);
        if (error) throw error;
      } else {
        const { error } = await supabase.from("service_requests").insert(payload);
        if (error) throw error;
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["service-requests"] });
      toast({ title: editId ? "রিকোয়েস্ট আপডেট হয়েছে" : "রিকোয়েস্ট যোগ হয়েছে" });
      closeDialog();
    },
    onError: (e: any) => toast({ title: "Error", description: e.message, variant: "destructive" }),
  });

  const deleteRequest = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("service_requests").delete().eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["service-requests"] });
      toast({ title: "রিকোয়েস্ট ডিলিট হয়েছে" });
    },
  });

  const acceptToServicing = useMutation({
    mutationFn: async (req: any) => {
      const { error: sErr } = await supabase.from("servicing").insert({
        client_name: req.customer_name,
        description: req.description,
        category: req.category,
        service_date: req.preferred_date || new Date().toISOString().split("T")[0],
        status: "pending",
        notes: `From service request. Phone: ${req.phone || "N/A"}`,
      });
      if (sErr) throw sErr;
      const { error: uErr } = await supabase.from("service_requests").update({ status: "accepted" }).eq("id", req.id);
      if (uErr) throw uErr;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["service-requests"] });
      toast({ title: "রিকোয়েস্ট গ্রহণ করা হয়েছে এবং সার্ভিসিং-এ যোগ হয়েছে ✅" });
    },
    onError: (e: any) => toast({ title: "Error", description: e.message, variant: "destructive" }),
  });

  const handleSendSMS = async (r: any) => {
    if (!r.phone) {
      toast({ title: "No phone number", description: "This customer does not have a phone number.", variant: "destructive" });
      return;
    }
    const message = `Hello ${r.customer_name}, your service request for ${r.category} is currently marked as ${r.status}. Thank you!`;
    try {
      await sendSMS(r.phone, message);
      toast({ title: "SMS Sent", description: "Message delivered successfully." });
    } catch (e: any) {
      toast({ title: "SMS Failed", description: e.message, variant: "destructive" });
    }
  };

  const closeDialog = () => {
    setOpen(false); setEditId(null);
    setForm({ customer_name: "", phone: "", email: "", category: "Other", description: "", preferred_date: "", urgency: "normal", status: "pending", notes: "" });
  };

  const openEdit = (r: any) => {
    setEditId(r.id);
    setForm({
      customer_name: r.customer_name, phone: r.phone || "", email: r.email || "",
      category: r.category, description: r.description, preferred_date: r.preferred_date || "",
      urgency: r.urgency, status: r.status, notes: r.notes || "",
    });
    setOpen(true);
  };

  const filtered = requests.filter((r: any) => {
    if (search && !r.customer_name.toLowerCase().includes(search.toLowerCase()) && !(r.phone || "").includes(search)) return false;
    if (statusFilter !== "all" && r.status !== statusFilter) return false;
    return true;
  });

  const pending = requests.filter((r: any) => r.status === "pending").length;
  const urgent = requests.filter((r: any) => r.urgency !== "normal" && r.status === "pending").length;

  return (
    <>
      <div className="space-y-6">
        <div className="flex items-center justify-between flex-wrap gap-3">
          <div>
            <h1 className="text-2xl font-bold">সার্ভিস রিকোয়েস্ট</h1>
            <p className="text-sm text-muted-foreground">কাস্টমারদের সার্ভিসিং রিকোয়েস্ট ম্যানেজ করুন</p>
          </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
          <Card><CardContent className="pt-4 pb-3 flex items-center gap-3">
            <div className="p-2 rounded-lg bg-yellow-500/10"><Clock className="h-5 w-5 text-yellow-600" /></div>
            <div><p className="text-xs text-muted-foreground">পেন্ডিং</p><p className="text-xl font-bold">{pending}</p></div>
          </CardContent></Card>
          <Card><CardContent className="pt-4 pb-3 flex items-center gap-3">
            <div className="p-2 rounded-lg bg-red-500/10"><AlertTriangle className="h-5 w-5 text-red-600" /></div>
            <div><p className="text-xs text-muted-foreground">আর্জেন্ট</p><p className="text-xl font-bold">{urgent}</p></div>
          </CardContent></Card>
          <Card><CardContent className="pt-4 pb-3 flex items-center gap-3">
            <div className="p-2 rounded-lg bg-primary/10"><Wrench className="h-5 w-5 text-primary" /></div>
            <div><p className="text-xs text-muted-foreground">মোট রিকোয়েস্ট</p><p className="text-xl font-bold">{requests.length}</p></div>
          </CardContent></Card>
        </div>

        <div className="flex flex-wrap gap-3">
          <div className="relative flex-1 min-w-[200px]">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input placeholder="নাম বা ফোন দিয়ে খুঁজুন..." value={search} onChange={(e) => setSearch(e.target.value)} className="pl-9" />
          </div>
          <Select value={statusFilter} onValueChange={setStatusFilter}>
            <SelectTrigger className="w-[140px]"><SelectValue /></SelectTrigger>
            <SelectContent>{STATUSES.map(s => <SelectItem key={s} value={s}>{s === "all" ? "সব" : s}</SelectItem>)}</SelectContent>
          </Select>
        </div>

        <Card>
          <CardContent className="p-0">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>কাস্টমার</TableHead>
                  <TableHead>ক্যাটাগরি</TableHead>
                  <TableHead>বিবরণ</TableHead>
                  <TableHead>জরুরিতা</TableHead>
                  <TableHead>স্ট্যাটাস</TableHead>
                  <TableHead>তারিখ</TableHead>
                  <TableHead className="text-right">অ্যাকশন</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {isLoading ? (
                  <TableRow><TableCell colSpan={7} className="text-center py-8">লোড হচ্ছে...</TableCell></TableRow>
                ) : filtered.length === 0 ? (
                  <TableRow><TableCell colSpan={7} className="text-center py-8 text-muted-foreground">কোনো রিকোয়েস্ট নেই</TableCell></TableRow>
                ) : filtered.map((r: any) => (
                  <TableRow key={r.id}>
                    <TableCell>
                      <p className="font-medium text-sm">{r.customer_name}</p>
                      <p className="text-xs text-muted-foreground">{r.phone || "—"}</p>
                    </TableCell>
                    <TableCell><Badge variant="outline" className="text-xs">{r.category}</Badge></TableCell>
                    <TableCell className="max-w-[200px] truncate text-sm">{r.description}</TableCell>
                    <TableCell><Badge className={`text-xs ${urgencyColors[r.urgency]}`}>{r.urgency}</Badge></TableCell>
                    <TableCell><Badge variant="outline" className={statusColors[r.status] || ""}>{r.status}</Badge></TableCell>
                    <TableCell className="text-xs">{format(new Date(r.created_at), "dd MMM yyyy")}</TableCell>
                    <TableCell className="text-right">
                      <div className="flex gap-1 justify-end">
                        {r.phone && (
                          <>
                            <Button size="sm" variant="ghost" className="h-7 w-7 p-0" onClick={() => openWhatsApp(r.phone, serviceRequestMessage(r))} title="WhatsApp">
                              <MessageSquare className="h-3.5 w-3.5 text-green-600" />
                            </Button>
                            <Button size="sm" variant="ghost" className="h-7 w-7 p-0" onClick={() => handleSendSMS(r)} title="Send SMS">
                              <svg className="h-3.5 w-3.5 text-blue-500" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>
                            </Button>
                          </>
                        )}
                        {r.status === "pending" && (
                          <Button size="sm" variant="ghost" className="h-7 w-7 p-0" onClick={() => acceptToServicing.mutate(r)} title="Accept & Servicing-এ যোগ">
                            <CheckCircle className="h-3.5 w-3.5 text-green-600" />
                          </Button>
                        )}
                        <Button size="sm" variant="ghost" className="h-7 w-7 p-0" onClick={() => openEdit(r)}><Edit2 className="h-3.5 w-3.5" /></Button>
                        <Button size="sm" variant="ghost" className="h-7 w-7 p-0" onClick={() => deleteRequest.mutate(r.id)}><Trash2 className="h-3.5 w-3.5 text-destructive" /></Button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </CardContent>
        </Card>
      </div>

      <Dialog open={open} onOpenChange={setOpen}>
        <DialogContent className="max-w-md">
          <DialogHeader><DialogTitle>{editId ? "রিকোয়েস্ট এডিট" : "নতুন রিকোয়েস্ট"}</DialogTitle></DialogHeader>
          <form onSubmit={(e) => { e.preventDefault(); saveRequest.mutate(); }} className="space-y-3">
            <div><Label>কাস্টমার নাম *</Label><Input value={form.customer_name} onChange={e => setForm({ ...form, customer_name: e.target.value })} required /></div>
            <div className="grid grid-cols-2 gap-3">
              <div><Label>ফোন</Label><Input value={form.phone} onChange={e => setForm({ ...form, phone: e.target.value })} /></div>
              <div><Label>ইমেইল</Label><Input type="email" value={form.email} onChange={e => setForm({ ...form, email: e.target.value })} /></div>
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div><Label>ক্যাটাগরি</Label>
                <Select value={form.category} onValueChange={v => setForm({ ...form, category: v })}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>{CATEGORIES.map(c => <SelectItem key={c} value={c}>{c}</SelectItem>)}</SelectContent>
                </Select>
              </div>
              <div><Label>জরুরিতা</Label>
                <Select value={form.urgency} onValueChange={v => setForm({ ...form, urgency: v })}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>{URGENCIES.map(u => <SelectItem key={u} value={u}>{u}</SelectItem>)}</SelectContent>
                </Select>
              </div>
            </div>
            <div><Label>বিবরণ *</Label><Textarea value={form.description} onChange={e => setForm({ ...form, description: e.target.value })} required rows={2} /></div>
            <div className="grid grid-cols-2 gap-3">
              <div><Label>পছন্দের তারিখ</Label><Input type="date" value={form.preferred_date} onChange={e => setForm({ ...form, preferred_date: e.target.value })} /></div>
              <div><Label>স্ট্যাটাস</Label>
                <Select value={form.status} onValueChange={v => setForm({ ...form, status: v })}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>{["pending", "accepted", "in_progress", "completed", "cancelled"].map(s => <SelectItem key={s} value={s}>{s}</SelectItem>)}</SelectContent>
                </Select>
              </div>
            </div>
            <div><Label>নোট</Label><Textarea value={form.notes} onChange={e => setForm({ ...form, notes: e.target.value })} rows={2} /></div>
            <Button type="submit" className="w-full" disabled={saveRequest.isPending}>{saveRequest.isPending ? "সেভ হচ্ছে..." : "সেভ করুন"}</Button>
          </form>
        </DialogContent>
      </Dialog>
    </>
  );
}

import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Plus, Pencil, Trash2, Search, Sparkles, RefreshCw, AlertCircle } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { ConfirmDeleteDialog } from "@/components/ConfirmDeleteDialog";
import { ImagePicker } from "@/components/ImagePicker";
import { GoogleGenerativeAI } from "@google/generative-ai";

const categories = [
  "CCTV",
  "Attendance Device",
  "Networking",
  "IT Support",
  "Installation",
  "Maintenance",
  "Server",
  "Computer",
];

interface ServiceForm {
  name: string;
  description: string;
  category: string;
  price: string;
  status: string;
  image_url: string;
}

const emptyForm: ServiceForm = {
  name: "",
  description: "",
  category: "CCTV",
  price: "0",
  status: "active",
  image_url: "",
};

export default function Services() {
  const queryClient = useQueryClient();
  const { toast } = useToast();
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);
  const [open, setOpen] = useState(false);
  const [editId, setEditId] = useState<string | null>(null);
  const [form, setForm] = useState<ServiceForm>(emptyForm);
  const [search, setSearch] = useState("");
  const [aiLoading, setAiLoading] = useState(false);

  // ── Data fetch with retry ──────────────────────────────────────────────────
  const {
    data: services = [],
    isLoading,
    isError,
    error,
    refetch,
  } = useQuery({
    queryKey: ["services"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("services")
        .select("*")
        .order("created_at", { ascending: false });
      if (error) throw new Error(error.message);
      return data ?? [];
    },
    retry: 3,
    retryDelay: (attempt) => Math.min(1000 * 2 ** attempt, 8000),
    staleTime: 30_000,
  });

  // ── AI description generator ───────────────────────────────────────────────
  const generateDescription = async () => {
    if (!form.name) {
      toast({ title: "Service Name দিন", description: "AI description generate করতে আগে Service এর নাম দিন।", variant: "destructive" });
      return;
    }
    const apiKey = import.meta.env.VITE_GEMINI_API_KEY;
    if (!apiKey) {
      toast({ title: "API Key নেই", description: ".env ফাইলে VITE_GEMINI_API_KEY যোগ করুন।", variant: "destructive" });
      return;
    }
    setAiLoading(true);
    try {
      const genAI = new GoogleGenerativeAI(apiKey);
      const model = genAI.getGenerativeModel({ model: "gemini-2.5-flash" });
      const prompt = `Write a short, professional service description (2-3 sentences, max 100 words) for an IT company in Bangladesh called "AK IT Solution" for the following service:

Service Name: ${form.name}
Category: ${form.category}

The description should be in English, highlight key benefits, and be suitable for a service catalog. Return ONLY the description text, no extra formatting.`;

      const result = await model.generateContent(prompt);
      const text = result.response.text().trim();
      setForm((prev) => ({ ...prev, description: text }));
      toast({ title: "✨ Description তৈরি হয়েছে!" });
    } catch (err: any) {
      toast({ title: "AI Error", description: err.message || "Description generate করতে সমস্যা হয়েছে।", variant: "destructive" });
    } finally {
      setAiLoading(false);
    }
  };

  // ── Mutations ──────────────────────────────────────────────────────────────
  const upsertMutation = useMutation({
    mutationFn: async () => {
      const payload = {
        name: form.name.trim(),
        description: form.description.trim() || null,
        category: form.category,
        price: Number(form.price) || 0,
        status: form.status,
        image_url: form.image_url || null,
      };
      if (editId) {
        const { error } = await supabase.from("services").update(payload).eq("id", editId);
        if (error) throw new Error(error.message);
      } else {
        const { error } = await supabase.from("services").insert(payload);
        if (error) throw new Error(error.message);
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["services"] });
      queryClient.invalidateQueries({ queryKey: ["store-services"] });
      toast({ title: editId ? "Service আপডেট হয়েছে ✅" : "নতুন Service যোগ হয়েছে ✅" });
      setOpen(false);
      setEditId(null);
      setForm(emptyForm);
    },
    onError: (err: any) =>
      toast({ title: "Error", description: err.message, variant: "destructive" }),
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("services").delete().eq("id", id);
      if (error) throw new Error(error.message);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["services"] });
      queryClient.invalidateQueries({ queryKey: ["store-services"] });
      toast({ title: "Service ডিলিট হয়েছে" });
      setDeleteConfirmId(null);
    },
    onError: (err: any) =>
      toast({ title: "Error", description: err.message, variant: "destructive" }),
  });

  // ── Helpers ────────────────────────────────────────────────────────────────
  const openEdit = (service: any) => {
    setEditId(service.id);
    setForm({
      name: service.name ?? "",
      description: service.description ?? "",
      category: service.category ?? "CCTV",
      price: String(service.price ?? 0),
      status: service.status ?? "active",
      image_url: service.image_url ?? "",
    });
    setOpen(true);
  };

  const openCreate = () => {
    setEditId(null);
    setForm(emptyForm);
    setOpen(true);
  };

  const filtered = services.filter(
    (s: any) =>
      s.name?.toLowerCase().includes(search.toLowerCase()) ||
      s.category?.toLowerCase().includes(search.toLowerCase())
  );

  // ── Render ─────────────────────────────────────────────────────────────────
  return (
    <>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between gap-4 flex-wrap">
          <div>
            <h1 className="text-2xl font-bold tracking-tight">Services</h1>
            <p className="text-muted-foreground text-sm mt-1">
              আপনার সার্ভিস ক্যাটালগ ম্যানেজ করুন
            </p>
          </div>

          <Dialog open={open} onOpenChange={setOpen}>
            <DialogTrigger asChild>
              <Button onClick={openCreate}>
                <Plus className="h-4 w-4 mr-2" /> Add Service
              </Button>
            </DialogTrigger>

            <DialogContent className="max-w-md max-h-[90dvh] overflow-y-auto">
              <DialogHeader>
                <DialogTitle>{editId ? "Edit Service" : "Add Service"}</DialogTitle>
              </DialogHeader>

              <form
                onSubmit={(e) => {
                  e.preventDefault();
                  if (!form.name.trim()) {
                    toast({ title: "Service Name দিন", variant: "destructive" });
                    return;
                  }
                  upsertMutation.mutate();
                }}
                className="space-y-4"
              >
                {/* Image */}
                <ImagePicker
                  label="Service Image"
                  value={form.image_url}
                  onChange={(url) => setForm((p) => ({ ...p, image_url: url }))}
                  bucket="service-images"
                  previewAspect="aspect-video"
                />

                {/* Name */}
                <div className="space-y-2">
                  <Label>Name *</Label>
                  <Input
                    value={form.name}
                    onChange={(e) => setForm((p) => ({ ...p, name: e.target.value }))}
                    required
                    placeholder="e.g. CCTV Installation"
                  />
                </div>

                {/* Description + AI button */}
                <div className="space-y-2">
                  <div className="flex items-center justify-between">
                    <Label>Description</Label>
                    <Button
                      type="button"
                      variant="ghost"
                      size="sm"
                      className="h-7 gap-1 text-xs text-purple-500 hover:text-purple-600"
                      onClick={generateDescription}
                      disabled={aiLoading}
                    >
                      <Sparkles className="h-3.5 w-3.5" />
                      {aiLoading ? "Generating…" : "AI Generate"}
                    </Button>
                  </div>
                  <Textarea
                    value={form.description}
                    onChange={(e) => setForm((p) => ({ ...p, description: e.target.value }))}
                    placeholder="Service details..."
                    rows={3}
                  />
                </div>

                {/* Category + Price */}
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label>Category</Label>
                    <Select
                      value={form.category}
                      onValueChange={(v) => setForm((p) => ({ ...p, category: v }))}
                    >
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        {categories.map((c) => (
                          <SelectItem key={c} value={c}>
                            {c}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label>Price (৳)</Label>
                    <Input
                      type="number"
                      min={0}
                      value={form.price}
                      onChange={(e) => setForm((p) => ({ ...p, price: e.target.value }))}
                    />
                  </div>
                </div>

                {/* Status */}
                <div className="space-y-2">
                  <Label>Status</Label>
                  <Select
                    value={form.status}
                    onValueChange={(v) => setForm((p) => ({ ...p, status: v }))}
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="active">Active</SelectItem>
                      <SelectItem value="inactive">Inactive</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <Button
                  type="submit"
                  className="w-full"
                  disabled={upsertMutation.isPending}
                >
                  {upsertMutation.isPending
                    ? "Saving…"
                    : editId
                    ? "Update Service"
                    : "Add Service"}
                </Button>
              </form>
            </DialogContent>
          </Dialog>
        </div>

        {/* Search */}
        <div className="relative max-w-sm">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Search services..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-10"
          />
        </div>

        {/* Table */}
        <Card className="glass-card">
          <CardContent className="p-0">
            {isError ? (
              /* Error state */
              <div className="flex flex-col items-center justify-center py-16 gap-3 text-destructive">
                <AlertCircle className="h-10 w-10" />
                <p className="font-medium text-sm">
                  {(error as Error)?.message || "ডাটা লোড করতে সমস্যা হয়েছে"}
                </p>
                <Button variant="outline" size="sm" onClick={() => refetch()}>
                  <RefreshCw className="h-4 w-4 mr-2" /> আবার চেষ্টা করুন
                </Button>
              </div>
            ) : isLoading ? (
              /* Loading skeleton */
              <div className="flex items-center justify-center py-16 gap-3 text-muted-foreground">
                <RefreshCw className="h-5 w-5 animate-spin" />
                <span className="text-sm">Loading services...</span>
              </div>
            ) : (
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Image</TableHead>
                    <TableHead>Service</TableHead>
                    <TableHead>Category</TableHead>
                    <TableHead>Price</TableHead>
                    <TableHead>Status</TableHead>
                    <TableHead className="text-right">Actions</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {filtered.length === 0 ? (
                    <TableRow>
                      <TableCell
                        colSpan={6}
                        className="text-center py-12 text-muted-foreground"
                      >
                        {search
                          ? `"${search}" এর জন্য কোনো সার্ভিস পাওয়া যায়নি`
                          : "কোনো সার্ভিস নেই। Add Service বাটন দিয়ে নতুন সার্ভিস যোগ করুন।"}
                      </TableCell>
                    </TableRow>
                  ) : (
                    filtered.map((s: any) => (
                      <TableRow key={s.id}>
                        <TableCell>
                          {s.image_url ? (
                            <img
                              src={s.image_url}
                              alt={s.name}
                              className="h-10 w-10 rounded-lg object-cover"
                              loading="lazy"
                            />
                          ) : (
                            <div className="h-10 w-10 rounded-lg bg-muted flex items-center justify-center text-muted-foreground text-xs">
                              —
                            </div>
                          )}
                        </TableCell>
                        <TableCell>
                          <div>
                            <div className="font-medium">{s.name}</div>
                            {s.description && (
                              <div className="text-xs text-muted-foreground truncate max-w-[200px]">
                                {s.description}
                              </div>
                            )}
                          </div>
                        </TableCell>
                        <TableCell>
                          <Badge variant="outline">{s.category}</Badge>
                        </TableCell>
                        <TableCell>৳{Number(s.price).toLocaleString()}</TableCell>
                        <TableCell>
                          <Badge
                            variant={s.status === "active" ? "default" : "secondary"}
                          >
                            {s.status}
                          </Badge>
                        </TableCell>
                        <TableCell className="text-right">
                          <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => openEdit(s)}
                          >
                            <Pencil className="h-4 w-4" />
                          </Button>
                          <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => setDeleteConfirmId(s.id)}
                          >
                            <Trash2 className="h-4 w-4 text-destructive" />
                          </Button>
                        </TableCell>
                      </TableRow>
                    ))
                  )}
                </TableBody>
              </Table>
            )}
          </CardContent>
        </Card>
      </div>

      {/* Delete confirmation */}
      <ConfirmDeleteDialog
        open={!!deleteConfirmId}
        onOpenChange={(o) => !o && setDeleteConfirmId(null)}
        onConfirm={() => {
          if (deleteConfirmId) deleteMutation.mutate(deleteConfirmId);
        }}
        title="স্থায়ীভাবে ডিলিট করুন"
        description="এই সার্ভিসটি স্থায়ীভাবে মুছে যাবে এবং স্টোর থেকেও সরিয়ে দেওয়া হবে।"
      />
    </>
  );
}

import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem, CommandList } from "@/components/ui/command";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from "@/components/ui/alert-dialog";
import { Textarea } from "@/components/ui/textarea";
import { Checkbox } from "@/components/ui/checkbox";
import { Badge } from "@/components/ui/badge";
import { Plus, Wrench, DollarSign, TrendingUp, TrendingDown, Trash2, Clock, CheckCircle, Search, Filter, CalendarIcon, X, Download, Pencil, FileText } from "lucide-react";
import { useNavigate } from "react-router-dom";
import { useToast } from "@/hooks/use-toast";
import { format, isWithinInterval, parseISO } from "date-fns";
import { Calendar } from "@/components/ui/calendar";
import { cn } from "@/lib/utils";

const SERVICE_CATEGORIES = [
  "CCTV Installation",
  "CCTV Repair",
  "CCTV Maintenance",
  "Networking Setup",
  "Network Troubleshooting",
  "Computer Repair",
  "Computer Maintenance",
  "Laptop Repair",
  "Software Installation",
  "Server Setup",
  "Server Maintenance",
  "Attendance Device Setup",
  "Attendance Device Repair",
  "Intercom Setup",
  "Fire Alarm Installation",
  "Fire Alarm Maintenance",
  "IP Phone Setup",
  "PA System",
  "Gate Barrier",
  "Access Control",
  "DVR/NVR Setup",
  "Hard Disk Replacement",
  "Cable Wiring",
  "UPS Installation",
  "Printer Setup",
  "Data Recovery",
  "AMC (Annual Maintenance)",
  "Other",
];

interface ServicingRecord {
  id: string;
  description: string;
  client_name: string;
  category: string;
  amount: number;
  cost: number;
  status: string;
  service_date: string;
  notes: string | null;
  created_at: string;
}

export default function Servicing() {
  const navigate = useNavigate();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingRecord, setEditingRecord] = useState<ServicingRecord | null>(null);
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [bulkDeleteOpen, setBulkDeleteOpen] = useState(false);
  const [form, setForm] = useState({
    description: "",
    client_name: "",
    category: "CCTV Installation",
    amount: 0,
    cost: 0,
    status: "pending",
    service_date: new Date().toISOString().split("T")[0],
    notes: "",
  });

  const { data: records } = useQuery({
    queryKey: ["servicing"],
    queryFn: async () => {
      const { data } = await (supabase as any)
        .from("servicing")
        .select("*")
        .order("service_date", { ascending: false });
      return (data || []) as ServicingRecord[];
    },
  });

  const { data: clients } = useQuery({
    queryKey: ["clients"],
    queryFn: async () => {
      const { data } = await supabase.from("clients").select("id, name, phone, address").order("name");
      return data || [];
    },
  });

  const [clientPopoverOpen, setClientPopoverOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [filterCategory, setFilterCategory] = useState("all");
  const [dateFrom, setDateFrom] = useState<Date | undefined>();
  const [dateTo, setDateTo] = useState<Date | undefined>();

  const addMutation = useMutation({
    mutationFn: async () => {
      const { error } = await (supabase as any).from("servicing").insert({
        description: form.description,
        client_name: form.client_name,
        category: form.category,
        amount: form.amount,
        cost: form.cost,
        status: form.status,
        service_date: form.service_date,
        notes: form.notes || null,
      } as any);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["servicing"] });
      toast({ title: editingRecord ? "Record updated" : "Servicing record added" });
      setDialogOpen(false);
      setEditingRecord(null);
      setForm({ description: "", client_name: "", category: "CCTV Installation", amount: 0, cost: 0, status: "pending", service_date: new Date().toISOString().split("T")[0], notes: "" });
    },
    onError: () => toast({ title: "Error saving record", variant: "destructive" }),
  });

  const updateMutation = useMutation({
    mutationFn: async () => {
      if (!editingRecord) return;
      const { error } = await (supabase as any).from("servicing").update({
        description: form.description,
        client_name: form.client_name,
        category: form.category,
        amount: form.amount,
        cost: form.cost,
        status: form.status,
        service_date: form.service_date,
        notes: form.notes || null,
      } as any).eq("id", editingRecord.id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["servicing"] });
      toast({ title: "Record updated" });
      setDialogOpen(false);
      setEditingRecord(null);
      setForm({ description: "", client_name: "", category: "CCTV Installation", amount: 0, cost: 0, status: "pending", service_date: new Date().toISOString().split("T")[0], notes: "" });
    },
    onError: () => toast({ title: "Error updating record", variant: "destructive" }),
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await (supabase as any).from("servicing").delete().eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["servicing"] });
      toast({ title: "Record deleted" });
    },
  });

  const toggleStatusMutation = useMutation({
    mutationFn: async (rec: ServicingRecord) => {
      const newStatus = rec.status === "completed" ? "pending" : "completed";
      const { error } = await (supabase as any).from("servicing").update({ status: newStatus }).eq("id", rec.id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["servicing"] });
    },
  });

  const filteredRecords = records?.filter(r => {
    const matchesSearch = !searchQuery || 
      r.client_name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      r.description.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesCategory = filterCategory === "all" || r.category === filterCategory;
    const matchesDate = (() => {
      if (!dateFrom && !dateTo) return true;
      const d = parseISO(r.service_date);
      if (dateFrom && dateTo) return isWithinInterval(d, { start: dateFrom, end: dateTo });
      if (dateFrom) return d >= dateFrom;
      if (dateTo) return d <= dateTo;
      return true;
    })();
    return matchesSearch && matchesCategory && matchesDate;
  });

  const totalEarned = filteredRecords?.filter(r => r.status === "completed").reduce((s, r) => s + Number(r.amount), 0) || 0;
  const totalSpent = filteredRecords?.reduce((s, r) => s + Number(r.cost), 0) || 0;
  const netProfit = totalEarned - totalSpent;
  const pendingCount = filteredRecords?.filter(r => r.status === "pending").length || 0;

  const exportCSV = () => {
    if (!filteredRecords?.length) return;
    const headers = ["Date", "Client", "Description", "Category", "Income", "Cost", "Status", "Notes"];
    const rows = filteredRecords.map(r => [
      r.service_date, r.client_name, r.description, r.category,
      r.amount, r.cost, r.status, r.notes || ""
    ]);
    const csv = [headers, ...rows].map(row => row.map(v => `"${String(v).replace(/"/g, '""')}"`).join(",")).join("\n");
    const blob = new Blob([csv], { type: "text/csv" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `servicing-${new Date().toISOString().split("T")[0]}.csv`;
    a.click();
    URL.revokeObjectURL(url);
    toast({ title: `Exported ${filteredRecords.length} records` });
  };

  const openEdit = (rec: ServicingRecord) => {
    setEditingRecord(rec);
    setForm({
      description: rec.description,
      client_name: rec.client_name,
      category: rec.category,
      amount: rec.amount,
      cost: rec.cost,
      status: rec.status,
      service_date: rec.service_date,
      notes: rec.notes || "",
    });
    setDialogOpen(true);
  };

  const openAdd = () => {
    setEditingRecord(null);
    setForm({ description: "", client_name: "", category: "CCTV Installation", amount: 0, cost: 0, status: "pending", service_date: new Date().toISOString().split("T")[0], notes: "" });
    setDialogOpen(true);
  };

  const toggleSelect = (id: string) => {
    setSelectedIds(prev => {
      const next = new Set(prev);
      next.has(id) ? next.delete(id) : next.add(id);
      return next;
    });
  };

  const toggleSelectAll = () => {
    if (!filteredRecords) return;
    if (selectedIds.size === filteredRecords.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(filteredRecords.map(r => r.id)));
    }
  };

  const bulkDeleteMutation = useMutation({
    mutationFn: async (ids: string[]) => {
      const { error } = await (supabase as any).from("servicing").delete().in("id", ids);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["servicing"] });
      toast({ title: `${selectedIds.size} records deleted` });
      setSelectedIds(new Set());
      setBulkDeleteOpen(false);
    },
  });

  const bulkStatusMutation = useMutation({
    mutationFn: async ({ ids, status }: { ids: string[]; status: string }) => {
      const { error } = await (supabase as any).from("servicing").update({ status }).in("id", ids);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["servicing"] });
      toast({ title: `${selectedIds.size} records updated` });
      setSelectedIds(new Set());
    },
  });

  const statusColor: Record<string, string> = {
    pending: "bg-warning/10 text-warning border-warning/20",
    completed: "bg-success/10 text-success border-success/20",
    cancelled: "bg-destructive/10 text-destructive border-destructive/20",
  };

  return (
      <>
      <div className="space-y-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold tracking-tight">Servicing</h1>
            <p className="text-muted-foreground text-sm">Track service income and costs</p>
          </div>
          <div className="flex gap-2">
            <Button variant="outline" onClick={exportCSV} disabled={!filteredRecords?.length}><Download className="h-4 w-4 mr-1" /> Export CSV</Button>
            <Button onClick={openAdd}><Plus className="h-4 w-4 mr-1" /> Add Service</Button>
          </div>
        </div>

        {/* Summary Cards */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <Card className="glass-card">
            <CardContent className="p-4 flex items-center gap-3">
              <div className="h-10 w-10 rounded-lg bg-success/10 flex items-center justify-center"><TrendingUp className="h-5 w-5 text-success" /></div>
              <div><p className="text-xs text-muted-foreground">Service Income</p><p className="text-lg font-bold">৳{totalEarned.toLocaleString()}</p></div>
            </CardContent>
          </Card>
          <Card className="glass-card">
            <CardContent className="p-4 flex items-center gap-3">
              <div className="h-10 w-10 rounded-lg bg-destructive/10 flex items-center justify-center"><TrendingDown className="h-5 w-5 text-destructive" /></div>
              <div><p className="text-xs text-muted-foreground">Service Cost</p><p className="text-lg font-bold">৳{totalSpent.toLocaleString()}</p></div>
            </CardContent>
          </Card>
          <Card className="glass-card">
            <CardContent className="p-4 flex items-center gap-3">
              <div className={`h-10 w-10 rounded-lg flex items-center justify-center ${netProfit >= 0 ? "bg-primary/10" : "bg-destructive/10"}`}><DollarSign className={`h-5 w-5 ${netProfit >= 0 ? "text-primary" : "text-destructive"}`} /></div>
              <div><p className="text-xs text-muted-foreground">Net Profit</p><p className={`text-lg font-bold ${netProfit >= 0 ? "text-success" : "text-destructive"}`}>৳{netProfit.toLocaleString()}</p></div>
            </CardContent>
          </Card>
          <Card className="glass-card">
            <CardContent className="p-4 flex items-center gap-3">
              <div className="h-10 w-10 rounded-lg bg-warning/10 flex items-center justify-center"><Clock className="h-5 w-5 text-warning" /></div>
              <div><p className="text-xs text-muted-foreground">Pending</p><p className="text-lg font-bold">{pendingCount}</p></div>
            </CardContent>
          </Card>
        </div>

        {/* Search & Filter Bar */}
        <div className="flex flex-col sm:flex-row gap-3">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder="Search by client or description..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-9"
            />
          </div>
          <Select value={filterCategory} onValueChange={setFilterCategory}>
            <SelectTrigger className="w-full sm:w-[200px]">
              <Filter className="h-4 w-4 mr-2 text-muted-foreground" />
              <SelectValue placeholder="All Categories" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All Categories</SelectItem>
              {SERVICE_CATEGORIES.map(c => <SelectItem key={c} value={c}>{c}</SelectItem>)}
            </SelectContent>
          </Select>
          <Popover>
            <PopoverTrigger asChild>
              <Button variant="outline" className={cn("w-full sm:w-[150px] justify-start text-left font-normal", !dateFrom && "text-muted-foreground")}>
                <CalendarIcon className="h-4 w-4 mr-2" />
                {dateFrom ? format(dateFrom, "dd MMM yy") : "From"}
              </Button>
            </PopoverTrigger>
            <PopoverContent className="w-auto p-0" align="start">
              <Calendar mode="single" selected={dateFrom} onSelect={setDateFrom} initialFocus className={cn("p-3 pointer-events-auto")} />
            </PopoverContent>
          </Popover>
          <Popover>
            <PopoverTrigger asChild>
              <Button variant="outline" className={cn("w-full sm:w-[150px] justify-start text-left font-normal", !dateTo && "text-muted-foreground")}>
                <CalendarIcon className="h-4 w-4 mr-2" />
                {dateTo ? format(dateTo, "dd MMM yy") : "To"}
              </Button>
            </PopoverTrigger>
            <PopoverContent className="w-auto p-0" align="start">
              <Calendar mode="single" selected={dateTo} onSelect={setDateTo} initialFocus className={cn("p-3 pointer-events-auto")} />
            </PopoverContent>
          </Popover>
          {(dateFrom || dateTo) && (
            <Button variant="ghost" size="icon" className="h-9 w-9" onClick={() => { setDateFrom(undefined); setDateTo(undefined); }}>
              <X className="h-4 w-4" />
            </Button>
          )}
        </div>

        {/* Bulk Actions Bar */}
        {selectedIds.size > 0 && (
          <div className="flex items-center gap-3 p-3 bg-muted/50 rounded-lg border">
            <span className="text-sm font-medium">{selectedIds.size} selected</span>
            <Button size="sm" variant="outline" onClick={() => bulkStatusMutation.mutate({ ids: Array.from(selectedIds), status: "completed" })}>
              <CheckCircle className="h-4 w-4 mr-1" /> Mark Completed
            </Button>
            <Button size="sm" variant="outline" onClick={() => bulkStatusMutation.mutate({ ids: Array.from(selectedIds), status: "pending" })}>
              <Clock className="h-4 w-4 mr-1" /> Mark Pending
            </Button>
            <Button size="sm" variant="destructive" onClick={() => setBulkDeleteOpen(true)}>
              <Trash2 className="h-4 w-4 mr-1" /> Delete Selected
            </Button>
            <Button size="sm" variant="ghost" onClick={() => setSelectedIds(new Set())}>
              <X className="h-4 w-4 mr-1" /> Clear
            </Button>
          </div>
        )}

        {/* Records Table */}
        <Card className="glass-card">
          <CardContent className="p-0">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead className="w-10">
                    <Checkbox
                      checked={!!filteredRecords?.length && selectedIds.size === filteredRecords.length}
                      onCheckedChange={toggleSelectAll}
                    />
                  </TableHead>
                  <TableHead>Date</TableHead>
                  <TableHead>Client</TableHead>
                  <TableHead>Description</TableHead>
                  <TableHead>Category</TableHead>
                  <TableHead>Income</TableHead>
                  <TableHead>Cost</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead className="w-28">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {filteredRecords?.map((rec) => (
                  <TableRow key={rec.id} className={selectedIds.has(rec.id) ? "bg-muted/30" : ""}>
                    <TableCell>
                      <Checkbox
                        checked={selectedIds.has(rec.id)}
                        onCheckedChange={() => toggleSelect(rec.id)}
                      />
                    </TableCell>
                    <TableCell className="text-sm">{format(new Date(rec.service_date), "dd MMM yyyy")}</TableCell>
                    <TableCell className="font-medium">{rec.client_name}</TableCell>
                    <TableCell className="text-sm max-w-[200px] truncate">{rec.description}</TableCell>
                    <TableCell><Badge variant="outline" className="text-xs">{rec.category}</Badge></TableCell>
                    <TableCell className="font-medium text-success">৳{Number(rec.amount).toLocaleString()}</TableCell>
                    <TableCell className="font-medium text-destructive">৳{Number(rec.cost).toLocaleString()}</TableCell>
                    <TableCell>
                      <Badge variant="outline" className={statusColor[rec.status] || ""}>{rec.status}</Badge>
                    </TableCell>
                    <TableCell>
                      <div className="flex gap-1">
                        <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => navigate("/invoices/create", { state: { fromServicing: true, servicingRecord: rec } })} title="Create Bill">
                          <FileText className="h-4 w-4 text-primary" />
                        </Button>
                        <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => openEdit(rec)} title="Edit">
                          <Pencil className="h-4 w-4 text-muted-foreground" />
                        </Button>
                        <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => toggleStatusMutation.mutate(rec)} title={rec.status === "completed" ? "Mark Pending" : "Mark Completed"}>
                          {rec.status === "completed" ? <CheckCircle className="h-4 w-4 text-success" /> : <Clock className="h-4 w-4 text-warning" />}
                        </Button>
                        <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => setDeleteId(rec.id)}><Trash2 className="h-4 w-4 text-destructive" /></Button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))}
                {(!filteredRecords || filteredRecords.length === 0) && (
                  <TableRow><TableCell colSpan={9} className="text-center text-muted-foreground py-8">{searchQuery || filterCategory !== "all" ? "No matching records found" : "No servicing records yet"}</TableCell></TableRow>
                )}
              </TableBody>
            </Table>
          </CardContent>
        </Card>
      </div>

      {/* Add Service Dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-md">
          <DialogHeader><DialogTitle>{editingRecord ? "Edit Servicing Record" : "Add Servicing Record"}</DialogTitle></DialogHeader>
          <div className="space-y-3">
            <div>
              <Label>Client Name</Label>
              <Popover open={clientPopoverOpen} onOpenChange={setClientPopoverOpen}>
                <PopoverTrigger asChild>
                  <Button variant="outline" className="w-full justify-start font-normal" role="combobox">
                    {form.client_name || "Select or type client..."}
                  </Button>
                </PopoverTrigger>
                <PopoverContent className="w-full p-0" align="start">
                  <Command>
                    <CommandInput placeholder="Search clients..." onValueChange={(v) => setForm({ ...form, client_name: v })} />
                    <CommandList>
                      <CommandEmpty>
                        <span className="text-xs text-muted-foreground">No match — type a new name above</span>
                      </CommandEmpty>
                      <CommandGroup heading="Existing Clients">
                        {clients?.map((c) => (
                          <CommandItem key={c.id} value={c.name} onSelect={() => { setForm({ ...form, client_name: c.name }); setClientPopoverOpen(false); }}>
                            <div>
                              <p className="font-medium text-sm">{c.name}</p>
                              {c.phone && <p className="text-xs text-muted-foreground">{c.phone}</p>}
                            </div>
                          </CommandItem>
                        ))}
                      </CommandGroup>
                    </CommandList>
                  </Command>
                </PopoverContent>
              </Popover>
            </div>
            <div><Label>Description</Label><Input value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })} placeholder="Service description" /></div>
            <div><Label>Category</Label>
              <Select value={form.category} onValueChange={(v) => setForm({ ...form, category: v })}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>{SERVICE_CATEGORIES.map(c => <SelectItem key={c} value={c}>{c}</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div><Label>Service Charge (৳)</Label><Input type="number" value={form.amount} onChange={(e) => setForm({ ...form, amount: Number(e.target.value) })} /></div>
              <div><Label>Cost/Expense (৳)</Label><Input type="number" value={form.cost} onChange={(e) => setForm({ ...form, cost: Number(e.target.value) })} /></div>
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div><Label>Date</Label><Input type="date" value={form.service_date} onChange={(e) => setForm({ ...form, service_date: e.target.value })} /></div>
              <div><Label>Status</Label>
                <Select value={form.status} onValueChange={(v) => setForm({ ...form, status: v })}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="pending">Pending</SelectItem>
                    <SelectItem value="completed">Completed</SelectItem>
                    <SelectItem value="cancelled">Cancelled</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>
            <div><Label>Notes (optional)</Label><Textarea value={form.notes} onChange={(e) => setForm({ ...form, notes: e.target.value })} rows={2} /></div>
