              {form.banner_images.map((url, i) => (
                <div key={i} className="relative group rounded-lg overflow-hidden border border-border aspect-[21/5]">
                  <img src={url} alt={`Banner ${i + 1}`} className="w-full h-full object-cover" />
                  <button
